function encodeInlineJsString(value) {
  return JSON.stringify(String(value ?? ''))
    .replace(/&/g, '&amp;')
    .replace(/"/g, '&quot;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

// Build the `reasoning` payload for /api/chat. Cloud providers now read their
// reasoning/thinking settings from shared provider config so the chat popover and
// Settings > Models stay in sync; only local backends still use ad hoc overrides.
function buildReasoningPayload() {
  const prov = window._activeProvider || 'ollama';
  const effortProviders = new Set(['openai', 'openai_codex', 'perplexity']);
  if (effortProviders.has(prov)) {
    return undefined;
  }
  if (prov === 'anthropic') {
    return undefined;
  }
  // Local providers ignore reasoning.
  return window.reasoningEnabled ? { enabled: true, level: window.reasoningLevel || 'low' } : undefined;
}

