function generateSessionId() {
  return (crypto?.randomUUID?.() || ('sess_' + Math.random().toString(36).slice(2)));
}

function generateSideChatId() {
  return `side_${generateSessionId().replace(/^sess_/, '')}`;
}

function normalizeSideChatLink(link) {
  const id = String(link?.id || link?.sessionId || '').trim();
  const parentSessionId = String(link?.parentSessionId || '').trim();
  if (!id || !parentSessionId) return null;
  return {
    id,
    parentSessionId,
    title: String(link?.title || 'Side chat').trim() || 'Side chat',
    anchorIndex: Number.isInteger(link?.anchorIndex) ? link.anchorIndex : null,
    anchorPreview: String(link?.anchorPreview || '').trim(),
    createdAt: Number(link?.createdAt || Date.now()) || Date.now(),
    updatedAt: Number(link?.updatedAt || link?.createdAt || Date.now()) || Date.now(),
    closed: link?.closed === true,
  };
}

function loadSideChatLinks() {
  try {
    const parsed = JSON.parse(localStorage.getItem(SIDE_CHAT_STATE_KEY) || '[]');
    window.sideChatLinks = Array.isArray(parsed)
      ? parsed.map(normalizeSideChatLink).filter(Boolean)
      : [];
  } catch {
    window.sideChatLinks = [];
  }
  return window.sideChatLinks;
}

function saveSideChatLinks() {
  try {
    localStorage.setItem(SIDE_CHAT_STATE_KEY, JSON.stringify((window.sideChatLinks || []).map(normalizeSideChatLink).filter(Boolean)));
  } catch {}
  updateSideChatChrome();
}

loadSideChatLinks();

function getSideChatLinksForParent(parentSessionId = window.activeChatSessionId, options = {}) {
  const parent = String(parentSessionId || '').trim();
  if (!parent) return [];
  const includeClosed = options.includeClosed === true;
  return (window.sideChatLinks || [])
    .filter((link) => String(link?.parentSessionId || '') === parent)
    .filter((link) => includeClosed || link.closed !== true)
    .sort((a, b) => Number(b.updatedAt || 0) - Number(a.updatedAt || 0));
}

function getActiveSideChatLink() {
  const activeId = String(window.activeSideChatId || '').trim();
  if (!activeId) return null;
  const link = (window.sideChatLinks || []).find((item) => String(item?.id || '') === activeId) || null;
  if (!link) return null;
  return String(link.parentSessionId || '') === String(window.activeChatSessionId || '') ? link : null;
}

function getSideChatSession() {
  const link = getActiveSideChatLink();
  return link ? getChatSessionById(link.id) : null;
}

function isSessionVisibleInChatSurface(sessionId) {
  const sid = String(sessionId || '').trim();
  if (!sid) return false;
  if (sid === String(window.activeChatSessionId || '').trim()) return true;
  return window.sideChatSplitOpen && sid === String(window.activeSideChatId || '').trim();
}

function getSideChatParentSession(link = getActiveSideChatLink()) {
  return link ? getChatSessionById(link.parentSessionId) : null;
}

function sideChatReferenceMessages(parentSession, anchorIndex = null) {
  const history = Array.isArray(parentSession?.history) ? parentSession.history : [];
  const selected = Number.isInteger(anchorIndex) && anchorIndex >= 0
    ? history.slice(Math.max(0, anchorIndex - 4), anchorIndex + 1)
    : history.slice(-8);
  return selected
    .filter((msg) => msg && !isInternalChatMessage(msg))
    .map((msg) => {
      const role = msg.role === 'user' ? 'User' : 'Prometheus';
      const text = String(msg.content || '').replace(/\s+/g, ' ').trim();
      return text ? `${role}: ${text.slice(0, 420)}` : '';
    })
    .filter(Boolean);
}

function buildSideChatBoundaryMessage(parentSession, options = {}) {
  const parentTitle = String(parentSession?.title || 'Main chat').trim();
  const anchorPreview = String(options.anchorPreview || '').trim();
  const reference = sideChatReferenceMessages(parentSession, options.anchorIndex);
  const lines = [
    '[Side chat boundary]',
    `Parent chat: ${parentTitle}`,
    '',
    'Inherited parent context is reference only.',
    'Do not continue old plans, edits, tool calls, approvals, or implementation work from the parent unless the user explicitly asks in this side chat.',
    'Default behavior: answer questions, explore lightly, and avoid mutating files, git, config, permissions, or workspace state.',
    anchorPreview ? `Anchor: ${anchorPreview}` : '',
    reference.length ? '' : '',
    reference.length ? 'Reference snapshot:' : '',
    ...reference.map((line) => `- ${line}`),
    '[/Side chat boundary]',
  ].filter((line) => line !== '');
  return {
    role: 'assistant',
    content: lines.join('\n'),
    timestamp: Date.now(),
    channelLabel: 'side chat',
    sideChatBoundary: true,
  };
}

function makeSideChatTitle(seed = '') {
  const text = String(seed || '').replace(/\s+/g, ' ').trim();
  if (!text) return 'Side chat';
  return text.length > 42 ? `${text.slice(0, 39)}...` : text;
}

function updateSideChatChrome() {
  const links = getSideChatLinksForParent(window.activeChatSessionId);
  const btn = document.getElementById('side-chats-toggle-btn');
  if (btn) {
    const hasLinks = links.length > 0;
    btn.style.display = hasLinks ? 'inline-flex' : 'none';
    btn.classList.toggle('active', window.sideChatSplitOpen && !!getActiveSideChatLink());
    btn.title = hasLinks ? `${links.length} linked side chat${links.length === 1 ? '' : 's'}` : 'Side chats';
  }
  document.body?.classList?.toggle('side-chat-split-active', window.sideChatSplitOpen && !!getActiveSideChatLink());
}

function showSideChatSplit(sideChatId = window.activeSideChatId) {
  const link = (window.sideChatLinks || []).find((item) => String(item?.id || '') === String(sideChatId || '')) || getSideChatLinksForParent()[0] || null;
  if (!link) {
    window.sideChatSplitOpen = false;
    window.activeSideChatId = '';
    updateSideChatChrome();
    renderChatMessages();
    return false;
  }
  link.closed = false;
  link.updatedAt = Date.now();
  window.activeSideChatId = link.id;
  window.sideChatSplitOpen = true;
  saveSideChatLinks();
  renderChatMessages();
  return true;
}

function closeSideChatSplit() {
  window.sideChatSplitOpen = false;
  updateSideChatChrome();
  renderChatMessages();
}

async function syncSessionHistoryToServerById(sessionId, history = [], options = {}) {
  const sid = String(sessionId || '').trim();
  if (!sid) return;
  try {
    await fetch(`/api/sessions/${encodeURIComponent(sid)}/history`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        history: historyForServer(history),
        resetCompaction: options.resetCompaction === true,
      }),
    });
  } catch (err) {
    console.warn('[ChatPage] failed to sync side chat history:', err);
  }
}

async function createSideChat(options = {}) {
  ensureActiveChatSessionExists();
  const parentSessionId = String(window.activeChatSessionId || '').trim();
  const parent = getChatSessionById(parentSessionId);
  if (!parent) return null;
  const id = generateSideChatId();
  const anchorIndex = Number.isInteger(options.anchorIndex) ? options.anchorIndex : null;
  const anchorMsg = anchorIndex != null ? (parent.history || [])[anchorIndex] : null;
  const initialText = String(options.initialText || '').trim();
  const anchorPreview = String(options.anchorPreview || anchorMsg?.content || '').replace(/\s+/g, ' ').trim().slice(0, 160);
  const side = {
    ...createEmptyChatSession(id),
    title: makeSideChatTitle(initialText || anchorPreview || 'Side chat'),
    autoTitleLocked: true,
    history: [buildSideChatBoundaryMessage(parent, { anchorIndex, anchorPreview })],
    processLog: [],
    creativeMode: normalizeCreativeMode(parent.creativeMode),
    canvasProjectRoot: normalizeCanvasPath(parent.canvasProjectRoot) || null,
    canvasProjectLabel: parent.canvasProjectLabel || null,
    canvasProjectLink: normalizeCanvasProjectLink(parent.canvasProjectLink),
    sideChat: true,
    parentSessionId,
  };
  window.chatSessions.unshift(side);
  window.sideChatLinks = [
    {
      id,
      parentSessionId,
      title: side.title,
      anchorIndex,
      anchorPreview,
      createdAt: side.createdAt,
      updatedAt: side.updatedAt,
      closed: false,
    },
    ...(window.sideChatLinks || []),
  ];
  saveChatSessions();
  saveSideChatLinks();
  await syncSessionHistoryToServerById(id, side.history, { resetCompaction: true });
  showSideChatSplit(id);
  if (initialText) {
    setTimeout(() => sendSideChatMessage(initialText), 0);
  }
  return side;
}

function openOrCreateSideChat(initialText = '') {
  const existing = getSideChatLinksForParent()[0];
  if (existing && !initialText) {
    showSideChatSplit(existing.id);
    return getChatSessionById(existing.id);
  }
  return createSideChat({ initialText });
}

function sideChatFromMessage(originalIndex, ev) {
  if (ev) ev.stopPropagation();
  const msg = (window.chatHistory || [])[originalIndex];
  createSideChat({
    anchorIndex: originalIndex,
    anchorPreview: msg?.content || '',
  });
}

async function sendSideChatMessage(message = null) {
  const link = getActiveSideChatLink();
  const side = getSideChatSession();
  if (!link || !side) return;
  const input = document.getElementById('side-chat-input');
  const text = String(message == null ? input?.value || '' : message).trim();
  if (!text) return;
  if (input) {
    input.value = '';
    input.style.height = 'auto';
  }
  link.updatedAt = Date.now();
  saveSideChatLinks();
  await sendChat(makeQueuedChatTurn(text), {
    clientRequestId: newChatClientRequestId(side.id),
    sessionIdOverride: side.id,
    sideChat: true,
  });
  window.activeSideChatId = side.id;
  window.sideChatSplitOpen = true;
  updateSideChatChrome();
  renderChatMessages();
}

function handleSideChatInputKeydown(event) {
  if (event?.key === 'Enter' && !event.shiftKey) {
    event.preventDefault();
    sendSideChatMessage();
  }
}

function handleSideChatInputResize(input) {
  if (!input) return;
  input.style.height = 'auto';
  input.style.height = `${Math.min(180, Math.max(42, input.scrollHeight))}px`;
}

function rememberActiveChatSessionId(id) {
  const sid = String(id || '').trim();
  if (!sid) return '';
  try { localStorage.setItem(ACTIVE_CHAT_SESSION_KEY, sid); } catch {}
  return sid;
}
function recallActiveChatSessionId() {
  try {
    return String(
      localStorage.getItem(ACTIVE_CHAT_SESSION_KEY)
        || localStorage.getItem(AGENT_SESSION_KEY)
        || ''
    ).trim();
  } catch {
    return '';
  }
}
function setAgentSessionId(id) {
  const next = String(id || '').trim() || generateSessionId();
  window.agentSessionId = next;
  window.agentSessionId = next;
  localStorage.setItem(AGENT_SESSION_KEY, next);
  rememberActiveChatSessionId(next);
  return next;
}

function getChatSessionById(id) {
  return window.chatSessions.find(s => s.id === id) || null;
}

function newChatClientRequestId(sessionId) {
  const suffix = crypto?.randomUUID?.() || `${Date.now()}_${Math.random().toString(36).slice(2)}`;
  return `web:${String(sessionId || 'default').replace(/[^a-zA-Z0-9_.:-]/g, '_').slice(0, 48)}:${suffix}`;
}

function normalizeChatSendFingerprint(message) {
  return String(message || '').replace(/\s+/g, ' ').trim().toLowerCase().slice(0, 600);
}

function acquireChatSendLock(sessionId, message) {
  const sid = String(sessionId || 'default');
  const fingerprint = normalizeChatSendFingerprint(message);
  if (!fingerprint) return null;
  const now = Date.now();
  const locks = window._chatSendLocks || (window._chatSendLocks = {});
  const key = `${sid}::${fingerprint}`;
  const existing = locks[key];
  if (existing && now - Number(existing.at || 0) < 2500) return null;
  const lock = { key, at: now };
  locks[key] = lock;
  return lock;
}

function releaseChatSendLock(lock) {
  if (!lock?.key) return;
  setTimeout(() => {
    const locks = window._chatSendLocks || {};
    if (locks[lock.key] === lock) delete locks[lock.key];
  }, 2500);
}

function rememberLocalMainChatRequest(sessionId, clientRequestId) {
  const sid = String(sessionId || '').trim();
  const cid = String(clientRequestId || '').trim();
  if (!sid || !cid) return;
  const map = window._localMainChatClientRequestIds || (window._localMainChatClientRequestIds = {});
  const bySession = map[sid] && typeof map[sid] === 'object' ? map[sid] : {};
  bySession[cid] = Date.now();
  map[sid] = bySession;
}

function forgetLocalMainChatRequest(sessionId, clientRequestId) {
  const sid = String(sessionId || '').trim();
  const cid = String(clientRequestId || '').trim();
  if (!sid || !cid) return;
  setTimeout(() => {
    const bySession = window._localMainChatClientRequestIds?.[sid];
    if (bySession) delete bySession[cid];
  }, 15000);
}

function isLocalMainChatRequest(sessionId, clientRequestId) {
  const sid = String(sessionId || '').trim();
  const cid = String(clientRequestId || '').trim();
  if (!sid || !cid) return false;
  return !!window._localMainChatClientRequestIds?.[sid]?.[cid];
}

async function fetchJsonWithTimeout(url, timeoutMs = 2500) {
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), timeoutMs);
  try {
    const res = await fetch(url, { signal: controller.signal });
    if (!res.ok) return null;
    return await res.json();
  } catch {
    return null;
  } finally {
    clearTimeout(timeout);
  }
}

const chatContextWindowState = {
  loading: false,
  open: false,
  expanded: false,
  expandedRows: new Set(),
  liveTurn: null,
  lastSessionId: '',
  lastFetchAt: 0,
  refreshTimer: 0,
  data: null,
  planFetchAt: 0,
  planData: null,
};

function resetChatContextWindowLiveTurn(sessionId) {
  const sid = String(sessionId || '').trim();
  chatContextWindowState.liveTurn = sid ? {
    sessionId: sid,
    active: true,
    startedAt: Date.now(),
    settledAt: 0,
    toolResultTokens: 0,
    toolResultBytes: 0,
    toolDurationMsTotal: 0,
    toolDurationMsMax: 0,
    tools: new Map(),
  } : null;
  scheduleChatContextWindowRefresh(0);
}

function settleChatContextWindowLiveTurn(sessionId) {
  const live = chatContextWindowState.liveTurn;
  if (!live || String(live.sessionId || '') !== String(sessionId || '')) return;
  live.active = false;
  live.settledAt = Date.now();
  setTimeout(() => {
    const current = chatContextWindowState.liveTurn;
    if (!current || current !== live) return;
    if (Date.now() - Number(current.settledAt || 0) < 7000) return;
    chatContextWindowState.liveTurn = null;
    renderChatContextWindow(chatContextWindowState.data);
  }, 7500);
  scheduleChatContextWindowRefresh(500);
}

function estimateContextTokensFromText(text) {
  const raw = String(text || '');
  if (!raw) return 0;
  return Math.max(1, Math.ceil(raw.length / 4));
}

function recordChatContextWindowToolResult(event, sessionId) {
  const sid = String(sessionId || getChatContextWindowSessionId() || '').trim();
  if (!sid) return;
  let live = chatContextWindowState.liveTurn;
  if (!live || String(live.sessionId || '') !== sid) {
    resetChatContextWindowLiveTurn(sid);
    live = chatContextWindowState.liveTurn;
  }
  if (!live) return;
  const telemetry = event?.extra?.telemetry || event?.telemetry || {};
  const fallbackText = String(event?.result || event?.output || event?.error || '');
  const resultTokens = Math.max(0, Number(telemetry.resultTokens || telemetry.result_tokens || 0))
    || estimateContextTokensFromText(fallbackText);
  if (resultTokens <= 0) return;
  const resultBytes = Math.max(0, Number(telemetry.resultBytes || telemetry.result_bytes || fallbackText.length || 0));
  const durationMsRaw = Number(telemetry.durationMs || telemetry.duration_ms || event?.durationMs || event?.elapsedMs || event?.elapsed_ms || 0);
  const durationMs = Number.isFinite(durationMsRaw) ? Math.max(0, Math.round(durationMsRaw)) : 0;
  const action = String(event?.action || event?.tool || event?.name || 'tool').trim() || 'tool';
  live.active = true;
  live.toolResultTokens += resultTokens;
  live.toolResultBytes += resultBytes;
  if (durationMs > 0) {
    live.toolDurationMsTotal = Math.max(0, Number(live.toolDurationMsTotal || 0)) + durationMs;
    live.toolDurationMsMax = Math.max(Math.max(0, Number(live.toolDurationMsMax || 0)), durationMs);
  }
  const tool = live.tools.get(action) || { tool: action, calls: 0, resultTokens: 0, resultBytes: 0, durationMsTotal: 0, durationMsMax: 0 };
  tool.calls += 1;
  tool.resultTokens += resultTokens;
  tool.resultBytes += resultBytes;
  if (durationMs > 0) {
    tool.durationMsTotal += durationMs;
    tool.durationMsMax = Math.max(tool.durationMsMax, durationMs);
  }
  live.tools.set(action, tool);
  renderChatContextWindow(chatContextWindowState.data);
  scheduleChatContextWindowRefresh(1200);
}

function getChatContextWindowSessionId() {
  return String(window.activeChatSessionId || window.agentSessionId || '').trim();
}

function formatContextDurationLabel(value) {
  const durationMs = Number(value);
  if (!Number.isFinite(durationMs) || durationMs <= 0) return '';
  if (durationMs < 1000) return `${Math.round(durationMs)}ms`;
  if (durationMs < 10_000) return `${(durationMs / 1000).toFixed(2)}s`;
  if (durationMs < 60_000) return `${(durationMs / 1000).toFixed(1)}s`;
  const minutes = Math.floor(durationMs / 60_000);
  const seconds = Math.round((durationMs % 60_000) / 1000);
  return `${minutes}m${seconds ? ` ${seconds}s` : ''}`;
}

function formatContextToolDurationSuffix(tool) {
  const value = Math.max(0, Number(tool?.durationMsMax || tool?.durationMsAvg || tool?.durationMsTotal || 0));
  const label = formatContextDurationLabel(value);
  if (!label) return '';
  return ` · ${label}${Number(tool?.durationMsMax || 0) > 0 && Number(tool?.calls || 0) > 1 ? ' max' : ''}`;
}

function formatContextTokenCount(value) {
  const n = Number(value);
  if (!Number.isFinite(n) || n <= 0) return '0';
  if (n >= 1_000_000) {
    const m = n / 1_000_000;
    return `${m >= 10 ? m.toFixed(0) : m.toFixed(1)}m`;
  }
  if (n >= 1_000) {
    const k = n / 1_000;
    return `${k >= 100 ? k.toFixed(0) : k.toFixed(1)}k`;
  }
  return String(Math.round(n));
}

function setChatContextWindowLoading(label = 'Loading...') {
  const total = document.getElementById('chat-context-window-total');
  if (total) total.textContent = label;
}

function setChatContextWindowHeadLabel(label = 'Context window') {
  const headLabel = document.querySelector('#chat-context-window-popover .chat-context-window-head span:first-child');
  if (!headLabel) return;
  headLabel.innerHTML = `${escHtml(label)}<svg class="ccw-chevron" width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="9 6 15 12 9 18"/></svg>`;
}

function formatContextPercent(tokens, total) {
  const n = Number(tokens);
  const d = Number(total);
  if (!Number.isFinite(n) || !Number.isFinite(d) || d <= 0) return '0.0%';
  return `${Math.max(0, (n / d) * 100).toFixed(1)}%`;
}

function renderChatContextRows(rows, windowTokens) {
  const metrics = document.querySelector('#chat-context-window-popover .chat-context-window-metrics');
  if (!metrics) return;
  const source = Array.isArray(rows) && rows.length ? rows : [];
  const renderRow = (row, depth = 0) => {
    const tokens = Math.max(0, Number(row?.tokens || 0));
    const active = row?.active !== false && tokens > 0;
    const muted = row?.outOfBand === true ? ' is-out-of-band' : '';
    const percentText = row?.percentLabel
      ? String(row.percentLabel)
      : (row?.percentBasis === 'window' ? formatContextPercent(tokens, windowTokens) : '');
    const children = Array.isArray(row?.children) ? row.children.filter(Boolean) : [];
    const rowId = String(row?.id || row?.label || `row_${depth}`);
    const expandable = children.length > 0;
    const expanded = expandable && chatContextWindowState.expandedRows.has(rowId);
    const tag = expandable ? 'button' : 'div';
    const typeAttr = expandable ? ' type="button"' : '';
    const dataAttr = expandable ? ` data-ccw-row-id="${escHtml(rowId)}" aria-expanded="${expanded ? 'true' : 'false'}"` : '';
    const titleAttr = row?.estimated ? ' title="Estimated drill-down; parent total is authoritative."' : '';
    const caret = expandable ? `<span class="chat-context-window-caret" aria-hidden="true">${expanded ? '&#9662;' : '&#9656;'}</span>` : '';
    const estimate = row?.estimated ? '<span class="chat-context-window-estimate">est</span>' : '';
    const childHtml = expanded ? children.map((child) => renderRow(child, depth + 1)).join('') : '';
    return `
      <${tag}${typeAttr}${dataAttr}${titleAttr} class="chat-context-window-row${active ? ' is-active' : ''}${muted}${expandable ? ' is-expandable' : ''}${depth > 0 ? ' is-child' : ''}" style="--ccw-depth:${Math.max(0, depth)};">
        <span class="chat-context-window-label">${caret}<span class="chat-context-window-swatch"></span>${escHtml(row?.label || 'Context')}${estimate}</span>
        <span class="chat-context-window-value">${formatContextTokenCount(tokens)}</span>
        <span class="chat-context-window-percent">${escHtml(percentText)}</span>
      </${tag}>
      ${childHtml}
    `;
  };
  metrics.innerHTML = source.map((row) => renderRow(row, 0)).join('');
  metrics.querySelectorAll('[data-ccw-row-id]').forEach((row) => {
    row.addEventListener('click', toggleChatContextWindowRow);
  });
}

function getChatContextWindowDisplayLimit(data, currentState = {}) {
  return Math.max(0, Number(
    data?.contextWindowTokens
    || currentState?.contextWindowTokens
    || data?.currentContextLimitTokens
    || data?.contextLimitTokens
    || currentState?.contextLimitTokens
    || data?.inputBudgetTokens
    || data?.compactionTriggerTokens
    || 0
  ));
}

function applyChatContextWindowLiveOverlay(data) {
  if (!data || data.success === false) return data;
  const live = chatContextWindowState.liveTurn;
  const sid = getChatContextWindowSessionId();
  if (!live || String(live.sessionId || '') !== sid) return data;
  const stillVisible = live.active || (live.settledAt && Date.now() - live.settledAt < 7000);
  const liveTokens = Math.max(0, Number(live.toolResultTokens || 0));
  if (!stillVisible || liveTokens <= 0) return data;
  const currentState = data.currentState || {};
  const rows = Array.isArray(currentState.rows)
    ? currentState.rows.map((row) => ({ ...row, children: Array.isArray(row.children) ? row.children.map((child) => ({ ...child })) : row.children }))
    : [];
  const toolChildren = Array.from(live.tools?.values?.() || [])
    .sort((a, b) => Number(b.resultTokens || 0) - Number(a.resultTokens || 0))
    .slice(0, 12)
    .map((tool, index) => ({
      id: `live_tool_${index}_${String(tool.tool || 'tool').replace(/[^a-z0-9_-]/gi, '_')}`,
      label: `${String(tool.tool || 'tool')} x${Math.max(1, Number(tool.calls || 0))}${formatContextToolDurationSuffix(tool)}`,
      tokens: Math.max(0, Number(tool.resultTokens || 0)),
      active: true,
      includedInContext: true,
      percentBasis: 'window',
      estimated: false,
    }));
  const liveRow = {
    id: 'live_tool_results',
    label: `Live tool results${live.toolDurationMsTotal ? ` · ${formatContextDurationLabel(live.toolDurationMsTotal)} total` : ''}`,
    tokens: liveTokens,
    active: true,
    includedInContext: true,
    percentBasis: 'window',
    estimated: false,
    children: toolChildren,
  };
  const freeIndex = rows.findIndex((row) => row?.id === 'free_space');
  if (freeIndex >= 0) rows[freeIndex] = { ...rows[freeIndex], tokens: Math.max(0, Number(rows[freeIndex].tokens || 0) - liveTokens) };
  const insertAt = rows.findIndex((row) => row?.id === 'mcp_tools');
  if (insertAt >= 0) rows.splice(insertAt, 0, liveRow);
  else rows.push(liveRow);
  const overlaidState = {
    ...currentState,
    currentStateTokens: Math.max(0, Number(currentState.currentStateTokens || data.currentStateTokens || 0)) + liveTokens,
    rows,
  };
  return {
    ...data,
    currentState: overlaidState,
    currentStateTokens: overlaidState.currentStateTokens,
  };
}

function toggleChatContextWindowRow(event) {
  if (event) event.stopPropagation();
  const id = event?.currentTarget?.dataset?.ccwRowId;
  if (!id) return;
  if (chatContextWindowState.expandedRows.has(id)) chatContextWindowState.expandedRows.delete(id);
  else chatContextWindowState.expandedRows.add(id);
  renderChatContextWindow(chatContextWindowState.data);
}

function renderChatContextWindow(data = chatContextWindowState.data) {
  data = applyChatContextWindowLiveOverlay(data);
  const btn = document.getElementById('chat-context-window-btn');
  const fill = document.getElementById('chat-context-window-fill');
  const total = document.getElementById('chat-context-window-total');
  if (!btn) return;

  if (!data || data.success === false) {
    btn.style.setProperty('--chat-context-window-deg', '0deg');
    if (fill) fill.style.width = '0%';
    if (total) total.textContent = 'Unavailable';
    setChatContextWindowHeadLabel('Context window');
    renderChatContextRows([], 0);
    return;
  }

  const currentState = data.currentState || {};
  const current = Math.max(0, Number(data.currentStateTokens || currentState.currentStateTokens || data.currentInputTokens || 0));
  const windowTokens = getChatContextWindowDisplayLimit(data, currentState);
  const percent = windowTokens > 0 ? Math.min(100, Math.max(0, (current / windowTokens) * 100)) : 0;
  btn.style.setProperty('--chat-context-window-deg', `${Math.round(percent * 3.6)}deg`);
  btn.title = `Context window: ${formatContextTokenCount(current)} / ${formatContextTokenCount(windowTokens)} tokens`;
  if (fill) fill.style.width = `${percent.toFixed(1)}%`;
  setChatContextWindowHeadLabel('Context window');
  if (total) {
    total.textContent = `${formatContextTokenCount(current)} / ${formatContextTokenCount(windowTokens)} (${Math.round(percent)}%)`;
  }
  renderChatContextRows(currentState.rows, windowTokens);
}

async function refreshChatContextWindow(options = {}) {
  const sid = getChatContextWindowSessionId();
  const btn = document.getElementById('chat-context-window-btn');
  if (!btn) return null;
  if (!sid) {
    chatContextWindowState.data = null;
    renderChatContextWindow(null);
    return null;
  }
  const force = options.force === true;
  const now = Date.now();
  if (chatContextWindowState.loading) return chatContextWindowState.data;
  if (!force && chatContextWindowState.lastSessionId === sid && now - chatContextWindowState.lastFetchAt < 3500) {
    return chatContextWindowState.data;
  }

  chatContextWindowState.loading = true;
  chatContextWindowState.lastSessionId = sid;
  if (!chatContextWindowState.data) setChatContextWindowLoading();
  try {
    const data = await fetchJsonWithTimeout(`/api/sessions/${encodeURIComponent(sid)}/context-window`, 5000);
    chatContextWindowState.lastFetchAt = Date.now();
    chatContextWindowState.data = data && data.success !== false ? data : null;
    renderChatContextWindow(chatContextWindowState.data);
    return chatContextWindowState.data;
  } finally {
    chatContextWindowState.loading = false;
  }
}

function scheduleChatContextWindowRefresh(delayMs = 450) {
  if (chatContextWindowState.refreshTimer) clearTimeout(chatContextWindowState.refreshTimer);
  chatContextWindowState.refreshTimer = setTimeout(() => {
    chatContextWindowState.refreshTimer = 0;
    refreshChatContextWindow({ force: true }).catch(() => renderChatContextWindow(null));
  }, Math.max(0, Number(delayMs) || 0));
}

function toggleChatContextWindowPopover(event) {
  if (event) event.stopPropagation();
  const popover = document.getElementById('chat-context-window-popover');
  const btn = document.getElementById('chat-context-window-btn');
  if (!popover || !btn) return;
  chatContextWindowState.open = popover.hidden;
  popover.hidden = !chatContextWindowState.open;
  btn.setAttribute('aria-expanded', chatContextWindowState.open ? 'true' : 'false');
  if (chatContextWindowState.open) {
    // Always open collapsed — the detailed breakdown expands only on bar click.
    setChatContextBreakdown(false);
    refreshChatContextWindow({ force: true }).catch(() => renderChatContextWindow(null));
    refreshChatContextPlanUsage().catch(() => {});
  }
}

function closeChatContextWindowPopover() {
  const popover = document.getElementById('chat-context-window-popover');
  const btn = document.getElementById('chat-context-window-btn');
  if (popover) popover.hidden = true;
  if (btn) btn.setAttribute('aria-expanded', 'false');
  chatContextWindowState.open = false;
}

// Collapsible detailed breakdown inside the popover (hidden until the user
// clicks the context-window bar — mirrors the Claude UI plan-usage popover).
function setChatContextBreakdown(expanded) {
  chatContextWindowState.expanded = !!expanded;
  const breakdown = document.getElementById('chat-context-window-breakdown');
  const toggle = document.getElementById('chat-context-window-toggle');
  if (breakdown) breakdown.hidden = !expanded;
  if (toggle) {
    toggle.setAttribute('aria-expanded', expanded ? 'true' : 'false');
    toggle.title = expanded ? 'Hide breakdown' : 'Show breakdown';
  }
}

function toggleChatContextBreakdown(event) {
  if (event) event.stopPropagation();
  setChatContextBreakdown(!chatContextWindowState.expanded);
}

// ─── Plan usage (live provider limits) inside the context popover ─────────────
function ccwUsageGaugeClass(pct) {
  const p = Number(pct) || 0;
  if (p >= 90) return 'crit';
  if (p >= 75) return 'warn';
  return 'ok';
}

function ccwFmtReset(iso) {
  if (!iso) return '';
  const ts = Date.parse(iso);
  if (!Number.isFinite(ts)) return '';
  const diff = ts - Date.now();
  if (diff <= 0) return 'resets now';
  const mins = Math.round(diff / 60000);
  if (mins < 60) return `resets in ${mins}m`;
  const hrs = Math.round(mins / 60);
  if (hrs < 48) return `resets in ${hrs}h`;
  const days = Math.round(hrs / 24);
  return `resets in ${days}d`;
}

function renderChatContextPlanUsage() {
  const wrap = document.getElementById('chat-context-window-plan');
  const body = document.getElementById('chat-context-window-plan-body');
  if (!wrap || !body) return;
  const result = chatContextWindowState.planData;
  const providerId = String(window._activeProvider || '').toLowerCase();
  const providers = (result && Array.isArray(result.providers)) ? result.providers : [];
  // Show the plan usage for the provider backing the current chat model.
  const prov = providers.find((p) => String(p.provider).toLowerCase() === providerId);

  if (!prov) { wrap.hidden = true; body.innerHTML = ''; return; }

  const windows = Array.isArray(prov.windows) ? prov.windows : [];
  let html = '';
  if (windows.length) {
    html += windows.map((w) => {
      const pct = Math.max(0, Math.min(100, Number(w.used_percent) || 0));
      const left = (100 - pct).toFixed(0);
      const reset = ccwFmtReset(w.reset_at || w.resets_at);
      return `
        <div class="ccw-plan-gauge">
          <div class="ccw-plan-gauge-head">
            <span class="ccw-plan-gauge-label">${escHtml(w.label || '')}${reset ? ` · ${escHtml(reset)}` : ''}</span>
            <span class="ccw-plan-gauge-pct">${left}% left</span>
          </div>
          <div class="ccw-plan-gauge-track"><div class="ccw-plan-gauge-fill ${ccwUsageGaugeClass(pct)}" style="width:${pct}%"></div></div>
          ${w.detail ? `<div class="ccw-plan-gauge-reset">${escHtml(w.detail)}</div>` : ''}
        </div>`;
    }).join('');
  }
  if (!windows.length) {
    const tokens = prov.tokens || {};
    const total = Number(tokens.total || 0);
    const calls = Number(tokens.calls || 0);
    html += `<div class="ccw-plan-tokens">${formatContextTokenCount(total)} tokens · ${calls} calls tracked</div>`;
  }
  body.innerHTML = html;
  wrap.hidden = false;
}

async function refreshChatContextPlanUsage(force = false) {
  const now = Date.now();
  if (!force && chatContextWindowState.planData && now - chatContextWindowState.planFetchAt < 60000) {
    renderChatContextPlanUsage();
    return;
  }
  try {
    const data = await fetchJsonWithTimeout('/api/usage/limits', 6000);
    if (data && data.success !== false) {
      chatContextWindowState.planData = data;
      chatContextWindowState.planFetchAt = Date.now();
    }
  } catch { /* leave previous planData */ }
  renderChatContextPlanUsage();
}

function toggleVoiceSettingsPopover(event) {
  if (event) event.stopPropagation();
  const popover = document.getElementById('voice-settings-popover');
  const btn = document.getElementById('voice-settings-btn');
  if (!popover || !btn) return;
  const nextOpen = !!popover.hidden;
  popover.hidden = !nextOpen;
  btn.setAttribute('aria-expanded', nextOpen ? 'true' : 'false');
  // Refresh control visibility/state on open so the per-mode toggles (incl. the
  // xAI realtime checkbox) reflect the current voice mode and saved settings.
  if (nextOpen) { try { renderVoiceProviderControls(); } catch {} }
}

function closeVoiceSettingsPopover() {
  const popover = document.getElementById('voice-settings-popover');
  const btn = document.getElementById('voice-settings-btn');
  if (popover) popover.hidden = true;
  if (btn) btn.setAttribute('aria-expanded', 'false');
}

if (!window.__promChatContextWindowHandlersInstalled) {
  window.__promChatContextWindowHandlersInstalled = true;
  document.addEventListener('click', (event) => {
    const wrap = document.querySelector('.chat-model-switcher-wrap');
    if (!wrap || !wrap.contains(event.target)) closeChatContextWindowPopover();
    const voiceWrap = document.querySelector('.voice-settings-wrap');
    if (!voiceWrap || !voiceWrap.contains(event.target)) closeVoiceSettingsPopover();
  });
  document.addEventListener('keydown', (event) => {
    if (event.key === 'Escape') {
      closeChatContextWindowPopover();
      closeVoiceSettingsPopover();
    }
  });
  setInterval(() => refreshChatContextWindow().catch(() => {}), 15000);
}

function makeEmptyStreamState() {
  return {
    streamingAIText: '',
    streamingThinkingText: '',
    currentPreflightStatus: '',
    currentProgressLines: [],
    currentProgressThinkingActive: false,
    currentProgressThinkingText: '',
    liveTraceEntries: [],
    finalResponseStarted: false,
    agentExecutionMode: '',
    runtimeProgressState: { source: 'none', activeIndex: -1, items: [] },
    declaredPlanToolCounter: 0,
    declaredPlanToolActiveIndex: -1,
    declaredPlanToolPrefixes: {},
    lastCompletedDeclaredPlanIndex: -1,
    lastHeartbeat: { state: 'idle', level: '', current_step: '-', retry_count: 0, format_violation_count: 0, message: '' },
    lastHeartbeatLogSignature: '',
    currentTurnStartIndex: -1,
    currentTurnProcessOpen: false,
    turnStartedAt: 0,
    activeModelBadge: null,
    pendingApprovals: [],
    abortRequested: false,
    abortRequestedAt: 0,
    abortRequestedSource: '',
    forceAppendAssistantAfterInterruption: false,
    pendingInterruptionWorkflowGroupId: '',
    pendingInterruptionWorkflowLabel: '',
  };
}

function getSessionStreamState(id) {
  if (!id) return null;
  const sess = getChatSessionById(id);
  if (!sess) return null;
  if (!window._sessionStreamState[id]) window._sessionStreamState[id] = makeEmptyStreamState();
  return window._sessionStreamState[id];
}

function resetSessionStreamState(id) {
  window._sessionStreamState[id] = makeEmptyStreamState();
  return window._sessionStreamState[id];
}

function applyStreamStateToWindow(id) {
  const st = getSessionStreamState(id) || makeEmptyStreamState();
  window.streamingAIText = st.streamingAIText || '';
  window.streamingThinkingText = st.streamingThinkingText || '';
  window.currentPreflightStatus = st.currentPreflightStatus || '';
  window.currentProgressLines = Array.isArray(st.currentProgressLines) ? st.currentProgressLines : [];
  window.currentProgressThinkingActive = !!st.currentProgressThinkingActive;
  window.currentProgressThinkingText = st.currentProgressThinkingText || '';
  window.liveTraceEntries = Array.isArray(st.liveTraceEntries) ? st.liveTraceEntries : [];
  window.runtimeProgressState = st.runtimeProgressState || { source: 'none', activeIndex: -1, items: [] };
  window.lastHeartbeat = st.lastHeartbeat || { state: 'idle', level: '', current_step: '-', retry_count: 0, format_violation_count: 0, message: '' };
  window.lastHeartbeatLogSignature = st.lastHeartbeatLogSignature || '';
  window.currentTurnStartIndex = Number.isFinite(Number(st.currentTurnStartIndex)) ? Number(st.currentTurnStartIndex) : -1;
  window.currentTurnProcessOpen = !!st.currentTurnProcessOpen;
  window.activeModelBadge = st.activeModelBadge || null;
  window.pendingApprovals = Array.isArray(st.pendingApprovals) ? st.pendingApprovals : [];
}

function isSessionThinking(id) {
  return !!(id && window._sessionThinking && window._sessionThinking[id]);
}

function syncActiveSessionRunState() {
  const activeId = window.activeChatSessionId;
  const activeThinking = isSessionThinking(activeId);
  window.isThinking = activeThinking;
  window.streamingSessionId = activeThinking ? activeId : null;
  window.queuedPrompts = getSessionQueuedPrompts(activeId);
  currentAbortController = (window._sessionAbortControllers && window._sessionAbortControllers[activeId]) || null;
  return activeThinking;
}

async function requestGatewayMainChatAbort(sessionId = window.activeChatSessionId, source = 'desktop') {
  const sid = String(sessionId || '').trim();
  const st = getSessionStreamState(sid);
  if (st) {
    st.abortRequested = true;
    st.abortRequestedAt = Date.now();
    st.abortRequestedSource = String(source || 'desktop');
  }
  try {
    const result = await api('/api/mobile/commands/stop-now', {
      method: 'POST',
      body: { sessionId: sid, source },
      timeoutMs: 15000,
    });
    if (result?.success) {
      addSessionProcessEntry(sid, 'warn', 'Gateway abort requested for active main chat runtime.', {
        actor: 'Desktop Abort',
        source,
        target: result.target || null,
      });
      return true;
    }
    if (result?.message) {
      addSessionProcessEntry(sid, 'warn', result.message, { actor: 'Desktop Abort', source });
    }
  } catch (err) {
    addSessionProcessEntry(sid, 'error', `Gateway abort request failed: ${String(err?.message || err)}`, {
      actor: 'Desktop Abort',
      source,
    });
  }
  return false;
}

function getSessionQueuedPrompts(id) {
  const sid = String(id || '').trim();
  if (!sid) return [];
  if (!Array.isArray(window._sessionQueuedPrompts[sid])) window._sessionQueuedPrompts[sid] = [];
  return window._sessionQueuedPrompts[sid];
}

function getActiveQueuedPrompts() {
  return getSessionQueuedPrompts(window.activeChatSessionId);
}

function normalizeQueuedChatTurn(value) {
  if (value && typeof value === 'object' && !Array.isArray(value)) {
    const message = String(value.message || value.text || '').trim();
    const files = Array.isArray(value.files) ? value.files : [];
    const excludedSkillIds = Array.isArray(value.excludedSkillIds) ? value.excludedSkillIds.map((id) => String(id || '').trim()).filter(Boolean) : [];
    const selectedSkillIds = normalizeSelectedSkillIds(value.selectedSkillIds || value.forcedSkillIds || value.matchedSkillIds);
    return { message, files, excludedSkillIds, selectedSkillIds };
  }
  return { message: String(value || '').trim(), files: [], excludedSkillIds: [], selectedSkillIds: [] };
}

function makeQueuedChatTurn(message, files = [], options = {}) {
  return {
    message: String(message || '').trim(),
    files: Array.isArray(files) ? files.slice() : [],
    excludedSkillIds: Array.isArray(options.excludedSkillIds) ? options.excludedSkillIds.map((id) => String(id || '').trim()).filter(Boolean) : [],
    selectedSkillIds: normalizeSelectedSkillIds(options.selectedSkillIds || options.forcedSkillIds || options.matchedSkillIds),
  };
}

function getQueuedTurnMessage(value) {
  return normalizeQueuedChatTurn(value).message;
}

function getQueuedTurnFiles(value) {
  return normalizeQueuedChatTurn(value).files;
}

function updateSessionStreamState(id, patch = {}, options = {}) {
  const st = getSessionStreamState(id);
  if (!st) return null;
  Object.assign(st, patch);
  if (options.active !== false && window.activeChatSessionId === id) applyStreamStateToWindow(id);
  return st;
}

function normalizeCanvasProjectLink(link) {
  if (!link || typeof link !== 'object') return null;
  const github = link.github && typeof link.github === 'object' ? {
    repoFullName: link.github.repoFullName || null,
    remoteUrl: link.github.remoteUrl || null,
    branch: link.github.branch || null,
    defaultBranch: link.github.defaultBranch || null,
  } : null;
  const vercel = link.vercel && typeof link.vercel === 'object' ? {
    projectId: link.vercel.projectId || null,
    projectName: link.vercel.projectName || null,
    teamId: link.vercel.teamId || null,
    orgId: link.vercel.orgId || null,
    deploymentUrl: link.vercel.deploymentUrl || null,
    dashboardUrl: link.vercel.dashboardUrl || null,
  } : null;
  return {
    rootPath: normalizeCanvasPath(link.rootPath || '') || null,
    github,
    vercel,
  };
}

