      lastRestorableTitle: '',
      lastTool: '',
      statusLabel: 'Browser idle',
      frameBase64: '',
      frameBlobUrl: '',
      frameWidth: 0,
      frameHeight: 0,
      frameBitmapWidth: 0,
      frameBitmapHeight: 0,
      frameViewportWidth: 0,
      frameViewportHeight: 0,
      frameScrollX: 0,
      frameScrollY: 0,
