window.addEventListener('prometheus:skills-cache-updated', () => {
  const input = document.getElementById('chat-input');
  if (input) {
    handleSkillTriggerInput(input);
    if (getSkillCommandState(input)) renderSlashCommandPopover(input.value);
  }
});

