const OPENAI_REALTIME_VOICE_IDS = new Set(['alloy', 'ash', 'ballad', 'coral', 'echo', 'sage', 'shimmer', 'verse', 'marin', 'cedar']);
const DESKTOP_VOICE_SETTINGS_KEY = 'pm_voice_settings_v1';
const DESKTOP_VOICE_MODES = new Set(['default', 'openai_realtime', 'xai']);
let desktopVoiceSettings = loadDesktopVoiceSettings();

const CANVAS_LANG_MAP = {
  js:'javascript', ts:'javascript', jsx:'javascript', tsx:'javascript', mjs:'javascript',
  html:'htmlmixed', htm:'htmlmixed',
  css:'css', py:'python', xml:'xml',
  json:'javascript', md:'markdown', txt:'null',
};

function normalizeCanvasPath(value) {
  return String(value || '').replace(/\\/g, '/').trim();
}

function creativeMediaSourceUrl(source = '') {
  const value = String(source || '').trim();
  if (!value) return '';
  if (/^(?:data:|blob:|https?:|\/api\/)/i.test(value)) return value;
  return `/api/canvas/inline?path=${encodeURIComponent(normalizeCanvasPath(value))}`;
}

function getSpeechRecognitionCtor() {
  return window.SpeechRecognition || window.webkitSpeechRecognition || null;
}

function getStoredVoiceProvider(kind, fallback) {
  try {
    const value = localStorage.getItem(`prometheus_voice_${kind}_provider`);
    return value ? String(value) : fallback;
  } catch {
    return fallback;
  }
}

function storeVoiceProvider(kind, provider) {
  try { localStorage.setItem(`prometheus_voice_${kind}_provider`, provider); } catch {}
}

function getStoredVoiceSetting(key, fallback = '') {
  try {
    const value = localStorage.getItem(`prometheus_${key}`);
    return value ? String(value) : fallback;
  } catch {
    return fallback;
  }
}

function storeVoiceSetting(key, value) {
  try { localStorage.setItem(`prometheus_${key}`, String(value || '')); } catch {}
}

function normalizeDesktopVoiceMode(value) {
  const mode = String(value || '').trim();
  return DESKTOP_VOICE_MODES.has(mode) ? mode : 'default';
}

function loadDesktopVoiceSettings() {
  try {
    const saved = JSON.parse(localStorage.getItem(DESKTOP_VOICE_SETTINGS_KEY) || '{}');
    const legacyStt = localStorage.getItem('prometheus_voice_stt_provider') || '';
    const legacyTts = localStorage.getItem('prometheus_voice_tts_provider') || '';
    const legacyMode = saved.voiceMode
      || (legacyStt === 'xai' || legacyTts === 'xai' ? 'xai' : 'default');
    return {
      voiceMode: normalizeDesktopVoiceMode(legacyMode),
      sttProvider: saved.sttProvider || legacyStt || 'browser',
      ttsProvider: saved.ttsProvider || legacyTts || 'browser',
      realtimeVoice: saved.realtimeVoice || getStoredVoiceSetting('realtime_voice', 'marin'),
      realtimeSpeed: Number(saved.realtimeSpeed || getStoredVoiceSetting('realtime_voice_speed', '1.1') || 1.1),
      serverVoice: saved.serverVoice || getStoredVoiceSetting('voice_xai_voice', 'eve'),
      xaiSpeed: Number(saved.xaiSpeed || saved.realtimeSpeed || 1.0),
      dictation: saved.dictation || 'quiet',
      sttProviderLocked: saved.sttProviderLocked === true,
      autoProviderDefault: saved.autoProviderDefault || '',
      voiceAgentRealtimeAgent: saved.voiceAgentRealtimeAgent !== false,
      voiceAgentXaiRealtime: saved.voiceAgentXaiRealtime === true,
    };
  } catch {
    return {
      voiceMode: 'default',
      sttProvider: 'browser',
      ttsProvider: 'browser',
      realtimeVoice: 'marin',
      realtimeSpeed: 1.1,
      serverVoice: 'eve',
      xaiSpeed: 1.0,
      dictation: 'quiet',
      sttProviderLocked: false,
      autoProviderDefault: '',
      voiceAgentRealtimeAgent: true,
      voiceAgentXaiRealtime: false,
    };
  }
}

function saveDesktopVoiceSettings(settings = {}) {
  desktopVoiceSettings = {
    ...desktopVoiceSettings,
    ...settings,
    voiceMode: normalizeDesktopVoiceMode(settings.voiceMode || desktopVoiceSettings.voiceMode),
  };
  try { localStorage.setItem(DESKTOP_VOICE_SETTINGS_KEY, JSON.stringify(desktopVoiceSettings)); } catch {}
  return desktopVoiceSettings;
}

function getDesktopVoiceDefaultProvider() {
  if (realtimeVoiceConfigured) return 'openai_realtime';
  const xaiReady = isVoiceProviderConfigured('stt', 'xai') && isVoiceProviderConfigured('tts', 'xai');
  return xaiReady ? 'xai' : 'default';
}

function applyDesktopVoiceProviderDefaults() {
  const provider = getDesktopVoiceDefaultProvider();
  if (provider === 'default') return false;
  const mode = normalizeDesktopVoiceMode(desktopVoiceSettings.voiceMode);
  const autoProviderDefault = String(desktopVoiceSettings.autoProviderDefault || '');
  const isDefaultRoute =
    !desktopVoiceSettings.sttProviderLocked ||
    autoProviderDefault ||
    mode === 'default' ||
    (
      String(desktopVoiceSettings.sttProvider || 'browser') === 'browser' &&
      String(desktopVoiceSettings.ttsProvider || 'browser') === 'browser'
    );
  if (!isDefaultRoute) return false;
  if (mode === provider && autoProviderDefault === provider) return false;
  const next =
    provider === 'openai_realtime'
      ? { voiceMode: 'openai_realtime', sttProvider: 'browser', ttsProvider: 'browser' }
      : { voiceMode: 'xai', sttProvider: 'xai', ttsProvider: 'xai', serverVoice: desktopVoiceSettings.serverVoice || 'eve' };
  saveDesktopVoiceSettings({
    ...next,
    sttProviderLocked: true,
    autoProviderDefault: provider,
  });
  return true;
}

function normalizeRealtimeVoiceSpeed(value) {
  const speed = Number(value);
  if (!Number.isFinite(speed)) return 1.1;
  return Math.max(0.5, Math.min(1.5, Math.round(speed * 100) / 100));
}

function loadRealtimeVoiceSpeed() {
  realtimeVoiceSpeed = normalizeRealtimeVoiceSpeed(getStoredVoiceSetting('realtime_voice_speed', '1.1'));
  return realtimeVoiceSpeed;
}

function storeRealtimeVoiceSpeed(speed) {
  realtimeVoiceSpeed = normalizeRealtimeVoiceSpeed(speed);
  storeVoiceSetting('realtime_voice_speed', String(realtimeVoiceSpeed));
  return realtimeVoiceSpeed;
}

function getCurrentRealtimeVoiceSpeed() {
  const mode = normalizeDesktopVoiceMode(desktopVoiceSettings.voiceMode);
  if (mode === 'xai') {
    const speed = Number(desktopVoiceSettings.xaiSpeed || realtimeVoiceSpeed || 1);
    if (!Number.isFinite(speed)) return 1;
    return Math.max(0.7, Math.min(1.5, Math.round(speed * 100) / 100));
  }
  return normalizeRealtimeVoiceSpeed(desktopVoiceSettings.realtimeSpeed || realtimeVoiceSpeed);
}

function sendVoiceAgentRealtimeSpeedUpdate() {
  const dc = voiceAgentRealtimeConnection?.dc;
  if (!dc || dc.readyState !== 'open') return false;
  const speed = getCurrentRealtimeVoiceSpeed();
  try {
    if (voiceAgentRealtimeConnection?.provider === 'xai') {
      dc.send(JSON.stringify({
        type: 'session.update',
        session: {
          speed,
          audio: {
            output: { speed },
          },
        },
      }));
    } else {
      dc.send(JSON.stringify({
        type: 'session.update',
        session: {
          type: 'realtime',
          audio: {
            output: {
              voice: normalizeRealtimeVoice(realtimeVoiceSelection || getStoredVoiceSetting('realtime_voice', 'marin')),
              speed,
            },
          },
        },
      }));
    }
    return true;
  } catch {
    return false;
  }
}

function normalizeRealtimeNarrationMode(value) {
  const mode = String(value || '').trim();
  return ['quiet', 'milestones'].includes(mode) ? mode : 'quiet';
}

function loadRealtimeNarrationMode() {
  realtimeNarrationMode = normalizeRealtimeNarrationMode(getStoredVoiceSetting('realtime_narration_mode', 'quiet'));
  return realtimeNarrationMode;
}

function storeRealtimeNarrationMode(mode) {
  realtimeNarrationMode = normalizeRealtimeNarrationMode(mode);
  storeVoiceSetting('realtime_narration_mode', realtimeNarrationMode);
  return realtimeNarrationMode;
}

function normalizeRealtimeListenMode(value) {
  const mode = String(value || '').trim();
  return ['auto_send', 'confirm_send', 'hold_space'].includes(mode) ? mode : 'auto_send';
}

function loadRealtimeListenMode() {
  realtimeListenMode = normalizeRealtimeListenMode(getStoredVoiceSetting('realtime_listen_mode', 'auto_send'));
  return realtimeListenMode;
}

function storeRealtimeListenMode(mode) {
  realtimeListenMode = normalizeRealtimeListenMode(mode);
  storeVoiceSetting('realtime_listen_mode', realtimeListenMode);
  return realtimeListenMode;
}

function realtimeAllowsAutoSubmit() {
  return realtimeListenMode === 'auto_send';
}

function realtimeUsesHoldSpace() {
  return realtimeListenMode === 'hold_space';
}

function realtimeAllowsContinuousCapture() {
  return realtimeVoiceRepliesEnabled && !realtimeUsesHoldSpace();
}

function wantsVoiceAgentRealtimeMode() {
  const mode = normalizeDesktopVoiceMode(desktopVoiceSettings.voiceMode);
  if (mode === 'openai_realtime') return desktopVoiceSettings.voiceAgentRealtimeAgent !== false;
  if (mode === 'xai') return desktopVoiceSettings.voiceAgentXaiRealtime === true;
  return false;
}

// True when the active voice mode is the xAI/Grok speech-to-speech realtime agent
// (the "Use xAI Realtime" checkbox is on). The non-realtime xAI STT/TTS route is
// the default; this only flips on when the user opts in.
function wantsXaiRealtimeMode() {
  const mode = normalizeDesktopVoiceMode(desktopVoiceSettings.voiceMode);
  return mode === 'xai' && desktopVoiceSettings.voiceAgentXaiRealtime === true;
}

function setRegularVoiceControlsVisible(visible) {
  regularVoiceControlsVisible = !!visible;
  const controls = document.getElementById('voice-provider-controls');
  if (!controls) return;
  controls.hidden = !regularVoiceControlsVisible;
  controls.classList.toggle('visible', regularVoiceControlsVisible);
}

function setRealtimeVoiceControlsVisible(visible) {
  const controls = document.getElementById('voice-provider-controls');
  if (controls && visible) {
    controls.hidden = false;
    controls.classList.add('visible');
  }
  const speedSelect = document.getElementById('realtime-voice-speed-select');
  if (speedSelect) speedSelect.value = String(realtimeVoiceSpeed);
  const narrationSelect = document.getElementById('realtime-narration-mode-select');
  if (narrationSelect) narrationSelect.value = realtimeNarrationMode;
  const select = document.getElementById('realtime-listen-mode-select');
  if (select) select.value = realtimeListenMode;
  renderRealtimeWakeGateState();
}

function disableRealtimeVoiceMode() {
  if (!realtimeVoiceRepliesEnabled && !realtimeVoiceStarting && !realtimeDictationConnection && !realtimeVoiceConnection && !voiceAgentRealtimeConnection && !voiceAgentRealtimeConnecting) return;
  realtimeVoiceModeEpoch += 1;
  realtimeVoiceStarting = false;
  realtimeHoldSpaceActive = false;
  clearRealtimeAssistantSpeakingState();
  realtimeVoiceRepliesEnabled = false;
  resetRealtimeSessionWakePhrase({ clearInput: true });
  stopVoiceAgentRealtimeSession();
  closeRealtimeDictationConnection();
  closeRealtimeVoiceConnection();
  resetRealtimeDictationTranscript();
  renderVoiceProviderControls();
  setRealtimeVoiceButtonState();
}

function resizeChatInput(input = document.getElementById('chat-input')) {
  if (!input) return;
  input.style.height = 'auto';
  input.style.height = Math.min(input.scrollHeight, 140) + 'px';
}

function setVoiceDictationState(active) {
  voiceDictationActive = !!active && voiceDictationEnabled;
  setUnifiedVoiceButtonState();
}

function setUnifiedVoiceButtonState() {
  const btn = document.getElementById('chat-voice-btn');
  if (!btn) return;
  const mode = normalizeDesktopVoiceMode(desktopVoiceSettings.voiceMode);
  const gate = getRealtimeWakeGate?.();
  const realtimeActive = !!realtimeVoiceRepliesEnabled;
  const regularActive = !!voiceDictationEnabled;
  const recording = !!voiceDictationActive || !!(realtimeActive && realtimeDictationRecording);
  btn.classList.toggle('recording', recording);
  btn.classList.toggle('active', regularActive || realtimeActive);
  btn.classList.toggle('silent', !!gate);
  btn.classList.toggle('unconfigured', mode === 'openai_realtime' && !realtimeVoiceConfigured);
  btn.dataset.voiceMode = mode;
  const showWave = realtimeActive || mode === 'openai_realtime';
  const micIcon = btn.querySelector('.voice-btn-icon-mic');
  const waveIcon = btn.querySelector('.voice-btn-icon-wave');
  if (micIcon) micIcon.hidden = showWave;
  if (waveIcon) waveIcon.hidden = !showWave;
  const modeLabel = mode === 'openai_realtime' ? 'OpenAI Realtime' : mode === 'xai' ? 'xAI / Grok' : 'Default voice';
  btn.title = gate
    ? `Silent until "${gate.phrase}"`
    : realtimeVoiceStarting
      ? 'Starting OpenAI Realtime voice'
      : realtimeActive
      ? 'Stop OpenAI Realtime voice'
      : regularActive
        ? 'Stop dictation'
        : `Start ${modeLabel}`;
  btn.setAttribute('aria-label', btn.title);
}

function writeDictationTranscript(interimText = '') {
  const input = document.getElementById('chat-input');
  if (!input) return;
  const pieces = [voiceDictationBaseText, voiceDictationFinalText, interimText]
    .map((part) => String(part || '').trim())
    .filter(Boolean);
  input.value = pieces.join(pieces.length > 1 ? ' ' : '');
  resizeChatInput(input);
}

function appendDictationText(text) {
  if (!voiceDictationEnabled) return;
  const input = document.getElementById('chat-input');
  const gateResult = handleVoiceWakeGateTranscript(text, { source: 'regular_voice' });
  if (gateResult.handled) return;
  const transcript = String(gateResult.text || '').trim();
  if (!input || !transcript) return;
  const current = String(input.value || '').trim();
  input.value = current ? `${current} ${transcript}` : transcript;
  resizeChatInput(input);
  input.focus();
  submitVoiceCommandIfPresent();
}

function extractVoiceSubmitCommand(value) {
  const source = String(value || '').replace(/\s+/g, ' ').trim();
  if (!source) return { text: '', shouldSubmit: false };
  const commandPattern = /(?:[,.!?;:]\s*|\s+)(?:please\s+)?(?:send(?:\s+(?:it|this|that|message))?|submit(?:\s+(?:it|this|that|message))?|go ahead and send(?:\s+(?:it|this|that|message))?)$/i;
  const match = source.match(commandPattern);
  if (!match) return { text: source, shouldSubmit: false };
  return {
    text: source.slice(0, match.index).replace(/[,\s]+$/g, '').trim(),
    shouldSubmit: true,
  };
}

function submitVoiceCommandIfPresent() {
  if (!voiceDictationEnabled) return false;
  const input = document.getElementById('chat-input');
  if (!input) return false;
  const parsed = extractVoiceSubmitCommand(input.value);
  if (!parsed.shouldSubmit || !parsed.text) return false;
  input.value = parsed.text;
  resizeChatInput(input);
  if (voiceRecognition) {
    try { voiceRecognition.stop(); } catch {}
  }
  setTimeout(() => {
    const result = sendChat(null, { voiceAgentHandoff: true, voiceSource: 'desktop_regular_voice' });
    if (result?.catch) result.catch((err) => showToast('Voice send failed', String(err?.message || err), 'error'));
  }, 0);
  voiceDictationEnabled = false;
  resetRealtimeSessionWakePhrase({ clearInput: false });
  setRegularVoiceControlsVisible(false);
  return true;
}

function getRecorderMimeType() {
  const candidates = ['audio/webm;codecs=opus', 'audio/webm', 'audio/mp4', 'audio/ogg;codecs=opus'];
  return candidates.find((type) => window.MediaRecorder?.isTypeSupported?.(type)) || '';
}

function toggleBrowserDictation() {
  const Recognition = getSpeechRecognitionCtor();
  if (!Recognition) {
    showToast('Voice dictation unavailable', 'This browser does not expose SpeechRecognition.', 'error');
    return;
  }

  const input = document.getElementById('chat-input');
  voiceDictationBaseText = String(input?.value || '').trim();
  voiceDictationFinalText = '';
  voiceRecognition = new Recognition();
  voiceRecognition.continuous = true;
  voiceRecognition.interimResults = true;
  voiceRecognition.lang = navigator.language || 'en-US';
  voiceRecognition.onstart = () => {
    if (!voiceDictationEnabled) {
      try { voiceRecognition?.stop?.(); } catch {}
      return;
    }
    stopRealtimeVoicePlayback({ recordInterrupt: true, reason: 'dictation_started' });
    setVoiceDictationState(true);
    showToast('Listening', 'Dictation is writing into the chat box.', 'info', 1800);
  };
  voiceRecognition.onerror = (event) => {
    const message = event?.error ? `Speech recognition error: ${event.error}` : 'Speech recognition stopped.';
    showToast('Dictation stopped', message, 'error');
  };
  voiceRecognition.onend = () => {
    setVoiceDictationState(false);
    voiceRecognition = null;
    if (voiceDictationEnabled) writeDictationTranscript('');
  };
  voiceRecognition.onresult = (event) => {
    if (!voiceDictationEnabled) return;
    let interim = '';
    let sawFinal = false;
    for (let i = event.resultIndex; i < event.results.length; i += 1) {
      const transcript = String(event.results[i]?.[0]?.transcript || '').trim();
      if (!transcript) continue;
      stopRealtimeVoicePlayback({ recordInterrupt: true, reason: 'dictation_transcribing' });
      if (event.results[i].isFinal) {
        const gateResult = handleVoiceWakeGateTranscript(transcript, { source: 'browser_voice' });
        if (!gateResult.handled && gateResult.text) {
          voiceDictationFinalText = `${voiceDictationFinalText} ${gateResult.text}`.trim();
          sawFinal = true;
        }
      } else {
        if (!getRealtimeWakeGate()) interim = `${interim} ${transcript}`.trim();
      }
    }
    writeDictationTranscript(interim);
    if (sawFinal) submitVoiceCommandIfPresent();
  };
  try {
    voiceRecognition.start();
  } catch (err) {
    setVoiceDictationState(false);
    showToast('Dictation could not start', String(err?.message || err), 'error');
  }
}

async function stopBackendDictation() {
  if (xaiStreamingDictationConnection) {
    stopXaiStreamingDictation(false);
    return;
  }
  if (!backendVoiceRecorder) return;
  try { backendVoiceRecorder.stop(); } catch {}
  try { backendVoiceRecorder.stream?.getTracks?.().forEach((track) => track.stop()); } catch {}
}

function buildGatewayWsUrl(path, params = {}) {
  const url = new URL(path, location.origin);
  url.protocol = location.protocol === 'https:' ? 'wss:' : 'ws:';
  try {
    const token = localStorage.getItem('pm_device_token');
    if (token) url.searchParams.set('pt', token);
  } catch {}
  for (const [key, value] of Object.entries(params || {})) {
    if (value == null || value === '') continue;
    url.searchParams.set(key, String(value));
  }
  return url.toString();
}

function downsampleFloat32ToInt16(input, inputRate, outputRate) {
  if (!input?.length) return new Int16Array(0);
  const ratio = inputRate && outputRate && inputRate !== outputRate ? inputRate / outputRate : 1;
  const length = ratio === 1 ? input.length : Math.max(1, Math.round(input.length / ratio));
  const output = new Int16Array(length);
  for (let i = 0; i < length; i += 1) {
    let sample = 0;
    if (ratio === 1) {
      sample = input[i] || 0;
    } else {
      const start = Math.floor(i * ratio);
      const end = Math.min(input.length, Math.floor((i + 1) * ratio));
      let sum = 0;
      let count = 0;
      for (let j = start; j < end; j += 1) {
        sum += input[j] || 0;
        count += 1;
      }
      sample = count ? sum / count : input[start] || 0;
    }
    sample = Math.max(-1, Math.min(1, sample));
    output[i] = sample < 0 ? sample * 0x8000 : sample * 0x7fff;
  }
  return output;
}

function writeXaiStreamingDictationTranscript() {
  writeDictationTranscript(xaiStreamingDictationInterimText);
}

function appendXaiStreamingDictationEvent(event) {
  const text = String(event?.text || event?.transcript || event?.channel?.text || '').replace(/\s+/g, ' ').trim();
  if (!text) return;
  if (event?.is_final === true || event?.speech_final === true || event?.type === 'transcript.done') {
    const gateResult = handleVoiceWakeGateTranscript(text, { source: 'xai_streaming_voice' });
    if (gateResult.handled) {
      xaiStreamingDictationFinalText = '';
      xaiStreamingDictationInterimText = '';
      voiceDictationFinalText = '';
      writeXaiStreamingDictationTranscript();
      return;
    }
    xaiStreamingDictationFinalText = gateResult.text || text;
    xaiStreamingDictationInterimText = '';
  } else {
    xaiStreamingDictationInterimText = getRealtimeWakeGate() ? '' : text;
  }
  voiceDictationFinalText = xaiStreamingDictationFinalText;
  writeXaiStreamingDictationTranscript();
}

async function startXaiStreamingDictation() {
  if (!navigator.mediaDevices?.getUserMedia || typeof WebSocket === 'undefined' || !(window.AudioContext || window.webkitAudioContext)) {
    return toggleBackendDictationFallback();
  }
  const selected = getProviderInfo('stt', 'xai');
  if (!selected?.configured) {
    showToast('Voice provider not configured', `${selected?.label || 'xAI / Grok'} needs its API key on the gateway.`, 'error');
    return;
  }
  const startedAt = Date.now();
  const input = document.getElementById('chat-input');
  voiceDictationBaseText = String(input?.value || '').trim();
  voiceDictationFinalText = '';
  xaiStreamingDictationFinalText = '';
  xaiStreamingDictationInterimText = '';
  const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
  const AudioCtx = window.AudioContext || window.webkitAudioContext;
  const audioContext = new AudioCtx({ sampleRate: 16000 });
  const source = audioContext.createMediaStreamSource(stream);
  const processor = audioContext.createScriptProcessor(2048, 1, 1);
  const mutedGain = audioContext.createGain();
  mutedGain.gain.value = 0;
  const sampleRate = Math.round(audioContext.sampleRate || 16000);
  const ws = new WebSocket(buildGatewayWsUrl('/api/voice/xai/stt-stream', {
    sample_rate: sampleRate,
    language: navigator.language?.split('-')?.[0] || 'en',
    endpointing: 120,
  }));
  ws.binaryType = 'arraybuffer';
  xaiStreamingDictationConnection = { ws, stream, audioContext, source, processor, mutedGain, stopping: false };
  setVoiceDictationState(true);
  voiceDictationEnabled = true;
  showToast('Listening', 'xAI streaming dictation is live.', 'info', 1400);
  let ready = false;
  let fellBack = false;
  const fallbackToBatch = async (reason) => {
    if (fellBack || !xaiStreamingDictationConnection) return;
    fellBack = true;
    console.warn('[voice] xAI streaming dictation fallback:', reason);
    stopXaiStreamingDictation(true);
    voiceDictationEnabled = true;
    voiceRepliesEnabled = true;
    showToast('xAI streaming unavailable', 'Using xAI batch transcription instead.', 'error');
    await toggleBackendDictationFallback();
  };
  const readyTimeout = setTimeout(() => {
    if (!ready) fallbackToBatch('xAI streaming STT did not become ready');
  }, 2800);
  ws.addEventListener('message', (event) => {
    let data = null;
    try { data = JSON.parse(event.data); } catch { return; }
    const type = String(data?.type || '');
    if (type === 'transcript.created') {
      ready = true;
      clearTimeout(readyTimeout);
      addProcessEntry?.('info', `xAI streaming STT ready in ${Date.now() - startedAt}ms.`);
      return;
    }
    if (type === 'transcript.partial' || type === 'transcript.done') {
      appendXaiStreamingDictationEvent(data);
      if (type === 'transcript.done') submitVoiceCommandIfPresent();
      return;
    }
    if (type === 'error') {
      showToast('xAI streaming STT failed', String(data?.error?.message || data?.error || 'Unknown error'), 'error');
      fallbackToBatch(data?.error?.message || data?.error || 'xAI streaming error');
    }
  });
  ws.addEventListener('error', () => fallbackToBatch('websocket_error'));
  ws.addEventListener('close', () => {
    clearTimeout(readyTimeout);
    if (!ready && !fellBack) fallbackToBatch('websocket_closed_before_ready');
  });
  processor.onaudioprocess = (event) => {
    if (!xaiStreamingDictationConnection || xaiStreamingDictationConnection.stopping || ws.readyState !== WebSocket.OPEN) return;
    const inputData = event.inputBuffer.getChannelData(0);
    const pcm = downsampleFloat32ToInt16(inputData, audioContext.sampleRate || sampleRate, sampleRate);
    if (pcm.byteLength > 0) {
      try { ws.send(pcm.buffer); } catch {}
    }
  };
  source.connect(processor);
  processor.connect(mutedGain);
  mutedGain.connect(audioContext.destination);
  await audioContext.resume?.();
}

function stopXaiStreamingDictation(abort = false) {
  const conn = xaiStreamingDictationConnection;
  xaiStreamingDictationConnection = null;
  if (!conn) return;
  conn.stopping = true;
  try { conn.processor?.disconnect?.(); } catch {}
  try { conn.source?.disconnect?.(); } catch {}
  try { conn.mutedGain?.disconnect?.(); } catch {}
  try { conn.stream?.getTracks?.().forEach((track) => track.stop()); } catch {}
  try { conn.audioContext?.close?.(); } catch {}
  if (abort) {
    try { conn.ws?.close?.(); } catch {}
    setVoiceDictationState(false);
    return;
  }
  try { conn.ws?.send?.(JSON.stringify({ type: 'audio.done' })); } catch {}
  setTimeout(() => {
    try { conn.ws?.close?.(); } catch {}
    voiceDictationFinalText = xaiStreamingDictationFinalText || xaiStreamingDictationInterimText || voiceDictationFinalText;
    writeDictationTranscript('');
    submitVoiceCommandIfPresent();
    setVoiceDictationState(false);
  }, 450);
}

async function toggleBackendDictationFallback() {
  return toggleBackendDictation({ forceBatch: true });
}

async function transcribeBackendRecording(blob) {
  if (!voiceDictationEnabled) return;
  const provider = voiceSttProvider;
  const audioBase64 = await blobToBase64(blob);
  const response = await fetch('/api/voice/stt', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      provider,
      audioBase64,
      mimeType: blob.type || backendVoiceMimeType || 'audio/webm',
      filename: `prometheus-voice-${Date.now()}.webm`,
      language: navigator.language?.split('-')?.[0] || undefined,
    }),
  });
  const data = await response.json().catch(() => ({}));
  if (!response.ok || data?.success === false) throw new Error(data?.error || `Transcription failed (${response.status})`);
  appendDictationText(data.text || '');
  if (data.text) showToast('Transcribed', `${provider.toUpperCase()} wrote into the chat box.`, 'success', 1800);
  else showToast('No speech detected', '', 'info', 1800);
}

async function toggleBackendDictation(options = {}) {
  if ((backendVoiceRecorder || xaiStreamingDictationConnection) && voiceDictationActive) {
    await stopBackendDictation();
    return;
  }
  if (voiceSttProvider === 'xai' && options.forceBatch !== true) {
    try {
      await startXaiStreamingDictation();
      return;
    } catch (err) {
      console.warn('[voice] xAI streaming dictation failed, falling back to batch STT', err);
      showToast('xAI streaming unavailable', 'Using xAI batch transcription instead.', 'error');
    }
  }
  if (!navigator.mediaDevices?.getUserMedia || typeof MediaRecorder === 'undefined') {
    showToast('Voice recording unavailable', 'This browser cannot record microphone audio for backend STT.', 'error');
    return;
  }
  const selected = getProviderInfo('stt', voiceSttProvider);
  if (!selected?.configured) {
    showToast('Voice provider not configured', `${selected?.label || voiceSttProvider} needs its API key on the gateway.`, 'error');
    return;
  }
  const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
  stopRealtimeVoicePlayback({ recordInterrupt: true, reason: 'backend_dictation_started' });
  backendVoiceChunks = [];
  backendVoiceMimeType = getRecorderMimeType();
  backendVoiceRecorder = new MediaRecorder(stream, backendVoiceMimeType ? { mimeType: backendVoiceMimeType } : undefined);
  backendVoiceRecorder.ondataavailable = (event) => {
    if (voiceDictationEnabled && event.data && event.data.size > 0) backendVoiceChunks.push(event.data);
  };
  backendVoiceRecorder.onerror = (event) => {
    showToast('Recording failed', String(event?.error?.message || event?.error || 'Unknown recording error'), 'error');
  };
  backendVoiceRecorder.onstop = async () => {
    const chunks = backendVoiceChunks.slice();
    backendVoiceChunks = [];
    const recorder = backendVoiceRecorder;
    backendVoiceRecorder = null;
    setVoiceDictationState(false);
    try { recorder?.stream?.getTracks?.().forEach((track) => track.stop()); } catch {}
    if (!voiceDictationEnabled) {
      backendVoiceChunks = [];
      return;
    }
    if (!chunks.length) return;
    const blob = new Blob(chunks, { type: backendVoiceMimeType || 'audio/webm' });
    try {
      showToast('Transcribing', `Sending audio to ${selected?.label || voiceSttProvider}.`, 'info', 1600);
      await transcribeBackendRecording(blob);
    } catch (err) {
      showToast('Transcription failed', String(err?.message || err), 'error');
    }
  };
  backendVoiceRecorder.start();
  setVoiceDictationState(true);
  showToast('Recording', `Tap the mic again to transcribe with ${selected?.label || voiceSttProvider}.`, 'info', 2200);
}

function toggleVoiceDictation() {
  if (realtimeVoiceStarting) {
    disableRealtimeVoiceMode();
    showToast('Realtime voice cancelled', '', 'info', 1400);
    return;
  }
  if (realtimeVoiceRepliesEnabled) {
    toggleRealtimeVoiceReplies().catch((err) => showToast('Realtime voice could not stop', String(err?.message || err), 'error'));
    return;
  }
  if (voiceDictationEnabled || voiceDictationActive || voiceRecognition || backendVoiceRecorder || xaiStreamingDictationConnection) {
    voiceDictationEnabled = false;
    voiceRepliesEnabled = false;
    resetRealtimeSessionWakePhrase({ clearInput: true });
    setRegularVoiceControlsVisible(false);
    setVoiceDictationState(false);
    if (voiceRecognition) {
      const recognition = voiceRecognition;
      voiceRecognition = null;
      try { recognition.onresult = null; recognition.onerror = null; recognition.onend = null; recognition.stop(); } catch {}
      try { recognition.abort?.(); } catch {}
    }
    if (backendVoiceRecorder) {
      const recorder = backendVoiceRecorder;
      backendVoiceRecorder = null;
      backendVoiceChunks = [];
      try { recorder.ondataavailable = null; recorder.onerror = null; recorder.onstop = null; recorder.stop(); } catch {}
      try { recorder.stream?.getTracks?.().forEach((track) => track.stop()); } catch {}
    }
    if (xaiStreamingDictationConnection) {
      stopXaiStreamingDictation(true);
    }
    showToast('Dictation off', '', 'info', 1400);
    return;
  }
  disableRealtimeVoiceMode();
  const mode = normalizeDesktopVoiceMode(desktopVoiceSettings.voiceMode);
  if (mode === 'openai_realtime') {
    toggleRealtimeVoiceReplies().catch((err) => showToast('Realtime voice could not start', String(err?.message || err), 'error'));
    return;
  }
  // xAI realtime opt-in: speech-to-speech over WebSocket, same agent machinery
  // as OpenAI Realtime. If realtime can't start, fall back to the standard xAI
  // STT/TTS route rather than leaving the user with no working voice.
  if (mode === 'xai') {
    // Visible on-screen diagnostic so the chosen route is unambiguous on Safari
    // (where the console isn't easily inspected).
    showToast('xAI voice route', wantsXaiRealtimeMode()
      ? 'Realtime ON → starting Grok speech-to-speech (WebSocket)…'
      : 'Realtime OFF → standard xAI STT/TTS', 'info', 3500);
  }
  if (mode === 'xai' && wantsXaiRealtimeMode()) {
    toggleRealtimeVoiceReplies().catch((err) => {
      const reason = String(err?.message || err || 'Unknown error').slice(0, 300);
      showToast('xAI realtime failed — using standard xAI voice', reason, 'error', 8000);
      try { addSessionProcessEntry(window.activeChatSessionId || 'default', 'warn', `xAI realtime failed: ${reason} (fell back to standard xAI voice)`, { actor: 'Voice Agent (xAI Realtime)' }); } catch {}
      console.warn('[xai-realtime] start failed, falling back to standard xAI route', err);
      startStandardDesktopDictation('xai');
    });
    return;
  }
  startStandardDesktopDictation(mode);
}

// Standard (non-realtime) desktop dictation: xAI or browser STT/TTS split flow.
// Extracted so the xAI realtime path can fall back to it on failure.
function startStandardDesktopDictation(mode) {
  if (mode === 'xai') {
    const xaiTtsReady = isVoiceProviderConfigured('tts', 'xai');
    const xaiSttReady = isVoiceProviderConfigured('stt', 'xai');
    if (!xaiTtsReady) {
      showToast('xAI/Grok voice unavailable', 'Connect xAI/Grok voice credentials, then try again. Using Default dictation for now.', 'error', 3200);
      voiceSttProvider = 'browser';
      voiceTtsProvider = 'browser';
    } else {
      voiceTtsProvider = 'xai';
      voiceSttProvider = xaiSttReady ? 'xai' : 'browser';
      if (!xaiSttReady) showToast('xAI/Grok transcription unavailable', 'Using browser dictation with xAI/Grok response voice.', 'info', 2600);
    }
    storeVoiceProvider('stt', voiceSttProvider);
    storeVoiceProvider('tts', voiceTtsProvider);
    saveDesktopVoiceSettings({ voiceMode: 'xai', sttProvider: voiceSttProvider, ttsProvider: voiceTtsProvider });
  } else {
    voiceSttProvider = 'browser';
    voiceTtsProvider = 'browser';
    storeVoiceProvider('stt', voiceSttProvider);
    storeVoiceProvider('tts', voiceTtsProvider);
    saveDesktopVoiceSettings({ voiceMode: 'default', sttProvider: 'browser', ttsProvider: 'browser' });
  }
  voiceDictationEnabled = true;
  voiceRepliesEnabled = true;
  setRegularVoiceControlsVisible(true);
  renderVoiceProviderControls();
  if (voiceSttProvider === 'browser') {
    toggleBrowserDictation();
    return;
  }
  toggleBackendDictation().catch((err) => {
    setVoiceDictationState(false);
    showToast('Dictation could not start', String(err?.message || err), 'error');
  });
}

function extractRealtimeClientSecret(data) {
  return String(data?.client_secret?.value || data?.value || data?.client_secret || '').trim();
}

function setRealtimeVoiceButtonState() {
  setUnifiedVoiceButtonState();
}

function closeRealtimeVoiceConnection() {
  const connection = realtimeVoiceConnection;
  realtimeVoiceConnection = null;
  realtimeVoicePlaybackActive = false;
  realtimeVoiceActiveResponseId = '';
  realtimeVoiceResponseWaiters.splice(0).forEach((resolve) => {
    try { resolve(); } catch {}
  });
  clearRealtimeAssistantSpeakingState();
  try { connection?.dc?.close?.(); } catch {}
  try { connection?.pc?.close?.(); } catch {}
  try { if (connection?.audio) connection.audio.srcObject = null; } catch {}
}

function setRealtimeDictationRecordingState(active) {
  realtimeDictationRecording = !!active;
  const btn = document.getElementById('chat-voice-btn');
  if (!btn) return;
  btn.classList.toggle('recording', !!active && realtimeVoiceRepliesEnabled);
  setUnifiedVoiceButtonState();
}

function normalizeRealtimeWakePhrase(value) {
  return String(value || '')
    .toLowerCase()
    .replace(/[^\p{L}\p{N}]+/gu, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function stripRealtimeWakeCommandPunctuation(value) {
  return String(value || '').replace(/^[\s,.:;"'!?-]+|[\s,.:;"'!?-]+$/g, '').trim();
}

function setRealtimeSessionWakePhrase(phrase, options = {}) {
  const clean = stripRealtimeWakeCommandPunctuation(String(phrase || '').replace(/\s+/g, ' ').trim());
  const normalized = normalizeRealtimeWakePhrase(clean);
  if (!normalized) return false;
  realtimeSessionWakePhrase = clean;
  if (options.toast !== false) {
    showToast('Wake phrase set', `"${clean}"`, 'success', 2200);
  }
  addProcessEntry?.('info', `Realtime voice: wake phrase set to "${clean}".`);
  return true;
}

function resetRealtimeSessionWakePhrase(options = {}) {
  const hadPhrase = !!realtimeSessionWakePhrase;
  realtimeSessionWakePhrase = '';
  clearRealtimeWakeGate({ silent: true, clearInput: options.clearInput });
  if (hadPhrase && options.toast === true) {
    showToast('Wake phrase cleared', '', 'info', 1600);
  }
}

function buildRealtimeWakeGateFromPhrase(phrase, source = '') {
  const clean = stripRealtimeWakeCommandPunctuation(String(phrase || '').replace(/\s+/g, ' ').trim());
  const normalizedPhrase = normalizeRealtimeWakePhrase(clean);
  if (!normalizedPhrase) return null;
  return {
    active: true,
    phrase: clean,
    normalizedPhrase,
    suppressTranscript: true,
    suppressSend: true,
    suppressVoice: true,
    workerPolicy: 'continue',
    source,
    createdAt: Date.now(),
  };
}

function parseRealtimeWakePhraseSettingCommand(value) {
  const source = String(value || '').replace(/\s+/g, ' ').trim();
  if (!source) return null;
  const patterns = [
    /\bset\s+(?:my\s+|the\s+)?wake\s+(?:phrase|word)\s+(?:to|as)\s+(.+)$/i,
    /\b(?:make|change)\s+(?:my\s+|the\s+)?wake\s+(?:phrase|word)\s+(?:to|as)\s+(.+)$/i,
    /\b(?:my\s+|the\s+)?wake\s+(?:phrase|word)\s+(?:is|should\s+be)\s+(.+)$/i,
  ];
  for (const pattern of patterns) {
    const match = source.match(pattern);
    const phrase = stripRealtimeWakeCommandPunctuation(match?.[1] || '');
    if (phrase) return { kind: 'set_wake_phrase', phrase };
  }
  return null;
}

function isRealtimeQuietModeCommand(value) {
  const normalized = normalizeRealtimeWakePhrase(value);
  if (!normalized) return false;
  const command = normalized
    .replace(/^(?:(?:okay|ok|alright|all right|great|cool|perfect|thanks|thank you|now|please)\s+)+/g, '')
    .replace(/^prometheus\s+please\s+/g, 'prometheus ')
    .replace(/\s+(?:please|thanks|thank you)$/g, '')
    .trim();
  return [
    /^prometheus\s+quiet$/,
    /^quiet\s+prometheus$/,
    /^(?:be|go|stay|get|keep|become)\s+quiet\s+prometheus$/,
    /^prometheus\s+(?:be\s+quiet|go\s+quiet|quiet|sleep)$/,
    /^prometheus\s+stop\s+listening$/,
    /^(?:turn\s+on|enter|go\s+into|start)\s+quiet\s+mode$/,
    /^(?:prometheus\s+)?(?:now\s+)?be\s+quiet$/,
  ].some((pattern) => pattern.test(command));
}

function isRealtimeWakeUnlockCommand(value) {
  const normalized = normalizeRealtimeWakePhrase(value);
  if (!normalized) return false;
  return (
    /\bprometheus\s+(?:unlock|wake\s+up|listen\s+normally)\b/.test(normalized)
    || /\b(?:unlock|wake\s+up)\s+prometheus\b/.test(normalized)
    || /\b(?:turn|switch)\s+off\s+(?:the\s+)?wake\s+(?:phrase|word)\b/.test(normalized)
    || /\b(?:disable|clear|remove|reset)\s+(?:the\s+)?wake\s+(?:phrase|word)\b/.test(normalized)
  );
}

function parseRealtimeWakeGateCommand(value) {
  const source = String(value || '').replace(/\s+/g, ' ').trim();
  if (!source) return null;
  const patterns = [
    /\b(?:do\s+not|don't|dont)\s+(?:respond|answer|reply|talk|speak)(?:\s+(?:to|about|at|for)\s+.*?|\s+again|\s+to\s+anything|\s+until|\s+unless)*?\s+(?:until|unless)\s+i\s+say\s+(.+)$/i,
    /\b(?:stay|be|remain)\s+(?:quiet|silent|muted)\s+(?:until|unless)\s+i\s+say\s+(.+)$/i,
    /\b(?:stop|pause|mute)\s+(?:talking|speaking|responding|replying|yourself)\s+(?:until|unless)\s+i\s+say\s+(.+)$/i,
    /\b(?:listen|keep\s+listening)\s+(?:silently\s+)?(?:until|unless)\s+i\s+say\s+(.+)$/i,
  ];
  for (const pattern of patterns) {
    const match = source.match(pattern);
    const phrase = stripRealtimeWakeCommandPunctuation(match?.[1] || '');
    if (!phrase) continue;
    return {
      active: true,
      phrase,
      normalizedPhrase: normalizeRealtimeWakePhrase(phrase),
      suppressTranscript: true,
      suppressSend: true,
      suppressVoice: true,
      workerPolicy: /\b(?:cancel|abort|stop\s+the\s+task|stop\s+prometheus)\b/i.test(source)
        ? 'interrupt'
        : /\b(?:pause\s+prometheus|pause\s+the\s+worker|pause\s+the\s+task)\b/i.test(source)
          ? 'pause'
          : 'continue',
      createdAt: Date.now(),
    };
  }
  return null;
}

function parseRealtimeControlCommand(value) {
  const normalized = normalizeRealtimeWakePhrase(value);
  if (!normalized) return null;
  if (isRealtimeWakeUnlockCommand(value)) {
    return { kind: 'unlock_voice' };
  }
  const wakePhraseCommand = parseRealtimeWakePhraseSettingCommand(value);
  if (wakePhraseCommand) return wakePhraseCommand;
  if (isRealtimeQuietModeCommand(value)) {
    return { kind: 'quiet_mode' };
  }
  if (/^(?:hey\s+)?(?:prometheus\s+)?(?:what\s+are\s+you\s+doing|what\s+is\s+going\s+on|what\s+s\s+going\s+on|what\s+are\s+you\s+working\s+on|status|status\s+update|any\s+progress|how\s+is\s+it\s+going|how\s+s\s+it\s+going)\??$/.test(normalized)) {
    return { kind: 'status' };
  }
  if (/^(?:hey\s+)?(?:prometheus\s+)?(?:stop|cancel|abort|stop\s+that|cancel\s+that|abort\s+that|stop\s+the\s+task|cancel\s+the\s+task)$/.test(normalized)) {
    return { kind: 'interrupt' };
  }
  if (/^(?:hey\s+)?(?:prometheus\s+)?(?:stop\s+talking|stop\s+speaking|be\s+quiet|mute\s+yourself|wait|hold\s+on|pause|one\s+sec|one\s+second)$/.test(normalized)) {
    return { kind: 'mute_voice' };
  }
  return null;
}

function getRealtimePrometheusStatusText() {
  const sid = String(window.activeChatSessionId || '').trim();
  const thinking = !!window._sessionThinking?.[sid] || !!window.isThinking;
  const entries = Array.isArray(window.processLogEntries) ? window.processLogEntries : [];
  const meaningful = entries
    .filter((entry) => entry && !['user', 'final'].includes(String(entry.type || '').toLowerCase()))
    .slice(-5)
    .map((entry) => String(entry.content || '').replace(/\s+/g, ' ').trim())
    .filter(Boolean);
  if (thinking && meaningful.length) {
    return `Prometheus is still working. Latest progress: ${meaningful.slice(-3).join(' Then ')}`;
  }
  if (thinking) return 'Prometheus is still working, but there is no detailed progress note yet.';
  if (meaningful.length) return `No active Prometheus worker right now. The latest note was: ${meaningful[meaningful.length - 1]}`;
  return 'No active Prometheus worker right now.';
}

function interruptActivePrometheusWorkerFromVoice() {
  const sid = String(window.activeChatSessionId || '').trim();
  const thinking = !!window._sessionThinking?.[sid] || !!window.isThinking;
  if (!thinking) return false;
  try { window.stopGeneration?.(); } catch {}
  const ctrl = window._sessionAbortControllers?.[sid] || currentAbortController;
  try { if (ctrl && !ctrl.signal?.aborted) ctrl.abort(); } catch {}
  requestGatewayMainChatAbort(sid, 'desktop_realtime_voice_interrupt').catch(() => {});
  addProcessEntry?.('warn', 'Realtime voice: worker interrupted by voice command.');
  return true;
}

function handleRealtimeControlCommand(command) {
  if (!command?.kind) return false;
  if (command.kind === 'unlock_voice') {
    resetRealtimeSessionWakePhrase({ clearInput: true, toast: true });
    const text = 'Unlocked. Listening normally.';
    speakAssistantReply(text).catch(() => {});
    return true;
  }
  if (command.kind === 'set_wake_phrase') {
    const ok = setRealtimeSessionWakePhrase(command.phrase);
    if (!ok) {
      const text = 'I did not catch the wake phrase. Say something like, set my wake phrase to hey Prometheus.';
      speakAssistantReply(text).catch(() => {});
    }
    return true;
  }
  if (command.kind === 'quiet_mode') {
    if (!realtimeSessionWakePhrase) {
      const text = 'Set a wake phrase first, so you do not get stuck in quiet mode.';
      showToast('Wake phrase needed', 'Say “set my wake phrase to ...” first.', 'info', 2600);
      speakAssistantReply(text).catch(() => {});
      return true;
    }
    const gate = buildRealtimeWakeGateFromPhrase(realtimeSessionWakePhrase, 'quiet_mode_command');
    if (gate) {
      activateRealtimeWakeGate(gate);
      return true;
    }
    return false;
  }
  if (command.kind === 'status') {
    const text = getRealtimePrometheusStatusText();
    addProcessEntry?.('info', `Realtime voice status: ${text}`);
    speakAssistantReply(text).catch((err) => showToast('Realtime status voice failed', String(err?.message || err), 'error'));
    return true;
  }
  if (command.kind === 'interrupt') {
    stopRealtimeVoicePlayback({ recordInterrupt: true, reason: 'voice_command_interrupt' });
    const stopped = interruptActivePrometheusWorkerFromVoice();
    const text = stopped ? 'Stopped the active Prometheus worker.' : 'There is no active Prometheus worker to stop.';
    showToast('Realtime interrupt', text, stopped ? 'success' : 'info', 1800);
    speakAssistantReply(text).catch(() => {});
    return true;
  }
  if (command.kind === 'mute_voice') {
    stopRealtimeVoicePlayback({ recordInterrupt: true, reason: 'voice_command_mute' });
    showToast('Realtime voice muted', '', 'info', 1400);
    return true;
  }
  return false;
}

function getRealtimeWakeGate() {
  return realtimeWakeGate?.active ? realtimeWakeGate : null;
}

function renderRealtimeWakeGateState() {
  const status = document.getElementById('realtime-wake-gate-status');
  const btn = document.getElementById('chat-voice-btn');
  const gate = getRealtimeWakeGate();
  if (btn) {
    btn.classList.toggle('silent', !!gate);
    if (gate) {
      btn.title = `Silent until "${gate.phrase}"`;
      btn.setAttribute('aria-label', btn.title);
    } else {
      setRealtimeVoiceButtonState();
    }
  }
  if (!status) return;
  if (!gate || !realtimeVoiceRepliesEnabled) {
    status.hidden = true;
    status.classList.remove('visible');
    status.innerHTML = '';
    return;
  }
  status.hidden = false;
  status.classList.add('visible');
  status.innerHTML = `<span class="realtime-wake-gate-pill" title="Prometheus is listening silently for this wake phrase">Silent until &quot;${escHtml(gate.phrase)}&quot;</span><button type="button" class="realtime-wake-gate-btn" onclick="clearRealtimeWakeGate()">Wake</button>`;
}

function normalizeRealtimeEchoText(value) {
  return String(value || '')
    .toLowerCase()
    .replace(/[^\p{L}\p{N}]+/gu, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function cleanupRealtimeAssistantEchoSnippets(now = Date.now()) {
  realtimeAssistantEchoSnippets = realtimeAssistantEchoSnippets.filter((item) => item && item.expiresAt > now);
}

function getRealtimeAssistantEchoSources() {
  cleanupRealtimeAssistantEchoSnippets();
  return [realtimeAssistantEchoText, ...realtimeAssistantEchoSnippets.map((item) => item.text)].filter(Boolean);
}

function hasRealtimeAssistantEchoMemory() {
  return getRealtimeAssistantEchoSources().length > 0;
}

function clearRealtimeAssistantSpeakingState(options = {}) {
  if (realtimeAssistantEchoTimer) clearTimeout(realtimeAssistantEchoTimer);
  realtimeAssistantEchoTimer = null;
  realtimeAssistantSpeaking = false;
  realtimeAssistantSpeakingUntil = 0;
  if (options.keepEcho !== true) {
    realtimeAssistantEchoText = '';
    realtimeAssistantSpokenText = '';
  }
}

function beginRealtimeAssistantSpeakingEchoGuard(text) {
  const normalized = normalizeRealtimeEchoText(text);
  realtimeAssistantSpeaking = true;
  realtimeAssistantSpeakingUntil = Date.now() + 2500;
  realtimeAssistantEchoText = normalized;
  realtimeAssistantSpokenText = String(text || '').replace(/\s+/g, ' ').trim();
  if (normalized) {
    cleanupRealtimeAssistantEchoSnippets();
    realtimeAssistantEchoSnippets.push({
      text: normalized,
      expiresAt: Date.now() + 90000,
    });
    if (realtimeAssistantEchoSnippets.length > 8) realtimeAssistantEchoSnippets = realtimeAssistantEchoSnippets.slice(-8);
  }
  if (realtimeAssistantEchoTimer) clearTimeout(realtimeAssistantEchoTimer);
  realtimeAssistantEchoTimer = null;
}

function finishRealtimeAssistantSpeakingEchoGuard(cooldownMs = 1000) {
  if (realtimeAssistantEchoTimer) clearTimeout(realtimeAssistantEchoTimer);
  realtimeAssistantSpeaking = false;
  realtimeAssistantSpeakingUntil = Date.now() + Math.max(0, Number(cooldownMs) || 0);
  realtimeAssistantEchoTimer = setTimeout(() => {
    realtimeAssistantEchoTimer = null;
    if (Date.now() >= realtimeAssistantSpeakingUntil) {
      realtimeAssistantSpeakingUntil = 0;
      realtimeAssistantEchoText = '';
    }
  }, Math.max(0, Number(cooldownMs) || 0) + 80);
}

function isRealtimeAssistantSpeechGuardActive() {
  return !!(realtimeAssistantSpeaking || realtimeVoicePlaybackActive || realtimeVoiceActiveResponseId || Date.now() < realtimeAssistantSpeakingUntil);
}

function shouldSuppressRealtimeAssistantEchoInput() {
  if (!isRealtimeAssistantSpeechGuardActive()) return false;
  return !(realtimeUsesHoldSpace() && realtimeHoldSpaceActive);
}

function isRealtimeAssistantEchoTranscript(transcript) {
  const normalized = normalizeRealtimeEchoText(transcript);
  if (normalized.length < 4) return false;
  const sources = getRealtimeAssistantEchoSources();
  if (!sources.length) return false;
  const transcriptWords = normalized.split(' ').filter(Boolean);
  if (!transcriptWords.length) return false;
  for (const source of sources) {
    if (normalized.length >= 4 && source.includes(normalized)) return true;
    if (transcriptWords.length < 2) continue;
    const sourceWords = new Set(source.split(' ').filter(Boolean));
    const common = transcriptWords.filter((word) => sourceWords.has(word)).length;
    const ratio = common / transcriptWords.length;
    if (transcriptWords.length <= 3 && ratio >= 0.8) return true;
    if (transcriptWords.length > 3 && ratio >= 0.55) return true;
  }
  return false;
}

function isRealtimeBargeInTranscript(transcript) {
  const normalized = normalizeRealtimeWakePhrase(transcript);
  if (!normalized) return false;
  if (parseRealtimeControlCommand(transcript)) return true;
  if (parseRealtimeWakeGateCommand(transcript)) return true;
  const words = normalized.split(' ').filter(Boolean);
  return words.length <= 8 && /^(?:hey\s+)?prometheus\s+(?:stop|wait|pause|hold|cancel|status|quiet|mute)\b/.test(normalized);
}

function captureRealtimeVoicePlaybackInterrupt(reason = 'barge_in') {
  const active = !!(realtimeVoicePlaybackActive || realtimeAssistantSpeaking || realtimeVoiceActiveResponseId);
  if (!active) return false;
  realtimeVoicePendingInterruptContext = {
    at: Date.now(),
    reason,
    responsePreview: String(realtimeAssistantSpokenText || realtimeAssistantEchoText || '').replace(/\s+/g, ' ').trim().slice(0, 1200),
  };
  try { addProcessEntry?.('warn', 'Realtime voice: spoken response interrupted by user.'); } catch {}
  return true;
}

function consumeRealtimeVoicePlaybackInterruptContext() {
  const ctx = realtimeVoicePendingInterruptContext;
  if (!ctx) return '';
  if (Date.now() - Number(ctx.at || 0) > 120000) {
    realtimeVoicePendingInterruptContext = null;
    return '';
  }
  realtimeVoicePendingInterruptContext = null;
  return [
    '[VOICE INTERRUPTION CONTEXT]',
    'The user interrupted Prometheus while it was speaking via web realtime voice/dictation.',
    'Treat the next user message as a barge-in/follow-up to the interrupted spoken response, not an unrelated new request.',
    'Acknowledge that you were interrupted only if it helps the response; do not over-apologize.',
    ctx.responsePreview ? `Interrupted spoken response preview:\n${ctx.responsePreview}` : '',
  ].filter(Boolean).join('\n');
}

async function finalizeRealtimeVoicePlaybackInterruptContext(userInterruptionTranscript = '') {
  const ctx = realtimeVoicePendingInterruptContext;
  if (!ctx) return '';
  if (Date.now() - Number(ctx.at || 0) > 180000) {
    realtimeVoicePendingInterruptContext = null;
    return '';
  }
  realtimeVoicePendingInterruptContext = null;
  const fallback = [
    '[VOICE INTERRUPTION EVENT]',
    `Reason: ${ctx.reason || 'barge_in'}`,
    'Original user request: current desktop realtime chat turn',
    `Spoken segment at interruption: ${ctx.responsePreview || '(unknown)'}`,
    `User interruption: ${String(userInterruptionTranscript || '').trim() || '(none)'}`,
    'Interpretation: unknown',
    'Runtime instruction: Treat this as a live voice interruption/follow-up. Do not abort unless the user explicitly cancelled.',
    '[/VOICE INTERRUPTION EVENT]',
  ].join('\n');
  try {
    const response = await fetch('/api/voice-agent/input', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        sessionId: window.activeChatSessionId || 'default',
        reason: ctx.reason || 'barge_in',
        currentSpokenSegment: ctx.responsePreview || '',
        assistantTextSoFar: ctx.responsePreview || '',
        transcript: userInterruptionTranscript,
        userInterruptionTranscript,
        voiceMode: 'desktop_realtime',
        source: 'desktop_realtime_voice_agent',
      }),
    });
    const data = await response.json().catch(() => ({}));
    if (!response.ok || data?.success === false) return fallback;
    return String(data?.injectedContextText || '').trim() || fallback;
  } catch {
    return fallback;
  }
}

async function handleRealtimeVoiceInterruptionOnly(userInterruptionTranscript = '') {
  const ctx = realtimeVoicePendingInterruptContext;
  if (!ctx) return false;
  const sessionId = String(window.activeChatSessionId || 'default').trim() || 'default';
  const requestBody = {
    sessionId,
    reason: ctx.reason || 'barge_in',
    currentSpokenSegment: ctx.responsePreview || '',
    assistantTextSoFar: ctx.responsePreview || '',
    transcript: userInterruptionTranscript,
    userInterruptionTranscript,
    voiceMode: 'desktop_realtime',
    source: 'desktop_realtime_voice_agent',
    deviceTime: desktopVoiceDeviceTimeContext(),
  };
  let data = null;
  let streamingDispatcher = createDesktopVoiceAgentStreamingDispatcher();
  try {
    try {
      data = await streamVoiceAgentInput(requestBody, (chunk) => {
        try { streamingDispatcher?.enqueue?.(chunk); } catch {}
      });
    } catch (streamErr) {
      console.warn('[voice-agent] interruption streaming failed, falling back to JSON:', streamErr);
      streamingDispatcher = null;
      const response = await fetch('/api/voice-agent/input', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(requestBody),
      });
      data = await response.json().catch(() => ({}));
    }
  } catch (err) {
    addProcessEntry?.('error', `Realtime voice interruption failed: ${String(err?.message || err)}`);
    return false;
  } finally {
    realtimeVoicePendingInterruptContext = null;
  }
  if (!data?.success && !data?.ok) return false;
  const intent = String(data?.classification?.intent || 'unknown');
  addProcessEntry?.('warn', `Voice interruption: ${intent}${userInterruptionTranscript ? ` - ${userInterruptionTranscript}` : ''}`, {
    actor: 'Voice Interruption',
    eventId: data.eventId,
  });
  const splitAddedAbortMessage = appendVoiceInterruptionWorkflowSplit(sessionId, userInterruptionTranscript, data);
  if (data?.classification?.shouldAbortOriginalRun) {
    const ctrl = window._sessionAbortControllers?.[sessionId] || currentAbortController;
    try { if (ctrl && !ctrl.signal?.aborted) ctrl.abort(); } catch {}
    await requestGatewayMainChatAbort(sessionId, 'desktop_realtime_voice_interruption_event');
    addProcessEntry?.('warn', 'Voice interruption requested worker abort. Process log preserved.', { actor: 'Voice Interruption' });
    await waitForSessionIdle(sessionId, 2400);
    const sess = getChatSessionById(sessionId);
    const st = getSessionStreamState(sessionId);
    if (sess) {
      if (!Array.isArray(sess.history)) sess.history = [];
      if (!Array.isArray(sess.processLog)) sess.processLog = [];
      const last = sess.history[sess.history.length - 1];
      const alreadyStopped = last && (last.role === 'ai' || last.role === 'assistant') && /^\[Stopped by user\]/i.test(String(last.content || ''));
      if (!alreadyStopped && !splitAddedAbortMessage) {
        const startIndex = Number.isFinite(Number(st?.currentTurnStartIndex)) ? Number(st.currentTurnStartIndex) : 0;
        const turnEntries = sess.processLog.slice(Math.max(0, startIndex));
        const streamedText = String(st?.streamingAIText || '').trim();
        const content = streamedText
          ? `[Stopped by user]\n\n${streamedText}`
          : `[Stopped by user]\n\nVoice interruption stopped the active Prometheus worker. Process log preserved.`;
        sess.history.push({
          role: 'ai',
          content,
          timestamp: Date.now(),
          mode: window.useAgentMode ? 'agentic' : 'chat',
          processEntries: turnEntries,
        });
        if (window.activeChatSessionId === sessionId) {
          window.chatHistory = sess.history;
          renderChatMessages();
        }
        persistSession(sessionId);
      }
    }
    delete window._sessionThinking[sessionId];
    delete window._sessionAbortControllers[sessionId];
    if (st) {
      st.streamingAIText = '';
      st.streamingThinkingText = '';
      st.liveTraceEntries = [];
      st.currentPreflightStatus = '';
    }
    if (window.activeChatSessionId === sessionId) {
      syncActiveSessionRunState();
      applyStreamStateToWindow(sessionId);
      if (typeof window.setButtonState === 'function') window.setButtonState(false);
      renderProgressPanel();
      renderChatMessages();
    }
  }
  const reply = String(data?.voiceReply || '').trim();
  const alreadySpoken = !!data?.streamedSpeech && !!streamingDispatcher;
  if (reply && !alreadySpoken) speakRealtimeNarration(reply, { force: true, minGapMs: 0 });
  renderProcessLog?.();
  return true;
}

async function submitDesktopVoiceAsLiveSteer(transcript = '', options = {}) {
  const text = String(transcript || '').trim();
  if (!text) return false;
  const sessionId = String(window.activeChatSessionId || 'default').trim() || 'default';
  const ctx = realtimeVoicePendingInterruptContext;
  realtimeVoicePendingInterruptContext = null;
  const requestBody = {
    sessionId,
    reason: ctx?.reason || 'voice_steer',
    currentSpokenSegment: ctx?.responsePreview || '',
    assistantTextSoFar: ctx?.responsePreview || '',
    transcript: text,
    userInterruptionTranscript: text,
    voiceMode: 'desktop_realtime',
    source: String(options.source || 'desktop_realtime_voice_steer'),
    deviceTime: desktopVoiceDeviceTimeContext(),
  };
  let data = null;
  let streamingDispatcher = createDesktopVoiceAgentStreamingDispatcher();
  try {
    try {
      data = await streamVoiceAgentInput(requestBody, (chunk) => {
        try { streamingDispatcher?.enqueue?.(chunk); } catch {}
      });
    } catch (streamErr) {
      console.warn('[voice-agent] steer streaming failed, falling back to JSON:', streamErr);
      streamingDispatcher = null;
      const response = await fetch('/api/voice-agent/input', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(requestBody),
      });
      data = await response.json().catch(() => ({}));
      if (!response.ok || (!data?.success && !data?.ok)) return false;
    }
    if (!data?.success && !data?.ok) return false;
  } catch (err) {
    addProcessEntry?.('error', `Realtime voice steer failed: ${String(err?.message || err)}`);
    return false;
  }
  const intent = String(data?.classification?.intent || 'unknown');
  addProcessEntry?.('warn', `Voice steer: ${intent}${text ? ` - ${text}` : ''}`, {
    actor: 'Voice Steer',
    eventId: data.eventId,
    runtimeId: data.runtimeId,
  });
  appendVoiceInterruptionWorkflowSplit(sessionId, text, data);
  if (data?.classification?.shouldAbortOriginalRun || data?.action === 'interrupt_worker') {
    const ctrl = window._sessionAbortControllers?.[sessionId] || currentAbortController;
    try { if (ctrl && !ctrl.signal?.aborted) ctrl.abort(); } catch {}
    await requestGatewayMainChatAbort(sessionId, 'desktop_realtime_voice_steer');
    await waitForSessionIdle(sessionId, 1800);
    const st = getSessionStreamState(sessionId);
    delete window._sessionThinking[sessionId];
    delete window._sessionAbortControllers[sessionId];
    if (st) {
      st.streamingAIText = '';
      st.streamingThinkingText = '';
      st.liveTraceEntries = [];
      st.currentPreflightStatus = '';
    }
    if (window.activeChatSessionId === sessionId) {
      syncActiveSessionRunState();
      applyStreamStateToWindow(sessionId);
      if (typeof window.setButtonState === 'function') window.setButtonState(false);
      renderProgressPanel();
      renderChatMessages();
    }
  }
  const reply = String(data?.voiceReply || '').trim();
  const alreadySpoken = !!data?.streamedSpeech && !!streamingDispatcher;
  if (reply && !alreadySpoken) speakRealtimeNarration(reply, { force: true, minGapMs: 0 });
  renderProcessLog?.();
  return true;
}

// Returns a streaming TTS dispatcher matched to the user's desktop voice
// settings, or null if the current setup can't stream sentence-by-sentence
// (browser TTS / openai_realtime — those have their own pipelines).
function createDesktopVoiceAgentStreamingDispatcher() {
  if (realtimeVoiceRepliesEnabled) {
    return {
      enqueue(text) {
        const t = String(text || '').trim();
        if (!t) return;
        speakRealtimeNarration(t, { force: true, minGapMs: 0 });
      },
      wait() { return Promise.resolve(); },
    };
  }
  const mode = normalizeDesktopVoiceMode(desktopVoiceSettings.voiceMode);
  const provider = mode === 'xai'
    ? 'xai'
    : (voiceTtsProvider || desktopVoiceSettings.ttsProvider || 'browser');
  if (provider === 'browser') {
    return {
      enqueue(text) {
        const t = String(text || '').trim();
        if (!t) return;
        try { speakWithBrowserVoice(t); } catch {}
      },
      wait() { return Promise.resolve(); },
    };
  }
  if (provider === 'openai_realtime') {
    return {
      enqueue(text) {
        const t = String(text || '').trim();
        if (!t) return;
        speakWithRealtimeVoice(t).catch(() => {});
      },
      wait() { return Promise.resolve(); },
    };
  }
  const selected = getProviderInfo('tts', provider);
  if (selected && !selected.configured) return null;
  return createStreamingTtsDispatcher(provider);
}

async function speakDesktopVoiceAgentReply(text) {
  const reply = String(text || '').trim();
  if (!reply) return;
  if (realtimeVoiceRepliesEnabled) {
    speakRealtimeNarration(reply, { force: true, minGapMs: 0 });
    return;
  }
  const mode = normalizeDesktopVoiceMode(desktopVoiceSettings.voiceMode);
  const provider = mode === 'xai'
    ? 'xai'
    : (voiceTtsProvider || desktopVoiceSettings.ttsProvider || 'browser');
  try {
    if (provider === 'browser') {
      speakWithBrowserVoice(reply);
      return;
    }
    if (provider === 'openai_realtime') {
      await speakWithRealtimeVoice(reply);
      return;
    }
    const selected = getProviderInfo('tts', provider);
    if (selected && !selected.configured) throw new Error(`${selected.label} needs its API key on the gateway.`);
    await speakWithServerTts(reply, provider);
  } catch (err) {
    console.warn('[voice-agent] desktop ack TTS failed, falling back to browser speech:', err);
    speakWithBrowserVoice(reply);
  }
}

function logDesktopVoiceLatency(sessionId, stage, startedAt, extra = {}) {
  const sid = String(sessionId || window.activeChatSessionId || 'default').trim() || 'default';
  const elapsedMs = Math.max(0, Math.round(Date.now() - Number(startedAt || Date.now())));
  const detail = extra && typeof extra === 'object' ? extra : {};
  addSessionProcessEntry(sid, 'info', `Voice latency: ${stage} ${elapsedMs}ms.`, {
    actor: 'Voice Latency',
    stage,
    elapsedMs,
    ...detail,
  });
}

function desktopVoiceDeviceTimeContext() {
  const now = new Date();
  const timezone = (() => {
    try { return Intl.DateTimeFormat().resolvedOptions().timeZone || ''; } catch { return ''; }
  })();
  const format = (options) => {
    try { return now.toLocaleString('en-US', options); } catch { return ''; }
  };
  return {
    source: 'device',
    capturedAt: Date.now(),
    localIso: now.toISOString(),
    timezone,
    utcOffsetMinutes: -now.getTimezoneOffset(),
    dateLabel: format({ weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' }),
    timeLabel: format({ hour: 'numeric', minute: '2-digit', timeZoneName: 'short' }),
  };
}

function getCachedRealtimeVoiceWorkerContextPacket(sessionId) {
  const sid = String(sessionId || 'default').trim() || 'default';
  const packet = realtimeVoiceWorkerContextPacketCache;
  const ageMs = Date.now() - Number(realtimeVoiceWorkerContextPacketFetchedAt || 0);
  if (!packet || String(packet.sessionId || '') !== sid || !Number.isFinite(ageMs) || ageMs < 0 || ageMs > 10_000) return null;
  return packet;
}

async function prefetchRealtimeVoiceWorkerContextPacket(sessionId, options = {}) {
  const sid = String(sessionId || 'default').trim() || 'default';
  try {
    const response = await fetch('/api/voice-agent/context', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        sessionId: sid,
        source: String(options.source || 'desktop_voice_context_prefetch'),
        voiceMode: realtimeVoiceRepliesEnabled ? 'desktop_realtime' : `desktop_${normalizeDesktopVoiceMode(desktopVoiceSettings.voiceMode)}`,
        originalUserPrompt: String(options.originalUserPrompt || ''),
        deviceTime: desktopVoiceDeviceTimeContext(),
      }),
    });
    const data = await response.json().catch(() => ({}));
    if (!response.ok || (!data?.success && !data?.ok) || !data?.contextPacket) return null;
    realtimeVoiceWorkerContextPacketCache = data.contextPacket;
    realtimeVoiceWorkerContextPacketFetchedAt = Date.now();
    return realtimeVoiceWorkerContextPacketCache;
  } catch (err) {
    console.warn('[voice-agent] context packet prefetch failed:', err);
    return null;
  }
}

async function prepareDesktopVoiceAgentHandoff(sessionId, transcript = '', options = {}) {
  const sid = String(sessionId || 'default').trim() || 'default';
  const text = String(transcript || '').trim();
  if (!text) return { shouldContinueToWorker: true, result: null, callerContext: '' };
  try {
    const handoffStartedAt = Date.now();
    addSessionProcessEntry(sid, 'info', 'Voice Agent: preparing contextual acknowledgement.', { actor: 'Voice Agent' });
    const contextPacket = getCachedRealtimeVoiceWorkerContextPacket(sid);
    const requestBody = {
      sessionId: sid,
      transcript: text,
      userInterruptionTranscript: text,
      source: String(options.source || 'desktop_voice_handoff'),
      voiceMode: realtimeVoiceRepliesEnabled ? 'desktop_realtime' : `desktop_${normalizeDesktopVoiceMode(desktopVoiceSettings.voiceMode)}`,
      deviceTime: desktopVoiceDeviceTimeContext(),
      ...(contextPacket ? { contextPacket } : {}),
    };
    // Try streaming first — fires TTS chunk-by-chunk as the model generates,
    // so the user hears the first word ~200-400ms after the model starts.
    let result = null;
    let streamingDispatcher = createDesktopVoiceAgentStreamingDispatcher();
    let firstChunkLogged = false;
    try {
      result = await streamVoiceAgentInput(requestBody, (chunk) => {
        if (!firstChunkLogged) {
          firstChunkLogged = true;
          logDesktopVoiceLatency(sid, 'first speech chunk', handoffStartedAt, { nonBlocking: true });
        }
        try { streamingDispatcher?.enqueue?.(chunk); } catch {}
      });
    } catch (err) {
      console.warn('[voice-agent] streaming failed, falling back to JSON:', err);
      streamingDispatcher = null;
      const response = await fetch('/api/voice-agent/input', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(requestBody),
      });
      result = await response.json().catch(() => ({}));
      if (!response.ok || (!result?.success && !result?.ok)) {
        throw new Error(result?.error || `Voice Agent failed (${response.status})`);
      }
    }
    logDesktopVoiceLatency(sid, 'voice-agent endpoint', handoffStartedAt, {
      action: result?.action || '',
      timings: result?.timings || null,
    });
    const reply = String(result?.voiceReply || '').trim();
    const alreadySpoken = !!(result?.streamedSpeech) && !!streamingDispatcher;
    if (result?.action === 'handoff_new_work') {
      if (reply && !alreadySpoken) {
        logDesktopVoiceLatency(sid, 'ack TTS started', handoffStartedAt, { nonBlocking: true });
        speakDesktopVoiceAgentReply(reply)
          .then(() => logDesktopVoiceLatency(sid, 'ack TTS dispatched', handoffStartedAt, { nonBlocking: true }))
          .catch((err) => addSessionProcessEntry(sid, 'warn', `Voice acknowledgement failed: ${String(err?.message || err)}`, { actor: 'Voice Latency' }));
      } else if (alreadySpoken) {
        // Let chunks finish playing in the background.
        streamingDispatcher.wait().then(() => logDesktopVoiceLatency(sid, 'streamed TTS finished', handoffStartedAt, { nonBlocking: true }));
      }
      logDesktopVoiceLatency(sid, 'worker handoff released', handoffStartedAt);
      return {
        shouldContinueToWorker: true,
        result,
        callerContext: String(result?.injectedContextText || '').trim(),
      };
    }
    if (reply && !alreadySpoken) {
      logDesktopVoiceLatency(sid, 'ack TTS started', handoffStartedAt, { nonBlocking: false });
      await speakDesktopVoiceAgentReply(reply);
      logDesktopVoiceLatency(sid, 'ack TTS completed', handoffStartedAt, { nonBlocking: false });
    } else if (alreadySpoken) {
      await streamingDispatcher.wait();
      logDesktopVoiceLatency(sid, 'streamed TTS completed', handoffStartedAt, { nonBlocking: false });
    }
    if (result?.steerApplied === true || result?.action === 'steer_worker') {
      appendVoiceInterruptionWorkflowSplit(sid, text, result);
      return { shouldContinueToWorker: false, result, callerContext: '' };
    }
    if (result?.action === 'interrupt_worker') {
      await requestGatewayMainChatAbort(sid, 'desktop_voice_agent_handoff');
      return { shouldContinueToWorker: false, result, callerContext: '' };
    }
    return { shouldContinueToWorker: false, result, callerContext: '' };
  } catch (err) {
    addSessionProcessEntry(sid, 'error', `Voice Agent handoff failed: ${String(err?.message || err)}`, { actor: 'Voice Agent' });
    return { shouldContinueToWorker: true, result: null, callerContext: '' };
  }
}

function stopRealtimeVoicePlayback(options = {}) {
  if (options.recordInterrupt === true) captureRealtimeVoicePlaybackInterrupt(options.reason || 'barge_in');
  try { window.speechSynthesis?.cancel?.(); } catch {}
  const audio = document.getElementById('realtime-voice-audio');
  try {
    audio?.pause?.();
    if (audio) audio.currentTime = 0;
  } catch {}
  const dc = realtimeVoiceConnection?.dc;
  if ((realtimeVoicePlaybackActive || realtimeVoiceActiveResponseId) && dc?.readyState === 'open') {
    try { dc.send(JSON.stringify({ type: 'response.cancel' })); } catch {}
    try { dc.send(JSON.stringify({ type: 'output_audio_buffer.clear' })); } catch {}
  }
  realtimeVoicePlaybackActive = false;
  realtimeVoiceActiveResponseId = '';
  finishRealtimeAssistantSpeakingEchoGuard(400);
}

function activateRealtimeWakeGate(gate, options = {}) {
  if (!gate?.normalizedPhrase) return false;
  realtimeWakeGate = gate;
  stopRealtimeVoicePlayback({ recordInterrupt: true, reason: 'wake_gate' });
  if (gate.workerPolicy === 'interrupt' && window._sessionThinking?.[window.activeChatSessionId]) {
    try { window.stopGeneration?.(); } catch {}
    addProcessEntry?.('warn', 'Realtime voice: worker interrupted before entering silent wake gate.');
  } else if (gate.workerPolicy === 'pause') {
    addProcessEntry?.('info', 'Realtime voice: pause requested; voice is silent, worker pause bridge is not active yet.');
  }
  const input = document.getElementById('chat-input');
  if (input) {
    input.value = '';
    resizeChatInput(input);
  }
  resetRealtimeDictationTranscript();
  renderRealtimeWakeGateState();
  if (options.toast !== false) {
    showToast('Realtime silent', `Listening for "${gate.phrase}".`, 'info', 2600);
  }
  addProcessEntry?.('info', `Realtime voice: silent until "${gate.phrase}".`);
  return true;
}

function clearRealtimeWakeGate(options = {}) {
  const gate = getRealtimeWakeGate();
  realtimeWakeGate = null;
  const input = document.getElementById('chat-input');
  if (input && options.clearInput !== false) {
    input.value = '';
    resizeChatInput(input);
  }
  resetRealtimeDictationTranscript();
  renderRealtimeWakeGateState();
  if (gate && options.silent !== true) {
    showToast('Realtime awake', 'Prometheus is listening normally again.', 'success', 1800);
    addProcessEntry?.('info', `Realtime voice: woke from "${gate.phrase}".`);
  }
  return gate;
}

function splitRealtimeWakePhraseRemainder(transcript, gate) {
  const source = String(transcript || '').trim();
  const normalizedSource = normalizeRealtimeWakePhrase(source);
  const normalizedPhrase = normalizeRealtimeWakePhrase(gate?.phrase);
  if (!source || !normalizedPhrase || !normalizedSource.includes(normalizedPhrase)) {
    return { woke: false, remainder: '' };
  }
  const phraseWords = normalizedPhrase.split(/\s+/).filter(Boolean);
  const sourceWords = source.split(/\s+/).filter(Boolean);
  if (!phraseWords.length) return { woke: false, remainder: '' };
  for (let i = 0; i <= sourceWords.length - phraseWords.length; i += 1) {
    const candidate = normalizeRealtimeWakePhrase(sourceWords.slice(i, i + phraseWords.length).join(' '));
    if (candidate === normalizedPhrase) {
      return {
        woke: true,
        remainder: stripRealtimeWakeCommandPunctuation(sourceWords.slice(i + phraseWords.length).join(' ')),
      };
    }
  }
  return { woke: true, remainder: '' };
}

function handleVoiceWakeGateTranscript(transcript, options = {}) {
  const rawTranscript = String(transcript || '').replace(/\s+/g, ' ').trim();
  if (!rawTranscript) return { handled: true, text: '' };
  if (isRealtimeWakeUnlockCommand(rawTranscript)) {
    handleRealtimeControlCommand({ kind: 'unlock_voice' });
    return { handled: true, text: '' };
  }
  const gate = getRealtimeWakeGate();
  if (gate) {
    const wake = splitRealtimeWakePhraseRemainder(rawTranscript, gate);
    if (!wake.woke) return { handled: true, text: '' };
    clearRealtimeWakeGate();
    const remainder = String(wake.remainder || '').trim();
    if (!remainder) return { handled: true, text: '' };
    const control = parseRealtimeControlCommand(remainder);
    if (control && handleRealtimeControlCommand(control)) return { handled: true, text: '' };
    const nextWakeCommand = parseRealtimeWakeGateCommand(remainder);
    if (nextWakeCommand) {
      if (nextWakeCommand.phrase) setRealtimeSessionWakePhrase(nextWakeCommand.phrase, { toast: false });
      activateRealtimeWakeGate(nextWakeCommand);
      return { handled: true, text: '' };
    }
    return { handled: false, text: remainder };
  }

  const control = parseRealtimeControlCommand(rawTranscript);
  if (control && handleRealtimeControlCommand(control)) return { handled: true, text: '' };

  const wakeCommand = parseRealtimeWakeGateCommand(rawTranscript);
  if (wakeCommand) {
    if (wakeCommand.phrase) setRealtimeSessionWakePhrase(wakeCommand.phrase, { toast: false });
    activateRealtimeWakeGate(wakeCommand);
    return { handled: true, text: '' };
  }

  return { handled: false, text: rawTranscript };
}

function resetRealtimeDictationTranscript(options = {}) {
  const input = document.getElementById('chat-input');
  realtimeDictationBaseText = options.baseFromInput === true ? String(input?.value || '').trim() : '';
  realtimeDictationFinalText = '';
  realtimeDictationDeltas = new Map();
  realtimeDraftFinalText = '';
  realtimeDraftInterimText = '';
  realtimeDictationLastSubmittedText = '';
  realtimeDictationUtteranceStartedAt = 0;
  realtimeDictationFirstDeltaLogged = false;
  if (realtimeDictationSubmitTimer) clearTimeout(realtimeDictationSubmitTimer);
  realtimeDictationSubmitTimer = null;
  if (realtimeDictationFallbackTimer) clearTimeout(realtimeDictationFallbackTimer);
  realtimeDictationFallbackTimer = null;
}

function resetRealtimeDictationEventDedupe() {
  realtimeDictationCompletedItemIds = new Set();
  realtimeDictationRecentSubmitKeys = new Map();
  realtimeDictationUtteranceSeq = 0;
  realtimeDictationSubmittedUtteranceSeq = -1;
  realtimeDictationSubmittedUtteranceUntil = 0;
}

function normalizeRealtimeTranscriptKey(value) {
  return String(value || '')
    .toLowerCase()
    .replace(/[\s.,!?;:'"()[\]{}-]+/g, ' ')
    .trim();
}

function hasRecentRealtimeTranscriptSubmit(key, now = Date.now()) {
  const normalized = normalizeRealtimeTranscriptKey(key);
  if (!normalized) return false;
  const maxAgeMs = 12000;
  for (const [existingKey, submittedAt] of realtimeDictationRecentSubmitKeys.entries()) {
    if (now - submittedAt > maxAgeMs) realtimeDictationRecentSubmitKeys.delete(existingKey);
  }
  const previous = realtimeDictationRecentSubmitKeys.get(normalized) || 0;
  if (previous && now - previous <= maxAgeMs) return true;
  realtimeDictationRecentSubmitKeys.set(normalized, now);
  return false;
}

function isRecentRealtimeTranscriptSubmit(key, now = Date.now()) {
  const normalized = normalizeRealtimeTranscriptKey(key);
  if (!normalized) return false;
  const submittedAt = realtimeDictationRecentSubmitKeys.get(normalized) || 0;
  return !!submittedAt && now - submittedAt <= 12000;
}

function writeRealtimeDictationTranscript() {
  if (!realtimeVoiceRepliesEnabled) return;
  if (shouldSuppressRealtimeAssistantEchoInput()) return;
  const input = document.getElementById('chat-input');
  if (!input) return;
  const interimText = Array.from(realtimeDictationDeltas.values()).join(' ').replace(/\s+/g, ' ').trim();
  const draftText = [realtimeDraftFinalText, realtimeDraftInterimText].filter(Boolean).join(' ').trim();
  const pieces = [realtimeDictationBaseText, realtimeDictationFinalText, interimText || draftText]
    .map((part) => String(part || '').trim())
    .filter(Boolean);
  input.value = pieces.join(pieces.length > 1 ? ' ' : '');
  resizeChatInput(input);
}

function getRealtimeDictationComposerText() {
  const interimText = Array.from(realtimeDictationDeltas.values()).join(' ').replace(/\s+/g, ' ').trim();
  const draftText = [realtimeDraftFinalText, realtimeDraftInterimText].filter(Boolean).join(' ').trim();
  return [realtimeDictationBaseText, realtimeDictationFinalText, interimText || draftText]
    .map((part) => String(part || '').trim())
    .filter(Boolean)
    .join(' ')
    .trim();
}

function appendRealtimeCompletedTranscript(itemId, transcript) {
  const text = String(transcript || '').replace(/\s+/g, ' ').trim();
  if (!text) return '';
  if (itemId && realtimeDictationCompletedItemIds.has(itemId)) return '';
  if (itemId) realtimeDictationCompletedItemIds.add(itemId);
  if (itemId) realtimeDictationDeltas.delete(itemId);
  realtimeDictationFinalText = [realtimeDictationFinalText, text].filter(Boolean).join(' ').trim();
  writeRealtimeDictationTranscript();
  return text;
}

function submitRealtimeDictationTranscript(sourceKey = '', messageOverride = '') {
  if (!realtimeVoiceRepliesEnabled) return;
  if (realtimeDictationSubmitTimer) clearTimeout(realtimeDictationSubmitTimer);
  realtimeDictationSubmitTimer = null;
  if (realtimeDictationFallbackTimer) clearTimeout(realtimeDictationFallbackTimer);
  realtimeDictationFallbackTimer = null;
  const input = document.getElementById('chat-input');
  const message = String(messageOverride || input?.value || '').trim();
  if (!message) return;
  if (message === realtimeDictationLastSubmittedText) return;
  if (hasRecentRealtimeTranscriptSubmit(sourceKey || message)) return;
  hasRecentRealtimeTranscriptSubmit(message);
  realtimeDictationLastSubmittedText = message;
  realtimeDictationSubmittedUtteranceSeq = realtimeDictationUtteranceSeq;
  realtimeDictationSubmittedUtteranceUntil = Date.now() + 900;
  realtimeDictationBaseText = '';
  realtimeDictationFinalText = '';
  realtimeDictationDeltas = new Map();
  realtimeDraftFinalText = '';
  realtimeDraftInterimText = '';
  if (input) {
    input.value = '';
    resizeChatInput(input);
  }
  const filesForTurn = Array.isArray(pendingChatFiles) && pendingChatFiles.length ? pendingChatFiles.slice() : [];
  if (filesForTurn.length) {
    pendingChatFiles = [];
    renderChatFilePills();
  }
  try {
    enqueueVoicePendingTurn(message, filesForTurn, 'realtime_voice');
    resetRealtimeDictationTranscript();
  } catch (err) {
    showToast('Realtime send failed', String(err?.message || err), 'error');
  }
}

function submitRealtimeDictationIfReady(sourceKey = '', messageOverride = '', options = {}) {
  if (!realtimeVoiceRepliesEnabled) return false;
  if (shouldSuppressRealtimeAssistantEchoInput() && options.force !== true) return false;
  const message = String(messageOverride || getRealtimeDictationComposerText()).trim();
  if (!message) return false;
  const parsed = extractVoiceSubmitCommand(message);
  if (parsed.shouldSubmit && parsed.text) {
    submitRealtimeDictationTranscript(sourceKey || parsed.text, parsed.text);
    return true;
  }
  if (options.force === true || realtimeAllowsAutoSubmit()) {
    submitRealtimeDictationTranscript(sourceKey || message, message);
    return true;
  }
  return false;
}

function scheduleRealtimeDictationFallbackSubmit(delayMs = 1300) {
  if (realtimeDictationFallbackTimer) clearTimeout(realtimeDictationFallbackTimer);
  if (!realtimeVoiceRepliesEnabled) {
    realtimeDictationFallbackTimer = null;
    return;
  }
  if (shouldSuppressRealtimeAssistantEchoInput()) {
    realtimeDictationFallbackTimer = null;
    return;
  }
  if (!realtimeAllowsAutoSubmit()) {
    realtimeDictationFallbackTimer = null;
    return;
  }
  realtimeDictationFallbackTimer = setTimeout(() => {
    realtimeDictationFallbackTimer = null;
    if (!realtimeVoiceRepliesEnabled) return;
    if (shouldSuppressRealtimeAssistantEchoInput()) return;
    if (getRealtimeWakeGate()) return;
    const text = getRealtimeDictationComposerText();
    if (!text) return;
    submitRealtimeDictationIfReady(text, text);
  }, Math.max(0, Number(delayMs) || 0));
}

function realtimeCurrentUtteranceRecentlySubmitted() {
  return realtimeDictationSubmittedUtteranceSeq === realtimeDictationUtteranceSeq
    && Date.now() < realtimeDictationSubmittedUtteranceUntil;
}

function beginImplicitRealtimeUtteranceIfSubmitted() {
  if (realtimeDictationSubmittedUtteranceSeq !== realtimeDictationUtteranceSeq) return;
  if (Date.now() < realtimeDictationSubmittedUtteranceUntil) return;
  realtimeDictationUtteranceSeq += 1;
  realtimeDictationSubmittedUtteranceSeq = -1;
  realtimeDictationSubmittedUtteranceUntil = 0;
  realtimeDictationBaseText = String(document.getElementById('chat-input')?.value || '').trim();
  realtimeDictationFinalText = '';
  realtimeDictationDeltas = new Map();
  realtimeDraftFinalText = '';
  realtimeDraftInterimText = '';
}

function startRealtimeDraftRecognition() {
  if (realtimeDraftRecognition || !realtimeVoiceRepliesEnabled) return;
  if (realtimeUsesHoldSpace() && !realtimeHoldSpaceActive) return;
  const Recognition = getSpeechRecognitionCtor();
  if (!Recognition) return;
  const input = document.getElementById('chat-input');
  const epoch = realtimeVoiceModeEpoch;
  realtimeDraftFinalText = '';
  realtimeDraftInterimText = '';
  realtimeDraftStartedAt = Date.now();
  const recognition = new Recognition();
  realtimeDraftRecognition = recognition;
  recognition.continuous = true;
  recognition.interimResults = true;
  recognition.lang = navigator.language || 'en-US';
  recognition.onresult = (event) => {
    if (!realtimeVoiceRepliesEnabled || realtimeVoiceModeEpoch !== epoch || realtimeDraftRecognition !== recognition || getRealtimeWakeGate()) return;
    if (shouldSuppressRealtimeAssistantEchoInput()) return;
    let interim = '';
    let sawFinal = false;
    for (let i = event.resultIndex; i < event.results.length; i += 1) {
      const transcript = String(event.results[i]?.[0]?.transcript || '').trim();
      if (!transcript) continue;
      stopRealtimeVoicePlayback({ recordInterrupt: true, reason: 'realtime_draft_transcribing' });
      if (event.results[i].isFinal) {
        realtimeDraftFinalText = `${realtimeDraftFinalText} ${transcript}`.trim();
        realtimeDraftInterimText = '';
        sawFinal = true;
      } else {
        interim = `${interim} ${transcript}`.trim();
      }
    }
    realtimeDraftInterimText = interim;
    if (hasRealtimeAssistantEchoMemory() && isRealtimeAssistantEchoTranscript([realtimeDraftFinalText, realtimeDraftInterimText].filter(Boolean).join(' '))) {
      realtimeDraftFinalText = '';
      realtimeDraftInterimText = '';
      writeRealtimeDictationTranscript();
      return;
    }
    if (!realtimeDictationFinalText && !realtimeDictationDeltas.size) writeRealtimeDictationTranscript();
    const parsed = extractVoiceSubmitCommand(getRealtimeDictationComposerText());
    if (parsed.shouldSubmit && parsed.text) {
      submitRealtimeDictationIfReady(parsed.text, parsed.text);
      return;
    }
    if (sawFinal) scheduleRealtimeDictationFallbackSubmit(650);
    else scheduleRealtimeDictationFallbackSubmit(1600);
  };
  recognition.onerror = (event) => {
    const err = String(event?.error || '').toLowerCase();
    if (err && !['no-speech', 'aborted'].includes(err)) console.warn('[Realtime draft dictation] recognition error', event);
  };
  recognition.onend = () => {
    if (realtimeDraftRecognition !== recognition) return;
    realtimeDraftRecognition = null;
    if (realtimeVoiceRepliesEnabled && realtimeVoiceModeEpoch === epoch && (!realtimeUsesHoldSpace() || realtimeHoldSpaceActive)) {
      setTimeout(startRealtimeDraftRecognition, 180);
    }
  };
  try { recognition.start(); } catch { realtimeDraftRecognition = null; }
}

function stopRealtimeDraftRecognition() {
  const recognition = realtimeDraftRecognition;
  realtimeDraftRecognition = null;
  realtimeDraftFinalText = '';
  realtimeDraftInterimText = '';
  realtimeDraftStartedAt = 0;
  if (!recognition) return;
  try { recognition.onresult = null; recognition.onerror = null; recognition.onend = null; recognition.stop(); } catch {}
  try { recognition.abort?.(); } catch {}
}

function handleRealtimeTranscriptionEvent(event, epoch = realtimeVoiceModeEpoch) {
  if (!realtimeVoiceRepliesEnabled || realtimeVoiceModeEpoch !== epoch) return;
  const type = String(event?.type || '');
  if (type === 'input_audio_buffer.speech_started') {
    realtimeDictationUtteranceSeq += 1;
    realtimeDictationUtteranceStartedAt = Date.now();
    realtimeDictationFirstDeltaLogged = false;
    logDesktopVoiceLatency(window.activeChatSessionId || 'default', 'mic speech started', realtimeDictationUtteranceStartedAt);
    prefetchRealtimeVoiceWorkerContextPacket(window.activeChatSessionId || 'default', { source: 'desktop_realtime_speech_started' }).catch(() => {});
    realtimeDraftFinalText = '';
    realtimeDraftInterimText = '';
    if (!realtimeDictationFinalText && !realtimeDictationDeltas.size) {
      realtimeDictationBaseText = String(document.getElementById('chat-input')?.value || '').trim();
    }
    setRealtimeDictationRecordingState(true);
    if (shouldSuppressRealtimeAssistantEchoInput()) return;
    stopRealtimeVoicePlayback({ recordInterrupt: true, reason: 'barge_in' });
    return;
  }
  if (type === 'input_audio_buffer.speech_stopped' || type === 'input_audio_buffer.committed') {
    setRealtimeDictationRecordingState(false);
    if (shouldSuppressRealtimeAssistantEchoInput()) return;
    if (realtimeCurrentUtteranceRecentlySubmitted()) return;
    beginImplicitRealtimeUtteranceIfSubmitted();
    scheduleRealtimeDictationFallbackSubmit(type === 'input_audio_buffer.committed' ? 900 : 1400);
    return;
  }
  if (type === 'conversation.item.input_audio_transcription.delta') {
    stopRealtimeVoicePlayback({ recordInterrupt: true, reason: 'realtime_transcribing' });
    if (shouldSuppressRealtimeAssistantEchoInput()) return;
    if (getRealtimeWakeGate()) return;
    if (realtimeCurrentUtteranceRecentlySubmitted()) return;
    beginImplicitRealtimeUtteranceIfSubmitted();
    const itemId = String(event?.item_id || 'current');
    const previous = realtimeDictationDeltas.get(itemId) || '';
    const candidate = `${previous}${String(event?.delta || '')}`.trim();
    if (!realtimeDictationFirstDeltaLogged) {
      realtimeDictationFirstDeltaLogged = true;
      logDesktopVoiceLatency(window.activeChatSessionId || 'default', 'first STT delta', realtimeDictationUtteranceStartedAt || Date.now(), {
        itemId,
        textLen: candidate.length,
      });
    }
    if (hasRealtimeAssistantEchoMemory() && isRealtimeAssistantEchoTranscript(candidate)) {
      realtimeDictationDeltas.delete(itemId);
      writeRealtimeDictationTranscript();
      return;
    }
    realtimeDictationDeltas.set(itemId, candidate);
    writeRealtimeDictationTranscript();
    const parsed = extractVoiceSubmitCommand(getRealtimeDictationComposerText());
    if (parsed.shouldSubmit && parsed.text) {
      submitRealtimeDictationIfReady(parsed.text, parsed.text);
    } else {
      scheduleRealtimeDictationFallbackSubmit(1800);
    }
    return;
  }
  if (type === 'conversation.item.input_audio_transcription.completed') {
    const itemId = String(event?.item_id || '');
    const rawTranscript = String(event?.transcript || '').replace(/\s+/g, ' ').trim();
    if (!rawTranscript) return;
    logDesktopVoiceLatency(window.activeChatSessionId || 'default', 'STT final', realtimeDictationUtteranceStartedAt || Date.now(), {
      itemId,
      textLen: rawTranscript.length,
    });
    stopRealtimeVoicePlayback({ recordInterrupt: true, reason: 'realtime_transcribed' });
    if (hasRealtimeAssistantEchoMemory() && isRealtimeAssistantEchoTranscript(rawTranscript)) {
      if (itemId) realtimeDictationDeltas.delete(itemId);
      realtimeDraftFinalText = '';
      realtimeDraftInterimText = '';
      writeRealtimeDictationTranscript();
      return;
    }
    if (shouldSuppressRealtimeAssistantEchoInput()) {
      if (itemId) realtimeDictationDeltas.delete(itemId);
      if (isRealtimeAssistantEchoTranscript(rawTranscript) || !isRealtimeBargeInTranscript(rawTranscript)) return;
      stopRealtimeVoicePlayback({ recordInterrupt: true, reason: 'barge_in' });
      const control = parseRealtimeControlCommand(rawTranscript);
      if (control && handleRealtimeControlCommand(control)) return;
      const wakeCommand = parseRealtimeWakeGateCommand(rawTranscript);
      if (wakeCommand) {
        if (wakeCommand.phrase) setRealtimeSessionWakePhrase(wakeCommand.phrase, { toast: false });
        activateRealtimeWakeGate(wakeCommand);
        return;
      }
      return;
    }
    if (realtimeCurrentUtteranceRecentlySubmitted() || isRecentRealtimeTranscriptSubmit(rawTranscript)) {
      if (itemId) realtimeDictationDeltas.delete(itemId);
      return;
    }
    beginImplicitRealtimeUtteranceIfSubmitted();

    const gate = getRealtimeWakeGate();
    if (gate) {
      if (itemId) realtimeDictationDeltas.delete(itemId);
      const wake = splitRealtimeWakePhraseRemainder(rawTranscript, gate);
      if (!wake.woke) return;
      clearRealtimeWakeGate();
      if (wake.remainder) {
        const control = parseRealtimeControlCommand(wake.remainder);
        if (control && handleRealtimeControlCommand(control)) return;
        const nextWakeCommand = parseRealtimeWakeGateCommand(wake.remainder);
        if (nextWakeCommand) {
          if (nextWakeCommand.phrase) setRealtimeSessionWakePhrase(nextWakeCommand.phrase, { toast: false });
          activateRealtimeWakeGate(nextWakeCommand);
          return;
        }
        const transcript = appendRealtimeCompletedTranscript(itemId, wake.remainder);
        if (transcript) {
          realtimeDraftFinalText = '';
          realtimeDraftInterimText = '';
          const message = String(document.getElementById('chat-input')?.value || '').trim();
          const parsed = extractVoiceSubmitCommand(message);
          submitRealtimeDictationIfReady(itemId || transcript, parsed.shouldSubmit && parsed.text ? parsed.text : message);
        }
      }
      return;
    }

    const controlCommand = parseRealtimeControlCommand(rawTranscript);
    if (controlCommand && handleRealtimeControlCommand(controlCommand)) {
      if (itemId) realtimeDictationDeltas.delete(itemId);
      return;
    }

    const wakeCommand = parseRealtimeWakeGateCommand(rawTranscript);
    if (wakeCommand) {
      if (itemId) realtimeDictationDeltas.delete(itemId);
      if (wakeCommand.phrase) setRealtimeSessionWakePhrase(wakeCommand.phrase, { toast: false });
      activateRealtimeWakeGate(wakeCommand);
      return;
    }

    const transcript = appendRealtimeCompletedTranscript(itemId, rawTranscript);
    if (transcript) {
      realtimeDraftFinalText = '';
      realtimeDraftInterimText = '';
      const message = String(document.getElementById('chat-input')?.value || '').trim();
      const parsed = extractVoiceSubmitCommand(message);
      submitRealtimeDictationIfReady(itemId || transcript, parsed.shouldSubmit && parsed.text ? parsed.text : message);
    }
    return;
  }
  if (type === 'conversation.item.input_audio_transcription.failed' || type === 'error') {
    const message = event?.error?.message || event?.error || 'Realtime transcription failed.';
    showToast('Realtime transcription failed', String(message), 'error');
  }
}

function closeRealtimeDictationConnection() {
  const connection = realtimeDictationConnection;
  realtimeDictationConnection = null;
  realtimeDictationConnecting = null;
  setRealtimeDictationRecordingState(false);
  stopRealtimeDraftRecognition();
  resetRealtimeDictationTranscript();
  resetRealtimeDictationEventDedupe();
  try { connection?.dc?.close?.(); } catch {}
  try { connection?.pc?.close?.(); } catch {}
  try { connection?.stream?.getTracks?.().forEach((track) => track.stop()); } catch {}
}

async function ensureRealtimeDictationConnection() {
  if (realtimeUsesHoldSpace() && !realtimeHoldSpaceActive) throw new Error('Realtime hold-to-talk is inactive.');
  if (realtimeDictationConnection?.dc?.readyState === 'open') return realtimeDictationConnection;
  if (realtimeDictationConnecting) return realtimeDictationConnecting;
  if (!navigator.mediaDevices?.getUserMedia) throw new Error('This browser cannot capture microphone audio.');
  const epoch = realtimeVoiceModeEpoch;
  realtimeDictationConnecting = (async () => {
    resetRealtimeDictationTranscript({ baseFromInput: true });
    resetRealtimeDictationEventDedupe();
    const tokenResponse = await fetch('/api/realtime/client-secret', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        mode: 'transcription',
        language: navigator.language?.split('-')?.[0] || undefined,
        vadThreshold: 0.22,
        prefixPaddingMs: 700,
        silenceDurationMs: 450,
      }),
    });
    const tokenData = await tokenResponse.json().catch(() => ({}));
    if (!realtimeVoiceRepliesEnabled || realtimeVoiceModeEpoch !== epoch) throw new Error('Realtime voice stopped.');
    if (!tokenResponse.ok || tokenData?.success === false) {
      throw new Error(tokenData?.error || `Realtime transcription token request failed (${tokenResponse.status})`);
    }
    const clientSecret = extractRealtimeClientSecret(tokenData);
    if (!clientSecret) throw new Error('Realtime transcription client secret was missing from the gateway response.');

    const stream = await navigator.mediaDevices.getUserMedia({
      audio: {
        echoCancellation: true,
        noiseSuppression: true,
        autoGainControl: true,
      },
    });
    if (!realtimeVoiceRepliesEnabled || realtimeVoiceModeEpoch !== epoch) {
      try { stream.getTracks().forEach((track) => track.stop()); } catch {}
      throw new Error('Realtime voice stopped.');
    }
    const pc = new RTCPeerConnection();
    stream.getAudioTracks().forEach((track) => pc.addTrack(track, stream));
    const dc = pc.createDataChannel('oai-events');
    dc.addEventListener('message', (messageEvent) => {
      try {
        handleRealtimeTranscriptionEvent(JSON.parse(messageEvent.data), epoch);
      } catch {}
    });
    const dcOpen = new Promise((resolve, reject) => {
      const timeout = setTimeout(() => reject(new Error('Realtime transcription data channel did not open.')), 12000);
      dc.addEventListener('open', () => { clearTimeout(timeout); resolve(true); }, { once: true });
      dc.addEventListener('error', () => { clearTimeout(timeout); reject(new Error('Realtime transcription data channel failed.')); }, { once: true });
    });
    const offer = await pc.createOffer();
    await pc.setLocalDescription(offer);
    const sdpResponse = await fetch('https://api.openai.com/v1/realtime/calls', {
      method: 'POST',
      headers: {
        Authorization: `Bearer ${clientSecret}`,
        'Content-Type': 'application/sdp',
      },
      body: offer.sdp,
    });
    const answerSdp = await sdpResponse.text();
    if (!realtimeVoiceRepliesEnabled || realtimeVoiceModeEpoch !== epoch) {
      try { dc.close(); } catch {}
      try { pc.close(); } catch {}
      try { stream.getTracks().forEach((track) => track.stop()); } catch {}
      throw new Error('Realtime voice stopped.');
    }
    if (!sdpResponse.ok) throw new Error(answerSdp || `Realtime transcription call failed (${sdpResponse.status})`);
    await pc.setRemoteDescription({ type: 'answer', sdp: answerSdp });
    await dcOpen;
    prefetchRealtimeVoiceWorkerContextPacket(window.activeChatSessionId || 'default', { source: 'desktop_realtime_ready' }).catch(() => {});
    if (!realtimeVoiceRepliesEnabled || realtimeVoiceModeEpoch !== epoch) {
      try { dc.close(); } catch {}
      try { pc.close(); } catch {}
      try { stream.getTracks().forEach((track) => track.stop()); } catch {}
      throw new Error('Realtime voice stopped.');
    }
    realtimeDictationConnection = { pc, dc, stream };
    pc.addEventListener('connectionstatechange', () => {
      if (realtimeVoiceModeEpoch === epoch && ['closed', 'failed', 'disconnected'].includes(pc.connectionState)) {
        closeRealtimeDictationConnection();
      }
    });
    return realtimeDictationConnection;
  })().finally(() => {
    realtimeDictationConnecting = null;
  });
  return realtimeDictationConnecting;
}

async function startRealtimeInputCapture() {
  if (!realtimeVoiceRepliesEnabled) return null;
  if (realtimeUsesHoldSpace() && !realtimeHoldSpaceActive) return null;
  startRealtimeDraftRecognition();
  return ensureRealtimeDictationConnection();
}

function stopRealtimeInputCapture(options = {}) {
  const shouldSubmit = options.submit === true;
  const delayMs = Math.max(0, Number(options.delayMs ?? 220) || 0);
  const finalize = () => {
    if (shouldSubmit && realtimeVoiceRepliesEnabled) {
      const text = getRealtimeDictationComposerText();
      if (text) submitRealtimeDictationIfReady(text, text, { force: true });
    }
    closeRealtimeDictationConnection();
    stopRealtimeDraftRecognition();
  };
  if (delayMs) setTimeout(finalize, delayMs);
  else finalize();
}

function isEditableVoiceTarget(target) {
  const el = target && target.nodeType === 1 ? target : null;
  if (!el) return false;
  const tag = String(el.tagName || '').toLowerCase();
  return tag === 'input' || tag === 'textarea' || tag === 'select' || !!el.isContentEditable || !!el.closest?.('[contenteditable="true"], input, textarea, select');
}

function handleRealtimeSpaceKeydown(event) {
  if (!realtimeVoiceRepliesEnabled || !realtimeUsesHoldSpace() || realtimeHoldSpaceActive) return;
  if (event.code !== 'Space' || event.repeat || isEditableVoiceTarget(event.target)) return;
  event.preventDefault();
  realtimeHoldSpaceActive = true;
  // Realtime end-to-end agent: open mic directly on the realtime session
  if (isVoiceAgentRealtimeMode()) {
    pttRealtimeAgentPress();
    return;
  }
  resetRealtimeDictationTranscript({ baseFromInput: true });
  startRealtimeInputCapture().catch((err) => {
    realtimeHoldSpaceActive = false;
    showToast('Realtime microphone failed', String(err?.message || err), 'error');
  });
}

function handleRealtimeSpaceKeyup(event) {
  if (!realtimeVoiceRepliesEnabled || !realtimeUsesHoldSpace() || !realtimeHoldSpaceActive) return;
  if (event.code !== 'Space') return;
  event.preventDefault();
  realtimeHoldSpaceActive = false;
  if (isVoiceAgentRealtimeMode()) {
    pttRealtimeAgentRelease();
    return;
  }
  stopRealtimeInputCapture({ submit: true, delayMs: 420 });
}

function getProviderInfo(kind, provider) {
  const list = kind === 'stt' ? voiceProvidersStatus.sttProviders : voiceProvidersStatus.ttsProviders;
  return (Array.isArray(list) ? list : []).find((item) => item.id === provider) || null;
}

function fallbackVoiceCatalog(provider) {
  if (provider === 'openai') {
    return [
      { id: 'alloy', label: 'Alloy' },
      { id: 'ash', label: 'Ash' },
      { id: 'ballad', label: 'Ballad' },
      { id: 'coral', label: 'Coral' },
      { id: 'echo', label: 'Echo' },
      { id: 'fable', label: 'Fable' },
      { id: 'marin', label: 'Marin' },
      { id: 'nova', label: 'Nova' },
      { id: 'onyx', label: 'Onyx' },
      { id: 'sage', label: 'Sage' },
      { id: 'shimmer', label: 'Shimmer' },
      { id: 'verse', label: 'Verse' },
    ];
  }
  if (provider === 'openai_realtime') {
    return [
      { id: 'alloy', label: 'Alloy' },
      { id: 'ash', label: 'Ash' },
      { id: 'ballad', label: 'Ballad' },
      { id: 'coral', label: 'Coral' },
      { id: 'echo', label: 'Echo' },
      { id: 'sage', label: 'Sage' },
      { id: 'shimmer', label: 'Shimmer' },
      { id: 'verse', label: 'Verse' },
      { id: 'marin', label: 'Marin' },
      { id: 'cedar', label: 'Cedar' },
    ];
  }
  if (provider === 'xai') {
    return [
      { id: 'eve', label: 'Eve' },
      { id: 'ara', label: 'Ara' },
      { id: 'rex', label: 'Rex' },
      { id: 'sal', label: 'Sal' },
      { id: 'leo', label: 'Leo' },
    ];
  }
  return [];
}

async function getVoiceCatalog(provider) {
  const id = String(provider || '').trim();
  if (!id) return [];
  if (voiceCatalogCache[id]) return voiceCatalogCache[id];
  try {
    const response = await fetch(`/api/voice/voices?provider=${encodeURIComponent(id)}`);
    const data = await response.json().catch(() => ({}));
    const voices = Array.isArray(data?.voices) && data.voices.length ? data.voices : fallbackVoiceCatalog(id);
    voiceCatalogCache[id] = voices;
    return voices;
  } catch {
    const voices = fallbackVoiceCatalog(id);
    voiceCatalogCache[id] = voices;
    return voices;
  }
}

function selectedRegularVoiceProvider() {
  return voiceTtsProvider === 'openai' || voiceTtsProvider === 'xai' ? voiceTtsProvider : '';
}

function normalizeRealtimeVoice(value) {
  const voice = String(value || '').trim();
  return OPENAI_REALTIME_VOICE_IDS.has(voice) ? voice : 'marin';
}

function getRenderableVoiceProviders(kind) {
  const list = kind === 'stt' ? voiceProvidersStatus.sttProviders : voiceProvidersStatus.ttsProviders;
  const providers = Array.isArray(list) ? list : [];
  if (kind !== 'tts') return providers;
  return providers.filter((provider) => provider.id !== 'openai_realtime');
}

function isVoiceProviderConfigured(kind, provider) {
  const info = getProviderInfo(kind, provider);
  return !!info?.configured;
}

function renderVoiceModeSelect() {
  const select = document.getElementById('voice-mode-provider');
  if (!select) return;
  const mode = normalizeDesktopVoiceMode(desktopVoiceSettings.voiceMode);
  const realtimeLabel = realtimeVoiceConfigured ? 'OpenAI Realtime' : 'OpenAI Realtime (not connected)';
  const xaiReady = isVoiceProviderConfigured('stt', 'xai') && isVoiceProviderConfigured('tts', 'xai');
  const xaiLabel = xaiReady ? 'xAI / Grok' : 'xAI / Grok (not connected)';
  select.innerHTML = [
    { value: 'default', label: 'Default' },
    { value: 'openai_realtime', label: realtimeLabel },
    { value: 'xai', label: xaiLabel },
  ].map((option) => `<option value="${escHtml(option.value)}">${escHtml(option.label)}</option>`).join('');
  select.value = mode;
}

function renderVoiceProviderSelect(kind) {
  const id = kind === 'stt' ? 'voice-stt-provider' : 'voice-tts-provider';
  const selected = kind === 'stt' ? voiceSttProvider : voiceTtsProvider;
  const list = getRenderableVoiceProviders(kind);
  const select = document.getElementById(id);
  if (!select || !Array.isArray(list) || !list.length) return;
  select.innerHTML = list.map((provider) => {
    const suffix = provider.configured ? '' : ' (key)';
    return `<option value="${escHtml(provider.id)}">${escHtml(provider.label + suffix)}</option>`;
  }).join('');
  select.value = list.some((provider) => provider.id === selected) ? selected : 'browser';
}

async function renderOutputVoiceSelect() {
  const label = document.getElementById('voice-output-voice-label');
  const select = document.getElementById('voice-output-voice');
  const provider = selectedRegularVoiceProvider();
  if (!label || !select) return;
  if (!provider) {
    label.hidden = true;
    select.innerHTML = '<option value="">Default</option>';
    return;
  }
  const voices = await getVoiceCatalog(provider);
  const stored = provider === 'xai'
    ? (desktopVoiceSettings.serverVoice || getStoredVoiceSetting(`voice_${provider}_voice`, 'eve'))
    : getStoredVoiceSetting(`voice_${provider}_voice`, 'alloy');
  voiceOutputVoice = voices.some((voice) => voice.id === stored) ? stored : (voices[0]?.id || '');
  select.innerHTML = voices.map((voice) => `<option value="${escHtml(voice.id)}">${escHtml(voice.label || voice.id)}</option>`).join('');
  select.value = voiceOutputVoice;
  label.hidden = false;
}

async function renderRealtimeVoiceSelect() {
  const select = document.getElementById('realtime-voice-select');
  if (!select) return;
  const voices = await getVoiceCatalog('openai_realtime');
  const allowedVoices = voices.filter((voice) => OPENAI_REALTIME_VOICE_IDS.has(voice.id));
  const list = allowedVoices.length ? allowedVoices : fallbackVoiceCatalog('openai_realtime');
  const stored = normalizeRealtimeVoice(getStoredVoiceSetting('realtime_voice', 'marin'));
  realtimeVoiceSelection = list.some((voice) => voice.id === stored) ? stored : 'marin';
  if (realtimeVoiceSelection !== stored) storeVoiceSetting('realtime_voice', realtimeVoiceSelection);
  select.innerHTML = list.map((voice) => `<option value="${escHtml(voice.id)}">${escHtml(voice.label || voice.id)}</option>`).join('');
  select.value = realtimeVoiceSelection;
}

function renderRealtimeVoiceSpeedSelect() {
  const select = document.getElementById('realtime-voice-speed-select');
  if (!select) return;
  const mode = normalizeDesktopVoiceMode(desktopVoiceSettings.voiceMode);
  const options = mode === 'xai'
    ? [
      { value: 0.7, label: '0.7x' },
      { value: 0.75, label: '0.75x' },
      { value: 1, label: '1.0x' },
      { value: 1.1, label: '1.1x' },
      { value: 1.25, label: '1.25x' },
      { value: 1.5, label: '1.5x' },
    ]
    : [
      { value: 0.9, label: '0.9x' },
      { value: 1, label: '1.0x' },
      { value: 1.1, label: '1.1x' },
      { value: 1.2, label: '1.2x' },
      { value: 1.35, label: '1.35x' },
      { value: 1.5, label: '1.5x' },
    ];
  select.innerHTML = options.map((option) => `<option value="${option.value}">${option.label}</option>`).join('');
  const speed = mode === 'xai'
    ? Math.max(0.7, Math.min(1.5, Number(desktopVoiceSettings.xaiSpeed || 1.0) || 1.0))
    : normalizeRealtimeVoiceSpeed(realtimeVoiceSpeed);
  select.value = options.some((option) => option.value === speed) ? String(speed) : (mode === 'xai' ? '1' : '1.1');
}

function renderRealtimeNarrationModeSelect() {
  const select = document.getElementById('realtime-narration-mode-select');
  if (!select) return;
  select.value = normalizeRealtimeNarrationMode(realtimeNarrationMode);
}

function renderRealtimeListenModeSelect() {
  const select = document.getElementById('realtime-listen-mode-select');
  if (!select) return;
  select.value = normalizeRealtimeListenMode(realtimeListenMode);
}

function renderVoiceProviderControls() {
  const mode = normalizeDesktopVoiceMode(desktopVoiceSettings.voiceMode);
  renderVoiceModeSelect();
  renderVoiceProviderSelect('stt');
  renderVoiceProviderSelect('tts');
  const controls = document.getElementById('voice-provider-controls');
  const showControls = regularVoiceControlsVisible || realtimeVoiceRepliesEnabled;
  if (controls) {
    controls.hidden = !showControls;
    controls.classList.toggle('visible', showControls);
  }
  const micLabel = document.getElementById('voice-mic-provider-label');
  const speakLabel = document.getElementById('voice-speak-provider-label');
  const realtimeVoiceLabel = document.getElementById('realtime-voice-label');
  const speedLabel = document.getElementById('voice-speed-label');
  const narrationLabel = document.getElementById('voice-narration-label');
  const listenLabel = document.getElementById('realtime-listen-label');
  if (micLabel) micLabel.hidden = true;
  if (speakLabel) speakLabel.hidden = true;
  if (realtimeVoiceLabel) realtimeVoiceLabel.hidden = mode !== 'openai_realtime';
  if (speedLabel) speedLabel.hidden = !['openai_realtime', 'xai'].includes(mode);
  if (narrationLabel) narrationLabel.hidden = !['openai_realtime', 'xai'].includes(mode);
  if (listenLabel) listenLabel.hidden = mode !== 'openai_realtime';
  const realtimeAgentLabel = document.getElementById('realtime-agent-toggle-label');
  const realtimeAgentToggle = document.getElementById('realtime-agent-toggle');
  if (realtimeAgentLabel) realtimeAgentLabel.hidden = mode !== 'openai_realtime';
  if (realtimeAgentToggle) realtimeAgentToggle.checked = desktopVoiceSettings.voiceAgentRealtimeAgent !== false;
  const xaiRealtimeLabel = document.getElementById('xai-realtime-toggle-label');
  const xaiRealtimeToggle = document.getElementById('xai-realtime-toggle');
  if (xaiRealtimeLabel) xaiRealtimeLabel.hidden = mode !== 'xai';
  if (xaiRealtimeToggle) xaiRealtimeToggle.checked = desktopVoiceSettings.voiceAgentXaiRealtime === true;
  const voiceLabel = document.getElementById('voice-output-voice-label');
  if (voiceLabel && mode !== 'xai') voiceLabel.hidden = true;
  renderOutputVoiceSelect().catch(() => {});
  renderRealtimeVoiceSelect().catch(() => {});
  renderRealtimeVoiceSpeedSelect();
  renderRealtimeNarrationModeSelect();
  renderRealtimeListenModeSelect();
  setRealtimeVoiceButtonState();
}

async function refreshVoiceProviderStatus() {
  desktopVoiceSettings = loadDesktopVoiceSettings();
  voiceSttProvider = desktopVoiceSettings.sttProvider || getStoredVoiceProvider('stt', 'browser');
  voiceTtsProvider = desktopVoiceSettings.ttsProvider || getStoredVoiceProvider('tts', 'browser');
  realtimeVoiceSelection = desktopVoiceSettings.realtimeVoice || getStoredVoiceSetting('realtime_voice', 'marin');
  loadRealtimeVoiceSpeed();
  realtimeVoiceSpeed = normalizeRealtimeVoiceSpeed(desktopVoiceSettings.realtimeSpeed || realtimeVoiceSpeed);
  loadRealtimeNarrationMode();
  loadRealtimeListenMode();
  try {
    const response = await fetch('/api/voice/status');
    const data = await response.json().catch(() => ({}));
    if (data?.success) {
      voiceProvidersStatus = {
        sttProviders: Array.isArray(data.sttProviders) ? data.sttProviders : [],
        ttsProviders: Array.isArray(data.ttsProviders) ? data.ttsProviders : [],
      };
      realtimeVoiceConfigured = !!getProviderInfo('tts', 'openai_realtime')?.configured;
      applyDesktopVoiceProviderDefaults();
      if (voiceTtsProvider === 'openai_realtime') {
        voiceTtsProvider = 'browser';
        storeVoiceProvider('tts', voiceTtsProvider);
      }
    }
  } catch {
    voiceProvidersStatus = {
      sttProviders: [{ id: 'browser', label: 'Browser dictation', configured: true, free: true }],
      ttsProviders: [{ id: 'browser', label: 'Browser voice', configured: true, free: true }],
    };
    realtimeVoiceConfigured = false;
  }
  const mode = normalizeDesktopVoiceMode(desktopVoiceSettings.voiceMode);
  if (mode === 'openai_realtime') {
    voiceSttProvider = 'browser';
    voiceTtsProvider = 'browser';
  } else if (mode === 'xai') {
    const xaiTtsReady = isVoiceProviderConfigured('tts', 'xai');
    const xaiSttReady = isVoiceProviderConfigured('stt', 'xai');
    voiceTtsProvider = xaiTtsReady ? 'xai' : 'browser';
    voiceSttProvider = xaiSttReady ? 'xai' : 'browser';
  } else {
    voiceSttProvider = 'browser';
    voiceTtsProvider = 'browser';
  }
  storeVoiceProvider('stt', voiceSttProvider);
  storeVoiceProvider('tts', voiceTtsProvider);
  renderVoiceProviderControls();
}

function onVoiceProviderChanged() {
  const stt = document.getElementById('voice-stt-provider');
  const tts = document.getElementById('voice-tts-provider');
  const voice = document.getElementById('voice-output-voice');
  voiceSttProvider = String(stt?.value || 'browser');
  voiceTtsProvider = String(tts?.value || 'browser');
  voiceOutputVoice = String(voice?.value || '');
  storeVoiceProvider('stt', voiceSttProvider);
  storeVoiceProvider('tts', voiceTtsProvider);
  const voiceProvider = selectedRegularVoiceProvider();
  if (voiceProvider && voiceOutputVoice) storeVoiceSetting(`voice_${voiceProvider}_voice`, voiceOutputVoice);
  saveDesktopVoiceSettings({
    voiceMode: normalizeDesktopVoiceMode(desktopVoiceSettings.voiceMode),
    sttProvider: voiceSttProvider,
    ttsProvider: voiceTtsProvider,
    serverVoice: voiceProvider === 'xai' && voiceOutputVoice ? voiceOutputVoice : desktopVoiceSettings.serverVoice,
    autoProviderDefault: '',
  });
  renderOutputVoiceSelect().catch(() => {});
  setRealtimeVoiceButtonState();
}

function onVoiceModeChanged() {
  const select = document.getElementById('voice-mode-provider');
  const mode = normalizeDesktopVoiceMode(select?.value || 'default');
  if (mode !== 'openai_realtime') disableRealtimeVoiceMode();
  if (mode === 'default') {
    voiceSttProvider = 'browser';
    voiceTtsProvider = 'browser';
  } else if (mode === 'xai') {
    voiceSttProvider = isVoiceProviderConfigured('stt', 'xai') ? 'xai' : 'browser';
    voiceTtsProvider = isVoiceProviderConfigured('tts', 'xai') ? 'xai' : 'browser';
  } else {
    voiceSttProvider = 'browser';
    voiceTtsProvider = 'browser';
  }
  storeVoiceProvider('stt', voiceSttProvider);
  storeVoiceProvider('tts', voiceTtsProvider);
  saveDesktopVoiceSettings({
    voiceMode: mode,
    sttProvider: voiceSttProvider,
    ttsProvider: voiceTtsProvider,
    realtimeVoice: realtimeVoiceSelection || desktopVoiceSettings.realtimeVoice || 'marin',
    realtimeSpeed: realtimeVoiceSpeed,
    serverVoice: desktopVoiceSettings.serverVoice || 'eve',
    sttProviderLocked: true,
    autoProviderDefault: '',
  });
  renderVoiceProviderControls();
  setUnifiedVoiceButtonState();
}

function onRealtimeVoiceChanged() {
  const select = document.getElementById('realtime-voice-select');
  realtimeVoiceSelection = normalizeRealtimeVoice(select?.value || 'marin');
  storeVoiceSetting('realtime_voice', realtimeVoiceSelection);
  saveDesktopVoiceSettings({ realtimeVoice: realtimeVoiceSelection });
  if (select) select.value = realtimeVoiceSelection;
  closeRealtimeVoiceConnection();
}

function onRealtimeVoiceSpeedChanged() {
  const select = document.getElementById('realtime-voice-speed-select');
  const mode = normalizeDesktopVoiceMode(desktopVoiceSettings.voiceMode);
  const rawSpeed = Number(select?.value || (mode === 'xai' ? 1 : 1.1));
  const speed = mode === 'xai'
    ? Math.max(0.7, Math.min(1.5, Math.round((Number.isFinite(rawSpeed) ? rawSpeed : 1) * 100) / 100))
    : storeRealtimeVoiceSpeed(rawSpeed);
  saveDesktopVoiceSettings(mode === 'xai' ? { xaiSpeed: speed } : { realtimeSpeed: speed });
  if (select) select.value = String(speed);
  sendVoiceAgentRealtimeSpeedUpdate();
  if (realtimeVoicePlaybackActive || realtimeVoiceActiveResponseId) {
    showToast('Realtime speed saved', 'Applies to the next spoken response.', 'info', 1800);
  }
}

function onRealtimeNarrationModeChanged() {
  const select = document.getElementById('realtime-narration-mode-select');
  const mode = storeRealtimeNarrationMode(select?.value || 'quiet');
  saveDesktopVoiceSettings({ dictation: mode === 'milestones' ? 'milestone' : 'quiet' });
  if (select) select.value = mode;
  realtimeNarrationRecentKeys.clear();
  realtimeNarrationLastSpokenAt = 0;
  if (realtimeVoiceRepliesEnabled || voiceRepliesEnabled) {
    showToast('Voice narration', mode === 'milestones' ? 'Milestone narration enabled.' : 'Narration quiet.', 'info', 1800);
  }
}

function onRealtimeListenModeChanged() {
  const select = document.getElementById('realtime-listen-mode-select');
  const previousMode = realtimeListenMode;
  const mode = storeRealtimeListenMode(select?.value || 'auto_send');
  if (select) select.value = mode;
  if (!realtimeVoiceRepliesEnabled || previousMode === mode) return;
  if (mode === 'hold_space') {
    closeRealtimeDictationConnection();
    stopRealtimeDraftRecognition();
    resetRealtimeDictationTranscript();
    realtimeHoldSpaceActive = false;
    showToast('Hold Space enabled', 'Hold Space to talk. Release to send.', 'info', 2200);
  } else if (previousMode === 'hold_space') {
    startRealtimeInputCapture().catch((err) => showToast('Realtime microphone failed', String(err?.message || err), 'error'));
  }
}

async function refreshRealtimeVoiceStatus() {
  const btn = document.getElementById('chat-voice-btn');
  if (!btn) return;
  try {
    const response = await fetch('/api/realtime/status');
    const data = await response.json().catch(() => ({}));
    realtimeVoiceConfigured = !!data?.configured;
    btn.classList.toggle('unconfigured', !realtimeVoiceConfigured);
  } catch {
    realtimeVoiceConfigured = false;
  }
  setRealtimeVoiceButtonState();
}

async function ensureRealtimeVoiceConnection() {
  if (realtimeVoiceConnection?.dc?.readyState === 'open') return realtimeVoiceConnection;
  if (realtimeVoiceConnecting) return realtimeVoiceConnecting;
  const epoch = realtimeVoiceModeEpoch;
  realtimeVoiceConnecting = (async () => {
    const instructions = await getRealtimeContextPackInstructions();
    if (!realtimeVoiceRepliesEnabled || realtimeVoiceModeEpoch !== epoch) throw new Error('Realtime voice stopped.');
    const tokenResponse = await fetch('/api/realtime/client-secret', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        voice: normalizeRealtimeVoice(realtimeVoiceSelection || getStoredVoiceSetting('realtime_voice', 'marin')),
        speed: normalizeRealtimeVoiceSpeed(realtimeVoiceSpeed),
        instructions,
      }),
    });
    const tokenData = await tokenResponse.json().catch(() => ({}));
    if (!realtimeVoiceRepliesEnabled || realtimeVoiceModeEpoch !== epoch) throw new Error('Realtime voice stopped.');
    if (!tokenResponse.ok || tokenData?.success === false) {
      throw new Error(tokenData?.error || `Realtime token request failed (${tokenResponse.status})`);
    }
    const clientSecret = extractRealtimeClientSecret(tokenData);
    if (!clientSecret) throw new Error('Realtime client secret was missing from the gateway response.');

    const pc = new RTCPeerConnection();
    const audio = document.getElementById('realtime-voice-audio') || document.createElement('audio');
    audio.autoplay = true;
    audio.muted = false;
    audio.volume = 1;
    audio.playsInline = true;
    audio.style.display = 'none';
    if (!audio.id) {
      audio.id = 'realtime-voice-audio';
      document.body.appendChild(audio);
    }
    pc.ontrack = (event) => {
      audio.srcObject = event.streams[0];
      audio.play?.().catch((err) => {
        console.warn('[Realtime voice] audio playback blocked', err);
        if (!realtimeVoicePlaybackWarningShown) {
          realtimeVoicePlaybackWarningShown = true;
          showToast('Realtime audio blocked', 'Click the page once, then try the Realtime mic again.', 'error', 4200);
        }
      });
    };
    try { pc.addTransceiver('audio', { direction: 'recvonly' }); } catch {}
    const dc = pc.createDataChannel('oai-events');
    dc.addEventListener('message', (messageEvent) => {
      try {
        const event = JSON.parse(messageEvent.data);
        const type = String(event?.type || '');
        if (type === 'response.created' || type === 'response.audio.delta' || type === 'response.output_audio.delta') {
          realtimeVoicePlaybackActive = true;
          if (realtimeAssistantEchoText) realtimeAssistantSpeaking = true;
          const responseId = String(event?.response?.id || event?.response_id || '').trim();
          if (responseId) realtimeVoiceActiveResponseId = responseId;
        }
        if (type === 'response.done' || type === 'response.audio.done' || type === 'response.output_audio.done' || type === 'response.cancelled') {
          realtimeVoicePlaybackActive = false;
          realtimeVoiceActiveResponseId = '';
          finishRealtimeAssistantSpeakingEchoGuard(2500);
          realtimeVoiceResponseWaiters.splice(0).forEach((resolve) => {
            try { resolve(); } catch {}
          });
        }
        if (event?.type === 'error') {
          const message = String(event?.error?.message || event?.error || '');
          if (/active response in progress/i.test(message)) {
            realtimeVoicePlaybackActive = true;
            return;
          }
          console.warn('[Realtime voice] server error', event);
          showToast('Realtime voice error', String(message || 'Unknown realtime error'), 'error');
        }
      } catch {}
    });
    const dcOpen = new Promise((resolve, reject) => {
      const timeout = setTimeout(() => reject(new Error('Realtime data channel did not open.')), 12000);
      dc.addEventListener('open', () => { clearTimeout(timeout); resolve(true); }, { once: true });
      dc.addEventListener('error', () => { clearTimeout(timeout); reject(new Error('Realtime data channel failed.')); }, { once: true });
    });
    const offer = await pc.createOffer();
    await pc.setLocalDescription(offer);
    const sdpResponse = await fetch('https://api.openai.com/v1/realtime/calls', {
      method: 'POST',
      headers: {
        Authorization: `Bearer ${clientSecret}`,
        'Content-Type': 'application/sdp',
      },
      body: offer.sdp,
    });
    const answerSdp = await sdpResponse.text();
    if (!realtimeVoiceRepliesEnabled || realtimeVoiceModeEpoch !== epoch) {
      try { dc.close(); } catch {}
      try { pc.close(); } catch {}
      try { audio.srcObject = null; } catch {}
      throw new Error('Realtime voice stopped.');
    }
    if (!sdpResponse.ok) throw new Error(answerSdp || `Realtime call failed (${sdpResponse.status})`);
    await pc.setRemoteDescription({ type: 'answer', sdp: answerSdp });
    await dcOpen;
    if (!realtimeVoiceRepliesEnabled || realtimeVoiceModeEpoch !== epoch) {
      try { dc.close(); } catch {}
      try { pc.close(); } catch {}
      try { audio.srcObject = null; } catch {}
      throw new Error('Realtime voice stopped.');
    }
    realtimeVoiceConnection = { pc, dc, audio };
    pc.addEventListener('connectionstatechange', () => {
      if (realtimeVoiceModeEpoch === epoch && ['closed', 'failed', 'disconnected'].includes(pc.connectionState)) realtimeVoiceConnection = null;
    });
    return realtimeVoiceConnection;
  })().finally(() => {
    realtimeVoiceConnecting = null;
  });
  return realtimeVoiceConnecting;
}

async function speakWithRealtimeVoice(text) {
  const content = String(text || '').trim();
  if (!content) return;
  if (getRealtimeWakeGate()?.suppressVoice) return;
  realtimeVoiceSpeakChain = realtimeVoiceSpeakChain
    .catch(() => {})
    .then(() => speakWithRealtimeVoiceManaged(content));
  return realtimeVoiceSpeakChain;
}

function normalizeRealtimeNarrationKey(value) {
  return String(value || '').toLowerCase().replace(/\s+/g, ' ').trim();
}

function cleanupRealtimeNarrationRecentKeys(now = Date.now()) {
  for (const [key, at] of realtimeNarrationRecentKeys.entries()) {
    if (!at || now - at > 45000) realtimeNarrationRecentKeys.delete(key);
  }
}

function shouldSpeakRealtimeNarration(text, options = {}) {
  if (!realtimeVoiceRepliesEnabled || realtimeNarrationMode !== 'milestones') return false;
  if (getRealtimeWakeGate()?.suppressVoice) return false;
  const spoken = String(text || '').replace(/\s+/g, ' ').trim();
  if (!spoken || spoken.length < 6) return false;
  const now = Date.now();
  cleanupRealtimeNarrationRecentKeys(now);
  const key = normalizeRealtimeNarrationKey(spoken);
  if (!key || realtimeNarrationRecentKeys.has(key)) return false;
  const minGap = Math.max(0, Number(options.minGapMs ?? 3500) || 0);
  if (options.force !== true && now - realtimeNarrationLastSpokenAt < minGap) return false;
  realtimeNarrationRecentKeys.set(key, now);
  realtimeNarrationLastSpokenAt = now;
  return true;
}

function speakRealtimeNarration(text, options = {}) {
  const spoken = String(text || '').replace(/\s+/g, ' ').trim();
  if (!shouldSpeakRealtimeNarration(spoken, options)) return;
  realtimeNarrationChain = realtimeNarrationChain
    .catch(() => {})
    .then(async () => {
      if (!realtimeVoiceRepliesEnabled || realtimeNarrationMode !== 'milestones') return;
      if (realtimeVoicePlaybackActive || realtimeVoiceActiveResponseId) return;
      await speakWithRealtimeVoice(spoken);
    })
    .catch((err) => {
      try { addProcessEntry?.('warn', `Realtime narration failed: ${String(err?.message || err)}`); } catch {}
    });
}

function speakVoiceMilestone(text, options = {}) {
  const spoken = String(text || '').replace(/\s+/g, ' ').trim();
  if (!spoken) return;
  if (realtimeNarrationMode !== 'milestones') return;
  if (wantsVoiceAgentRealtimeMode()) {
    speakVoiceAgentRealtimeMilestone(spoken, options);
    return;
  }
  if (realtimeVoiceRepliesEnabled) {
    speakRealtimeNarration(spoken, options);
    return;
  }
  if (!voiceRepliesEnabled) return;
  cleanupRealtimeNarrationRecentKeys();
  const key = normalizeRealtimeNarrationKey(spoken);
  if (!key || realtimeNarrationRecentKeys.has(key)) return;
  const now = Date.now();
  const minGap = Math.max(0, Number(options.minGapMs ?? 3500) || 0);
  if (options.force !== true && now - realtimeNarrationLastSpokenAt < minGap) return;
  realtimeNarrationRecentKeys.set(key, now);
  realtimeNarrationLastSpokenAt = now;
  speakAssistantReply(spoken).catch((err) => {
    try { addProcessEntry?.('warn', `Voice milestone failed: ${String(err?.message || err)}`); } catch {}
  });
}

function isDesktopVoiceNarrationActive() {
  return realtimeNarrationMode === 'milestones' && !!(realtimeVoiceRepliesEnabled || voiceRepliesEnabled);
}

function speakVoiceAgentRealtimeMilestone(text, options = {}) {
  const spoken = cleanVoiceSpeechText(text);
  const dc = voiceAgentRealtimeConnection?.dc;
  if (!spoken || !dc || dc.readyState !== 'open') return;
  if (voiceAgentRealtimeQuiet?.active) return;
  if (voiceAgentRealtimeConnection?.activeResponse || realtimeVoicePlaybackActive || realtimeVoiceActiveResponseId) return;
  if (voiceAgentRealtimeTurn?.hadFunctionCall && options.force !== true) return;
  if (!shouldSpeakRealtimeNarration(spoken, { ...options, minGapMs: Number(options.minGapMs ?? 20000) || 20000 })) return;
  try {
    dc.send(JSON.stringify({
      type: 'conversation.item.create',
      item: {
        type: 'message',
        role: 'user',
        content: [{
          type: 'input_text',
          text: [
            '[WORKER_MILESTONE]',
            `Current worker update: ${spoken}`,
            'If this is a final completion update, give a natural spoken summary with the important outcome, files/areas touched, and any verification or caveat the user should know.',
            'For in-progress milestones, keep it brief. For final summaries, use enough detail to be genuinely useful instead of forcing a tiny recap.',
            'Do not start new work. Do not repeat the original acknowledgement.',
            '[/WORKER_MILESTONE]',
          ].join('\n'),
        }],
      },
    }));
    dc.send(JSON.stringify({
      type: 'response.create',
      response: {
        output_modalities: ['audio'],
        instructions: 'You are Prometheus in realtime voice mode. Speak a natural update grounded in the worker milestone. For final completion, include the useful details and context, usually a few clear sentences, not a tiny under-20-word recap. For routine progress, keep it brief or say nothing if it is not useful. Speak only normal words and numbers; never vocalize punctuation marks, symbols, emoji, markdown, bullets, or standalone characters.',
      },
    }));
  } catch (err) {
    try { addProcessEntry?.('warn', `Realtime milestone forward failed: ${String(err?.message || err)}`); } catch {}
  }
}

function realtimeNarrationFromToolCall(action, displayAction = '') {
  const tool = String(action || '').trim();
  const display = String(displayAction || '').replace(/\s+/g, ' ').trim();
  if (!tool) return '';
  if (tool.startsWith('browser_')) {
    if (tool === 'browser_open') return 'Opening the browser.';
    if (tool === 'browser_snapshot' || tool === 'browser_snapshot_delta') return 'Checking the page.';
    if (tool.includes('click')) return 'Clicking in the browser.';
    if (tool.includes('type')) return 'Typing in the browser.';
    return 'Working in the browser.';
  }
  if (tool.startsWith('desktop_')) {
    if (tool.includes('open')) return 'Opening it on your computer.';
    if (tool.includes('click')) return 'Clicking on your computer.';
    if (tool.includes('type')) return 'Typing on your computer.';
    return 'Controlling your computer.';
  }
  if (tool === 'run_command') return 'Running a command.';
  if (tool === 'web_search') return 'Searching the web.';
  if (tool.startsWith('creative_') || tool.startsWith('canvas')) return 'Updating the workspace.';
  if (tool.startsWith('background_')) return 'Starting a background agent.';
  if (display) return display.length > 90 ? `${display.slice(0, 87).trim()}...` : display;
  return '';
}

function realtimeNarrationFromToolResult(action, ok) {
  const tool = String(action || '').trim();
  if (!tool) return '';
  if (tool.startsWith('browser_')) return ok ? 'Browser step complete.' : 'The browser step had an issue.';
  if (tool.startsWith('desktop_')) return ok ? 'Computer control step complete.' : 'The computer control step had an issue.';
  if (tool === 'run_command') return ok ? 'Command finished.' : 'The command failed.';
  if (tool === 'web_search') return ok ? 'Search complete.' : 'Search had an issue.';
  if (tool.startsWith('background_')) return ok ? 'Background agent is moving.' : 'Background agent had an issue.';
  return ok ? '' : 'That step had an issue.';
}

function waitForRealtimeVoiceResponseSettled(timeoutMs = 700) {
  if (!realtimeVoicePlaybackActive && !realtimeVoiceActiveResponseId) return Promise.resolve();
  return new Promise((resolve) => {
    const timeout = setTimeout(() => {
      const idx = realtimeVoiceResponseWaiters.indexOf(done);
      if (idx >= 0) realtimeVoiceResponseWaiters.splice(idx, 1);
      resolve();
    }, Math.max(0, Number(timeoutMs) || 0));
    const done = () => {
      clearTimeout(timeout);
      resolve();
    };
    realtimeVoiceResponseWaiters.push(done);
  });
}

async function cancelRealtimeVoiceResponse(dc, settleMs = 220) {
  if (!dc || dc.readyState !== 'open') return;
  if (realtimeVoicePlaybackActive || realtimeVoiceActiveResponseId) {
    try { dc.send(JSON.stringify({ type: 'response.cancel' })); } catch {}
  }
  try { dc.send(JSON.stringify({ type: 'output_audio_buffer.clear' })); } catch {}
  const audio = document.getElementById('realtime-voice-audio');
  try { audio?.pause?.(); } catch {}
  await waitForRealtimeVoiceResponseSettled(settleMs);
  await new Promise((resolve) => setTimeout(resolve, 80));
  realtimeVoicePlaybackActive = false;
  realtimeVoiceActiveResponseId = '';
  finishRealtimeAssistantSpeakingEchoGuard(300);
}

async function speakWithRealtimeVoiceManaged(content) {
  const { dc } = await ensureRealtimeVoiceConnection();
  if (!realtimeVoiceRepliesEnabled) return;
  await cancelRealtimeVoiceResponse(dc);
  if (!realtimeVoiceRepliesEnabled) return;
  try {
    dc.send(JSON.stringify({
      type: 'session.update',
      session: {
        type: 'realtime',
        audio: {
          output: {
            voice: normalizeRealtimeVoice(realtimeVoiceSelection || getStoredVoiceSetting('realtime_voice', 'marin')),
            speed: normalizeRealtimeVoiceSpeed(realtimeVoiceSpeed),
          },
        },
      },
    }));
  } catch {}
  beginRealtimeAssistantSpeakingEchoGuard(content);
  const prompt = `Read this Prometheus response aloud exactly, without adding commentary:\n\n${content.slice(0, 5000)}`;
  dc.send(JSON.stringify({
    type: 'conversation.item.create',
    item: {
      type: 'message',
      role: 'user',
      content: [{ type: 'input_text', text: prompt }],
    },
  }));
  dc.send(JSON.stringify({
    type: 'response.create',
    response: {
      output_modalities: ['audio'],
      instructions: 'Speak only the supplied Prometheus response text.',
    },
  }));
  realtimeVoicePlaybackActive = true;
  const audio = realtimeVoiceConnection?.audio || document.getElementById('realtime-voice-audio');
  if (audio) {
    audio.muted = false;
    audio.volume = 1;
    audio.play?.().catch((err) => {
      console.warn('[Realtime voice] audio playback failed after response.create', err);
      if (!realtimeVoicePlaybackWarningShown) {
        realtimeVoicePlaybackWarningShown = true;
        showToast('Realtime audio blocked', 'Click the page once, then try the Realtime mic again.', 'error', 4200);
      }
    });
  }
}

// ============================================================================
// REALTIME VOICE AGENT — full audio-in / audio-out via OpenAI Realtime API.
// Replaces the split flow (transcription session + voice-agent decision + TTS
// session) with a single Realtime session whose model handles small talk,
// voice_* / skill_* tool calls, and worker dispatch through function calling. Used when
// the user has voiceMode === 'openai_realtime' end-to-end.
// ============================================================================

let voiceAgentRealtimeConnection = null;       // { pc, dc, audio, micStream, micTrack, sessionId, listenMode }
let voiceAgentRealtimeConnecting = null;
let voiceAgentRealtimeListenMode = 'idle';      // 'idle' | 'push_to_talk' | 'always_listening'
const voiceAgentRealtimeFunctionCallBuffers = new Map(); // call_id -> { name, argsStr }
let voiceAgentRealtimeLastHotRestartSummaryKey = '';

// Quiet mode for the realtime end-to-end agent. We keep OpenAI's own STT running
// (transcription stays on) but flip turn_detection.create_response OFF so the model
// stops auto-replying. Each completed user transcript is checked for the wake phrase;
// a match re-opens the agent and replies to that utterance. No second recognizer.
const voiceAgentRealtimeQuiet = { active: false, wakePhrase: '', wakeNormalized: '', pendingActivate: false };
let voiceAgentRealtimeContextRefreshTimer = null;
let voiceAgentRealtimePendingCreateResponse = null;

function isDesktopVoiceStatusQuestion(text) {
  const value = String(text || '').toLowerCase();
  return /\b(what are you doing|what're you doing|what is happening|what's happening|status|where are we|where are you|what step|what stage|what did you do|what have you done|what do you see|what are you seeing|what's on screen|what is on screen)\b/.test(value);
}

// Inject fresh worker context into the live realtime session after read-only status
// calls so later status/progress questions stay grounded without steering Worker.
function sendVoiceAgentRealtimeContextUpdate(contextPacket, options = {}) {
  const dc = voiceAgentRealtimeConnection?.dc;
  if (!dc || dc.readyState !== 'open') return false;
  const packet = contextPacket && typeof contextPacket === 'object' ? contextPacket : null;
  if (!packet) return false;
  const summary = String(packet.summary || '').trim();
  const lines = [
    '## Live Worker context update',
    `Reason: ${String(options.reason || 'worker context refreshed')}`,
    `Active Worker: ${packet.active === true ? 'yes' : 'no'}`,
    summary ? `Summary: ${summary.slice(0, 1600)}` : '',
    packet.trigger?.detail ? `Triggered by: ${String(packet.trigger.detail).slice(0, 700)}` : '',
    packet.currentlyDoing ? `Currently doing: ${String(packet.currentlyDoing).slice(0, 300)}` : '',
    packet.currentGoal ? `Current goal: ${String(packet.currentGoal).slice(0, 600)}` : '',
    packet.currentPhase ? `Current phase: ${String(packet.currentPhase).slice(0, 200)}` : '',
    packet.activeToolLabel || packet.activeToolName ? `Active tool: ${String(packet.activeToolLabel || packet.activeToolName).slice(0, 200)}` : '',
    Array.isArray(packet.processEntries) && packet.processEntries.length
      ? `Recent process entries: ${packet.processEntries.slice(-5).map(entry => String(entry?.message || entry?.text || entry?.stage || '').trim()).filter(Boolean).join(' | ').slice(0, 1000)}`
      : '',
    Array.isArray(packet.doneAlready) && packet.doneAlready.length
      ? `Done already: ${packet.doneAlready.slice(-6).map(entry => String(entry || '').trim()).filter(Boolean).join(' | ').slice(0, 1000)}`
      : '',
    Array.isArray(packet.recentEvents) && packet.recentEvents.length
      ? `Recent stream events: ${packet.recentEvents.slice(-5).map(entry => String(entry?.message || entry?.text || entry?.stage || '').trim()).filter(Boolean).join(' | ').slice(0, 1000)}`
      : '',
    `Packet id: ${packet.id || packet.contextPacketId || ''}`,
    'Use this update for status/progress questions. Do not steer the Worker unless the user clearly gives a correction, cancellation, or direction change.',
  ].filter(Boolean).join('\n');
  try {
    dc.send(JSON.stringify({
      type: 'conversation.item.create',
      item: {
        type: 'message',
        role: 'system',
        content: [{ type: 'input_text', text: lines }],
      },
    }));
    return true;
  } catch (err) {
    console.warn('[voice-agent-realtime] context update failed', err);
    return false;
  }
}

function clearVoiceAgentRealtimePendingCreateResponse() {
  if (voiceAgentRealtimePendingCreateResponse?.timer) {
    clearTimeout(voiceAgentRealtimePendingCreateResponse.timer);
  }
  voiceAgentRealtimePendingCreateResponse = null;
}

function sendVoiceAgentRealtimeResponseCreate(reason = 'manual') {
  const dc = voiceAgentRealtimeConnection?.dc;
  if (!dc || dc.readyState !== 'open') return false;
  try {
    dc.send(JSON.stringify({ type: 'response.create' }));
    if (window.__voiceAgentRealtimeDebug) console.debug('[voice-agent-realtime] response.create', reason);
    return true;
  } catch (err) {
    if (window.__voiceAgentRealtimeDebug) console.warn('[voice-agent-realtime] response.create failed', err);
    return false;
  }
}

function scheduleVoiceAgentRealtimeResponseAfterSkillContext(reason = 'ptt_release') {
  clearVoiceAgentRealtimePendingCreateResponse();
  const createdAt = Date.now();
  const pending = { createdAt, reason, timer: null };
  pending.timer = setTimeout(() => {
    if (voiceAgentRealtimePendingCreateResponse !== pending) return;
    voiceAgentRealtimePendingCreateResponse = null;
    sendVoiceAgentRealtimeResponseCreate(`${reason}_skill_context_timeout`);
  }, 500);
  voiceAgentRealtimePendingCreateResponse = pending;
}

function finishVoiceAgentRealtimePendingResponse(reason = 'skill_context_ready') {
  if (!voiceAgentRealtimePendingCreateResponse) return false;
  clearVoiceAgentRealtimePendingCreateResponse();
  return sendVoiceAgentRealtimeResponseCreate(reason);
}

function normalizeVoiceAgentRealtimeContextKey(text) {
  return String(text || '')
    .toLowerCase()
    .replace(/[^\p{L}\p{N}]+/gu, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function sanitizeVoiceAgentRealtimeSkillContext(rawContext) {
  const context = String(rawContext || '').trim();
  if (!context) return '';
  const body = context
    .split(/\r?\n/)
    .filter((line) => !/^Latest spoken request\s*:/i.test(String(line || '').trim()))
    .join('\n')
    .replace(/^##\s*Realtime Skill Trigger Update\s*/i, '')
    .trim();
  if (!body) return '';
  return [
    '## Realtime Skill Trigger Update',
    'Metadata for the current audio turn only. The user did not send a second message. Do not mention duplicate input because of this update.',
    body,
  ].join('\n');
}

function pruneVoiceAgentRealtimeRecentList(list, maxAgeMs) {
  const now = Date.now();
  for (let i = list.length - 1; i >= 0; i -= 1) {
    if (now - Number(list[i]?.at || 0) > maxAgeMs) list.splice(i, 1);
  }
  return list;
}

const voiceAgentRealtimeRecentSkillContextKeys = [];

function shouldInjectVoiceAgentRealtimeSkillContext(sessionId, transcript) {
  const textKey = normalizeVoiceAgentRealtimeContextKey(transcript);
  if (!textKey) return false;
  pruneVoiceAgentRealtimeRecentList(voiceAgentRealtimeRecentSkillContextKeys, 4500);
  const key = `${sessionId || ''}:${textKey}`;
  if (voiceAgentRealtimeRecentSkillContextKeys.some((entry) => entry.key === key)) {
    if (window.__voiceAgentRealtimeDebug) console.debug('[voice-agent-realtime] duplicate skill context ignored', { sessionId, textLen: String(transcript || '').length });
    return false;
  }
  voiceAgentRealtimeRecentSkillContextKeys.push({ key, at: Date.now() });
  while (voiceAgentRealtimeRecentSkillContextKeys.length > 24) voiceAgentRealtimeRecentSkillContextKeys.shift();
  return true;
}

async function injectVoiceAgentRealtimeSkillContext(sessionId, transcript, options = {}) {
  const dc = voiceAgentRealtimeConnection?.dc;
  const text = String(transcript || '').trim();
  if (!dc || dc.readyState !== 'open' || !text) return false;
  if (!shouldInjectVoiceAgentRealtimeSkillContext(sessionId, text)) return false;
  try {
    const response = await fetch('/api/voice-agent/realtime-skill-context', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        sessionId,
        transcript: text,
        maxChars: options.maxChars || 4200,
      }),
    });
    const data = await response.json().catch(() => ({}));
    const context = sanitizeVoiceAgentRealtimeSkillContext(data?.context);
    if (!response.ok || !data?.success || !data?.matched || !context) return false;
    dc.send(JSON.stringify({
      type: 'conversation.item.create',
      item: {
        type: 'message',
        role: 'system',
        content: [{ type: 'input_text', text: context }],
      },
    }));
    addSessionProcessEntry(sessionId, 'skill', `Realtime skill trigger matched: ${(data.skills || []).map(s => s.id).filter(Boolean).join(', ')}`, {
      actor: 'Voice Agent (Realtime)',
      skills: data.skills || [],
    });
    return true;
  } catch (err) {
    if (window.__voiceAgentRealtimeDebug) console.warn('[voice-agent-realtime] skill context injection failed', err);
    return false;
  }
}

function requestVoiceAgentRealtimeWorkerNarration(reason = 'worker_context_tick') {
  const dc = voiceAgentRealtimeConnection?.dc;
  if (!dc || dc.readyState !== 'open') return false;
  if (voiceAgentRealtimeQuiet?.active) return false;
  if (realtimeNarrationMode !== 'milestones') return false;
  if (voiceAgentRealtimeConnection?.activeResponse || realtimeVoicePlaybackActive || realtimeVoiceActiveResponseId) return false;
  const now = Date.now();
  const minGap = 20000;
  if (now - Number(voiceAgentRealtimeConnection?.lastNarrationRequestAt || 0) < minGap) return false;
  if (now - Number(voiceAgentRealtimeConnection?.lastResponseEndedAt || 0) < 8000) return false;
  voiceAgentRealtimeConnection.lastNarrationRequestAt = now;
  voiceAgentRealtimeConnection.narrationPending = true;
  try {
    dc.send(JSON.stringify({
      type: 'response.create',
      response: {
        output_modalities: ['audio'],
        instructions: [
          'You are Prometheus in realtime voice mode.',
          'Review the freshest Live Worker context update already in this conversation.',
          'If the user benefits from a short progress update, speak one natural sentence grounded in that worker context.',
          'If the update is minor, duplicate, uncertain, or not useful, produce no spoken update.',
          'Speak only normal words and numbers. Never vocalize punctuation marks, symbols, emoji, markdown, bullets, dashes, or standalone characters.',
          'Do not steer, dispatch, or interrupt the Worker from this narration tick.',
          `Narration tick reason: ${String(reason || 'worker_context_tick')}`,
        ].join('\n'),
      },
    }));
    return true;
  } catch (err) {
    try { addProcessEntry?.('warn', `Realtime narration request failed: ${String(err?.message || err)}`); } catch {}
    return false;
  }
}

function requestVoiceAgentRealtimeFinalSummary(text, options = {}) {
  const content = String(text || '').replace(/\s+/g, ' ').trim();
  const dc = voiceAgentRealtimeConnection?.dc;
  if (!content || !dc || dc.readyState !== 'open') return false;
  if (voiceAgentRealtimeQuiet?.active) return false;
  const sid = String(options.sessionId || window.activeChatSessionId || '').trim();
  const connSid = String(voiceAgentRealtimeConnection?.sessionId || '').trim();
  if (sid && connSid && sid !== connSid) return false;
  if (voiceAgentRealtimeConnection?.activeResponse || realtimeVoicePlaybackActive || realtimeVoiceActiveResponseId) return false;
  try {
    dc.send(JSON.stringify({
      type: 'conversation.item.create',
      item: {
        type: 'message',
        role: 'user',
        content: [{
          type: 'input_text',
          text: [
            '[WORKER_FINAL_RESPONSE]',
            'The Prometheus worker has finished. Give the user one natural spoken wrap-up in your own realtime voice.',
            'Do not read this verbatim. Do not repeat the full worker answer. Do not preserve the worker wording or sentence order.',
            'Summarize the result, outcome, or next useful thing conversationally. Quote only tiny names, paths, or labels when needed.',
            'Keep it concise unless the result genuinely needs detail.',
            '',
            content.slice(0, 5000),
            '[/WORKER_FINAL_RESPONSE]',
          ].join('\n'),
        }],
      },
    }));
    dc.send(JSON.stringify({
      type: 'response.create',
      response: {
        output_modalities: ['audio'],
        instructions: 'You are Prometheus in realtime voice mode. Speak a natural, concise wrap-up grounded in the worker final response. Use your own words; do not read whole worker sentences unchanged or preserve its structure. Do not start new work.',
      },
    }));
    return true;
  } catch (err) {
    try { addProcessEntry?.('warn', `Realtime final summary request failed: ${String(err?.message || err)}`); } catch {}
    return false;
  }
}

function requestVoiceAgentRealtimeFinalSummaryWithRetry(text, options = {}) {
  const content = String(text || '').trim();
  const key = String(options.key || `${String(options.sessionId || '')}:${content.length}:${content.slice(0, 120)}`);
  if (!content || key === voiceAgentRealtimeLastHotRestartSummaryKey) return false;
  const markIfSpoken = () => {
    if (key === voiceAgentRealtimeLastHotRestartSummaryKey) return true;
    const spoke = requestVoiceAgentRealtimeFinalSummary(content, options);
    if (spoke) voiceAgentRealtimeLastHotRestartSummaryKey = key;
    return spoke;
  };
  if (markIfSpoken()) return true;
  if (voiceAgentRealtimeConnection?.dc?.readyState !== 'open' || voiceAgentRealtimeQuiet?.active) return false;
  [900, 2400].forEach((delay) => {
    setTimeout(() => {
      try { markIfSpoken(); } catch {}
    }, delay);
  });
  return false;
}

async function refreshVoiceAgentRealtimeWorkerContext(reason = 'manual_refresh', options = {}) {
  const sid = String(voiceAgentRealtimeConnection?.sessionId || window.activeChatSessionId || '').trim();
  if (!sid || !voiceAgentRealtimeConnection?.dc || voiceAgentRealtimeConnection.dc.readyState !== 'open') return null;
  try {
    const response = await fetch('/api/voice-agent/context', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ sessionId: sid, source: `desktop_realtime_${reason}` }),
    });
    const data = await response.json().catch(() => ({}));
    const packet = overlayPendingVoiceAgentRealtimeWorkerPacket(data?.contextPacket || null, sid, reason);
    if (packet) {
      sendVoiceAgentRealtimeContextUpdate(packet, { reason });
      if (options.requestNarration === true && packet.active === true) requestVoiceAgentRealtimeWorkerNarration(reason);
    }
    return packet;
  } catch (err) {
    if (window.__voiceAgentRealtimeDebug) console.warn('[voice-agent-realtime] context refresh failed', err);
    return null;
  }
}

function startVoiceAgentRealtimeContextRefreshLoop(conn) {
  if (voiceAgentRealtimeContextRefreshTimer) clearInterval(voiceAgentRealtimeContextRefreshTimer);
  const run = () => {
    if (!voiceAgentRealtimeConnection || voiceAgentRealtimeConnection !== conn) return;
    refreshVoiceAgentRealtimeWorkerContext('periodic_worker_context', { requestNarration: true }).catch(() => {});
  };
  voiceAgentRealtimeContextRefreshTimer = setInterval(run, 5600);
  setTimeout(run, 1500);
}

// Per-response tracking for explicit realtime worker handoffs. The old
// transcript-claim recovery is intentionally disabled: realtime must call
// dispatch_prometheus_worker explicitly, not auto-start Worker from spoken text.
const voiceAgentRealtimeTurn = {
  hadFunctionCall: false,
  dispatchedWorkerThisResponse: false,
  lastUserTranscript: '',
  lastAssistantTranscript: '',
  nudged: false,
  pendingWorkerDispatch: null,
  recentTranscriptEvents: [],
};
const REALTIME_HANDOFF_RECOVERY_ENABLED = false;
const REALTIME_HANDOFF_CLAIM_RE = /\b(hand(?:ing|ed)?\s*(?:it|that|this)?\s*off|to the worker|kick(?:ing)?\s*(?:it|that)?\s*off|i('?ve|\s*have)?\s*started|getting started|i'?ll\s*(?:start|get|run|handle|take care)|on it|working on (?:it|that)|in progress|started (?:it|that|the|on)|spun? up|firing up)\b/i;

function normalizeRealtimeAgentMatchText(value) {
  return String(value || '').toLowerCase().replace(/[^a-z0-9]+/g, ' ').replace(/\s+/g, ' ').trim();
}

function getPendingVoiceAgentRealtimeWorkerDispatch(sessionId) {
  const pending = voiceAgentRealtimeTurn.pendingWorkerDispatch;
  const sid = String(sessionId || window.activeChatSessionId || '').trim();
  if (!pending || pending.sessionId !== sid) return null;
  if (Date.now() - Number(pending.startedAt || 0) > 30000) {
    voiceAgentRealtimeTurn.pendingWorkerDispatch = null;
    return null;
  }
  return pending;
}

function makePendingVoiceAgentRealtimeWorkerPacket(sessionId, reason = 'worker_dispatch_pending') {
  const pending = getPendingVoiceAgentRealtimeWorkerDispatch(sessionId);
  if (!pending) return null;
  const id = pending.contextPacketId || `realtime_pending_worker_${pending.startedAt}`;
  return {
    id,
    contextPacketId: id,
    active: true,
    summary: `The Prometheus worker has just been dispatched and is starting up: ${pending.task}`,
    currentGoal: pending.task,
    currentPhase: 'starting',
    activeToolName: 'dispatch_prometheus_worker',
    activeToolLabel: 'Worker dispatch is starting',
    pendingSteerCount: 0,
    activeRun: null,
    trigger: {
      source: 'realtime_agent_dispatch',
      detail: pending.task,
      startedAt: pending.startedAt,
    },
    currentlyDoing: 'Starting the Prometheus worker for the realtime voice handoff.',
    doneAlready: ['Realtime voice agent sent the task to the Prometheus worker.'],
    observations: [`Pending worker context synthesized locally because the live worker registry has not caught up yet. Reason: ${reason}.`],
    processEntries: [],
    recentEvents: [],
  };
}

function overlayPendingVoiceAgentRealtimeWorkerPacket(packet, sessionId, reason = 'worker_context') {
  if (packet?.active === true) {
    voiceAgentRealtimeTurn.pendingWorkerDispatch = null;
    return packet;
  }
  return makePendingVoiceAgentRealtimeWorkerPacket(sessionId, reason) || packet;
}

function shouldIgnoreVoiceAgentRealtimeTranscriptEvent(sessionId, event, transcript) {
  const textKey = normalizeVoiceAgentRealtimeContextKey(transcript);
  if (!textKey) return true;
  const itemId = String(event?.item_id || event?.item?.id || '').trim();
  const list = pruneVoiceAgentRealtimeRecentList(voiceAgentRealtimeTurn.recentTranscriptEvents, 4500);
  const itemKey = itemId ? `${sessionId || ''}:${itemId}` : '';
  const duplicate = list.some((entry) => (
    (itemKey && entry.itemKey === itemKey)
    || (entry.textKey === textKey && Date.now() - Number(entry.at || 0) < 4500)
  ));
  if (duplicate) {
    if (window.__voiceAgentRealtimeDebug) console.debug('[voice-agent-realtime] duplicate transcript event ignored', { sessionId, itemId, textLen: String(transcript || '').length });
    return true;
  }
  list.push({ itemKey, textKey, at: Date.now() });
  while (list.length > 24) list.shift();
  return false;
}

function markVoiceAgentRealtimeWorkerDispatch(sessionId, task) {
  const sid = String(sessionId || window.activeChatSessionId || '').trim();
  const cleanTask = String(task || '').trim();
  if (!sid || !cleanTask) return null;
  voiceAgentRealtimeTurn.pendingWorkerDispatch = {
    sessionId: sid,
    task: cleanTask,
    startedAt: Date.now(),
    contextPacketId: `realtime_pending_worker_${Date.now()}`,
  };
  const packet = makePendingVoiceAgentRealtimeWorkerPacket(sid, 'worker_dispatch');
  if (packet) sendVoiceAgentRealtimeContextUpdate(packet, { reason: 'worker_dispatch_pending' });
  return packet;
}

function removeRecentRealtimeAgentChatMessage(sessionId, role, text) {
  const sid = String(sessionId || window.activeChatSessionId || '').trim();
  const target = normalizeRealtimeAgentMatchText(text);
  if (!sid || !target) return false;
  const sess = getChatSessionById(sid);
  const history = sess?.history;
  if (!Array.isArray(history)) return false;
  const wantedRole = role === 'user' ? 'user' : 'ai';
  const now = Date.now();
  for (let i = history.length - 1; i >= Math.max(0, history.length - 12); i -= 1) {
    const msg = history[i];
    if (!msg || msg.role !== wantedRole || msg.source !== 'voice_agent_realtime') continue;
    if (now - Number(msg.timestamp || now) > 120000) continue;
    const candidate = normalizeRealtimeAgentMatchText(msg.content || msg.text || '');
    if (candidate && (candidate === target || candidate.includes(target) || target.includes(candidate))) {
      history.splice(i, 1);
      try { persistSession(sid); } catch {}
      if (window.activeChatSessionId === sid) {
        window.chatHistory = history;
        try { renderChatMessages(); } catch {}
      }
      return true;
    }
  }
  return false;
}

function cancelVoiceAgentRealtimeResponseForDispatch() {
  const dc = voiceAgentRealtimeConnection?.dc;
  if (dc && dc.readyState === 'open') {
    try { dc.send(JSON.stringify({ type: 'response.cancel' })); } catch {}
    try { dc.send(JSON.stringify({ type: 'output_audio_buffer.clear' })); } catch {}
  }
  if (voiceAgentRealtimeConnection) {
    voiceAgentRealtimeConnection.activeResponse = false;
    voiceAgentRealtimeConnection.narrationPending = false;
    voiceAgentRealtimeConnection.lastResponseEndedAt = Date.now();
  }
  realtimeVoicePlaybackActive = false;
  realtimeVoiceActiveResponseId = '';
}

function sendRealtimeAgentCreateResponseFlag(enabled) {
  const dc = voiceAgentRealtimeConnection?.dc;
  if (!dc || dc.readyState !== 'open') return;
  const listenMode = voiceAgentRealtimeConnection?.listenMode || voiceAgentRealtimeListenMode;
  // Quiet mode (create_response gating) only applies to always-listening server VAD.
  // In push-to-talk there is no turn_detection, so don't reinstate server VAD here.
  if (listenMode !== 'always_listening') return;
  const turnDetection = {
    type: 'server_vad',
    threshold: 0.5,
    prefix_padding_ms: 300,
    silence_duration_ms: 500,
    create_response: !!enabled,
  };
  try {
    if (voiceAgentRealtimeConnection?.provider === 'xai') {
      dc.send(JSON.stringify({
        type: 'session.update',
        session: { turn_detection: turnDetection },
      }));
    } else {
      dc.send(JSON.stringify({
        type: 'session.update',
        session: {
          type: 'realtime',
          audio: {
            input: {
              turn_detection: turnDetection,
              transcription: { model: 'gpt-realtime-whisper' },
            },
          },
        },
      }));
    }
  } catch {}
}

function setRealtimeAgentWakePhrase(phrase) {
  const clean = String(phrase || '').replace(/\s+/g, ' ').trim();
  voiceAgentRealtimeQuiet.wakePhrase = clean;
  voiceAgentRealtimeQuiet.wakeNormalized = normalizeRealtimeWakePhrase(clean);
  realtimeSessionWakePhrase = clean;
}

function activateRealtimeAgentQuietMode() {
  if (!voiceAgentRealtimeConnection) return;
  voiceAgentRealtimeQuiet.active = true;
  voiceAgentRealtimeQuiet.pendingActivate = false;
  if (voiceAgentRealtimeQuiet.wakePhrase) {
    realtimeWakeGate = buildRealtimeWakeGateFromPhrase(voiceAgentRealtimeQuiet.wakePhrase, 'realtime_agent_quiet_mode');
  }
  stopRealtimeVoicePlayback({ recordInterrupt: true, reason: 'realtime_agent_quiet_mode' });
  sendRealtimeAgentCreateResponseFlag(false);
  const phrase = voiceAgentRealtimeQuiet.wakePhrase;
  showToast('Quiet mode', phrase ? `Silent until you say "${phrase}".` : 'Silent until you wake Prometheus.', 'info', 2600);
  setUnifiedVoiceButtonState();
  renderRealtimeWakeGateState();
}

function deactivateRealtimeAgentQuietMode() {
  if (!voiceAgentRealtimeQuiet.active) return;
  voiceAgentRealtimeQuiet.active = false;
  voiceAgentRealtimeQuiet.pendingActivate = false;
  clearRealtimeWakeGate({ silent: true, clearInput: true });
  sendRealtimeAgentCreateResponseFlag(true);
  setUnifiedVoiceButtonState();
  renderRealtimeWakeGateState();
}

function handleRealtimeAgentQuietTranscript(transcript) {
  if (!voiceAgentRealtimeQuiet.active) return false;
  const wake = voiceAgentRealtimeQuiet.wakeNormalized;
  if (!wake) return true;
  const heard = normalizeRealtimeWakePhrase(transcript);
  if (!heard || !heard.includes(wake)) {
    sendRealtimeAgentCreateResponseFlag(false);
    cancelVoiceAgentRealtimeResponseForDispatch();
    return true; // not woken — stay silent and suppress transcript display
  }
  deactivateRealtimeAgentQuietMode();
  showToast('Awake', 'Prometheus is listening again.', 'success', 1800);
  // Reply to the wake utterance now that create_response is back on.
  const dc = voiceAgentRealtimeConnection?.dc;
  if (dc?.readyState === 'open') {
    try { dc.send(JSON.stringify({ type: 'response.create' })); } catch {}
  }
  return false;
}

function isVoiceAgentRealtimeMode() {
  if (!realtimeVoiceRepliesEnabled) return false;
  // openai_realtime (WebRTC) or xai (WebSocket) qualify as full realtime agent,
  // each gated by its own per-provider realtime opt-in checkbox.
  const mode = normalizeDesktopVoiceMode(desktopVoiceSettings.voiceMode);
  if (mode === 'openai_realtime') return desktopVoiceSettings.voiceAgentRealtimeAgent !== false;
  if (mode === 'xai') return desktopVoiceSettings.voiceAgentXaiRealtime === true;
  return false;
}

async function startVoiceAgentRealtimeSession(sessionId, options = {}) {
  // Provider dispatch: xAI uses a native WebSocket transport, OpenAI uses WebRTC.
  if (wantsXaiRealtimeMode()) return startXaiRealtimeSession(sessionId, options);
  if (voiceAgentRealtimeConnection?.dc?.readyState === 'open') return voiceAgentRealtimeConnection;
  if (voiceAgentRealtimeConnecting) return voiceAgentRealtimeConnecting;
  const sid = String(sessionId || window.activeChatSessionId || 'default').trim() || 'default';
  const listenMode = String(options.listenMode || 'push_to_talk').trim();
  voiceAgentRealtimeListenMode = listenMode;

  voiceAgentRealtimeConnecting = (async () => {
    const startedAt = Date.now();
    addSessionProcessEntry(sid, 'info', 'Voice Agent (Realtime): bootstrapping session.', { actor: 'Voice Agent (Realtime)' });

    // 1. Bootstrap — gateway builds instructions, tools, and mints ephemeral token
    const wakeGate = getRealtimeWakeGate?.();
    voiceAgentRealtimeQuiet.active = !!(wakeGate?.active && wakeGate?.suppressVoice === true);
    voiceAgentRealtimeQuiet.pendingActivate = false;
    setRealtimeAgentWakePhrase(wakeGate?.phrase || '');
    const bootstrapResp = await fetch('/api/voice-agent/realtime-bootstrap', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        sessionId: sid,
        voice: normalizeRealtimeVoice(realtimeVoiceSelection || getStoredVoiceSetting('realtime_voice', 'marin')),
        speed: getCurrentRealtimeVoiceSpeed(),
        voiceRuntime: wakeGate?.phrase
          ? { wakePhrase: wakeGate.phrase, wakeGateActive: wakeGate?.suppressVoice === true }
          : undefined,
        deviceTime: desktopVoiceDeviceTimeContext(),
      }),
    });
    const bootstrap = await bootstrapResp.json().catch(() => ({}));
    if (!bootstrapResp.ok || !bootstrap?.success) {
      throw new Error(bootstrap?.error || `Voice agent realtime bootstrap failed (${bootstrapResp.status})`);
    }
    logDesktopVoiceLatency?.(sid, 'realtime-agent bootstrap', startedAt);

    // 2. Establish WebRTC: mic in (sendrecv) + audio out
    const pc = new RTCPeerConnection();
    let audio = document.getElementById('voice-agent-realtime-audio');
    if (!audio) {
      audio = document.createElement('audio');
      audio.id = 'voice-agent-realtime-audio';
      audio.autoplay = true;
      audio.playsInline = true;
      audio.style.display = 'none';
      document.body.appendChild(audio);
    }
    audio.muted = false;
    audio.volume = 1;
    pc.ontrack = (event) => {
      audio.srcObject = event.streams[0];
      audio.play?.().catch((err) => {
        console.warn('[voice-agent-realtime] audio playback blocked', err);
      });
    };

    const micStream = await navigator.mediaDevices.getUserMedia({ audio: { echoCancellation: true, noiseSuppression: true, autoGainControl: true } });
    const micTrack = micStream.getAudioTracks()[0];
    micTrack.enabled = listenMode === 'always_listening';
    pc.addTrack(micTrack, micStream);
    // Explicit recvonly audio transceiver so OpenAI knows we want audio back.
    try { pc.addTransceiver('audio', { direction: 'recvonly' }); } catch {}

    const dc = pc.createDataChannel('oai-events');
    dc.addEventListener('message', (msgEvent) => {
      let event = null;
      try { event = JSON.parse(msgEvent.data); } catch { return; }
      handleVoiceAgentRealtimeEvent(event, sid).catch(() => {});
    });

    const dcOpen = new Promise((resolve, reject) => {
      const timeout = setTimeout(() => reject(new Error('Voice agent realtime data channel did not open.')), 12000);
      dc.addEventListener('open', () => { clearTimeout(timeout); resolve(true); }, { once: true });
      dc.addEventListener('error', () => { clearTimeout(timeout); reject(new Error('Voice agent realtime data channel failed.')); }, { once: true });
    });

    const offer = await pc.createOffer();
    await pc.setLocalDescription(offer);
    const sdpResp = await fetch('https://api.openai.com/v1/realtime/calls', {
      method: 'POST',
      headers: {
        Authorization: `Bearer ${bootstrap.clientSecret}`,
        'Content-Type': 'application/sdp',
      },
      body: offer.sdp,
    });
    const answerSdp = await sdpResp.text();
    if (!sdpResp.ok) throw new Error(answerSdp || `Realtime call failed (${sdpResp.status})`);
    await pc.setRemoteDescription({ type: 'answer', sdp: answerSdp });
    await dcOpen;
    if (window.__voiceAgentRealtimeDebug) {
      console.debug('[voice-agent-realtime] data channel open; bootstrap', {
        model: bootstrap.model, voice: bootstrap.voice, toolCount: bootstrap.toolCount, listenMode,
      });
    }

    // 3. Configure turn detection per listen mode (gpt-realtime format — under audio.input)
    //    always_listening -> server VAD auto-commits + auto-replies.
    //    push_to_talk     -> turn_detection disabled; audio only flows while the
    //                        mic track is enabled (button held), and we manually
    //                        commit + create_response on release. This stops the
    //                        session from "staying on" / auto-replying when PTT is on.
    try {
      const sessionUpdate = {
        type: 'session.update',
        session: {
          type: 'realtime',
          audio: {
            output: {
              voice: normalizeRealtimeVoice(realtimeVoiceSelection || getStoredVoiceSetting('realtime_voice', 'marin')),
              speed: getCurrentRealtimeVoiceSpeed(),
            },
            input: {
              turn_detection: listenMode === 'always_listening'
                ? {
                    type: 'server_vad',
                    threshold: 0.5,
                    prefix_padding_ms: 300,
                    silence_duration_ms: 500,
                    create_response: !voiceAgentRealtimeQuiet.active,
                  }
                : null,
              transcription: { model: 'gpt-realtime-whisper' },
            },
          },
        },
      };
      dc.send(JSON.stringify(sessionUpdate));
      if (window.__voiceAgentRealtimeDebug) console.debug('[voice-agent-realtime] sent session.update', sessionUpdate.session.audio);
    } catch (err) {
      if (window.__voiceAgentRealtimeDebug) console.warn('[voice-agent-realtime] session.update failed', err);
    }

    // Seed the live session with the chat thread the user just had on screen so
    // the voice agent continues the conversation instead of starting fresh.
    seedVoiceAgentRealtimeConversationHistory(dc, sid);

    voiceAgentRealtimeConnection = { pc, dc, audio, micStream, micTrack, sessionId: sid, listenMode };
    if (voiceAgentRealtimeQuiet.active) sendRealtimeAgentCreateResponseFlag(false);
    startVoiceAgentRealtimeContextRefreshLoop(voiceAgentRealtimeConnection);
    pc.addEventListener('connectionstatechange', () => {
      if (['closed', 'failed', 'disconnected'].includes(pc.connectionState)) {
        if (voiceAgentRealtimeConnection?.pc === pc) {
          voiceAgentRealtimeConnection = null;
        }
      }
    });
    logDesktopVoiceLatency?.(sid, 'realtime-agent ready', startedAt);
    addSessionProcessEntry(sid, 'info', `Voice Agent (Realtime): connected (${listenMode}).`, { actor: 'Voice Agent (Realtime)' });
    return voiceAgentRealtimeConnection;
  })().finally(() => {
    voiceAgentRealtimeConnecting = null;
  });
  return voiceAgentRealtimeConnecting;
}

function stopVoiceAgentRealtimeSession() {
  const conn = voiceAgentRealtimeConnection;
  voiceAgentRealtimeConnection = null;
  voiceAgentRealtimeConnecting = null;
  voiceAgentRealtimeListenMode = 'idle';
  voiceAgentRealtimeFunctionCallBuffers.clear();
  clearVoiceAgentRealtimePendingCreateResponse();
  if (voiceAgentRealtimeContextRefreshTimer) {
    clearInterval(voiceAgentRealtimeContextRefreshTimer);
    voiceAgentRealtimeContextRefreshTimer = null;
  }
  try { conn?.cleanup?.(); } catch {}
  try { conn?.dc?.close(); } catch {}
  try { conn?.pc?.close(); } catch {}
  try { if (conn?.audio) conn.audio.srcObject = null; } catch {}
  try { conn?.micStream?.getTracks().forEach((t) => t.stop()); } catch {}
}

function setVoiceAgentRealtimeMicEnabled(enabled) {
  const track = voiceAgentRealtimeConnection?.micTrack;
  if (!track) return;
  track.enabled = !!enabled;
}

// Seed the live realtime session with the recent chat thread so the voice agent
// picks up the conversation the user just had on screen instead of starting cold.
// Injected as a single system context item (mirrors the skill-context injection)
// right after the data channel opens — robust against instruction clamping and
// not dependent on a server restart.
function seedVoiceAgentRealtimeConversationHistory(dc, sessionId) {
  try {
    if (!dc || dc.readyState !== 'open') return false;
    const sid = String(sessionId || window.activeChatSessionId || '').trim();
    if (!sid) return false;
    const sess = getChatSessionById(sid);
    const history = Array.isArray(sess?.history) ? sess.history : [];
    const turns = history
      .filter((msg) => {
        const role = String(msg?.role || '');
        if (role !== 'user' && role !== 'ai' && role !== 'assistant') return false;
        const text = cleanVoiceSpeechText(typeof msg?.content === 'string' ? msg.content : (msg?.content?.text || ''));
        return !!text;
      })
      .slice(-12)
      .map((msg) => {
        const speaker = String(msg?.role || '') === 'user' ? 'User' : 'Prometheus';
        const text = cleanVoiceSpeechText(typeof msg?.content === 'string' ? msg.content : (msg?.content?.text || '')).slice(0, 600);
        return text ? `${speaker}: ${text}` : '';
      })
      .filter(Boolean);
    if (!turns.length) return false;
    const block = [
      'You are joining an in-progress chat the user just had on screen. Continue from here — do not reintroduce yourself, do not ask what they need from scratch, and reference what was already said. Recent conversation:',
      '',
      turns.join('\n'),
    ].join('\n');
    dc.send(JSON.stringify({
      type: 'conversation.item.create',
      item: {
        type: 'message',
        role: 'system',
        content: [{ type: 'input_text', text: block }],
      },
    }));
    if (window.__voiceAgentRealtimeDebug) console.debug('[voice-agent-realtime] seeded conversation history', { sessionId: sid, turns: turns.length });
    return true;
  } catch (err) {
    if (window.__voiceAgentRealtimeDebug) console.warn('[voice-agent-realtime] seed conversation history failed', err);
    return false;
  }
}

// Push a realtime-agent turn into the visible desktop chat thread so the user
// sees their own spoken messages and Prom's replies in the main chat — not just
// the process log. Display-only: the realtime session itself owns the audio.
function appendRealtimeAgentChatMessage(sessionId, role, text) {
  const sid = String(sessionId || window.activeChatSessionId || '').trim();
  const content = cleanVoiceSpeechText(text);
  if (!sid || !content) return;
  const sess = getChatSessionById(sid);
  if (!sess) return;
  if (!Array.isArray(sess.history)) sess.history = [];
  const pendingEntries = role === 'user' ? [] : takePendingVoiceAgentProcessEntries(sid);
  const message = {
    role: role === 'user' ? 'user' : 'ai',
    content,
    timestamp: Date.now(),
    source: 'voice_agent_realtime',
    channel: 'voice',
    channelLabel: 'Realtime voice',
    processEntries: pendingEntries.length ? pendingEntries : undefined,
  };
  if (pendingEntries.length) {
    message.workStartedAt = message.timestamp;
    message.workEndedAt = message.timestamp;
    message.workDurationMs = 0;
  }
  sess.history.push(message);
  try { persistSession(sid); } catch {}
  if (window.activeChatSessionId === sid) {
    window.chatHistory = sess.history;
    try { renderChatMessages(); } catch {}
  }
}

// Disabled deterministic recovery: realtime must emit dispatch_prometheus_worker.
// Do not infer a Worker handoff from assistant transcript text.
function maybeRecoverHallucinatedRealtimeHandoff(sessionId) {
  if (!REALTIME_HANDOFF_RECOVERY_ENABLED) return;
  if (voiceAgentRealtimeTurn.hadFunctionCall || voiceAgentRealtimeTurn.nudged) return;
  const claim = voiceAgentRealtimeTurn.lastAssistantTranscript || '';
  const task = String(voiceAgentRealtimeTurn.lastUserTranscript || '').trim();
  if (!task || !REALTIME_HANDOFF_CLAIM_RE.test(claim)) return;
  voiceAgentRealtimeTurn.nudged = true;
  addSessionProcessEntry(sessionId, 'warn', `Realtime model claimed a hand-off without calling dispatch_prometheus_worker — auto-dispatching: ${task.slice(0, 160)}`, { actor: 'Voice Agent (Realtime)' });
  try {
  if (typeof window.sendChat === 'function') {
      removeRecentRealtimeAgentChatMessage(sessionId, 'user', task);
      markVoiceAgentRealtimeWorkerDispatch(sessionId, task);
      window.sendChat(task, { skipVoiceAgent: true, voiceSource: 'realtime_agent_dispatch_recovery' });
    }
  } catch (err) {
    console.warn('[voice-agent-realtime] handoff recovery failed', err);
  }
}

async function handleVoiceAgentRealtimeEvent(event, sessionId) {
  const type = String(event?.type || '');
  if (window.__voiceAgentRealtimeDebug) {
    try {
      console.debug('[voice-agent-realtime] event', type, type === 'error' ? event?.error : (event?.transcript ?? ''));
    } catch {}
  }

  // Streaming function-call argument accumulation
  if (type === 'response.function_call_arguments.delta') {
    const callId = String(event.call_id || '').trim();
    if (!callId) return;
    const buf = voiceAgentRealtimeFunctionCallBuffers.get(callId) || { name: '', argsStr: '' };
    buf.argsStr += String(event.delta || '');
    voiceAgentRealtimeFunctionCallBuffers.set(callId, buf);
    return;
  }
  if (type === 'response.function_call_arguments.done') {
    const callId = String(event.call_id || '').trim();
    const name = String(event.name || '').trim();
    const argsStr = String(event.arguments || voiceAgentRealtimeFunctionCallBuffers.get(callId)?.argsStr || '');
    voiceAgentRealtimeFunctionCallBuffers.delete(callId);
    let args = {};
    try { args = argsStr ? JSON.parse(argsStr) : {}; } catch {}
    await executeVoiceAgentRealtimeFunctionCall({ call_id: callId, name, args }, sessionId);
    return;
  }
  if (type === 'response.created') {
    if (voiceAgentRealtimeConnection) voiceAgentRealtimeConnection.activeResponse = true;
    voiceAgentRealtimeTurn.hadFunctionCall = false;
    voiceAgentRealtimeTurn.dispatchedWorkerThisResponse = false;
    voiceAgentRealtimeTurn.lastAssistantTranscript = '';
    return;
  }
  if (type === 'response.output_item.added' && event.item?.type === 'function_call') {
    const item = event.item;
    voiceAgentRealtimeTurn.hadFunctionCall = true;
    const callId = String(item.call_id || '').trim();
    if (callId) {
      voiceAgentRealtimeFunctionCallBuffers.set(callId, { name: String(item.name || ''), argsStr: '' });
    }
    return;
  }

  // User-side transcript (what the user said)
  if (type === 'conversation.item.input_audio_transcription.completed') {
    const transcript = String(event.transcript || '').trim();
    if (transcript) {
      if (shouldIgnoreVoiceAgentRealtimeTranscriptEvent(sessionId, event, transcript)) return;
      if (handleRealtimeAgentQuietTranscript(transcript)) return;
      voiceAgentRealtimeTurn.lastUserTranscript = transcript;
      voiceAgentRealtimeTurn.nudged = false;
      addSessionProcessEntry(sessionId, 'user', `User: ${transcript}`, { actor: 'Voice Agent (Realtime)' });
      appendRealtimeAgentChatMessage(sessionId, 'user', transcript);
      const pendingResponse = voiceAgentRealtimePendingCreateResponse;
      const shouldGateResponse = !!(
        pendingResponse
        && Date.now() - Number(pendingResponse.createdAt || 0) >= 0
        && Date.now() - Number(pendingResponse.createdAt || 0) < 2500
      );
      if (shouldGateResponse) {
        await injectVoiceAgentRealtimeSkillContext(sessionId, transcript, { reason: 'ptt_transcript' });
        finishVoiceAgentRealtimePendingResponse('ptt_transcript_ready');
      } else {
        injectVoiceAgentRealtimeSkillContext(sessionId, transcript, { reason: 'transcript_observed' }).catch(() => {});
      }
    }
    return;
  }

  // Assistant-side transcript (what Prom said) — for chat history + display
  if (type === 'response.audio_transcript.done' || type === 'response.output_audio_transcript.done') {
    const transcript = cleanVoiceSpeechText(event.transcript || '');
    if (transcript) {
      voiceAgentRealtimeTurn.lastAssistantTranscript = transcript;
      if (voiceAgentRealtimeTurn.dispatchedWorkerThisResponse) {
        removeRecentRealtimeAgentChatMessage(sessionId, 'ai', transcript);
        return;
      }
      addSessionProcessEntry(sessionId, 'info', `Prom: ${transcript}`, { actor: 'Voice Agent (Realtime)' });
      appendRealtimeAgentChatMessage(sessionId, 'ai', transcript);
    }
    return;
  }

  // A response finished — quiet-mode activation + hallucinated-handoff safety net.
  if (type === 'response.done' || type === 'response.audio.done' || type === 'response.output_audio.done' || type === 'response.cancelled') {
    if (voiceAgentRealtimeConnection) {
      voiceAgentRealtimeConnection.activeResponse = false;
      voiceAgentRealtimeConnection.narrationPending = false;
      voiceAgentRealtimeConnection.lastResponseEndedAt = Date.now();
    }
    if (voiceAgentRealtimeQuiet.pendingActivate) {
      voiceAgentRealtimeQuiet.pendingActivate = false;
      activateRealtimeAgentQuietMode();
    }
    maybeRecoverHallucinatedRealtimeHandoff(sessionId);
    return;
  }

  // Errors
  if (type === 'error') {
    const message = String(event?.error?.message || event?.error || '');
    console.warn('[voice-agent-realtime] server error', event);
    if (message) {
      addSessionProcessEntry(sessionId, 'warn', `Realtime error: ${message}`, { actor: 'Voice Agent (Realtime)' });
      showToast('Realtime error', message, 'error', 5000);
    }
    return;
  }
}

async function executeVoiceAgentRealtimeFunctionCall(call, sessionId) {
  const name = String(call?.name || '').trim();
  if (!name) return;
  const callId = String(call?.call_id || '').trim();
  const args = call?.args && typeof call.args === 'object' ? call.args : {};

  addSessionProcessEntry(sessionId, 'tool', `Realtime model called: ${name}`, { actor: 'Voice Agent (Realtime)', args });

  // Worker control — handled client-side via existing flows
  if (name === 'dispatch_prometheus_worker') {
    const singleTask = String(args.task || args.prompt || '').trim();
    const tasks = Array.isArray(args.tasks)
      ? args.tasks.map((raw, index) => {
          const prompt = typeof raw === 'string'
            ? raw
            : String(raw?.prompt || raw?.task || raw?.objective || raw?.message || '').trim();
          if (!prompt) return null;
          const title = typeof raw === 'object' && raw
            ? String(raw.title || raw.name || raw.label || '').trim()
            : '';
          return { title: title || `Voice worker ${index + 1}`, prompt };
        }).filter(Boolean)
      : [];
    if (!tasks.length && singleTask) tasks.push({ title: String(args.title || '').trim(), prompt: singleTask });
    const dispatchLabel = tasks.length > 1
      ? `${tasks.length} workers: ${tasks.map((task) => task.title || task.prompt).join('; ')}`
      : String(tasks[0]?.prompt || singleTask || '').trim();
    let data = null;
    let dispatched = false;
    let error = '';
    if (tasks.length) {
      try {
        voiceAgentRealtimeTurn.dispatchedWorkerThisResponse = true;
        cancelVoiceAgentRealtimeResponseForDispatch();
        removeRecentRealtimeAgentChatMessage(sessionId, 'user', singleTask || voiceAgentRealtimeTurn.lastUserTranscript || dispatchLabel);
        markVoiceAgentRealtimeWorkerDispatch(sessionId, dispatchLabel);
        const response = await fetch('/api/voice-agent/dispatch-workers', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            sessionId,
            task: singleTask,
            tasks,
            delivery: 'report_each',
            sourceTranscript: String(voiceAgentRealtimeTurn.lastUserTranscript || singleTask || dispatchLabel || '').trim(),
            source: 'desktop_realtime_agent_dispatch',
          }),
        });
        data = await response.json().catch(() => ({}));
        dispatched = response.ok && (data?.success === true || data?.ok === true);
        error = data?.error || '';
        if (dispatched) {
          addSessionProcessEntry(sessionId, 'info', `Dispatched ${tasks.length} Prometheus worker${tasks.length === 1 ? '' : 's'}.`, {
            actor: 'Voice Agent (Realtime)',
            workgroupId: data?.workgroupId || '',
            taskIds: data?.taskIds || [],
          });
          setTimeout(() => refreshVoiceAgentRealtimeWorkerContext('worker_dispatched_fast').catch(() => {}), 300);
          setTimeout(() => refreshVoiceAgentRealtimeWorkerContext('worker_dispatched').catch(() => {}), 1200);
        }
      } catch (err) {
        error = String(err?.message || err);
        console.warn('[voice-agent-realtime] dispatch failed', err);
      }
    }
    sendVoiceAgentRealtimeFunctionOutput(callId, JSON.stringify({
      ok: dispatched,
      dispatched,
      task: singleTask,
      tasks,
      workgroupId: data?.workgroupId || '',
      taskIds: data?.taskIds || [],
      error,
      spoken_confirmation_not_needed: true,
      note: dispatched
        ? 'Worker dispatch has started through the voice workgroup bridge. Do not speak another handoff acknowledgement.'
        : 'Worker dispatch failed before any worker started.',
    }), { createResponse: false });
    return;
  }
  if (name === 'steer_active_worker') {
    const message = String(args.message || '').trim();
    let ok = false;
    let error = '';
    if (isDesktopVoiceStatusQuestion(message)) {
      try {
        const response = await fetch('/api/voice-agent/realtime-tool', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ sessionId, toolName: 'voice_worker_status', toolArgs: { include_recent_events: true } }),
        });
        const status = await response.json().catch(() => ({}));
        const result = status?.result && typeof status.result === 'object' ? status.result : null;
        const packet = overlayPendingVoiceAgentRealtimeWorkerPacket(result ? {
          id: result.contextPacketId,
          active: result.active,
          summary: result.summary,
          currentGoal: result.currentGoal,
          currentPhase: result.currentPhase,
          activeToolName: result.activeToolName,
          activeToolLabel: result.activeToolLabel,
          trigger: result.trigger,
          currentlyDoing: result.currentlyDoing,
          doneAlready: result.doneAlready,
          processEntries: result.processEntries,
          recentEvents: result.recentEvents,
        } : null, sessionId, 'blocked_status_as_steer');
        if (packet) sendVoiceAgentRealtimeContextUpdate(packet, { reason: 'blocked_status_as_steer' });
        sendVoiceAgentRealtimeFunctionOutput(callId, JSON.stringify({
          ok: true,
          steered: false,
          statusQuestion: true,
          workerStatus: overlayPendingVoiceAgentRealtimeWorkerPacket(result || null, sessionId, 'blocked_status_as_steer_output') || null,
        }));
      } catch (err) {
        sendVoiceAgentRealtimeFunctionOutput(callId, JSON.stringify({ ok: false, steered: false, statusQuestion: true, error: String(err?.message || err) }));
      }
      return;
    }
    if (message) {
      try {
        const response = await fetch('/api/chat/steer', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ sessionId, message, source: 'realtime_agent_steer' }),
        });
        const data = await response.json().catch(() => ({}));
        ok = response.ok && (data?.success === true || data?.ok === true);
        error = data?.error || '';
      } catch (err) {
        error = String(err?.message || err);
      }
    } else {
      error = 'message required';
    }
    sendVoiceAgentRealtimeFunctionOutput(callId, JSON.stringify({ ok, steered: ok, message, error }));
    return;
  }
  if (name === 'interrupt_active_worker') {
    try {
      const ctrl = window._sessionAbortControllers?.[sessionId] || currentAbortController;
      if (ctrl && !ctrl.signal?.aborted) ctrl.abort();
    } catch {}
    try { await requestGatewayMainChatAbort?.(sessionId, 'realtime_agent_interrupt'); } catch {}
    sendVoiceAgentRealtimeFunctionOutput(callId, JSON.stringify({ ok: true, interrupted: true, reason: String(args.reason || '') }));
    return;
  }

  // All voice_* / skill_* tools route through the gateway tool endpoint
  try {
    const response = await fetch('/api/voice-agent/realtime-tool', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ sessionId, toolName: name, toolArgs: args }),
    });
    const data = await response.json().catch(() => ({}));
    if (!response.ok || !data?.success) {
      sendVoiceAgentRealtimeFunctionOutput(callId, JSON.stringify({ ok: false, error: data?.error || `Tool failed (${response.status})` }));
      return;
    }
    if (name === 'voice_worker_status') {
      const packet = overlayPendingVoiceAgentRealtimeWorkerPacket(data?.result && typeof data.result === 'object'
        ? {
          id: data.result.contextPacketId,
          active: data.result.active,
          summary: data.result.summary,
          currentGoal: data.result.currentGoal,
          currentPhase: data.result.currentPhase,
          activeToolName: data.result.activeToolName,
          activeToolLabel: data.result.activeToolLabel,
          trigger: data.result.trigger,
          currentlyDoing: data.result.currentlyDoing,
          doneAlready: data.result.doneAlready,
          processEntries: data.result.processEntries,
          recentEvents: data.result.recentEvents,
        }
        : null, sessionId, 'voice_worker_status_tool');
      if (packet) sendVoiceAgentRealtimeContextUpdate(packet, { reason: 'voice_worker_status_tool' });
    }

    // Apply any runtime directive (wake phrase / quiet mode) to the live session.
    const directive = data.runtimeDirective;
    if (directive?.action) {
      const phrase = String(directive.wakePhrase || '').trim();
      if (directive.action === 'set_wake_phrase' && phrase) {
        setRealtimeAgentWakePhrase(phrase);
      } else if (directive.action === 'enter_quiet_mode' || directive.action === 'set_quiet_until') {
        if (phrase) setRealtimeAgentWakePhrase(phrase);
        activateRealtimeAgentQuietMode();
        const quietResult = data.result && typeof data.result === 'object'
          ? data.result
          : { ok: true, summary: String(data.raw || 'Quiet mode active.') };
        sendVoiceAgentRealtimeFunctionOutput(callId, JSON.stringify({
          ...quietResult,
          realtime_quiet_applied: true,
          spoken_confirmation_not_needed: true,
        }), { createResponse: false });
        return;
      }
    }
    if (Array.isArray(data?.processEntries) && data.processEntries.length) {
      attachVoiceAgentProcessEntriesToRecentAssistantTurn(sessionId, data.processEntries);
    }
    // A voice show_* tool produced a rich-artifact card — render it into the chat
    // thread now, and send the model only a lean confirmation (not the full card JSON).
    const voiceArtifacts = data?.result && Array.isArray(data.result.richArtifacts) ? data.result.richArtifacts : null;
    if (voiceArtifacts && voiceArtifacts.length) {
      try {
        const sid = String(sessionId || window.activeChatSessionId || '').trim();
        const sess = sid ? getChatSessionById(sid) : null;
        if (sess) {
          if (!Array.isArray(sess.history)) sess.history = [];
          sess.history.push({
            role: 'ai',
            content: '',
            richArtifacts: voiceArtifacts,
            timestamp: Date.now(),
            source: 'voice_agent_realtime',
            channel: 'voice',
            channelLabel: 'Realtime voice',
            processEntries: mergeVoiceAgentProcessEntryLists(takePendingVoiceAgentProcessEntries(sid)),
          });
          try { persistSession(sid); } catch {}
          if (window.activeChatSessionId === sid) {
            window.chatHistory = sess.history;
            try { renderChatMessages(); } catch {}
          }
        }
      } catch (err) { console.warn('[voice-agent-realtime] artifact card render failed', err); }
      sendVoiceAgentRealtimeFunctionOutput(callId, JSON.stringify({
        ok: data.result.ok !== false,
        summary: data.result.summary || 'Card shown.',
        shown: true,
      }));
      return;
    }
    const toolOutput = name === 'voice_worker_status'
      ? (overlayPendingVoiceAgentRealtimeWorkerPacket(data.result || null, sessionId, 'voice_worker_status_output') || data.result || data.raw || { ok: true })
      : (data.result || data.raw || { ok: true });
    sendVoiceAgentRealtimeFunctionOutput(callId, JSON.stringify(toolOutput), { preview: data.preview });
  } catch (err) {
    sendVoiceAgentRealtimeFunctionOutput(callId, JSON.stringify({ ok: false, error: String(err?.message || err) }));
  }
}

// Downscale/recompress a data URL so a full-res screenshot reliably fits in ONE
// realtime data-channel (SCTP) message. Without this a 1-3MB PNG send can fail
// silently and the voice agent gets only the text metadata.
async function downscaleDataUrlForRealtime(dataUrl, maxDim = 1280, quality = 0.82) {
  const src = String(dataUrl || '');
  if (!src.startsWith('data:image')) return src;
  try {
    const img = await new Promise((resolve, reject) => {
      const im = new Image();
      im.onload = () => resolve(im);
      im.onerror = () => reject(new Error('image decode failed'));
      im.src = src;
    });
    const w = img.naturalWidth || img.width || 0;
    const h = img.naturalHeight || img.height || 0;
    if (!w || !h) return src;
    const scale = Math.min(1, maxDim / Math.max(w, h));
    if (scale >= 1 && src.length < 600000) return src;
    const cw = Math.max(1, Math.round(w * scale));
    const ch = Math.max(1, Math.round(h * scale));
    const canvas = document.createElement('canvas');
    canvas.width = cw; canvas.height = ch;
    const ctx = canvas.getContext('2d');
    if (!ctx) return src;
    ctx.drawImage(img, 0, 0, cw, ch);
    return canvas.toDataURL('image/jpeg', quality);
  } catch {
    return src;
  }
}

async function sendVoiceAgentRealtimeFunctionOutput(callId, output, options = {}) {
  const dc = voiceAgentRealtimeConnection?.dc;
  if (!dc || dc.readyState !== 'open' || !callId) return;
  try {
    const preview = options.preview && typeof options.preview === 'object' ? options.preview : null;
    const previewDataUrl = String(preview?.dataUrl || '').trim();
    const canSendPreviewImage = !!previewDataUrl && String(voiceAgentRealtimeConnection?.provider || 'openai_realtime') !== 'xai';
    dc.send(JSON.stringify({
      type: 'conversation.item.create',
      item: {
        type: 'function_call_output',
        call_id: callId,
        output: String(output || ''),
      },
    }));
    if (canSendPreviewImage) {
      const source = String(preview?.source || '').trim() || 'screen';
      const dimensions = preview?.width && preview?.height ? ` ${preview.width}x${preview.height}` : '';
      // Inject the ACTUAL screenshot pixels (downscaled to fit the data channel).
      const imageUrl = await downscaleDataUrlForRealtime(previewDataUrl, 1280, 0.82);
      if (dc.readyState === 'open') {
        dc.send(JSON.stringify({
          type: 'conversation.item.create',
          item: {
            type: 'message',
            role: 'user',
            content: [
              {
                type: 'input_text',
                text: `Fresh ${source} screenshot after the tool call${dimensions}. Look at this image directly and use it as visual context for the next realtime browser/desktop step.`,
              },
              {
                type: 'input_image',
                image_url: imageUrl,
              },
            ],
          },
        }));
      }
    }
    // Trigger the model to continue/respond to the tool result when the tool
    // result needs a spoken answer. Worker dispatch already has its own visible
    // worker turn, so creating another response here causes duplicate acks.
    if (options.createResponse !== false && dc.readyState === 'open') dc.send(JSON.stringify({ type: 'response.create' }));
  } catch (err) {
    console.warn('[voice-agent-realtime] sendFunctionCallOutput failed', err);
  }
}

// Public hooks used by the mic UI: PTT button and always-listening toggle
function pttRealtimeAgentPress() {
  // User pressed PTT — open mic and let user speak
  if (!voiceAgentRealtimeConnection) {
    startVoiceAgentRealtimeSession(window.activeChatSessionId || 'default', { listenMode: 'push_to_talk' })
      .then(() => setVoiceAgentRealtimeMicEnabled(true))
      .catch((err) => console.warn('[voice-agent-realtime] PTT start failed', err));
    return;
  }
  setVoiceAgentRealtimeMicEnabled(true);
}

function pttRealtimeAgentRelease() {
  const conn = voiceAgentRealtimeConnection;
  const isXai = conn?.provider === 'xai';
  // Capture-health diagnostic: if appends==0 the mic isn't feeding audio; if
  // appends>0 but nonSilent==0 the mic is producing silence (Safari rate bug).
  if (isXai && window.__xaiRealtimeCapture) {
    const c = window.__xaiRealtimeCapture;
    showToast('xAI mic capture', `chunks sent: ${c.appends}, with sound: ${c.nonSilent}, rate: ${c.sampleRate}`, c.nonSilent > 0 ? 'info' : 'error', 6000);
  }
  const commitAndRespond = () => {
    const dc = voiceAgentRealtimeConnection?.dc;
    if (dc?.readyState === 'open') {
      try {
        dc.send(JSON.stringify({ type: 'input_audio_buffer.commit' }));
        if (isXai) {
          dc.send(JSON.stringify({ type: 'response.create' }));
        } else {
          scheduleVoiceAgentRealtimeResponseAfterSkillContext('ptt_release');
        }
      } catch {}
    }
  };
  if (isXai) {
    // Let the last ~150ms of audio chunks flush over the socket before committing,
    // then stop the mic. (Stopping first can clip the tail of the utterance.)
    setTimeout(() => {
      commitAndRespond();
      setVoiceAgentRealtimeMicEnabled(false);
    }, 150);
    return;
  }
  setVoiceAgentRealtimeMicEnabled(false);
  commitAndRespond();
}

async function enableRealtimeAgentAlwaysListening() {
  await startVoiceAgentRealtimeSession(window.activeChatSessionId || 'default', { listenMode: 'always_listening' });
  setVoiceAgentRealtimeMicEnabled(true);
}

function disableRealtimeAgentAlwaysListening() {
  stopVoiceAgentRealtimeSession();
}

// ============================================================================
// xAI / Grok Realtime — native WebSocket transport
// ----------------------------------------------------------------------------
// xAI's realtime Voice Agent is WebSocket-only for browsers (no WebRTC/SDP path).
// We connect with an ephemeral token passed as a WS subprotocol, stream mic audio
// as base64 PCM16 via input_audio_buffer.append, and play response.output_audio
// deltas through Web Audio. All non-audio events (transcripts, function calls,
// quiet-mode, errors) reuse the shared OpenAI handler by populating
// voiceAgentRealtimeConnection with a WebSocket-backed `dc` shim, so PTT,
// dispatch, steering, and wake-gate behave identically across providers.
// ============================================================================

const XAI_REALTIME_OUTPUT_SAMPLE_RATE = 24000;
const XAI_REALTIME_INPUT_SAMPLE_RATE = 24000;

function int16ToFloat32(int16) {
  const out = new Float32Array(int16.length);
  for (let i = 0; i < int16.length; i++) {
    const s = int16[i];
    out[i] = s < 0 ? s / 0x8000 : s / 0x7fff;
  }
  return out;
}

function base64ToArrayBuffer(b64) {
  const binary = atob(String(b64 || ''));
  const len = binary.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) bytes[i] = binary.charCodeAt(i);
  return bytes.buffer;
}

function arrayBufferToBase64(buffer) {
  const bytes = new Uint8Array(buffer);
  let binary = '';
  const chunk = 0x8000;
  for (let i = 0; i < bytes.length; i += chunk) {
    binary += String.fromCharCode.apply(null, bytes.subarray(i, i + chunk));
  }
  return btoa(binary);
}

// Sequential PCM16 playback scheduler over a single AudioContext. Each audio
// delta is queued so chunks play gap-free; barge-in clears the queue.
function createXaiRealtimePlayback() {
  const AudioCtx = window.AudioContext || window.webkitAudioContext;
  const ctx = new AudioCtx({ sampleRate: XAI_REALTIME_OUTPUT_SAMPLE_RATE });
  let nextStartTime = 0;
  const sources = new Set();
  return {
    ctx,
    enqueue(int16) {
      if (!int16 || !int16.length) return;
      const float = int16ToFloat32(int16);
      const buffer = ctx.createBuffer(1, float.length, XAI_REALTIME_OUTPUT_SAMPLE_RATE);
      buffer.copyToChannel(float, 0);
      const src = ctx.createBufferSource();
      src.buffer = buffer;
      const rate = getCurrentRealtimeVoiceSpeed();
      try { src.playbackRate.value = rate; } catch {}
      src.connect(ctx.destination);
      const now = ctx.currentTime;
      const startAt = Math.max(now, nextStartTime);
      src.start(startAt);
      nextStartTime = startAt + (buffer.duration / Math.max(0.25, rate || 1));
      sources.add(src);
      src.onended = () => sources.delete(src);
    },
    interrupt() {
      for (const src of sources) { try { src.stop(); } catch {} }
      sources.clear();
      nextStartTime = 0;
    },
    async resume() { try { await ctx.resume?.(); } catch {} },
    close() {
      this.interrupt();
      try { ctx.close?.(); } catch {}
    },
  };
}

async function startXaiRealtimeSession(sessionId, options = {}) {
  if (voiceAgentRealtimeConnection?.dc?.readyState === 'open') return voiceAgentRealtimeConnection;
  if (voiceAgentRealtimeConnecting) return voiceAgentRealtimeConnecting;
  const sid = String(sessionId || window.activeChatSessionId || 'default').trim() || 'default';
  const listenMode = String(options.listenMode || 'push_to_talk').trim();
  voiceAgentRealtimeListenMode = listenMode;

  voiceAgentRealtimeConnecting = (async () => {
    const startedAt = Date.now();
    addSessionProcessEntry(sid, 'info', 'Voice Agent (xAI Realtime): bootstrapping session.', { actor: 'Voice Agent (xAI Realtime)' });

    // 1. Bootstrap — gateway builds instructions/tools/context and mints an
    //    ephemeral xAI client secret. Unlike OpenAI, the session config is sent
    //    by the client over the socket (session.update) after connect.
    const wakeGate = getRealtimeWakeGate?.();
    voiceAgentRealtimeQuiet.active = !!(wakeGate?.active && wakeGate?.suppressVoice === true);
    voiceAgentRealtimeQuiet.pendingActivate = false;
    setRealtimeAgentWakePhrase(wakeGate?.phrase || '');
    const bootstrapResp = await fetch('/api/voice-agent/xai-realtime-bootstrap', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        sessionId: sid,
        voice: normalizeXaiRealtimeVoice(desktopVoiceSettings.serverVoice || realtimeVoiceSelection),
        speed: getCurrentRealtimeVoiceSpeed(),
        voiceRuntime: wakeGate?.phrase
          ? { wakePhrase: wakeGate.phrase, wakeGateActive: wakeGate?.suppressVoice === true }
          : undefined,
        deviceTime: desktopVoiceDeviceTimeContext(),
      }),
    });
    const bootstrap = await bootstrapResp.json().catch(() => ({}));
    if (!bootstrapResp.ok || !bootstrap?.success) {
      throw new Error(bootstrap?.error || `xAI realtime bootstrap failed (${bootstrapResp.status})`);
    }
    logDesktopVoiceLatency?.(sid, 'xai-realtime bootstrap', startedAt);
    console.info('[xai-realtime] bootstrap ok', {
      wsUrl: bootstrap.wsUrl,
      model: bootstrap.model,
      voice: bootstrap.voice,
      auth: bootstrap.auth,
      hasClientSecret: !!bootstrap.clientSecret,
      clientSecretPrefix: String(bootstrap.clientSecret || '').slice(0, 6),
      instructionsLength: bootstrap.instructionsLength,
      toolCount: bootstrap.toolCount,
    });

    // 2. Open the WebSocket with the ephemeral token as the (single) subprotocol.
    //    xAI expects exactly one subprotocol entry: xai-client-secret.<token>.
    //    Offering extra protocols (e.g. 'realtime') makes the server negotiate the
    //    wrong protocol and the session config / auth silently misbehaves.
    const ws = new WebSocket(bootstrap.wsUrl, [`xai-client-secret.${bootstrap.clientSecret}`]);
    ws.binaryType = 'arraybuffer';
    const playback = createXaiRealtimePlayback();
    await playback.resume();

    // 3. Mic capture → PCM16 → input_audio_buffer.append.
    //    IMPORTANT: do NOT force the AudioContext sampleRate. On Safari, forcing a
    //    rate that differs from the mic's native rate makes the MediaStream source
    //    emit silence. Use the native rate and downsample to 24k in software.
    const micStream = await navigator.mediaDevices.getUserMedia({ audio: { echoCancellation: true, noiseSuppression: true, autoGainControl: true } });
    const micTrack = micStream.getAudioTracks()[0];
    micTrack.enabled = listenMode === 'always_listening';
    const AudioCtx = window.AudioContext || window.webkitAudioContext;
    const captureCtx = new AudioCtx();
    const source = captureCtx.createMediaStreamSource(micStream);
    const processor = captureCtx.createScriptProcessor(2048, 1, 1);
    const mutedGain = captureCtx.createGain();
    mutedGain.gain.value = 0;
    let xaiAppendCount = 0;
    let xaiNonSilentCount = 0;
    processor.onaudioprocess = (event) => {
      if (ws.readyState !== WebSocket.OPEN || !micTrack.enabled) return;
      const inputData = event.inputBuffer.getChannelData(0);
      // Track whether the mic is actually producing sound (Safari silence guard).
      let peak = 0;
      for (let i = 0; i < inputData.length; i += 64) { const a = Math.abs(inputData[i]); if (a > peak) peak = a; }
      if (peak > 0.01) xaiNonSilentCount += 1;
      const pcm = downsampleFloat32ToInt16(inputData, captureCtx.sampleRate || 48000, XAI_REALTIME_INPUT_SAMPLE_RATE);
      if (pcm.byteLength > 0) {
        try { ws.send(JSON.stringify({ type: 'input_audio_buffer.append', audio: arrayBufferToBase64(pcm.buffer) })); xaiAppendCount += 1; } catch {}
      }
    };
    source.connect(processor);
    processor.connect(mutedGain);
    mutedGain.connect(captureCtx.destination);
    await captureCtx.resume?.();
    // Expose counters so PTT release / diagnostics can report capture health.
    window.__xaiRealtimeCapture = {
      get appends() { return xaiAppendCount; },
      get nonSilent() { return xaiNonSilentCount; },
      sampleRate: captureCtx.sampleRate,
    };

    // Persistent close/error logging — xAI reports auth/protocol failures as a
    // WebSocket close code+reason rather than an in-band error event.
    ws.addEventListener('close', (ev) => {
      console.warn('[xai-realtime] socket closed', { code: ev.code, reason: ev.reason, wasClean: ev.wasClean, negotiatedProtocol: ws.protocol });
      try { addSessionProcessEntry(sid, 'warn', `xAI realtime socket closed (code ${ev.code}${ev.reason ? `: ${ev.reason}` : ''}).`, { actor: 'Voice Agent (xAI Realtime)' }); } catch {}
    });
    ws.addEventListener('error', (ev) => { console.warn('[xai-realtime] socket error', ev); });

    const wsOpen = new Promise((resolve, reject) => {
      const timeout = setTimeout(() => reject(new Error('xAI realtime socket did not open.')), 12000);
      ws.addEventListener('open', () => {
        console.info('[xai-realtime] socket open', { negotiatedProtocol: ws.protocol });
        clearTimeout(timeout);
        resolve(true);
      }, { once: true });
      ws.addEventListener('close', (ev) => { clearTimeout(timeout); reject(new Error(`xAI realtime socket closed before open (code ${ev.code}${ev.reason ? `: ${ev.reason}` : ''}).`)); }, { once: true });
      ws.addEventListener('error', () => { clearTimeout(timeout); reject(new Error('xAI realtime socket failed.')); }, { once: true });
    });
    await wsOpen;

    // WebSocket-backed shim so the shared OpenAI agent helpers (function output,
    // quiet-mode response.create, etc.) operate on this connection unchanged.
    const dcShim = {
      get readyState() { return ws.readyState === WebSocket.OPEN ? 'open' : 'closed'; },
      send: (payload) => { try { if (ws.readyState === WebSocket.OPEN) ws.send(payload); } catch {} },
      close: () => { try { ws.close(); } catch {} },
    };

    ws.addEventListener('message', (msgEvent) => {
      let event = null;
      try { event = JSON.parse(typeof msgEvent.data === 'string' ? msgEvent.data : ''); } catch { return; }
      if (!event) return;
      handleXaiRealtimeEvent(event, sid, playback).catch(() => {});
    });

    // 4. Configure the session over the socket.
    const turnDetection = listenMode === 'always_listening'
      ? { type: 'server_vad', threshold: 0.5, prefix_padding_ms: 300, silence_duration_ms: 500, create_response: !voiceAgentRealtimeQuiet.active }
      : null;
    // xAI's realtime API is OpenAI-Realtime-compatible, so use the OpenAI
    // Realtime WebSocket session format: flat input_audio_format/output_audio_format
    // = "pcm16" (24kHz mono 16-bit LE — exactly what our capture produces) and
    // input_audio_transcription to surface user-speech transcripts. Send core
    // config first (must be accepted), then tools separately so a tools-schema
    // mismatch can't break the audio/transcription config.
    const speed = getCurrentRealtimeVoiceSpeed();
    const coreSession = {
      modalities: ['audio', 'text'],
      instructions: bootstrap.instructions,
      voice: bootstrap.voice,
      speed,
      audio: {
        output: { speed },
      },
      input_audio_format: 'pcm16',
      output_audio_format: 'pcm16',
      input_audio_transcription: { model: 'grok-stt' },
      turn_detection: turnDetection,
    };
    try { ws.send(JSON.stringify({ type: 'session.update', session: coreSession })); } catch (err) {
      console.warn('[xai-realtime] core session.update send failed', err);
    }
    if (Array.isArray(bootstrap.tools) && bootstrap.tools.length) {
      try { ws.send(JSON.stringify({ type: 'session.update', session: { tools: bootstrap.tools, tool_choice: 'auto' } })); } catch {}
    }
    if (window.__voiceAgentRealtimeDebug) {
      console.debug('[xai-realtime] connected', { wsUrl: bootstrap.wsUrl, model: bootstrap.model, voice: bootstrap.voice, toolCount: bootstrap.toolCount, listenMode, protocol: ws.protocol });
    }

    voiceAgentRealtimeConnection = {
      provider: 'xai',
      ws,
      dc: dcShim,
      pc: null,
      audio: null,
      micStream,
      micTrack,
      sessionId: sid,
      listenMode,
      playback,
      cleanup: () => {
        try { processor.disconnect(); } catch {}
        try { source.disconnect(); } catch {}
        try { mutedGain.disconnect(); } catch {}
        try { captureCtx.close?.(); } catch {}
        try { playback.close(); } catch {}
        try { ws.close(); } catch {}
      },
    };
    startVoiceAgentRealtimeContextRefreshLoop(voiceAgentRealtimeConnection);
    if (voiceAgentRealtimeQuiet.active) sendRealtimeAgentCreateResponseFlag(false);
    ws.addEventListener('close', () => {
      if (voiceAgentRealtimeConnection?.ws === ws) voiceAgentRealtimeConnection = null;
    });
    logDesktopVoiceLatency?.(sid, 'xai-realtime ready', startedAt);
    addSessionProcessEntry(sid, 'info', `Voice Agent (xAI Realtime): connected (${listenMode}).`, { actor: 'Voice Agent (xAI Realtime)' });
    return voiceAgentRealtimeConnection;
  })().finally(() => {
    voiceAgentRealtimeConnecting = null;
  });
  return voiceAgentRealtimeConnecting;
}

function normalizeXaiRealtimeVoice(value) {
  const xaiVoices = new Set(['eve', 'ara', 'rex', 'sal', 'leo']);
  const voice = String(value || '').trim().toLowerCase();
  return xaiVoices.has(voice) ? voice : 'eve';
}

let xaiRealtimeStatusCache = null;
let xaiRealtimeStatusFetchedAt = 0;
async function isXaiRealtimeConfigured() {
  const now = Date.now();
  if (!xaiRealtimeStatusCache || now - xaiRealtimeStatusFetchedAt > 30 * 1000) {
    try {
      const response = await fetch('/api/realtime/xai/status', { cache: 'no-store' });
      xaiRealtimeStatusCache = await response.json().catch(() => ({}));
      xaiRealtimeStatusFetchedAt = now;
    } catch {
      xaiRealtimeStatusCache = { configured: false };
    }
  }
  return !!xaiRealtimeStatusCache?.configured;
}

// xAI WS event router: handle audio playback + barge-in here, delegate every
// other event to the shared OpenAI agent handler (transcripts, tool calls, etc.).
async function handleXaiRealtimeEvent(event, sessionId, playback) {
  const type = String(event?.type || '');
  if (window.__voiceAgentRealtimeDebug && !/delta$/.test(type)) {
    try { console.debug('[xai-realtime] event', type, event?.transcript ?? ''); } catch {}
  }
  // Surface session lifecycle + errors so config rejections are visible without
  // the debug flag (a rejected session.update is the usual cause of "no transcription").
  if (type === 'session.created' || type === 'session.updated') {
    try { console.info('[xai-realtime]', type, event?.session ? { voice: event.session.voice, turn_detection: event.session.turn_detection, audio: event.session.audio } : event); } catch {}
    if (type === 'session.updated') {
      const sess = event?.session || {};
      const inFmt = sess.input_audio_format || sess?.audio?.input?.format?.type || '?';
      try { showToast('xAI session configured', `voice=${sess.voice || '?'} in=${typeof inFmt === 'string' ? inFmt : JSON.stringify(inFmt)} vad=${sess?.turn_detection?.type || 'none'}`, 'info', 5000); } catch {}
    }
  }
  if (type === 'error' || type === 'response.error' || /\.error$/.test(type)) {
    const msg = String(event?.error?.message || event?.error || event?.message || JSON.stringify(event)).slice(0, 400);
    console.warn('[xai-realtime] server error event', type, event);
    addSessionProcessEntry(sessionId, 'warn', `xAI realtime error: ${msg}`, { actor: 'Voice Agent (xAI Realtime)' });
    try { showToast('xAI realtime error', msg, 'error', 8000); } catch {}
  }
  // Streamed assistant audio
  if (type === 'response.output_audio.delta' || type === 'response.audio.delta') {
    if (voiceAgentRealtimeConnection) voiceAgentRealtimeConnection.activeResponse = true;
    realtimeVoicePlaybackActive = true;
    const b64 = event.delta || event.audio;
    if (b64) {
      try { playback.enqueue(new Int16Array(base64ToArrayBuffer(b64))); } catch {}
    }
    return;
  }
  // Barge-in: user started talking while Prom was speaking — stop playback.
  if (type === 'input_audio_buffer.speech_started' || type === 'response.output_audio.cancelled') {
    try { playback.interrupt(); } catch {}
    if (type !== 'input_audio_buffer.speech_started') return;
  }
  // Everything else (transcripts, function calls, response.done, errors) reuses
  // the provider-agnostic OpenAI agent handler.
  await handleVoiceAgentRealtimeEvent(event, sessionId);
}

// Expose for cross-module use (mic button handlers, settings UI)
window.startVoiceAgentRealtimeSession = startVoiceAgentRealtimeSession;
window.stopVoiceAgentRealtimeSession = stopVoiceAgentRealtimeSession;
window.isVoiceAgentRealtimeMode = isVoiceAgentRealtimeMode;
window.pttRealtimeAgentPress = pttRealtimeAgentPress;
window.pttRealtimeAgentRelease = pttRealtimeAgentRelease;
window.enableRealtimeAgentAlwaysListening = enableRealtimeAgentAlwaysListening;
window.disableRealtimeAgentAlwaysListening = disableRealtimeAgentAlwaysListening;

function cleanVoiceSpeechText(text) {
  const value = String(text || '')
    .replace(/[^\x20-\x7E]/g, '')
    .replace(/(^|\s)[!?.,;:()[\]{}"'`~@#$%^&*_+=|\\/<>-]+(?=\s|$)/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
  return /[A-Za-z0-9]/.test(value) ? value : '';
}

function splitVoiceText(text, maxLength = 180) {
  const source = cleanVoiceSpeechText(text);
  if (!source) return [];
  const sentences = source.match(/[^.!?]+[.!?]+|[^.!?]+$/g) || [source];
  const chunks = [];
  let current = '';
  for (const sentence of sentences) {
    const next = sentence.trim();
    if (!next) continue;
    if ((current + ' ' + next).trim().length <= maxLength) {
      current = (current + ' ' + next).trim();
      continue;
    }
    if (current) chunks.push(current);
    if (next.length <= maxLength) {
      current = next;
    } else {
      for (let i = 0; i < next.length; i += maxLength) chunks.push(next.slice(i, i + maxLength));
      current = '';
    }
  }
  if (current) chunks.push(current);
  return chunks;
}

function getRecentRealtimeChatDigest(maxChars = 3500) {
  const history = Array.isArray(window.chatHistory) ? window.chatHistory : [];
  const messages = history
    .filter((msg) => msg && (msg.role === 'user' || msg.role === 'ai' || msg.role === 'assistant'))
    .slice(-10)
    .map((msg) => {
      const role = msg.role === 'user' ? 'User' : 'Prometheus';
      const content = String(msg.content || '').replace(/\s+/g, ' ').trim();
      return content ? `${role}: ${content.slice(0, 700)}` : '';
    })
    .filter(Boolean);
  const processEntries = Array.isArray(window.processLogEntries) ? window.processLogEntries : [];
  const process = processEntries
    .slice(-8)
    .map((entry) => {
      const type = String(entry?.type || 'info').toUpperCase();
      const content = String(entry?.content || '').replace(/\s+/g, ' ').trim();
      return content ? `${type}: ${content.slice(0, 300)}` : '';
    })
    .filter(Boolean);
  const gate = getRealtimeWakeGate();
  const sections = [
    messages.length ? `Recent chat:\n${messages.join('\n')}` : '',
    process.length ? `Recent process notes:\n${process.join('\n')}` : '',
    gate ? `Current wake gate: silent until "${gate.phrase}".` : '',
  ].filter(Boolean).join('\n\n');
  return sections.length > maxChars ? `${sections.slice(0, maxChars - 18).trimEnd()}\n...[truncated]` : sections;
}

async function getRealtimeContextPackInstructions() {
  const now = Date.now();
  if (!realtimeContextPackCache || now - realtimeContextPackFetchedAt > 5 * 60 * 1000) {
    try {
      const response = await fetch('/api/realtime/context-pack', { cache: 'no-store' });
      const data = await response.json().catch(() => ({}));
      if (!response.ok || data?.success === false) {
        throw new Error(data?.error || `Realtime context pack failed (${response.status})`);
      }
      realtimeContextPackCache = String(data?.instructions || '').trim();
      realtimeContextPackFetchedAt = now;
    } catch (err) {
      console.warn('[Realtime voice] context pack unavailable, using fallback instructions', err);
      realtimeContextPackCache = [
        '# Prometheus Realtime Context Pack',
        'You are Prometheus in live Realtime voice form. Mirror Prometheus identity and route real work to the Prometheus worker.',
        'You may handle voice controls, wake/silent mode, status, and interrupts. Do not claim you used tools or completed work unless the worker reports it.',
      ].join('\n\n');
      realtimeContextPackFetchedAt = now;
    }
  }
  const recent = getRecentRealtimeChatDigest();
  const localContract = [
    '## Live Browser-Side Voice State',
    recent || 'No recent local chat/process context is available in the browser yet.',
    '',
    '## Voice Output Instruction',
    'When asked to speak supplied Prometheus text aloud, speak the supplied text faithfully. Keep Prometheus identity and warmth in delivery, but do not add new claims or extra work results.',
  ].join('\n');
  return [realtimeContextPackCache, localContract].filter(Boolean).join('\n\n---\n\n').slice(0, 22000);
}

function playAudioBase64(audioBase64, mimeType) {
  return new Promise((resolve, reject) => {
    const audio = document.getElementById('realtime-voice-audio') || document.createElement('audio');
    const binary = atob(String(audioBase64 || ''));
    const bytes = new Uint8Array(binary.length);
    for (let i = 0; i < binary.length; i += 1) bytes[i] = binary.charCodeAt(i);
    const blob = new Blob([bytes], { type: mimeType || 'audio/mpeg' });
    const url = URL.createObjectURL(blob);
    audio.autoplay = true;
    audio.style.display = 'none';
    if (!audio.id) {
      audio.id = 'realtime-voice-audio';
      document.body.appendChild(audio);
    }
    let settled = false;
    const finish = (ok = true) => {
      if (settled) return;
      settled = true;
      URL.revokeObjectURL(url);
      if (ok) resolve(true);
      else reject(new Error('Could not play generated audio.'));
    };
    audio.onended = () => finish(true);
    audio.onpause = () => finish(true);
    audio.onerror = () => finish(false);
    audio.src = url;
    audio.play?.().catch((err) => {
      if (settled) return;
      settled = true;
      URL.revokeObjectURL(url);
      reject(err);
    });
  });
}

function speakWithBrowserVoice(text) {
  const content = String(text || '').trim();
  if (!content || !window.speechSynthesis) return;
  window.speechSynthesis.cancel();
  const utterance = new SpeechSynthesisUtterance(content.slice(0, 5000));
  utterance.lang = navigator.language || 'en-US';
  window.speechSynthesis.speak(utterance);
}

// Streaming voice-agent call: POSTs to /api/voice-agent/input with stream:true,
// consumes SSE chunks, and pipes each sentence to TTS as it arrives so the user
// hears the first word ~200-400ms after the model starts generating.
// Returns a promise resolving with the full result payload (same shape as JSON).
async function streamVoiceAgentInput(body, onChunk) {
  const response = await fetch('/api/voice-agent/input', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Accept: 'text/event-stream',
    },
    body: JSON.stringify({ ...body, stream: true }),
  });
  if (!response.ok || !response.body) {
    throw new Error(`Voice agent stream failed (${response.status})`);
  }
  const reader = response.body.getReader();
  const decoder = new TextDecoder('utf-8');
  let buf = '';
  let finalResult = null;
  while (true) {
    const { value, done } = await reader.read();
    if (done) break;
    buf += decoder.decode(value, { stream: true });
    let sep;
    while ((sep = buf.indexOf('\n\n')) !== -1) {
      const rawEvent = buf.slice(0, sep);
      buf = buf.slice(sep + 2);
      const dataLine = rawEvent.split('\n').find((l) => l.startsWith('data:'));
      if (!dataLine) continue;
      const json = dataLine.slice(5).trim();
      if (!json) continue;
      let payload = null;
      try { payload = JSON.parse(json); } catch { continue; }
      if (!payload || typeof payload !== 'object') continue;
      if (payload.type === 'chunk' && payload.text) {
        try { onChunk?.(String(payload.text)); } catch {}
      } else if (payload.type === 'done') {
        finalResult = payload.result || null;
      } else if (payload.type === 'error') {
        throw new Error(String(payload.error || 'voice-agent stream error'));
      }
    }
  }
  return finalResult || {};
}

// Per-call streaming TTS dispatcher. Each chunk fetched and played sequentially,
// pre-fetching the next chunk while the current one plays for seamless audio.
function createStreamingTtsDispatcher(provider) {
  const voiceProvider = provider === 'openai' || provider === 'xai' ? provider : '';
  const selectedVoice = provider === 'xai'
    ? (desktopVoiceSettings.serverVoice || getStoredVoiceSetting(`voice_${voiceProvider}_voice`, 'eve'))
    : (voiceProvider ? getStoredVoiceSetting(`voice_${voiceProvider}_voice`, 'alloy') : '');
  const fetchChunk = async (chunk) => {
    const body = { provider, text: chunk };
    if (provider === 'openai' && selectedVoice) body.voice = selectedVoice;
    if (provider === 'xai' && selectedVoice) body.voiceId = selectedVoice;
    if (provider === 'xai') body.speed = Number(desktopVoiceSettings.xaiSpeed || 1.0);
    const response = await fetch('/api/voice/tts', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
    });
    const data = await response.json().catch(() => ({}));
    if (!response.ok || data?.success === false) throw new Error(data?.error || `TTS failed (${response.status})`);
    return data;
  };
  // Sequential playback chain — each enqueue chains the next fetch + play.
  // The TTS fetch begins immediately when a chunk arrives from the server.
  let chain = Promise.resolve();
  let pendingFetch = null;
  return {
    enqueue(text) {
      const t = String(text || '').trim();
      if (!t) return;
      // Kick off the fetch right away (don't wait for the previous chunk to finish).
      const fetched = fetchChunk(t).catch((err) => {
        console.warn('[voice-agent] streaming TTS fetch failed:', err);
        return null;
      });
      chain = chain
        .catch(() => {})
        .then(async () => {
          const data = await fetched;
          if (!data) return;
          try { await playAudioBase64(data.audioBase64, data.mimeType); } catch {}
        });
    },
    wait() { return chain.catch(() => {}); },
  };
}

async function speakWithServerTts(text, provider) {
  const chunkMax = provider === 'groq' ? 180 : 400;
  const chunks = splitVoiceText(text, chunkMax).filter(Boolean);
  if (!chunks.length) return;
  const voiceProvider = provider === 'openai' || provider === 'xai' ? provider : '';
  const selectedVoice = provider === 'xai'
    ? (desktopVoiceSettings.serverVoice || getStoredVoiceSetting(`voice_${voiceProvider}_voice`, 'eve'))
    : (voiceProvider ? getStoredVoiceSetting(`voice_${voiceProvider}_voice`, 'alloy') : '');
  const fetchChunk = async (chunk) => {
    const body = { provider, text: chunk };
    if (provider === 'openai' && selectedVoice) body.voice = selectedVoice;
    if (provider === 'xai' && selectedVoice) body.voiceId = selectedVoice;
    if (provider === 'xai') body.speed = Number(desktopVoiceSettings.xaiSpeed || 1.0);
    const response = await fetch('/api/voice/tts', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
    });
    const data = await response.json().catch(() => ({}));
    if (!response.ok || data?.success === false) throw new Error(data?.error || `TTS failed (${response.status})`);
    return data;
  };
  // Pipeline: pre-fetch the next chunk while the current one plays so audio is
  // ready immediately after each segment ends — first audio byte arrives faster
  // on multi-sentence replies.
  let nextFetch = fetchChunk(chunks[0]);
  for (let i = 0; i < chunks.length; i++) {
    const data = await nextFetch;
    if (i + 1 < chunks.length) nextFetch = fetchChunk(chunks[i + 1]);
    await playAudioBase64(data.audioBase64, data.mimeType);
  }
}

async function speakAssistantReply(text) {
  text = cleanVoiceSpeechText(text);
  if (!text) return;
  if (getRealtimeWakeGate()?.suppressVoice) return;
  if (realtimeVoiceRepliesEnabled) {
    await speakWithRealtimeVoice(text);
    return;
  }

  if (!voiceRepliesEnabled) return;
  const provider = voiceTtsProvider || 'browser';
  if (provider === 'browser') {
    speakWithBrowserVoice(text);
    return;
  }
  if (provider === 'openai_realtime') {
    await speakWithRealtimeVoice(text);
    return;
  }
  const selected = getProviderInfo('tts', provider);
  if (selected && !selected.configured) throw new Error(`${selected.label} needs its API key on the gateway.`);
  await speakWithServerTts(text, provider);
}

async function toggleRealtimeVoiceReplies() {
  const xaiRealtime = wantsXaiRealtimeMode();
  if (xaiRealtime) {
    if (!(await isXaiRealtimeConfigured())) {
      // Not configured for realtime — let the caller fall back to standard xAI.
      throw new Error('xAI realtime not configured');
    }
  } else {
    await refreshRealtimeVoiceStatus();
    if (!realtimeVoiceConfigured) {
      setRegularVoiceControlsVisible(true);
      renderVoiceProviderControls();
      showToast('Realtime voice not configured', 'Connect OpenAI Codex OAuth or set an OpenAI Realtime API key on the gateway.', 'error');
      return;
    }
  }
  if (realtimeVoiceStarting) {
    disableRealtimeVoiceMode();
    showToast('Realtime voice cancelled', '', 'info', 1400);
    return;
  }
  realtimeVoiceModeEpoch += 1;
  const epoch = realtimeVoiceModeEpoch;
  const nextEnabled = !realtimeVoiceRepliesEnabled;
  if (nextEnabled) {
    voiceRepliesEnabled = false;
    realtimeVoicePlaybackWarningShown = false;
    saveDesktopVoiceSettings(xaiRealtime
      ? {
          voiceMode: 'xai',
          voiceAgentXaiRealtime: true,
          realtimeVoice: normalizeXaiRealtimeVoice(realtimeVoiceSelection),
          xaiSpeed: Number(desktopVoiceSettings.xaiSpeed || realtimeVoiceSpeed || 1.0),
        }
      : {
          voiceMode: 'openai_realtime',
          sttProvider: 'browser',
          ttsProvider: 'browser',
          realtimeVoice: realtimeVoiceSelection || 'marin',
          realtimeSpeed: realtimeVoiceSpeed,
        });
    if (voiceDictationActive && voiceRecognition) {
      try { voiceRecognition.stop(); } catch {}
    }
    if (backendVoiceRecorder) {
      try { backendVoiceRecorder.stop(); } catch {}
    }

    // Full Realtime end-to-end agent path — single OpenAI session does STT,
    // reasoning, TTS, and tool calls. Replaces the legacy transcription +
    // gateway voice agent + TTS split flow.
    if (wantsVoiceAgentRealtimeMode()) {
      const listenMode = !realtimeUsesHoldSpace() ? 'always_listening' : 'push_to_talk';
      const listenMessage = listenMode === 'always_listening'
        ? 'Realtime end-to-end agent is listening. Speak naturally — Prometheus hears, thinks, and replies in one OpenAI session.'
        : 'Realtime end-to-end agent is ready. Hold Space to talk.';
      realtimeVoiceStarting = true;
      setRealtimeVoiceButtonState();
      showToast('Starting realtime agent', listenMode === 'always_listening' ? 'Opening your microphone and realtime session...' : 'Opening realtime session...', 'info', 2200);
      const sid = window.activeChatSessionId || 'default';
      try {
        await startVoiceAgentRealtimeSession(sid, { listenMode });
        if (realtimeVoiceModeEpoch !== epoch) return;
        realtimeVoiceStarting = false;
        realtimeVoiceRepliesEnabled = true;
        setRegularVoiceControlsVisible(false);
        setRealtimeVoiceControlsVisible(true);
        renderVoiceProviderControls();
        renderRealtimeVoiceSelect().catch(() => {});
        if (listenMode === 'always_listening') setVoiceAgentRealtimeMicEnabled(true);
        addSessionProcessEntry(sid, 'info', `Realtime agent connected (${listenMode}).`, { actor: 'Voice Agent (Realtime)' });
        setRealtimeVoiceButtonState();
        showToast('Realtime agent on', listenMessage, 'success', 3200);
      } catch (err) {
        if (realtimeVoiceModeEpoch !== epoch || /stopped/i.test(String(err?.message || err))) return;
        realtimeVoiceStarting = false;
        realtimeVoiceRepliesEnabled = false;
        realtimeVoiceModeEpoch += 1;
        stopVoiceAgentRealtimeSession();
        setRegularVoiceControlsVisible(true);
        renderVoiceProviderControls();
        setRealtimeVoiceButtonState();
        // For xAI, let the caller fall back to the standard STT/TTS route.
        if (xaiRealtime) throw err;
        showToast('Realtime agent failed', String(err?.message || err), 'error');
      }
      return;
    }

    realtimeVoiceRepliesEnabled = true;
    setRegularVoiceControlsVisible(false);
    setRealtimeVoiceControlsVisible(true);
    renderVoiceProviderControls();
    renderRealtimeVoiceSelect().catch(() => {});
    setRealtimeVoiceButtonState();
    const listenMessage = realtimeUsesHoldSpace()
      ? 'Hold Space to talk. Release to send.'
      : realtimeListenMode === 'confirm_send'
        ? 'Speak naturally. Say "send message" when you want Prometheus to receive it.'
        : 'Speak naturally. Prometheus will receive the transcript and answer aloud.';
    showToast('Realtime voice on', listenMessage, 'success', 2600);
    renderRealtimeWakeGateState();
    if (realtimeAllowsContinuousCapture()) {
      startRealtimeInputCapture().catch((err) => {
        if (!realtimeVoiceRepliesEnabled || realtimeVoiceModeEpoch !== epoch || /stopped|inactive/i.test(String(err?.message || err))) return;
        realtimeVoiceRepliesEnabled = false;
        realtimeVoiceModeEpoch += 1;
        resetRealtimeSessionWakePhrase({ clearInput: true });
        closeRealtimeDictationConnection();
        closeRealtimeVoiceConnection();
        stopRealtimeDraftRecognition();
        setRegularVoiceControlsVisible(true);
        renderVoiceProviderControls();
        setRealtimeVoiceButtonState();
        showToast('Realtime microphone failed', String(err?.message || err), 'error');
      });
    }
    ensureRealtimeVoiceConnection().catch((err) => {
      if (!realtimeVoiceRepliesEnabled || realtimeVoiceModeEpoch !== epoch || /stopped/i.test(String(err?.message || err))) return;
      realtimeVoiceRepliesEnabled = false;
      realtimeVoiceModeEpoch += 1;
      resetRealtimeSessionWakePhrase({ clearInput: true });
      closeRealtimeDictationConnection();
      closeRealtimeVoiceConnection();
      stopRealtimeDraftRecognition();
      setRegularVoiceControlsVisible(true);
      renderVoiceProviderControls();
      setRealtimeVoiceButtonState();
      showToast('Realtime voice failed', String(err?.message || err), 'error');
    });
  } else {
    realtimeVoiceRepliesEnabled = false;
    setRealtimeVoiceButtonState();
    realtimeHoldSpaceActive = false;
    clearRealtimeAssistantSpeakingState();
    resetRealtimeSessionWakePhrase({ clearInput: true });
    stopVoiceAgentRealtimeSession();
    closeRealtimeDictationConnection();
    closeRealtimeVoiceConnection();
    stopRealtimeDraftRecognition();
    resetRealtimeDictationTranscript();
    renderVoiceProviderControls();
    try { window.speechSynthesis?.cancel?.(); } catch {}
    showToast('Realtime voice off', '', 'info', 1600);
  }
}

