function getCreativeRenderJobEntry(jobId) {
  const normalizedId = String(jobId || '').trim();
  if (!normalizedId) return null;
  return Array.isArray(creativeAssetsState.renderJobs)
    ? creativeAssetsState.renderJobs.find((candidate) => String(candidate?.id || '').trim() === normalizedId) || null
    : null;
}

function mergeCreativeRenderJobEntry(entry, options = {}) {
  const jobId = String(entry?.id || '').trim();
  if (!jobId) return null;
  const nextEntry = Object.entries(entry || {}).reduce((acc, [key, value]) => {
    if (value !== undefined) acc[key] = value;
    return acc;
  }, { id: jobId });
  const existing = Array.isArray(creativeAssetsState.renderJobs)
    ? creativeAssetsState.renderJobs.find((candidate) => String(candidate?.id || '').trim() === jobId) || null
    : null;
  const merged = {
    ...(existing || {}),
    ...nextEntry,
    updatedAt: nextEntry.updatedAt || existing?.updatedAt || new Date().toISOString(),
  };
  const nextJobs = Array.isArray(creativeAssetsState.renderJobs)
    ? creativeAssetsState.renderJobs.filter((candidate) => String(candidate?.id || '').trim() !== jobId)
    : [];
  nextJobs.push(merged);
  creativeAssetsState = {
    ...creativeAssetsState,
    renderJobs: sortCreativeRenderJobEntries(nextJobs),
    counts: {
      ...(creativeAssetsState.counts || {}),
      jobs: Math.max(nextJobs.length, Number(creativeAssetsState.counts?.jobs) || 0),
    },
  };
  if (options.render !== false) renderCreativeWorkspace();
  return merged;
}

