let _iconifyDebounceTimer = null;
async function canvasSearchIconify(query) {
  const q = String(query || '').trim();
  // Update query state immediately but don't re-render — that would blow away the input/focus.
  creativeIconifySearch.query = q;
  if (_iconifyDebounceTimer) { clearTimeout(_iconifyDebounceTimer); _iconifyDebounceTimer = null; }
  if (!q) {
    creativeIconifySearch = { query: '', results: [], loading: false, error: '' };
    renderCreativeWorkspace({ skipStageRender: true });
    refocusIconifySearchInput();
    return;
  }
  _iconifyDebounceTimer = setTimeout(async () => {
    creativeIconifySearch = { query: q, results: creativeIconifySearch.results, loading: true, error: '' };
    renderCreativeWorkspace({ skipStageRender: true });
    refocusIconifySearchInput();
    try {
      const res = await fetch(`https://api.iconify.design/search?query=${encodeURIComponent(q)}&limit=64`);
      const data = await res.json();
      creativeIconifySearch = { query: q, results: Array.isArray(data.icons) ? data.icons : [], loading: false, error: '' };
    } catch (err) {
      creativeIconifySearch = { ...creativeIconifySearch, loading: false, error: 'Search failed. Check connection.' };
    }
    renderCreativeWorkspace({ skipStageRender: true });
    refocusIconifySearchInput();
  }, 280);
}

function refocusIconifySearchInput() {
  setTimeout(() => {
    const input = document.querySelector('#canvas-creative-library input[type="search"]');
    if (input && document.activeElement !== input) {
      input.focus();
      const len = input.value.length;
      try { input.setSelectionRange(len, len); } catch {}
    }
  }, 0);
}

function canvasAddIconifyIcon(iconName) {
  const name = String(iconName || '').trim();
  if (!name) return;
  ensureCreativeSceneForMode(window.currentCreativeMode);
  const nextZ = creativeSceneDoc.elements.length;
  const baseX = 96 + (creativeSceneDoc.elements.length % 4) * 56;
  const baseY = 120 + (creativeSceneDoc.elements.length % 5) * 44;
  const patch = { op: 'add', type: 'icon', x: baseX, y: baseY, width: 84, height: 84, zIndex: nextZ, meta: { iconName: name, color: '#111827' } };
  const nextDoc = executeSceneGraphOps(creativeSceneDoc, [patch]);
  const added = nextDoc.elements[nextDoc.elements.length - 1];
  setCreativeSceneDoc(nextDoc, { render: false, recordHistory: true });
  setCreativeSelection(added?.id || null, { render: false });
  renderCreativeWorkspace();
}

