async function canvasImportCreativeLibraryManifest(source = 'text') {
  const sessionId = getActiveCreativeSessionId();
  const mode = normalizeCreativeMode(window.currentCreativeMode);
  if (!sessionId || !isStructuredCreativeMode(mode)) return null;
  const importMode = String(source || 'text').trim().toLowerCase();
  const manifestText = String(creativeLibraryImportDraft.manifestText || '').trim();
  const sourceUrl = String(creativeLibraryImportDraft.sourceUrl || '').trim();
  if (importMode === 'url' && !sourceUrl) {
    showToast('Manifest URL required', 'Paste a manifest URL before importing.', 'info');
    return null;
  }
  if (importMode !== 'url' && !manifestText) {
    showToast('Manifest JSON required', 'Paste a manifest JSON block or load a local pack file first.', 'info');
    return null;
  }
  creativeLibrariesState = {
    ...creativeLibrariesState,
    loading: true,
    error: '',
  };
  renderCreativeWorkspace();
  try {
    const response = await fetch('/api/canvas/creative-libraries/import', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        sessionId,
        mode,
        root: canvasProjectRoot || '',
        enabled: true,
        sourceUrl: importMode === 'url' ? sourceUrl : '',
        manifestText: importMode === 'url' ? '' : manifestText,
      }),
    });
    const data = await response.json().catch(() => ({}));
    if (!response.ok || data?.success === false) {
      throw new Error(data?.error || `HTTP ${response.status}`);
    }
    creativeLibraryImportDraft = {
      manifestText: '',
      sourceUrl: '',
      fileName: '',
    };
    syncCreativeLibrariesFromPayload(data, {
      sessionId,
      mode,
      key: getCreativeLibrariesRequestKey(mode),
      root: canvasProjectRoot || '',
    });
    showToast('Creative pack imported', `${data?.importedLibraryId || 'Custom pack'} is now available in the studio rail.`, 'success');
    renderCreativeWorkspace();
    persistActiveChat();
    return data;
  } catch (err) {
    creativeLibrariesState = {
      ...creativeLibrariesState,
      loading: false,
      error: String(err?.message || err || 'Could not import creative library pack.'),
    };
    showToast('Could not import creative library', creativeLibrariesState.error, 'error');
    renderCreativeWorkspace();
    return null;
  }
}

async function canvasRemoveCreativeLibraryPack(libraryId) {
  const sessionId = getActiveCreativeSessionId();
  const mode = normalizeCreativeMode(window.currentCreativeMode);
  const normalizedId = String(libraryId || '').trim().toLowerCase();
  if (!sessionId || !normalizedId || !isStructuredCreativeMode(mode)) return null;
  const ok = typeof confirm === 'function' ? confirm(`Remove the custom library pack "${normalizedId}" from this creative workspace?`) : true;
  if (!ok) return null;
  creativeLibrariesState = {
    ...creativeLibrariesState,
    loading: true,
    error: '',
  };
  renderCreativeWorkspace();
  try {
    const params = new URLSearchParams({
      sessionId,
      root: canvasProjectRoot || '',
    });
    const response = await fetch(`/api/canvas/creative-libraries/${encodeURIComponent(normalizedId)}?${params.toString()}`, {
      method: 'DELETE',
    });
    const data = await response.json().catch(() => ({}));
    if (!response.ok || data?.success === false) {
      throw new Error(data?.error || `HTTP ${response.status}`);
    }
    syncCreativeLibrariesFromPayload(data, {
      sessionId,
      mode,
      key: getCreativeLibrariesRequestKey(mode),
      root: canvasProjectRoot || '',
    });
    showToast('Creative pack removed', `${normalizedId} has been removed from the workspace library registry.`, 'success');
    renderCreativeWorkspace();
    persistActiveChat();
    return data;
  } catch (err) {
    creativeLibrariesState = {
      ...creativeLibrariesState,
      loading: false,
      error: String(err?.message || err || 'Could not remove creative library pack.'),
    };
    showToast('Could not remove creative library', creativeLibrariesState.error, 'error');
    renderCreativeWorkspace();
    return null;
  }
}

function ensureCreativeAssetsHydrated(mode = window.currentCreativeMode) {
  const normalizedMode = normalizeCreativeMode(mode);
  const sessionId = getActiveCreativeSessionId();
  if (!sessionId || !isStructuredCreativeMode(normalizedMode)) return;
  const requestKey = getCreativeAssetsRequestKey(normalizedMode);
  if (creativeAssetsState.loading && creativeAssetsState.key === requestKey) return;
  if (creativeAssetsState.key === requestKey && creativeAssetsState.loadedAt && !creativeAssetsState.error) return;
  loadCreativeAssets({ mode: normalizedMode, silent: true, renderStart: false }).catch(() => {});
}

async function loadCreativeAssets(options = {}) {
  const sessionId = getActiveCreativeSessionId();
  const normalizedMode = normalizeCreativeMode(options.mode || window.currentCreativeMode);
  if (!sessionId || !isStructuredCreativeMode(normalizedMode)) {
    creativeAssetsState = {
      key: '',
      sessionId: '',
      mode: null,
      storageRoot: '',
      storageRootRelative: '',
      usesProjectRoot: false,
      renderJobsDir: '',
      renderJobsDirRelative: '',
      scenes: [],
      renderJobs: [],
      exports: [],
      counts: { scenes: 0, exports: 0, jobs: 0 },
      loadedAt: 0,
      loading: false,
      error: '',
    };
    creativeLibrariesState = {
      key: '',
      sessionId: '',
      mode: null,
      storageRoot: '',
      storageRootRelative: '',
      usesProjectRoot: false,
      librariesDir: '',
      librariesDirRelative: '',
      libraries: [],
      customPacks: [],
      enabledLibraryIds: [],
      loadedAt: 0,
      loading: false,
      error: '',
    };
    setCreativeLibraryRuntimePacks([]);
    if (window.prometheusCreativeCore && typeof window.prometheusCreativeCore === 'object') {
      window.prometheusCreativeCore.libraryPacks = getCreativeLibraryPackCatalog([]);
      window.prometheusCreativeCore.elementLibrary = getCreativeElementLibrary([]);
      window.prometheusCreativeCore.enabledLibraryIds = getEnabledCreativeLibraryIds([]);
    }
    return null;
  }
  const rootHint = normalizeCanvasPath(options.root || canvasProjectRoot || '');
  const requestKey = `${sessionId}::${normalizedMode}::${rootHint}`;
  if (!options.force) {
    if (creativeAssetsState.loading && creativeAssetsState.key === requestKey) return creativeAssetsState;
    if (creativeAssetsState.key === requestKey && creativeAssetsState.loadedAt && !creativeAssetsState.error) return creativeAssetsState;
  }
  const preserveExisting = creativeAssetsState.key === requestKey;
  creativeAssetsState = {
    ...creativeAssetsState,
    key: requestKey,
    sessionId,
    mode: normalizedMode,
    storageRoot: preserveExisting ? creativeAssetsState.storageRoot : '',
    storageRootRelative: preserveExisting ? creativeAssetsState.storageRootRelative : '',
    usesProjectRoot: preserveExisting ? creativeAssetsState.usesProjectRoot : false,
    renderJobsDir: preserveExisting ? creativeAssetsState.renderJobsDir : '',
    renderJobsDirRelative: preserveExisting ? creativeAssetsState.renderJobsDirRelative : '',
    scenes: preserveExisting ? creativeAssetsState.scenes : [],
    renderJobs: preserveExisting ? creativeAssetsState.renderJobs : [],
    exports: preserveExisting ? creativeAssetsState.exports : [],
    indexedAssets: preserveExisting ? creativeAssetsState.indexedAssets : [],
    counts: preserveExisting ? creativeAssetsState.counts : { scenes: 0, exports: 0, jobs: 0, indexedAssets: 0 },
    loadedAt: preserveExisting ? creativeAssetsState.loadedAt : 0,
    loading: true,
    error: '',
  };
  if (options.renderStart !== false) renderCreativeWorkspace();
  const requestToken = ++creativeAssetsRequestToken;
  try {
    const params = new URLSearchParams({ sessionId });
    if (rootHint) params.set('root', rootHint);
    const response = await fetch(`/api/canvas/creative-assets?${params.toString()}`);
    const data = await response.json().catch(() => ({}));
    if (!response.ok || data?.success === false) {
      throw new Error(data?.error || `HTTP ${response.status}`);
    }
    if (requestToken !== creativeAssetsRequestToken) return creativeAssetsState;
    syncCreativeLibrariesFromPayload(data, { sessionId, mode: normalizedMode, key: requestKey, root: rootHint });
    creativeAssetsState = {
      key: requestKey,
      sessionId,
      mode: normalizedMode,
      storageRoot: normalizeCanvasPath(data?.storageRoot || rootHint || ''),
      storageRootRelative: normalizeCanvasPath(data?.storageRootRelative || ''),
      usesProjectRoot: !!data?.usesProjectRoot,
      renderJobsDir: normalizeCanvasPath(data?.renderJobsDir || ''),
      renderJobsDirRelative: normalizeCanvasPath(data?.renderJobsDirRelative || ''),
      scenes: Array.isArray(data?.sceneEntries) ? data.sceneEntries : [],
      renderJobs: Array.isArray(data?.renderJobEntries) ? data.renderJobEntries : [],
      exports: Array.isArray(data?.exportEntries) ? data.exportEntries : [],
      indexedAssets: Array.isArray(data?.indexedAssets) ? data.indexedAssets : [],
      counts: {
        scenes: Number(data?.counts?.scenes) || (Array.isArray(data?.sceneEntries) ? data.sceneEntries.length : 0),
        jobs: Number(data?.counts?.jobs) || (Array.isArray(data?.renderJobEntries) ? data.renderJobEntries.length : 0),
        exports: Number(data?.counts?.exports) || (Array.isArray(data?.exportEntries) ? data.exportEntries.length : 0),
        indexedAssets: Number(data?.counts?.indexedAssets) || (Array.isArray(data?.indexedAssets) ? data.indexedAssets.length : 0),
      },
      loadedAt: Date.now(),
      loading: false,
      error: '',
    };
    window.prometheusCreativeAssetsState = creativeAssetsState;
    try {
      window.prometheusCreativeEditor?.hydrateCreativeAssets?.(creativeAssetsState);
    } catch (err) {
      console.warn('Could not hydrate Prometheus Video editor assets:', err);
    }
    return creativeAssetsState;
  } catch (err) {
    if (requestToken !== creativeAssetsRequestToken) return null;
    creativeAssetsState = {
      ...creativeAssetsState,
      key: requestKey,
      sessionId,
      mode: normalizedMode,
      loading: false,
      error: String(err?.message || err || 'Could not load creative assets.'),
    };
    if (!options.silent) {
      showToast('Could not load creative assets', creativeAssetsState.error, 'error');
    }
    return null;
  } finally {
    if (requestToken === creativeAssetsRequestToken && options.renderEnd !== false) {
      renderCreativeWorkspace();
    }
  }
}

async function canvasRefreshCreativeAssets() {
  await loadCreativeAssets({ force: true });
}

async function canvasRevealCreativeStorageRoot() {
  const mode = normalizeCreativeMode(window.currentCreativeMode);
  const storageRoot = normalizeCanvasPath(creativeAssetsState.storageRoot || canvasProjectRoot || '');
  if (!storageRoot) {
    showToast('No creative storage root yet', 'Save a scene or export an asset first so Prometheus has a workspace folder to reveal.', 'info');
    return;
  }
  if (!canvasProjectRoot) {
    setCanvasProjectState(storageRoot, getCreativeWorkspaceLabel(mode), { refreshPublish: false });
    await canvasLoadWorkspaceFiles(storageRoot).catch(() => {});
  }
  await openInFileLocation(storageRoot);
}

async function canvasSaveCreativeSceneSnapshot(options = {}) {
  const mode = normalizeCreativeMode(options.mode || window.currentCreativeMode);
  if (!isStructuredCreativeMode(mode)) return null;
  if (creativeSceneSavePending) return null;
  creativeSceneSavePending = true;
  renderCreativeWorkspace();
  try {
    const filename = options.filename || `${getCreativeArtifactStem(mode)}-scene-${buildCreativeArtifactTimestamp()}.json`;
    const result = await persistCreativeSceneSnapshot({ mode, filename });
    addProcessEntry('info', `${getStructuredCreativeModeLabel(mode)}: saved scene snapshot ${result?.path || filename}.`);
    await loadCreativeAssets({ force: true, silent: true, renderStart: false, renderEnd: false });
    showToast('Scene snapshot saved', result?.path || filename, 'success');
    return result;
  } catch (err) {
    const message = String(err?.message || err || 'Could not save scene snapshot.');
    addProcessEntry('warn', `${getStructuredCreativeModeLabel(mode)}: could not save scene snapshot (${message})`);
    showToast('Could not save scene snapshot', message, 'error');
    return null;
  } finally {
    creativeSceneSavePending = false;
    renderCreativeWorkspace();
  }
}

async function canvasLoadCreativeSceneAsset(scenePath) {
  const normalizedPath = normalizeCanvasPath(scenePath);
  if (!normalizedPath) return;
  try {
    if (activeCreativeStageGesture) endCreativeStageGesture({ persist: false, render: false });
    if (activeCreativeTimelineGesture) endCreativeTimelineGesture({ persist: false, render: false });
    if (isCreativePlaybackActive()) stopCreativePlayback({ persist: false });
    const response = await fetch(`/api/canvas/creative-scene?path=${encodeURIComponent(normalizedPath)}`);
    const data = await response.json().catch(() => ({}));
    if (!response.ok || data?.success === false) {
      throw new Error(data?.error || `HTTP ${response.status}`);
    }
    const nextMode = normalizeCreativeMode(data?.meta?.creativeMode || window.currentCreativeMode);
    const sessionId = getActiveCreativeSessionId();
    if (sessionId && isStructuredCreativeMode(nextMode) && nextMode !== normalizeCreativeMode(window.currentCreativeMode)) {
      try {
        const savedMode = await persistCreativeMode(sessionId, nextMode);
        applySessionCreativeMode(sessionId, savedMode);
      } catch {
        applySessionCreativeMode(sessionId, nextMode);
      }
    }
    if (data?.meta?.storageRoot) {
      await ensureCreativeStorageRootVisible({ storageRoot: data.meta.storageRoot }, nextMode);
    }
    commitCreativeHistorySnapshot(captureCreativeSnapshot());
    const nextDoc = createSceneDocument(data?.doc || {});
    const nextSelectedId = nextDoc.elements[nextDoc.elements.length - 1]?.id || null;
    restoreCreativeSnapshot({
      doc: nextDoc,
      selectedId: nextSelectedId,
      timelineMs: 0,
    }, { render: false, persist: false });
    persistActiveChat();
    renderCreativeWorkspace();
    await loadCreativeAssets({ force: true, silent: true, renderStart: false, renderEnd: false });
    addProcessEntry('info', `${getStructuredCreativeModeLabel(nextMode)}: loaded saved scene ${normalizedPath}.`);
    showToast('Scene loaded', normalizedPath, 'success');
  } catch (err) {
    const message = String(err?.message || err || 'Could not load creative scene.');
    addProcessEntry('warn', `Creative scene load failed (${message})`);
    showToast('Could not load scene', message, 'error');
  }
}

function isCreativeVideoMediaPath(value = '') {
  const ext = String(value || '').split('?')[0].split('#')[0].split('.').pop().toLowerCase();
  return /^(mp4|mov|m4v|webm|avi|mkv|mpeg|mpg|3gp)$/i.test(ext);
}

function isCreativeImageMediaPath(value = '') {
  const ext = String(value || '').split('?')[0].split('#')[0].split('.').pop().toLowerCase();
  return /^(png|jpg|jpeg|webp|gif|svg)$/i.test(ext);
}

function canvasPlaceCreativeExportOnCanvas(sourcePath, filename = '') {
  const source = normalizeCanvasPath(sourcePath);
  if (!source) {
    showToast('No export path found', 'The selected export does not have a workspace path to place on the canvas.', 'error');
    return null;
  }
  const isVideoAsset = isCreativeVideoMediaPath(source);
  const isImageAsset = isCreativeImageMediaPath(source);
  if (!isVideoAsset && !isImageAsset) {
    showToast('Asset type cannot be placed here', filename || source, 'info');
    return null;
  }
  const mode = normalizeCreativeMode(window.currentCreativeMode);
  if (isVideoAsset && mode !== 'video') {
    showToast('Switch to Creative Video first', 'Video exports can be placed as live layers in the video workspace.', 'info');
    return null;
  }
  if (isImageAsset && mode !== 'image') {
    showToast('Switch to Creative Image first', 'Image assets can be placed as editable image layers in the image workspace.', 'info');
    return null;
  }
  if (isCreativePlaybackActive()) stopCreativePlayback({ persist: false });
  const result = applyCreativeAddAssetCommand({
    source,
    type: isVideoAsset ? 'video' : 'image',
    x: 0,
    y: 0,
    width: Math.max(1, Number(creativeSceneDoc?.width) || 1080),
    height: Math.max(1, Number(creativeSceneDoc?.height) || 1920),
    zIndex: (creativeSceneDoc?.elements || []).length,
    fit: 'contain',
    radius: 0,
    muted: true,
    volume: 0,
    startMs: 0,
    durationMs: Math.max(1000, Number(creativeSceneDoc?.durationMs) || 12000),
    meta: {
      label: filename || source.split(/[\\/]/).pop() || (isVideoAsset ? 'Video export' : 'Image asset'),
      sourceKind: isVideoAsset ? 'creative-export' : 'creative-layer-asset',
    },
  });
  showToast(isVideoAsset ? 'Video export placed on canvas' : 'Image asset placed on canvas', filename || source, 'success');
  return result;
}

async function buildCreativeExportSvgMarkup() {
  if (isCreativeFabricRendererAvailable(window.currentCreativeMode)) {
    await Promise.resolve(creativeFabricLastRenderPromise).catch(() => null);
    const sourceCanvas = creativeFabricBridge?.canvas;
    if (sourceCanvas && typeof sourceCanvas.toSVG === 'function') {
      const restoreFabricExportState = prepareCreativeFabricCanvasForCleanExport();
      try {
        const svgMarkup = sourceCanvas.toSVG();
        return String(svgMarkup || '').startsWith('<?xml')
          ? String(svgMarkup)
          : `<?xml version="1.0" encoding="UTF-8"?>\n${svgMarkup}`;
      } finally {
        restoreFabricExportState?.();
      }
    }
  }
    const stage = document.getElementById('canvas-creative-stage');
    if (!stage) throw new Error('Creative stage is not available.');
    await syncCreativeVideoElementsToTimeline();
    const clone = stage.cloneNode(true);
    clone.querySelectorAll('video[data-creative-video-element]').forEach((node) => {
      if (node instanceof HTMLElement) {
        node.style.opacity = '0';
        node.style.background = 'transparent';
        node.removeAttribute('src');
      }
    });
    clone.querySelectorAll('[data-creative-resize-handle="true"]').forEach((node) => node.remove());
  clone.querySelectorAll('[data-creative-selection="true"]').forEach((node) => {
    if (node instanceof HTMLElement) node.style.boxShadow = 'none';
  });
  const nodes = [clone, ...clone.querySelectorAll('*')];
  nodes.forEach((node) => {
    if (!(node instanceof HTMLElement)) return;
    node.style.outline = 'none';
    node.style.outlineOffset = '0';
    node.style.cursor = 'default';
  });
  clone.style.margin = '0';
  clone.style.width = `${creativeSceneDoc.width}px`;
  clone.style.height = `${creativeSceneDoc.height}px`;
  clone.style.maxWidth = 'none';
  return `<?xml version="1.0" encoding="UTF-8"?>
<svg xmlns="http://www.w3.org/2000/svg" width="${creativeSceneDoc.width}" height="${creativeSceneDoc.height}" viewBox="0 0 ${creativeSceneDoc.width} ${creativeSceneDoc.height}">
  <foreignObject x="0" y="0" width="${creativeSceneDoc.width}" height="${creativeSceneDoc.height}">
    <div xmlns="http://www.w3.org/1999/xhtml" style="width:${creativeSceneDoc.width}px;height:${creativeSceneDoc.height}px;overflow:hidden;background:${creativeSceneDoc.background || '#ffffff'};font-family:Manrope, Arial, sans-serif;">
      ${clone.outerHTML}
    </div>
  </foreignObject>
</svg>`;
}

function loadImageFromUrl(url) {
  return new Promise((resolve, reject) => {
    const image = new Image();
    image.onload = () => resolve(image);
    image.onerror = () => reject(new Error('Could not rasterize creative export.'));
    image.src = url;
  });
}

async function renderCreativeExportCanvas(format = 'png') {
  if (isCreativeFabricRendererAvailable(window.currentCreativeMode)) {
    await Promise.resolve(creativeFabricLastRenderPromise).catch(() => null);
    const restoreFabricExportState = prepareCreativeFabricCanvasForCleanExport();
    try {
      const sourceCanvas = getActiveCreativeFabricExportCanvas();
      if (sourceCanvas) {
        const canvas = document.createElement('canvas');
        canvas.width = creativeSceneDoc.width;
        canvas.height = creativeSceneDoc.height;
        const ctx = canvas.getContext('2d');
        if (!ctx) throw new Error('Canvas export context is unavailable.');
        if (String(format).toLowerCase() === 'jpeg') {
          ctx.fillStyle = creativeSceneDoc.background || '#ffffff';
          ctx.fillRect(0, 0, canvas.width, canvas.height);
        }
        ctx.drawImage(sourceCanvas, 0, 0, canvas.width, canvas.height);
        return canvas;
      }
    } finally {
      restoreFabricExportState?.();
    }
  }
  const svgMarkup = await buildCreativeExportSvgMarkup();
  const svgBlob = new Blob([svgMarkup], { type: 'image/svg+xml;charset=utf-8' });
  const svgUrl = URL.createObjectURL(svgBlob);
  try {
    const image = await loadImageFromUrl(svgUrl);
    const canvas = document.createElement('canvas');
    canvas.width = creativeSceneDoc.width;
    canvas.height = creativeSceneDoc.height;
    const ctx = canvas.getContext('2d');
    if (!ctx) throw new Error('Canvas export context is unavailable.');
      if (String(format).toLowerCase() === 'jpeg') {
        ctx.fillStyle = creativeSceneDoc.background || '#ffffff';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
      }
      drawCreativeVideoLayersOnCanvas(ctx);
      ctx.drawImage(image, 0, 0, canvas.width, canvas.height);
      return canvas;
  } finally {
    URL.revokeObjectURL(svgUrl);
  }
}

function sanitizeCreativeLayerAssetName(raw, fallback = 'layer') {
  return String(raw || fallback)
    .trim()
    .replace(/[^a-zA-Z0-9._\-() ]/g, '_')
    .replace(/\s+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 80) || fallback;
}

function getCreativeLayerAssetExportCandidates(options = {}) {
  const selectedOnly = options.selectedOnly === true;
  const selectedId = String(options.elementId || creativeSelectedId || '').trim();
  return (creativeSceneDoc?.elements || [])
    .filter((element) => {
      if (!element || element.visible === false) return false;
      if (selectedOnly && element.id !== selectedId) return false;
      const type = String(element.type || '').toLowerCase();
      if (!['text', 'shape', 'image', 'icon', 'group'].includes(type)) return false;
      if (Math.max(1, Number(element.width) || 0) <= 1 || Math.max(1, Number(element.height) || 0) <= 1) return false;
      return true;
    })
    .sort((left, right) => (Number(left.zIndex) || 0) - (Number(right.zIndex) || 0));
}

async function hydrateCreativeLayerExportIcons(root) {
  const iconNodes = [...root.querySelectorAll('iconify-icon')];
  if (!iconNodes.length) return;
  const iconify = window.Iconify;
  if (!iconify?.renderSVG) return;
  const names = iconNodes.map((node) => String(node.getAttribute('icon') || '').trim()).filter(Boolean);
  if (names.length && typeof iconify.loadIcons === 'function') {
    await new Promise((resolve) => iconify.loadIcons([...new Set(names)], () => resolve()));
  }
  iconNodes.forEach((node) => {
    const iconName = String(node.getAttribute('icon') || '').trim();
    const svg = iconify.renderSVG(iconName, {
      width: node.getAttribute('width') || '100%',
      height: node.getAttribute('height') || '100%',
    });
    if (!svg) return;
    svg.setAttribute('width', node.getAttribute('width') || '100%');
    svg.setAttribute('height', node.getAttribute('height') || '100%');
    if (node.style?.color) svg.setAttribute('color', node.style.color);
    node.replaceWith(svg);
  });
}

function sanitizeCreativeLayerExportDom(root, element, width, height) {
  root.querySelectorAll('[data-creative-resize-handle="true"]').forEach((node) => node.remove());
  const nodes = [root, ...root.querySelectorAll('*')];
  nodes.forEach((node) => {
    if (!(node instanceof HTMLElement) && !(node instanceof SVGElement)) return;
    [...node.attributes].forEach((attr) => {
      if (/^on/i.test(attr.name)) node.removeAttribute(attr.name);
    });
    if (node instanceof HTMLElement) {
      node.style.outline = 'none';
      node.style.outlineOffset = '0';
      node.style.boxShadow = 'none';
      node.style.cursor = 'default';
      node.style.pointerEvents = 'none';
    }
  });
  root.style.position = 'absolute';
  root.style.left = '0';
  root.style.top = '0';
  root.style.width = `${width}px`;
  root.style.height = `${height}px`;
  root.style.transform = 'none';
  root.style.zIndex = '0';
  root.style.margin = '0';
  root.style.visibility = 'visible';
  root.style.pointerEvents = 'none';
  if (element?.type === 'image') {
    const body = root.firstElementChild;
    if (body instanceof HTMLElement) body.style.border = 'none';
  }
}

async function buildCreativeLayerExportSvgMarkup(element, mode) {
  const rendered = getRenderedCreativeElement(element, mode);
  const width = Math.max(1, Math.ceil(Number(rendered.width) || Number(element.width) || 1));
  const height = Math.max(1, Math.ceil(Number(rendered.height) || Number(element.height) || 1));
  const previousSelectedId = creativeSelectedId;
  let markup = '';
  try {
    creativeSelectedId = null;
    markup = renderCreativeStageElementStudioV3({ ...element, x: 0, y: 0, width, height, rotation: 0 }, mode);
  } finally {
    creativeSelectedId = previousSelectedId;
  }
  const holder = document.createElement('div');
  holder.innerHTML = markup;
  const root = holder.firstElementChild;
  if (!(root instanceof HTMLElement)) throw new Error('Could not prepare layer markup.');
  sanitizeCreativeLayerExportDom(root, element, width, height);
  await hydrateCreativeLayerExportIcons(root);
  return {
    width,
    height,
    svg: `<?xml version="1.0" encoding="UTF-8"?>
<svg xmlns="http://www.w3.org/2000/svg" width="${width}" height="${height}" viewBox="0 0 ${width} ${height}">
  <foreignObject x="0" y="0" width="${width}" height="${height}">
    <div xmlns="http://www.w3.org/1999/xhtml" style="position:relative;width:${width}px;height:${height}px;overflow:hidden;background:transparent;font-family:Manrope, Arial, sans-serif;">
      ${root.outerHTML}
    </div>
  </foreignObject>
</svg>`,
  };
}

async function renderCreativeElementLayerCanvas(element, mode) {
  const layerSvg = await buildCreativeLayerExportSvgMarkup(element, mode);
  const svgBlob = new Blob([layerSvg.svg], { type: 'image/svg+xml;charset=utf-8' });
  const svgUrl = URL.createObjectURL(svgBlob);
  try {
    const image = await loadImageFromUrl(svgUrl);
    const canvas = document.createElement('canvas');
    canvas.width = layerSvg.width;
    canvas.height = layerSvg.height;
    const ctx = canvas.getContext('2d');
    if (!ctx) throw new Error('Layer export canvas is unavailable.');
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    ctx.drawImage(image, 0, 0, canvas.width, canvas.height);
    return canvas;
  } finally {
    URL.revokeObjectURL(svgUrl);
  }
}

function canvasToCreativePngBlob(canvas) {
  return new Promise((resolve, reject) => {
    canvas.toBlob((blob) => {
      if (blob) resolve(blob);
      else reject(new Error('Could not encode layer PNG.'));
    }, 'image/png', 1);
  });
}

async function canvasSaveCreativeLayerAssets(options = {}) {
  try {
    const mode = normalizeCreativeMode(window.currentCreativeMode);
    if (mode !== 'image') {
      showToast('Switch to Image mode', 'Layer PNG assets are saved from the Image canvas.', 'info');
      return null;
    }
    const candidates = getCreativeLayerAssetExportCandidates(options);
    if (!candidates.length) {
      showToast('No layers to save', 'Add or show at least one image, text, shape, icon, or component layer first.', 'info');
      return null;
    }
    const limit = Math.min(candidates.length, Math.max(1, Number(options.limit) || 300));
    const layers = [];
    const stamp = buildCreativeArtifactTimestamp();
    showToast('Saving layer PNGs', `${limit} layer${limit === 1 ? '' : 's'} queued.`, 'info');
    for (let index = 0; index < limit; index += 1) {
      const element = candidates[index];
      const label = getCreativeElementDisplayLabelStudioV3(element, index);
      const canvas = await renderCreativeElementLayerCanvas(element, mode);
      const blob = await canvasToCreativePngBlob(canvas);
      layers.push({
        elementId: element.id,
        elementType: element.type,
        filename: `${String(index + 1).padStart(3, '0')}-${sanitizeCreativeLayerAssetName(label || element.id || `layer-${index + 1}`)}.png`,
        mimeType: 'image/png',
        width: canvas.width,
        height: canvas.height,
        base64: await blobToBase64(blob),
        tags: [String(element.type || 'layer').toLowerCase()],
      });
    }
    const result = await persistCreativeLayerAssetBatch(layers, {
      mode,
      batchName: `${getCreativeArtifactStem(mode)}-layers-${stamp}`,
    });
    const count = Number(result?.count || layers.length || 0);
    addProcessEntry('info', `${getStructuredCreativeModeLabel(mode)}: saved ${count} layer PNG asset${count === 1 ? '' : 's'} to the Creative asset library.`);
    showToast('Layer PNGs saved', `${count} asset${count === 1 ? '' : 's'} indexed for reuse.`, 'success');
    loadCreativeAssets({ force: true }).catch(() => {});
    renderCreativeWorkspace({ skipStageRender: true });
    return result;
  } catch (err) {
    const message = String(err?.message || err || 'Layer PNG export failed.');
    addProcessEntry('error', `Layer PNG export failed: ${message}`);
    showToast('Layer PNG export failed', message, 'error');
    return null;
  }
}

function waitForCreativeExportDelay(ms = 0) {
  return creativeExportEngine.waitForCreativeExportDelay(ms);
}

function waitForCreativeExportPaint(frames = 1) {
  return creativeExportEngine.waitForCreativeExportPaint(frames);
}

function getCreativeVideoExportConfig(format = 'webm') {
  return creativeExportEngine.getCreativeVideoExportConfig(format);
}

function getCreativeGifExportConfig() {
  return creativeExportEngine.getCreativeGifExportConfig();
}

async function renderCreativeExportCanvasAtTimeline(atMs = 0, format = 'png') {
  return creativeExportEngine.renderCreativeExportCanvasAtTimeline(atMs, format);
}

async function exportCreativeVideoRecording(format = 'webm', options = {}) {
  return creativeExportEngine.exportCreativeVideoRecording(format, options);
}

async function exportCreativeVideoWebm(options = {}) {
  return exportCreativeVideoRecording('webm', options);
}

async function exportCreativeVideoMp4(options = {}) {
  return exportCreativeVideoRecording('mp4', options);
}

async function exportCreativeVideoGif(options = {}) {
  return creativeExportEngine.exportCreativeVideoGif(options);
}

function shouldPreferCreativeServerRender(format = 'webm') {
  if (isCreativeRenderWorkerMode()) return false;
  const normalized = String(format || '').trim().toLowerCase();
  return normalizeCreativeMode(window.currentCreativeMode) === 'video' && ['webm', 'gif'].includes(normalized);
}

async function startCreativeServerRenderExport(format = 'webm') {
  const normalized = String(format || 'webm').trim().toLowerCase();
  if (normalizeCreativeMode(window.currentCreativeMode) !== 'video') {
    throw new Error(`${normalized.toUpperCase()} export is only available in Video mode.`);
  }
  if (isCreativeExportActive()) {
    showToast('Creative export already running', 'Wait for the current export to finish before starting another one.', 'info');
    return;
  }
  const durationMs = getCreativeTimelineDurationMs();
  const exportFrameRate = Math.max(6, Math.min(normalized === 'gif' ? 16 : 30, getCreativeTimelineFrameRate()));
  const width = Math.max(1, Number(creativeSceneDoc?.width) || 1);
  const height = Math.max(1, Number(creativeSceneDoc?.height) || 1);
  const hasAudioLane = hasCreativeAudioTrack();
  const label = normalized.toUpperCase();
  const serverJob = await createCreativeRenderJob({
    mode: 'video',
    format: normalized,
    renderer: 'server-browser',
    autoStart: true,
    doc: creativeSceneDoc,
    exportOptions: {
      durationMs,
      frameRate: exportFrameRate,
      width,
      height,
      audioRequested: hasAudioLane,
    },
    metadata: {
      audioRequested: hasAudioLane,
      exportLabel: label,
      requestedBy: 'studio-ui',
    },
  });
  if (!serverJob?.id) {
    throw new Error('Could not create the server render job.');
  }
  creativeExportUiStamp = 0;
  creativeActiveExport = {
    format: normalized,
    renderer: 'server-browser',
    serverJobId: serverJob.id,
    startedAt: Date.now(),
    frameRate: exportFrameRate,
    progress: Number(serverJob.progress) || 0,
    elapsedMs: 0,
    cancelRequested: false,
    status: normalizeCreativeRenderJobStatus(serverJob.status) === 'queued' ? 'queued' : 'recording',
    progressLabel: serverJob.progressLabel || 'Queued for server render',
    audioRequested: hasAudioLane,
    audioEnabled: hasAudioLane,
  };
  renderCreativeWorkspace();
  addProcessEntry('info', `${getStructuredCreativeModeLabel()}: queued server ${label} export job ${serverJob.id}.`);
  showToast(`Queued server ${label} export`, 'Prometheus is rendering this export in a headless browser worker.', 'info');
  return serverJob;
}

async function canvasExportCreative(format = 'png', options = {}) {
    const normalized = String(format || 'png').trim().toLowerCase();
    const baseName = getCreativeExportBaseName(normalized);
    const skipDownload = options?.skipDownload === true;
    try {
    const selectedForExport = getSelectedCreativeElement();
    if (selectedForExport?.type === 'hyperframes' && ['mp4', 'webm', 'mov'].includes(normalized)) {
      return await window.canvasExportHyperframesClip(selectedForExport.id, normalized);
    }
    if (isCreativeExportActive()) {
      showToast('Creative export already running', 'Wait for the current export to finish before starting another one.', 'info');
      return;
    }
      if (shouldPreferCreativeServerRender(normalized)) {
        try {
          const serverJob = await startCreativeServerRenderExport(normalized);
          return { format: normalized, queued: true, job: serverJob || null };
        } catch (serverErr) {
        addProcessEntry('warn', `${getStructuredCreativeModeLabel()}: server ${normalized.toUpperCase()} export bootstrap failed, falling back to local export (${String(serverErr?.message || serverErr)}).`);
        showToast(`Server ${normalized.toUpperCase()} export unavailable`, 'Falling back to the in-browser exporter for this run.', 'info');
      }
      }
      if (normalized === 'webm') {
        return await exportCreativeVideoWebm({ skipDownload });
      }
      if (normalized === 'mp4') {
        return await exportCreativeVideoMp4({ skipDownload });
      }
      if (normalized === 'gif') {
        return await exportCreativeVideoGif({ skipDownload });
      }
      if (normalized === 'svg') {
        const svgBlob = new Blob([await buildCreativeExportSvgMarkup()], { type: 'image/svg+xml;charset=utf-8' });
        if (!skipDownload) downloadBlob(svgBlob, `${baseName}.svg`);
        addProcessEntry('info', `${getStructuredCreativeModeLabel()}: exported SVG.`);
        const exportResult = await persistCreativeExportBundle({ blob: svgBlob, extension: 'svg', mimeType: 'image/svg+xml', mode: window.currentCreativeMode });
        return { format: normalized, extension: 'svg', mimeType: 'image/svg+xml', filename: `${baseName}.svg`, ...(exportResult || {}) };
      }
    const canvas = await renderCreativeExportCanvas(normalized);
    if (normalized === 'pdf') {
      const { jsPDF } = await import('/vendor/jspdf/jspdf.es.min.js');
      const pdf = new jsPDF({
        orientation: creativeSceneDoc.width >= creativeSceneDoc.height ? 'landscape' : 'portrait',
        unit: 'px',
        format: [creativeSceneDoc.width, creativeSceneDoc.height],
      });
      pdf.addImage(canvas.toDataURL('image/png', 1), 'PNG', 0, 0, creativeSceneDoc.width, creativeSceneDoc.height);
        const pdfBlob = pdf.output('blob');
        if (!skipDownload) downloadBlob(pdfBlob, `${baseName}.pdf`);
        addProcessEntry('info', `${getStructuredCreativeModeLabel()}: exported PDF.`);
        const exportResult = await persistCreativeExportBundle({ blob: pdfBlob, extension: 'pdf', mimeType: 'application/pdf', mode: window.currentCreativeMode });
        return { format: normalized, extension: 'pdf', mimeType: 'application/pdf', filename: `${baseName}.pdf`, ...(exportResult || {}) };
      }
    const mime = normalized === 'jpeg' ? 'image/jpeg' : 'image/png';
    const extension = normalized === 'jpeg' ? 'jpg' : 'png';
      return await new Promise((resolve, reject) => {
        canvas.toBlob(async (blob) => {
        if (!blob) {
          reject(new Error('Creative export failed.'));
          return;
        }
        try {
            if (!skipDownload) downloadBlob(blob, `${baseName}.${extension}`);
            addProcessEntry('info', `${getStructuredCreativeModeLabel()}: exported ${extension.toUpperCase()}.`);
            const exportResult = await persistCreativeExportBundle({ blob, extension, mimeType: mime, mode: window.currentCreativeMode });
            resolve({ format: normalized, extension, mimeType: mime, filename: `${baseName}.${extension}`, ...(exportResult || {}) });
          } catch (err) {
          reject(err);
        }
      }, mime, normalized === 'jpeg' ? 0.94 : 1);
    });
    } catch (err) {
      showToast(`Creative export failed: ${err.message}`, 'error');
      addProcessEntry('error', `Creative export failed: ${String(err?.message || err)}`);
      throw err;
    }
  }

function getRenderedCreativeElement(element, mode = window.currentCreativeMode) {
  const normalizedMode = normalizeCreativeMode(mode);
  if (normalizedMode !== 'video') return element;
  return resolveElementAtTime(element, creativeTimelineMs);
}

function createCreativeLocalId(prefix = 'kf') {
  const token = typeof crypto !== 'undefined' && crypto?.randomUUID
    ? crypto.randomUUID().replace(/-/g, '').slice(0, 10)
    : Math.random().toString(36).slice(2, 12);
  return `${prefix}_${token}`;
}

function findCreativeElementInDoc(doc, elementId) {
  if (!elementId || !Array.isArray(doc?.elements)) return null;
  return doc.elements.find((element) => element.id === elementId) || null;
}

function findCreativeKeyframeInElement(elementId, keyframeId) {
  const element = findCreativeElementInDoc(creativeSceneDoc, elementId);
  if (!element || !keyframeId) return null;
  const keyframes = Array.isArray(element.meta?.keyframes) ? element.meta.keyframes : [];
  const index = keyframes.findIndex((keyframe) => String(keyframe?.id || '').trim() === String(keyframeId || '').trim());
  if (index === -1) return null;
  return {
    element,
    keyframe: keyframes[index],
    index,
  };
}

function getCreativeTimelineDurationMs() {
  return Math.max(1000, Number(creativeSceneDoc?.durationMs) || 12000);
}

function getCreativeTimelineFrameRate() {
  const mode = normalizeCreativeMode(window.currentCreativeMode);
  return Math.max(mode === 'video' ? 60 : 1, Number(creativeSceneDoc?.frameRate) || (mode === 'video' ? 60 : 60));
}

function snapCreativeTimelineMs(rawValue, durationOverride = getCreativeTimelineDurationMs()) {
  const durationMs = Math.max(1000, Number(durationOverride) || 12000);
  const rawMs = Math.max(0, Math.min(durationMs, Number(rawValue) || 0));
  const frameRate = getCreativeTimelineFrameRate();
  const frameIndex = Math.round((rawMs * frameRate) / 1000);
  return Math.max(0, Math.min(durationMs, Math.round((frameIndex / frameRate) * 1000)));
}

function getCreativeTimelineMsFromLanePosition(clientX, laneRect, durationMs = getCreativeTimelineDurationMs()) {
  const width = Number(laneRect?.width) || 0;
  if (width <= 0) return 0;
  const left = Number(laneRect?.left) || 0;
  const ratio = clamp(((Number(clientX) || 0) - left) / width, 0, 1);
  return snapCreativeTimelineMs(ratio * durationMs, durationMs);
}

function measureCreativeTextHeight(element, width, fallbackHeight) {
  const meta = element?.meta || {};
  try {
    const fontSpec = buildTextFontSpec(meta);
    const measurement = measureTextBlock(
      meta.content || 'Text',
      fontSpec,
      Math.max(80, Number(width) || Number(element?.width) || 80),
      Number(meta.lineHeight) || 1.2,
      {
        fontSize: meta.fontSize,
        fontWeight: meta.fontWeight,
        fontFamily: meta.fontFamily,
        fontStyle: meta.fontStyle,
      }
    );
    return Math.max(CREATIVE_STAGE_MIN_SIZE, Math.ceil(Number(measurement?.height) || Number(fallbackHeight) || Number(element?.height) || CREATIVE_STAGE_MIN_SIZE));
  } catch {
    return Math.max(CREATIVE_STAGE_MIN_SIZE, Math.ceil(Number(fallbackHeight) || Number(element?.height) || CREATIVE_STAGE_MIN_SIZE));
  }
}

function normalizeCreativeStageRect(element, rect = {}) {
  const stageWidth = Math.max(120, Number(creativeSceneDoc?.width) || 120);
  const stageHeight = Math.max(120, Number(creativeSceneDoc?.height) || 120);
  const minWidth = element?.type === 'icon' ? 24 : CREATIVE_STAGE_MIN_SIZE;
  let width = Math.max(minWidth, Number(rect.width) || Number(element?.width) || minWidth);
  let height = Math.max(CREATIVE_STAGE_MIN_SIZE, Number(rect.height) || Number(element?.height) || CREATIVE_STAGE_MIN_SIZE);
  const shape = String(element?.meta?.shape || '').trim().toLowerCase();

  if (element?.type === 'text') {
    height = measureCreativeTextHeight(element, width, height);
  } else if (element?.type === 'icon' || (element?.type === 'shape' && shape === 'circle')) {
    const size = Math.max(width, height);
    width = size;
    height = size;
  } else if (element?.type === 'shape' && (shape === 'line' || shape === 'arrow')) {
    height = Math.max(2, Number(element?.meta?.strokeWidth) || 2, Number(rect.height) || 0);
  }

  const x = Math.min(Math.max(0, Number(rect.x) || 0), Math.max(0, stageWidth - width));
  const y = Math.min(Math.max(0, Number(rect.y) || 0), Math.max(0, stageHeight - height));
  return {
    x: Math.round(x),
    y: Math.round(y),
    width: Math.round(width),
    height: Math.round(height),
  };
}

function buildCreativeVideoKeyframeDoc(elementId, patch = {}, options = {}) {
  const sourceDoc = createSceneDocument(options.doc || creativeSceneDoc || {});
  const nextDoc = createSceneDocument(sourceDoc);
  const atMs = Math.max(0, Number(options.atMs ?? creativeTimelineMs) || 0);
  nextDoc.elements = nextDoc.elements.map((candidate) => {
    if (candidate.id !== elementId) return candidate;
    const rendered = getRenderedCreativeElement(candidate, 'video') || candidate;
    const existingKeyframes = Array.isArray(candidate.meta?.keyframes)
      ? candidate.meta.keyframes.map((keyframe) => ({ ...keyframe }))
      : [];
    const existingIndex = existingKeyframes.findIndex((keyframe) => Number(keyframe?.atMs) === atMs);
    if (existingIndex >= 0) {
      const current = existingKeyframes[existingIndex] || {};
      existingKeyframes[existingIndex] = {
        ...current,
        ...patch,
        id: current.id || createCreativeLocalId('kf'),
        atMs,
      };
    } else {
      existingKeyframes.push({
        id: createCreativeLocalId('kf'),
        atMs,
        x: rendered.x,
        y: rendered.y,
        width: rendered.width,
        height: rendered.height,
        opacity: rendered.opacity,
        rotation: rendered.rotation,
        ...patch,
      });
    }
    existingKeyframes.sort((left, right) => (left.atMs || 0) - (right.atMs || 0));
    return {
      ...candidate,
      meta: {
        ...(candidate.meta || {}),
        keyframes: existingKeyframes,
      },
    };
  });
  return createSceneDocument(nextDoc);
}

function applyCreativeGeometryPatch(elementId, partialRect = {}, options = {}) {
  const sourceDoc = createSceneDocument(options.doc || creativeSceneDoc || {});
  const element = findCreativeElementInDoc(sourceDoc, elementId);
  if (!element) return null;
  const mode = normalizeCreativeMode(options.mode || window.currentCreativeMode);
  const source = getRenderedCreativeElement(element, mode) || element;
  const rawRect = {
    x: partialRect.x ?? source.x,
    y: partialRect.y ?? source.y,
    width: partialRect.width ?? source.width,
    height: partialRect.height ?? source.height,
  };
  const aspectLockedRect = options.aspectLock === true
    ? applyCreativeAspectLockToRect(element, source, rawRect, {
        prefer: options.prefer,
        mode: options.resizeMode,
      })
    : rawRect;
  const patch = normalizeCreativeStageRect(element, aspectLockedRect);
  if (mode === 'video') return buildCreativeVideoKeyframeDoc(elementId, patch, { ...options, doc: sourceDoc });
  return executeSceneGraphOps(sourceDoc, [{ op: 'set', id: elementId, patch }]);
}

function applyCreativeTimelineScalarPatch(elementId, key, value, options = {}) {
  const sourceDoc = createSceneDocument(options.doc || creativeSceneDoc || {});
  const mode = normalizeCreativeMode(options.mode || window.currentCreativeMode);
  if (mode !== 'video' || !CREATIVE_VIDEO_TIMELINE_KEYS.has(String(key || '').trim())) {
    return executeSceneGraphOps(sourceDoc, [{ op: 'set', id: elementId, patch: { [key]: value } }]);
  }
  return buildCreativeVideoKeyframeDoc(elementId, { [key]: value }, { ...options, doc: sourceDoc });
}

function endCreativeTimelineGesture(options = {}) {
  if (!activeCreativeTimelineGesture) return;
  document.removeEventListener('mousemove', handleCreativeTimelineGestureMove);
  document.removeEventListener('mouseup', handleCreativeTimelineGestureEnd);
  document.body.style.userSelect = '';
  document.body.style.cursor = '';
  activeCreativeTimelineGesture = null;
  if (options.render !== false) renderCreativeWorkspace();
  if (options.persist !== false) persistActiveChat();
}

function handleCreativeTimelineGestureMove(event) {
  const gesture = activeCreativeTimelineGesture;
  if (!gesture) return;
  event.preventDefault();
  const nextAtMs = getCreativeTimelineMsFromLanePosition(event.clientX, gesture.laneRect, gesture.durationMs);
  if (nextAtMs === gesture.lastAtMs) return;
  gesture.lastAtMs = nextAtMs;
  if (gesture.kind === 'scrub' || gesture.kind === 'scrub-audio') {
    setCreativeTimelinePosition(nextAtMs, { render: false, persist: false });
    renderCreativeWorkspace();
    return;
  }
  if (gesture.kind === 'trim-audio-start' || gesture.kind === 'trim-audio-end') {
    const track = getCreativeAudioTrackConfig();
    const totalMs = gesture.durationMs;
    let startMs = Math.max(0, Number(track.startMs) || 0);
    let durMs = Math.max(0, Number(track.durationMs) || 0) || Math.max(0, totalMs - startMs);
    if (gesture.kind === 'trim-audio-start') {
      const endMs = startMs + durMs;
      startMs = Math.max(0, Math.min(endMs - 100, nextAtMs));
      durMs = Math.max(100, endMs - startMs);
    } else {
      const endMs = Math.max(startMs + 100, Math.min(totalMs, nextAtMs));
      durMs = Math.max(100, endMs - startMs);
    }
    if (!gesture.historyCommitted) {
      commitCreativeHistorySnapshot(gesture.snapshotBefore);
      gesture.historyCommitted = true;
    }
    const nextDocAudio = createSceneDocument({
      ...creativeSceneDoc,
      audioTrack: {
        ...(creativeSceneDoc.audioTrack || {}),
        startMs,
        durationMs: durMs,
      },
    });
    setCreativeSceneDoc(nextDocAudio, { render: false, persist: false });
    renderCreativeWorkspace();
    return;
  }
  const nextDoc = executeSceneGraphOps(creativeSceneDoc, [{
    op: 'move-keyframe',
    id: gesture.elementId,
    keyframeId: gesture.keyframeId,
    atMs: nextAtMs,
  }]);
  const updatedElement = findCreativeElementInDoc(nextDoc, gesture.elementId);
  const updatedKeyframes = Array.isArray(updatedElement?.meta?.keyframes) ? updatedElement.meta.keyframes : [];
  if (!updatedKeyframes.some((keyframe) => keyframe?.id === gesture.keyframeId)) return;
  if (!gesture.historyCommitted) {
    commitCreativeHistorySnapshot(gesture.snapshotBefore);
    gesture.historyCommitted = true;
  }
  setCreativeSceneDoc(nextDoc, { render: false, persist: false });
  setCreativeTimelinePosition(nextAtMs, { render: false, persist: false });
  renderCreativeWorkspace();
}

function handleCreativeTimelineGestureEnd(event) {
  if (event) event.preventDefault();
  endCreativeTimelineGesture({ persist: true });
}

function canvasHandleCreativeTimelineLanePointer(event, elementId, laneNode) {
  if (!event || event.button !== 0) return;
  const target = event.target;
  if (target instanceof Element && target.closest('.creative-timeline-keyframe')) return;
  const lane = laneNode instanceof Element
    ? laneNode
    : (target instanceof Element ? target.closest('.creative-timeline-track-lane') : null);
  if (!lane) return;
  if (activeCreativeStageGesture) endCreativeStageGesture({ persist: false, render: false });
  if (activeCreativeTimelineGesture) endCreativeTimelineGesture({ persist: false, render: false });
  if (isCreativePlaybackActive()) pauseCreativePlayback();
  const durationMs = getCreativeTimelineDurationMs();
  const nextAtMs = getCreativeTimelineMsFromLanePosition(event.clientX, lane.getBoundingClientRect(), durationMs);
  setCreativeSelection(elementId, { render: false, persist: false });
  setCreativeTimelinePosition(nextAtMs, { render: false, persist: false });
  activeCreativeTimelineGesture = {
    kind: 'scrub',
    elementId,
    durationMs,
    laneRect: lane.getBoundingClientRect(),
    lastAtMs: nextAtMs,
  };
  document.addEventListener('mousemove', handleCreativeTimelineGestureMove);
  document.addEventListener('mouseup', handleCreativeTimelineGestureEnd);
  document.body.style.userSelect = 'none';
  document.body.style.cursor = 'ew-resize';
  event.preventDefault();
  event.stopPropagation();
  renderCreativeWorkspace();
}

function canvasHandleCreativeAudioLanePointer(event, laneNode) {
  if (!event || event.button !== 0) return;
  const target = event.target;
  const lane = laneNode instanceof Element
    ? laneNode
    : (target instanceof Element ? target.closest('.creative-timeline-track-lane') : null);
  if (!lane) return;
  if (activeCreativeStageGesture) endCreativeStageGesture({ persist: false, render: false });
  if (activeCreativeTimelineGesture) endCreativeTimelineGesture({ persist: false, render: false });
  if (isCreativePlaybackActive()) pauseCreativePlayback();
  const durationMs = getCreativeTimelineDurationMs();
  const nextAtMs = getCreativeTimelineMsFromLanePosition(event.clientX, lane.getBoundingClientRect(), durationMs);
  setCreativeTimelinePosition(nextAtMs, { render: false, persist: false });
  activeCreativeTimelineGesture = {
    kind: 'scrub-audio',
    durationMs,
    laneRect: lane.getBoundingClientRect(),
    lastAtMs: nextAtMs,
  };
  document.addEventListener('mousemove', handleCreativeTimelineGestureMove);
  document.addEventListener('mouseup', handleCreativeTimelineGestureEnd);
  document.body.style.userSelect = 'none';
  document.body.style.cursor = 'ew-resize';
  event.preventDefault();
  event.stopPropagation();
  renderCreativeWorkspace();
}

function canvasBeginCreativeKeyframeDrag(event, elementId, keyframeId, laneNode) {
  if (!event || event.button !== 0) return;
  const lane = laneNode instanceof Element
    ? laneNode
    : (event.target instanceof Element ? event.target.closest('.creative-timeline-track-lane') : null);
  const match = findCreativeKeyframeInElement(elementId, keyframeId);
  if (!lane || !match?.keyframe) return;
  if (activeCreativeStageGesture) endCreativeStageGesture({ persist: false, render: false });
  if (activeCreativeTimelineGesture) endCreativeTimelineGesture({ persist: false, render: false });
  if (isCreativePlaybackActive()) pauseCreativePlayback();
  const startAtMs = Math.max(0, Number(match.keyframe.atMs) || 0);
  setCreativeSelection(elementId, { render: false, persist: false });
  setCreativeTimelinePosition(startAtMs, { render: false, persist: false });
  activeCreativeTimelineGesture = {
    kind: 'move-keyframe',
    elementId,
    keyframeId,
    durationMs: getCreativeTimelineDurationMs(),
    laneRect: lane.getBoundingClientRect(),
    lastAtMs: startAtMs,
    snapshotBefore: captureCreativeSnapshot(),
    historyCommitted: false,
  };
  document.addEventListener('mousemove', handleCreativeTimelineGestureMove);
  document.addEventListener('mouseup', handleCreativeTimelineGestureEnd);
  document.body.style.userSelect = 'none';
  document.body.style.cursor = 'ew-resize';
  event.preventDefault();
  event.stopPropagation();
  renderCreativeWorkspace();
}

function canvasBeginCreativeTrimGesture(event, elementId, keyframeId, edge, laneNode) {
  if (!event || event.button !== 0) return;
  const lane = laneNode instanceof Element
    ? laneNode
    : (event.target instanceof Element ? event.target.closest('.creative-timeline-track-lane') : null);
  const match = findCreativeKeyframeInElement(elementId, keyframeId);
  if (!lane || !match?.keyframe) return;
  if (activeCreativeStageGesture) endCreativeStageGesture({ persist: false, render: false });
  if (activeCreativeTimelineGesture) endCreativeTimelineGesture({ persist: false, render: false });
  if (isCreativePlaybackActive()) pauseCreativePlayback();
  const startAtMs = Math.max(0, Number(match.keyframe.atMs) || 0);
  setCreativeSelection(elementId, { render: false, persist: false });
  activeCreativeTimelineGesture = {
    kind: 'move-keyframe',
    elementId,
    keyframeId,
    durationMs: getCreativeTimelineDurationMs(),
    laneRect: lane.getBoundingClientRect(),
    lastAtMs: startAtMs,
    snapshotBefore: captureCreativeSnapshot(),
    historyCommitted: false,
  };
  document.addEventListener('mousemove', handleCreativeTimelineGestureMove);
  document.addEventListener('mouseup', handleCreativeTimelineGestureEnd);
  document.body.style.userSelect = 'none';
  document.body.style.cursor = 'ew-resize';
  event.preventDefault();
  event.stopPropagation();
  renderCreativeWorkspace();
}

function canvasBeginCreativeAudioTrimGesture(event, edge, laneNode) {
  if (!event || event.button !== 0) return;
  const lane = laneNode instanceof Element
    ? laneNode
    : (event.target instanceof Element ? event.target.closest('.creative-timeline-track-lane') : null);
  if (!lane) return;
  if (activeCreativeStageGesture) endCreativeStageGesture({ persist: false, render: false });
  if (activeCreativeTimelineGesture) endCreativeTimelineGesture({ persist: false, render: false });
  if (isCreativePlaybackActive()) pauseCreativePlayback();
  const durationMs = getCreativeTimelineDurationMs();
  activeCreativeTimelineGesture = {
    kind: edge === 'end' ? 'trim-audio-end' : 'trim-audio-start',
    durationMs,
    laneRect: lane.getBoundingClientRect(),
    lastAtMs: -1,
    snapshotBefore: captureCreativeSnapshot(),
    historyCommitted: false,
  };
  document.addEventListener('mousemove', handleCreativeTimelineGestureMove);
  document.addEventListener('mouseup', handleCreativeTimelineGestureEnd);
  document.body.style.userSelect = 'none';
  document.body.style.cursor = 'ew-resize';
  event.preventDefault();
  event.stopPropagation();
  renderCreativeWorkspace();
}

function beginCreativeStageGesture(event, elementId, kind, mode) {
  const element = findCreativeElementInDoc(creativeSceneDoc, elementId);
  if (!element) return;
  if (activeCreativeStageGesture) endCreativeStageGesture({ persist: false, render: false });
  if (activeCreativeTimelineGesture) endCreativeTimelineGesture({ persist: false, render: false });
  const rendered = getRenderedCreativeElement(element, mode) || element;
  activeCreativeStageGesture = {
    kind,
    mode,
    elementId,
    startClientX: Number(event.clientX) || 0,
    startClientY: Number(event.clientY) || 0,
    initialRect: {
      x: Number(rendered.x) || 0,
      y: Number(rendered.y) || 0,
      width: Number(rendered.width) || Number(element.width) || 0,
      height: Number(rendered.height) || Number(element.height) || 0,
    },
    startZoom: Math.max(CREATIVE_STAGE_ZOOM_MIN, Number(creativeStageZoom) || 1),
    lastRect: null,
    snapshotBefore: captureCreativeSnapshot(),
    historyCommitted: false,
  };
  document.addEventListener('mousemove', handleCreativeStageGestureMove);
  document.addEventListener('mouseup', handleCreativeStageGestureEnd);
  document.body.style.userSelect = 'none';
  document.body.style.cursor = kind === 'resize' ? 'nwse-resize' : 'grabbing';
}

function handleCreativeStageGestureMove(event) {
  const gesture = activeCreativeStageGesture;
  if (!gesture) return;
  event.preventDefault();
  const zoom = Math.max(CREATIVE_STAGE_ZOOM_MIN, Number(gesture.startZoom) || Number(creativeStageZoom) || 1);
  const deltaX = ((Number(event.clientX) || 0) - gesture.startClientX) / zoom;
  const deltaY = ((Number(event.clientY) || 0) - gesture.startClientY) / zoom;
  const nextRect = gesture.kind === 'resize'
    ? {
        x: gesture.initialRect.x,
        y: gesture.initialRect.y,
        width: gesture.initialRect.width + deltaX,
        height: gesture.initialRect.height + deltaY,
      }
    : {
        x: gesture.initialRect.x + deltaX,
        y: gesture.initialRect.y + deltaY,
        width: gesture.initialRect.width,
        height: gesture.initialRect.height,
      };
  const nextDoc = applyCreativeGeometryPatch(gesture.elementId, nextRect, {
    mode: gesture.mode,
    atMs: creativeTimelineMs,
    resizeMode: gesture.kind === 'resize' ? 'resize' : 'move',
    aspectLock: gesture.kind === 'resize',
  });
  const currentElement = findCreativeElementInDoc(nextDoc, gesture.elementId);
  const currentResolved = currentElement
    ? (gesture.mode === 'video' ? resolveElementAtTime(currentElement, creativeTimelineMs) : currentElement)
    : null;
  const currentRect = currentResolved ? normalizeCreativeStageRect(currentElement || currentResolved, currentResolved) : null;
  const previousRect = gesture.lastRect || gesture.initialRect;
  if (
    !currentRect
    || (
      currentRect.x === previousRect.x
      && currentRect.y === previousRect.y
      && currentRect.width === previousRect.width
      && currentRect.height === previousRect.height
    )
  ) {
    return;
  }
  if (!gesture.historyCommitted) {
    commitCreativeHistorySnapshot(gesture.snapshotBefore);
    gesture.historyCommitted = true;
  }
  gesture.lastRect = currentRect;
  setCreativeSceneDoc(nextDoc, { render: false, persist: false });
  renderCreativeWorkspace();
}

function endCreativeStageGesture(options = {}) {
  if (!activeCreativeStageGesture) return;
  document.removeEventListener('mousemove', handleCreativeStageGestureMove);
  document.removeEventListener('mouseup', handleCreativeStageGestureEnd);
  document.body.style.userSelect = '';
  document.body.style.cursor = '';
  activeCreativeStageGesture = null;
  if (options.render !== false) renderCreativeWorkspace();
  if (options.persist !== false) persistActiveChat();
}

function handleCreativeStageGestureEnd(event) {
  if (event) event.preventDefault();
  endCreativeStageGesture({ persist: true });
}

function bindCreativeStageInteractions(stage, mode) {
  if (!stage) return;
  stage.onmousedown = (event) => {
    if (event.button !== 0) return;
    const target = event.target;
    if (!(target instanceof Element)) return;
    const elementNode = target.closest('[data-creative-element-id]');
    if (!elementNode || !stage.contains(elementNode)) return;
    const elementId = String(elementNode.getAttribute('data-creative-element-id') || '').trim();
    if (!elementId) return;
    const element = findCreativeElementInDoc(creativeSceneDoc, elementId);
    if (!element) return;
    const isResizeHandle = !!target.closest('[data-creative-resize-handle="true"]');
    setCreativeSelection(elementId, { render: false, persist: false });
    if (element.locked) {
      renderCreativeWorkspace();
      persistActiveChat();
      return;
    }
    if (mode === 'video' && isCreativePlaybackActive()) pauseCreativePlayback();
    event.preventDefault();
    event.stopPropagation();
    beginCreativeStageGesture(event, elementId, isResizeHandle ? 'resize' : 'move', mode);
    renderCreativeWorkspace();
  };
}

function applyCreativeAssistantOps(replyText) {
  const mode = normalizeCreativeMode(window.currentCreativeMode);
  if (!isStructuredCreativeMode(mode)) return false;
  const parsed = parseCreativeOpsFromText(replyText);
  if (!parsed.matched || !Array.isArray(parsed.ops) || parsed.ops.length === 0) return false;
  ensureCreativeSceneForMode(mode);
  const beforeIds = new Set((creativeSceneDoc.elements || []).map((element) => element.id));
  const nextDoc = applySceneGraphOps(creativeSceneDoc, parsed.ops);
  const afterIds = nextDoc.elements.map((element) => element.id);
  const addedIds = afterIds.filter((id) => !beforeIds.has(id));
  const explicitTarget = parsed.ops
    .map((op) => String(op?.id || '').trim())
    .filter(Boolean)
    .reverse()
    .find((id) => afterIds.includes(id));
  const nextSelectedId = explicitTarget
    || addedIds[addedIds.length - 1]
    || (creativeSelectedId && afterIds.includes(creativeSelectedId) ? creativeSelectedId : null)
    || afterIds[afterIds.length - 1]
    || null;
  setCreativeSceneDoc(nextDoc, { render: false, persist: false, recordHistory: true });
  setCreativeSelection(nextSelectedId, { render: false, persist: false });
  creativeTimelineMs = Math.max(0, Math.min(Math.max(1000, Number(nextDoc.durationMs) || 12000), creativeTimelineMs));
  const session = getActiveChatSessionRecord();
  if (session) session.creativeTimelineMs = creativeTimelineMs;
  renderCreativeWorkspace();
  persistActiveChat();
  const kinds = [...new Set(parsed.ops.map((op) => String(op?.op || '').trim()).filter(Boolean))];
  addProcessEntry('info', `${getStructuredCreativeModeLabel(mode)}: applied ${parsed.ops.length} scene op${parsed.ops.length === 1 ? '' : 's'}${kinds.length ? ` (${kinds.join(', ')})` : ''}.`);
  return true;
}

function canvasUndoCreativeChange() {
  if (!creativeHistoryPast.length) return;
  const current = captureCreativeSnapshot();
  const previous = creativeHistoryPast.pop();
  creativeHistoryFuture.push(current);
  if (creativeHistoryFuture.length > CREATIVE_HISTORY_LIMIT) {
    creativeHistoryFuture = creativeHistoryFuture.slice(creativeHistoryFuture.length - CREATIVE_HISTORY_LIMIT);
  }
  restoreCreativeSnapshot(previous);
  refreshCreativeCanvasPreview({ reason: 'undo' });
}

function canvasRedoCreativeChange() {
  if (!creativeHistoryFuture.length) return;
  const current = captureCreativeSnapshot();
  const next = creativeHistoryFuture.pop();
  creativeHistoryPast.push(current);
  if (creativeHistoryPast.length > CREATIVE_HISTORY_LIMIT) {
    creativeHistoryPast = creativeHistoryPast.slice(creativeHistoryPast.length - CREATIVE_HISTORY_LIMIT);
  }
  restoreCreativeSnapshot(next);
  refreshCreativeCanvasPreview({ reason: 'redo' });
}

function canvasApplyCreativeSizePreset(presetKey) {
  const preset = CREATIVE_SIZE_PRESETS[String(presetKey || '').trim()];
  if (!preset) return;
  const nextDoc = createSceneDocument({
    ...creativeSceneDoc,
    width: preset.width,
    height: preset.height,
  });
  commitCreativeHistorySnapshot(captureCreativeSnapshot());
  setCreativeSceneDoc(nextDoc, { render: false, persist: false });
  renderCreativeWorkspace();
  persistActiveChat();
  addProcessEntry('info', `Creative scene resized to ${preset.label} (${preset.width}x${preset.height}).`);
}

// HyperFrames controller registry — keyed by element.id. Survives stage
// re-renders so the iframe doesn't re-mount on every keystroke. Reconciled
// after every stage.innerHTML write by syncHyperframesControllers().
const _hfControllers = new Map();

function applyHyperframesExtractionToElement(live, extraction = {}, html = null) {
  if (!live) return;
  const meta = { ...(live.meta || {}) };
  if (typeof html === 'string') meta.html = html;
  if (Array.isArray(extraction.layers)) meta.layers = extraction.layers;
  if (Array.isArray(extraction.tracks)) meta.tracks = extraction.tracks;
  if (Array.isArray(extraction.slots)) meta.slots = extraction.slots;
  if (Array.isArray(extraction.variableBindings)) meta.variableBindings = extraction.variableBindings;
  if (Array.isArray(extraction.variables)) meta.variables = extraction.variables;
  if (typeof extraction.compositionId === 'string' && extraction.compositionId) meta.compositionId = extraction.compositionId;
  if (Number.isFinite(Number(extraction.durationMs))) meta.durationMs = Math.max(100, Number(extraction.durationMs));
  if (typeof extraction.advancedBlock === 'boolean') meta.advancedBlock = extraction.advancedBlock;
  if (Array.isArray(extraction.warnings)) meta.warnings = extraction.warnings;
  if (Array.isArray(extraction.assets)) meta.assets = extraction.assets;
  if (extraction.ingest && typeof extraction.ingest === 'object') meta.ingest = extraction.ingest;
  live.meta = { ...meta, dirty: false };
}

function syncHyperframesControllers(stage) {
  if (!stage) return;
  const liveIds = new Set();
  const placeholders = stage.querySelectorAll('[data-hyperframes-mount]');
  for (const placeholder of placeholders) {
    const elementId = placeholder.getAttribute('data-hyperframes-mount');
    liveIds.add(elementId);
    const element = creativeSceneDoc.elements.find((el) => el.id === elementId);
    if (!element) continue;
    let entry = _hfControllers.get(elementId);
    if (!entry) {
      const controller = createHyperframesController({
        element,
        mount: placeholder,
        api: {
          post: (url, body) => api(url, { method: 'POST', body }),
          get: (url) => api(url),
        },
        onSourceChanged: (html) => {
          const live = creativeSceneDoc.elements.find((el) => el.id === elementId);
          if (live) {
            live.meta = { ...(live.meta || {}), html, dirty: false };
          }
        },
        onLayersChanged: (layers, extraction = {}) => {
          const live = creativeSceneDoc.elements.find((el) => el.id === elementId);
          if (live) {
            applyHyperframesExtractionToElement(live, { ...extraction, layers });
            if (creativeSelectedId === elementId) {
              try { renderCreativeWorkspace(); } catch {}
            }
          }
        },
        onExtractionChanged: (extraction = {}) => {
          const live = creativeSceneDoc.elements.find((el) => el.id === elementId);
          if (live) {
            applyHyperframesExtractionToElement(live, extraction);
            if (creativeSelectedId === elementId) {
              try { renderCreativeWorkspace(); } catch {}
            }
          }
        },
        onPick: (info) => {
          // Picker hits inside the iframe don't yet move canvas selection —
          // canvas selection is at the clip level. Logged for the inspector.
          window._lastHyperframesPick = info;
        },
        onError: (err) => console.warn('hyperframes controller error', err),
        useStudio: element.meta?.useStudio === true,
      });
      entry = { controller, element };
      _hfControllers.set(elementId, entry);
    } else if (entry.element !== element) {
      // Element identity changed — refresh source HTML if it differs.
      const nextHtml = String(element.meta?.html || '');
      if (nextHtml && entry.controller.getHtml() !== nextHtml) {
        entry.controller.setHtml(nextHtml);
      }
      entry.element = element;
    }
  }
  // Dispose controllers whose elements were removed.
  for (const [id, entry] of _hfControllers) {
    if (!liveIds.has(id)) {
      try { entry.controller.dispose(); } catch {}
      _hfControllers.delete(id);
    }
  }
}

window.canvasOpenHyperframesCatalog = function () {
  let modal = document.querySelector('#hyperframes-catalog-modal');
  if (modal) { modal.remove(); modal = null; }
  modal = document.createElement('div');
  modal.id = 'hyperframes-catalog-modal';
  modal.style.cssText = 'position:fixed;inset:0;z-index:9999;background:rgba(0,0,0,0.5);display:flex;align-items:center;justify-content:center';
  const panel = document.createElement('div');
  panel.style.cssText = 'background:#fff;width:min(960px,90vw);height:min(720px,85vh);border-radius:12px;display:flex;flex-direction:column;overflow:hidden';
  const header = document.createElement('div');
  header.style.cssText = 'padding:12px 16px;display:flex;align-items:center;justify-content:space-between;border-bottom:1px solid #e5e7eb';
  header.innerHTML = `<div style="font-weight:700">HyperFrames Catalog</div><button id="hf-catalog-close" style="padding:4px 10px">Close</button>`;
  const body = document.createElement('div');
  body.style.cssText = 'flex:1;overflow:hidden;display:flex;flex-direction:column';
  panel.appendChild(header);
  panel.appendChild(body);
  modal.appendChild(panel);
  document.body.appendChild(modal);
  header.querySelector('#hf-catalog-close').addEventListener('click', () => modal.remove());
  modal.addEventListener('click', (e) => { if (e.target === modal) modal.remove(); });
  createHyperframesCatalogBrowser({
    mount: body,
    api: { get: (url) => api(url), post: (url, b) => api(url, { method: 'POST', body: b }) },
    onInsertEditable: (payload) => insertHyperframesClip({ ...payload, advancedBlock: false, modal }),
    onInsertAdvanced: (payload) => insertHyperframesClip({ ...payload, advancedBlock: true, modal }),
    onError: (err) => showToast({ message: `HyperFrames catalog: ${err?.message || err}`, kind: 'error' }),
  });
};

function renderHyperframesInspector(selected) {
  const layers = Array.isArray(selected.meta?.layers) ? selected.meta.layers : [];
  const tracks = Array.isArray(selected.meta?.tracks) ? selected.meta.tracks : [];
  const slots = Array.isArray(selected.meta?.slots) ? selected.meta.slots : [];
  const variableBindings = Array.isArray(selected.meta?.variableBindings) ? selected.meta.variableBindings : [];
  const assets = Array.isArray(selected.meta?.assets) ? selected.meta.assets : [];
  const warnings = Array.isArray(selected.meta?.warnings) ? selected.meta.warnings : [];
  const lintErrors = Array.isArray(selected.meta?.lint?.errors) ? selected.meta.lint.errors : [];
  const lintWarnings = Array.isArray(selected.meta?.lint?.warnings) ? selected.meta.lint.warnings : [];
  const qaIssues = Array.isArray(selected.meta?.qaReport?.issues) ? selected.meta.qaReport.issues : [];
  const ingest = selected.meta?.ingest && typeof selected.meta.ingest === 'object' ? selected.meta.ingest : null;
  const advanced = selected.meta?.advancedBlock === true;
  const safeElementId = escHtml(selected.id).replace(/'/g, '&#39;');
  const layerRows = advanced
    ? `<div style="font-size:11px;color:#a8a29e;padding:8px 0">Advanced block — internals are code-backed. Edit via slots and variables below.</div>`
    : layers.length
      ? layers.map((layer) => `
          <div style="display:flex;align-items:center;justify-content:space-between;padding:6px 8px;border:1px solid rgba(255,255,255,0.08);border-radius:6px;margin-bottom:4px">
            <div>
              <div style="font-size:12px;color:#fafaf9">${escHtml(layer.name || layer.elementId)}</div>
              <div style="font-size:10px;color:#a8a29e">${escHtml(layer.kind)} · ${layer.startMs}–${layer.endMs}ms</div>
            </div>
            ${layer.editable?.text ? `<button onclick="canvasHyperframesEditLayer('${escHtml(selected.id)}','${escHtml(layer.elementId)}','text')" style="font-size:10px;padding:3px 6px">Edit text</button>` : ''}
          </div>
        `).join('')
      : `<div style="font-size:11px;color:#a8a29e;padding:8px 0">No layers extracted yet — open the clip preview to populate.</div>`;

  const trackRows = tracks.length ? tracks.map((track) => `
    <div style="display:grid;grid-template-columns:48px 1fr;gap:8px;align-items:center;padding:6px 8px;border:1px solid rgba(255,255,255,0.08);border-radius:6px;margin-bottom:4px">
      <div style="font-size:10px;color:#a8a29e;font-weight:800">T${escHtml(String(track.index ?? 0))}</div>
      <div style="min-width:0">
        <div style="font-size:12px;color:#fafaf9;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${escHtml(track.name || `${track.layers?.length || 0} layers`)}</div>
        <div style="font-size:10px;color:#a8a29e">${escHtml(String(track.startMs || 0))}-${escHtml(String(track.endMs || 0))}ms | ${escHtml(String(track.layers?.length || 0))} clips</div>
      </div>
    </div>
  `).join('') : '';

  const slotRows = slots.length ? slots.map((slot) => `
    <div style="margin-bottom:8px">
      <div style="font-size:10px;color:#a8a29e;margin-bottom:3px">${escHtml(slot.label || slot.id)} · ${escHtml(slot.kind)}</div>
      <input data-hf-slot="${escHtml(slot.id)}" data-hf-slot-kind="${escHtml(slot.kind)}" data-hf-element="${escHtml(selected.id)}" type="${slot.kind === 'color' ? 'color' : slot.kind === 'number' ? 'number' : 'text'}" ${slot.min !== null ? `min="${slot.min}"` : ''} ${slot.max !== null ? `max="${slot.max}"` : ''} ${slot.step !== null ? `step="${slot.step}"` : ''} value="${escHtml(String(slot.default ?? ''))}" oninput="canvasHyperframesPatchFromSlot(this)" style="width:100%;padding:5px 8px;font-size:12px;background:rgba(255,255,255,0.06);color:#fafaf9;border:1px solid rgba(255,255,255,0.1);border-radius:6px"/>
    </div>
  `).join('') : '';

  const variableRows = variableBindings.length ? variableBindings.map((binding) => {
    const v = binding.variable || {};
    return `
      <div style="margin-bottom:8px">
        <div style="font-size:10px;color:#a8a29e;margin-bottom:3px">${escHtml(v.label || v.id)} · ${escHtml(v.type || 'string')}</div>
        <input data-hf-variable="${escHtml(v.id)}" data-hf-element="${escHtml(selected.id)}" type="${v.type === 'number' ? 'number' : v.type === 'color' ? 'color' : v.type === 'boolean' ? 'checkbox' : 'text'}" ${v.type === 'boolean' ? (binding.currentValue ? 'checked' : '') : `value="${escHtml(String(binding.currentValue ?? v.default ?? ''))}"`} onchange="canvasHyperframesPatchFromVariable(this)" style="width:100%;padding:5px 8px;font-size:12px;background:rgba(255,255,255,0.06);color:#fafaf9;border:1px solid rgba(255,255,255,0.1);border-radius:6px"/>
      </div>
    `;
  }).join('') : '';

  return `
    <div style="padding:0 16px 14px">
      <div style="font-size:10px;font-weight:800;letter-spacing:0.06em;text-transform:uppercase;color:#a8a29e;margin-top:8px">HyperFrames clip</div>
      <div style="font-size:11px;color:#a8a29e;margin-top:4px">${escHtml(selected.meta?.compositionId || '(unknown composition)')} · ${escHtml(advanced ? 'advanced' : 'editable')}</div>
      <div style="margin-top:10px">
        <div style="font-size:10px;font-weight:800;color:#a8a29e;margin-bottom:6px">LAYERS</div>
        ${layerRows}
      </div>
      <div class="creative-pill-row" style="margin-top:10px">
        <button type="button" class="creative-chip-btn" onclick="canvasToggleHyperframesStudio('${safeElementId}')"><iconify-icon icon="solar:code-square-bold-duotone" width="14" height="14"></iconify-icon>${selected.meta?.useStudio === true ? 'Canvas Preview' : 'Studio'}</button>
        <button type="button" class="creative-chip-btn" onclick="canvasRefreshHyperframesClip('${safeElementId}')"><iconify-icon icon="solar:refresh-bold-duotone" width="14" height="14"></iconify-icon>Refresh</button>
        <button type="button" class="creative-chip-btn" onclick="canvasLintHyperframesClip('${safeElementId}')"><iconify-icon icon="solar:check-circle-bold-duotone" width="14" height="14"></iconify-icon>Lint</button>
        <button type="button" class="creative-chip-btn" onclick="canvasQaHyperframesClip('${safeElementId}')"><iconify-icon icon="solar:eye-bold-duotone" width="14" height="14"></iconify-icon>QA</button>
        <button type="button" class="creative-chip-btn creative-chip-btn--accent" onclick="canvasExportHyperframesClip('${safeElementId}', 'mp4')"><iconify-icon icon="solar:videocamera-record-bold-duotone" width="14" height="14"></iconify-icon>Producer MP4</button>
      </div>
      ${ingest ? `<div class="creative-info-note" style="margin-top:10px">Catalog ingest: ${escHtml(String(ingest.assetCount ?? assets.length))} assets, ${escHtml(String(ingest.fontCount ?? 0))} fonts, ${escHtml(String(ingest.rewrittenPathCount ?? 0))} paths rewritten.</div>` : ''}
      ${warnings.length ? `<div class="creative-info-note" style="margin-top:10px;color:#fbbf24">${warnings.slice(0, 3).map((warning) => escHtml(String(warning))).join('<br>')}</div>` : ''}
      ${lintErrors.length || lintWarnings.length ? `<div class="creative-info-note" style="margin-top:10px">${lintErrors.length} lint errors, ${lintWarnings.length} warnings.</div>` : ''}
      ${qaIssues.length ? `<div class="creative-info-note" style="margin-top:10px">${qaIssues.length} QA issues found.</div>` : ''}
      ${trackRows ? `<div style="margin-top:10px"><div style="font-size:10px;font-weight:800;color:#a8a29e;margin-bottom:6px">TRACKS</div>${trackRows}</div>` : ''}
      ${slotRows ? `<div style="margin-top:10px"><div style="font-size:10px;font-weight:800;color:#a8a29e;margin-bottom:6px">SLOTS</div>${slotRows}</div>` : ''}
      ${variableRows ? `<div style="margin-top:10px"><div style="font-size:10px;font-weight:800;color:#a8a29e;margin-bottom:6px">VARIABLES</div>${variableRows}</div>` : ''}
    </div>
  `;
}

window.canvasToggleHyperframesStudio = function (elementId) {
  const live = getHyperframesElementById(elementId);
  if (!live) return;
  live.meta = { ...(live.meta || {}), useStudio: live.meta?.useStudio !== true };
  const entry = _hfControllers.get(elementId);
  if (entry) {
    try { entry.controller.dispose(); } catch {}
    _hfControllers.delete(elementId);
  }
  renderCreativeWorkspace();
  persistActiveChat();
};

window.canvasHyperframesEditLayer = function (elementId, layerElementId, kind) {
  const entry = _hfControllers.get(elementId);
  if (!entry) return;
  if (kind === 'text') {
    const newText = window.prompt('New text for layer:');
    if (newText === null) return;
    entry.controller.patch([{ op: 'set-text', elementId: layerElementId, text: newText }]);
  }
};

window.canvasHyperframesPatchFromSlot = function (input) {
  if (!input) return;
  const elementId = input.getAttribute('data-hf-element');
  const slotId = input.getAttribute('data-hf-slot');
  const kind = input.getAttribute('data-hf-slot-kind');
  const value = input.value;
  const entry = _hfControllers.get(elementId);
  if (!entry) return;
  // Slot dispatch — the slot's `selector` resolved to an element id at extract
  // time; we just pass through to set-attribute or set-variable depending on
  // the kind. Element-level slots with selector "#id" route via element id.
  const slot = (entry.element.meta?.slots || []).find((s) => s.id === slotId);
  if (!slot) return;
  if (slot.kind === 'variable') {
    entry.controller.patch([{ op: 'set-variable', name: slot.variableName || slot.id, value }]);
    return;
  }
  if (!slot.selector || !slot.selector.startsWith('#')) return;
  const elementHfId = slot.selector.slice(1);
  if (kind === 'text') entry.controller.patch([{ op: 'set-text', elementId: elementHfId, text: value }]);
  else if (kind === 'color') entry.controller.patch([{ op: 'set-color', elementId: elementHfId, color: value }]);
  else if (kind === 'number') entry.controller.patch([{ op: 'set-font-size', elementId: elementHfId, fontSize: Number(value) }]);
  else if (kind === 'asset') entry.controller.patch([{ op: 'set-asset', elementId: elementHfId, assetPlaceholderId: value }]);
};

window.canvasHyperframesPatchFromVariable = function (input) {
  if (!input) return;
  const elementId = input.getAttribute('data-hf-element');
  const variableId = input.getAttribute('data-hf-variable');
  const value = input.type === 'checkbox' ? input.checked : input.type === 'number' ? Number(input.value) : input.value;
  const entry = _hfControllers.get(elementId);
  if (!entry) return;
  entry.controller.patch([{ op: 'set-variable', name: variableId, value }]);
};

function getHyperframesElementById(elementId) {
  return creativeSceneDoc.elements.find((element) => element.id === elementId && element.type === 'hyperframes') || null;
}

function updateHyperframesElementMeta(elementId, patch = {}, options = {}) {
  const live = getHyperframesElementById(elementId);
  if (!live) return null;
  live.meta = { ...(live.meta || {}), ...patch };
  if (options.render !== false) renderCreativeWorkspace({ skipStageRender: options.skipStageRender === true });
  persistActiveChat();
  return live;
}

function getHyperframesElementEntryPath(element) {
  const projectPath = String(element?.meta?.projectPath || '').trim().replace(/\\/g, '/').replace(/\/+$/g, '');
  const entryFile = String(element?.meta?.entryFile || 'index.html').trim().replace(/\\/g, '/').replace(/^\/+/g, '') || 'index.html';
  if (!projectPath) return '';
  return `${projectPath}/${entryFile}`.replace(/\/+/g, '/');
}

async function ensureHyperframesElementSourceHtml(element) {
  if (!element || element.type !== 'hyperframes') return '';
  const existing = String(element.meta?.html || '');
  if (existing.trim()) return existing;
  const entryPath = getHyperframesElementEntryPath(element);
  if (!entryPath) return '';
  const res = await api(`/api/canvas/file?path=${encodeURIComponent(entryPath)}`);
  const html = typeof res?.content === 'string' ? res.content : '';
  if (html.trim()) {
    element.meta = { ...(element.meta || {}), html, dirty: false };
    persistActiveChat();
  }
  return html;
}

window.canvasRefreshHyperframesClip = async function (elementId) {
  const live = getHyperframesElementById(elementId);
  if (!live) return;
  try {
    const html = await ensureHyperframesElementSourceHtml(live);
    const extraction = await api('/api/canvas/hyperframes/extract-layers', { method: 'POST', body: { html } });
    if (!extraction?.success) throw new Error(extraction?.error || 'Could not parse HyperFrames clip');
    applyHyperframesExtractionToElement(live, extraction);
    renderCreativeWorkspace({ skipStageRender: true });
    showToast({ message: 'HyperFrames metadata refreshed.', kind: 'success' });
  } catch (err) {
    showToast({ message: `HyperFrames refresh failed: ${err?.message || err}`, kind: 'error' });
  }
};

window.canvasLintHyperframesClip = async function (elementId) {
  const live = getHyperframesElementById(elementId);
  if (!live) return;
  try {
    const html = await ensureHyperframesElementSourceHtml(live);
    const lint = await api('/api/canvas/hyperframes/lint', { method: 'POST', body: { html } });
    if (!lint?.success) throw new Error(lint?.error || 'HyperFrames lint failed');
    const lintResult = lint.lint || lint;
    updateHyperframesElementMeta(elementId, { lint: lintResult }, { skipStageRender: true });
    const errorCount = Array.isArray(lintResult.errors) ? lintResult.errors.length : 0;
    const warningCount = Array.isArray(lintResult.warnings) ? lintResult.warnings.length : 0;
    showToast({ message: `HyperFrames lint: ${errorCount} errors, ${warningCount} warnings.`, kind: errorCount ? 'error' : 'success' });
  } catch (err) {
    showToast({ message: `HyperFrames lint failed: ${err?.message || err}`, kind: 'error' });
  }
};

window.canvasQaHyperframesClip = async function (elementId) {
  const live = getHyperframesElementById(elementId);
  if (!live) return;
  try {
    const html = await ensureHyperframesElementSourceHtml(live);
    const qaReport = await api('/api/canvas/hyperframes/qa', { method: 'POST', body: { html } });
    if (!qaReport?.success) throw new Error(qaReport?.error || 'HyperFrames QA failed');
    const report = qaReport.report || qaReport;
    updateHyperframesElementMeta(elementId, { qaReport: report }, { skipStageRender: true });
    const issueCount = Array.isArray(report.issues) ? report.issues.length : 0;
    showToast({ message: `HyperFrames QA: ${issueCount} issues.`, kind: issueCount ? 'warning' : 'success' });
  } catch (err) {
    showToast({ message: `HyperFrames QA failed: ${err?.message || err}`, kind: 'error' });
  }
};

window.canvasExportHyperframesClip = async function (elementId, format = 'mp4') {
  const live = getHyperframesElementById(elementId);
  if (!live) return;
  try {
    showToast({ message: 'Rendering HyperFrames clip with producer...', kind: 'info' });
    const html = await ensureHyperframesElementSourceHtml(live);
    if (!html.trim()) throw new Error('HyperFrames source HTML is missing.');
    const safeId = String(live.meta?.compositionId || elementId || 'hyperframes').replace(/[^a-z0-9._-]+/gi, '-').replace(/^-+|-+$/g, '') || 'hyperframes';
    const variables = {};
    (Array.isArray(live.meta?.variableBindings) ? live.meta.variableBindings : []).forEach((binding) => {
      const id = String(binding?.variable?.id || '').trim();
      if (id) variables[id] = binding.currentValue;
    });
    const result = await api('/api/canvas/hyperframes/render', {
      method: 'POST',
      body: {
        html,
        filename: `${safeId}.${String(format || 'mp4').toLowerCase()}`,
        format,
        fps: Number(creativeSceneDoc?.frameRate) || 60,
        quality: 'standard',
        variables,
      },
    });
    if (!result?.success) throw new Error(result?.error || 'HyperFrames render failed');
    updateHyperframesElementMeta(elementId, { lastProducerExport: result }, { skipStageRender: true });
    if (result.outputPath) canvasDownloadFile(result.outputPath, result.outputPath.split(/[\\/]/).pop() || `${safeId}.${format}`);
    creativeActiveExport = {
      format: String(format || 'mp4').toLowerCase(),
      renderer: 'hyperframes-producer',
      serverJobId: result.job?.id || '',
      startedAt: Date.now(),
      frameRate: Number(creativeSceneDoc?.frameRate) || 60,
      progress: 1,
      elapsedMs: 0,
      cancelRequested: false,
      status: 'complete',
      progressLabel: 'HyperFrames producer export complete',
      hyperframesElementId: elementId,
      outputPath: result.outputPath || '',
    };
    showToast({ message: 'HyperFrames producer export complete.', kind: 'success' });
  } catch (err) {
    showToast({ message: `HyperFrames export failed: ${err?.message || err}`, kind: 'error' });
  }
};

function insertHyperframesClip({ html, item, durationMs, compositionId, advancedBlock, modal, importResult = null, extraction = null }) {
  try {
    const extracted = extraction && typeof extraction === 'object' ? extraction : {};
    const ingest = importResult?.ingest && typeof importResult.ingest === 'object' ? importResult.ingest : null;
    const op = {
      type: 'add',
      element: {
        type: 'hyperframes',
        x: 80,
        y: 80,
        width: 1080,
        height: 1920,
        meta: {
          html, compositionId,
          advancedBlock: !!advancedBlock,
          durationMs: Number(durationMs) || 6000,
          catalogId: item?.id || null,
          sourceFormat: 'hyperframes',
          layers: Array.isArray(extracted.layers) ? extracted.layers : [],
          tracks: Array.isArray(extracted.tracks) ? extracted.tracks : [],
          slots: Array.isArray(extracted.slots) ? extracted.slots : [],
          variableBindings: Array.isArray(extracted.variableBindings) ? extracted.variableBindings : [],
          variables: Array.isArray(extracted.variables) ? extracted.variables : {},
          assets: Array.isArray(importResult?.assets) ? importResult.assets : [],
          warnings: Array.isArray(importResult?.warnings) ? importResult.warnings : [],
          ingest,
        },
      },
    };
    creativeSceneDoc = applySceneGraphOps(creativeSceneDoc, [op]);
    const inserted = [...(creativeSceneDoc.elements || [])].reverse().find((element) => element?.type === 'hyperframes' && element?.meta?.compositionId === compositionId);
    creativeComposition = createVideoCompositionFromActiveClip({ scene: creativeSceneDoc, hyperframesClip: inserted || null });
    persistCompositionState();
    if (modal) modal.remove();
    renderCreativeWorkspace();
    showToast({ message: `Inserted ${item?.name || 'HyperFrames clip'}`, kind: 'success' });
  } catch (err) {
    showToast({ message: `Failed to insert: ${err?.message || err}`, kind: 'error' });
  }
}

function renderCreativeWorkspace(options = {}) {
  const shell = document.getElementById('canvas-creative-shell');
  const library = document.getElementById('canvas-creative-library');
  const stage = document.getElementById('canvas-creative-stage');
  const props = document.getElementById('canvas-creative-properties');
  const timeline = document.getElementById('canvas-video-timeline');
  const timelineTracks = document.getElementById('canvas-video-track-list');
  const timelineMeta = document.getElementById('canvas-video-meta');
  const title = document.getElementById('canvas-creative-title');
  const subtitle = document.getElementById('canvas-creative-subtitle');
  const emptyState = document.getElementById('canvas-empty-state');
  const noFilesHint = document.getElementById('canvas-no-files-hint');
  const fileBrowser = document.getElementById('canvas-file-browser');
  const editorWrap = document.getElementById('canvas-editor-wrap');
  const previewShell = document.getElementById('canvas-preview-shell');
  const previewFrame = document.getElementById('canvas-preview-frame');
  if (!shell || !library || !stage || !props) return;
  const mode = normalizeCreativeMode(window.currentCreativeMode);
  if (mode !== 'video') {
    if (isCreativePlaybackActive()) stopCreativePlayback({ persist: false });
    stopCreativeAudioPreview();
  }
  if (!isStructuredCreativeMode(mode)) {
    creativeStageLastMode = null;
    creativeStageZoomMode = 'auto';
    creativeStageViewportSignature = '';
    disposeCreativeFabricBridge();
    shell.style.display = 'none';
    return;
  }
  if (creativeStageLastMode !== mode) {
    creativeStageLastMode = mode;
    creativeStageZoomMode = 'auto';
    creativeStageViewportSignature = '';
  }
  if (emptyState) emptyState.style.display = 'none';
  if (noFilesHint) noFilesHint.style.display = 'none';
  if (fileBrowser) fileBrowser.style.display = 'none';
  if (editorWrap) editorWrap.style.display = 'none';
  if (previewShell) previewShell.style.display = 'none';
  if (previewFrame) previewFrame.style.display = 'none';
  try {
    ensureCreativeSceneForMode(mode);
    creativeTimelineMs = Math.max(0, Math.min(Math.max(1000, Number(creativeSceneDoc.durationMs) || 12000), creativeTimelineMs));
    return renderCreativeWorkspaceStudioV3({ shell, library, stage, props, timeline, timelineTracks, timelineMeta, title, subtitle, mode, skipStageRender: options.skipStageRender === true });
  } catch (err) {
    shell.style.display = 'flex';
    if (title) title.textContent = getStructuredCreativeModeLabel(mode);
    if (subtitle) subtitle.textContent = 'Creative workspace recovered from a render error';
    library.innerHTML = `<div style="padding:16px;color:#a8a29e;font-size:11px;line-height:1.7">The creative library could not render for this frame.</div>`;
    stage.style.width = '100%';
    stage.style.height = '100%';
    stage.style.background = 'linear-gradient(180deg,#18181b,#27272a)';
    stage.innerHTML = `<div style="position:absolute;inset:18px;display:flex;align-items:center;justify-content:center;border:1px dashed rgba(248,113,113,0.45);border-radius:18px;color:#fecaca;font-size:12px;font-weight:700;text-align:center;padding:24px">Creative workspace render error<br>${escHtml(String(err?.message || err || 'Unknown error'))}</div>`;
    props.innerHTML = `<div style="padding:18px 16px"><div style="font-size:10px;font-weight:800;letter-spacing:0.06em;text-transform:uppercase;color:#fca5a5">Render Error</div><div style="font-size:12px;color:#e7e5e4;line-height:1.7;margin-top:10px">${escHtml(String(err?.stack || err?.message || err || 'Unknown error')).slice(0, 2000)}</div></div>`;
    if (timeline) timeline.style.display = 'none';
    addProcessEntry('error', `Creative workspace render failed: ${String(err?.message || err || 'Unknown error')}`);
    return;
  }
  shell.style.display = 'flex';
  if (title) title.textContent = getStructuredCreativeModeLabel(mode);
  if (subtitle) subtitle.textContent = mode === 'video'
    ? 'Shared scene graph with a video timeline foundation'
    : 'Shared scene graph with direct composition controls';

  const selected = getSelectedCreativeElement();
  library.innerHTML = `<div style="padding:10px 14px;border-bottom:1px solid rgba(255,255,255,0.06)"><button onclick="canvasOpenHyperframesCatalog()" style="width:100%;text-align:left;padding:8px 10px;border:1px solid rgba(255,255,255,0.12);background:linear-gradient(135deg,#0ea5e9,#6366f1);color:#fff;border-radius:8px;font-size:12px;font-weight:700;cursor:pointer">＋ HyperFrames Catalog</button></div>` + (mode === 'video' ? renderCompositionAssetSection() : '') + Object.entries(getActiveCreativeElementLibrary()).map(([section, items]) => `
    <div style="padding:14px 14px 6px">
      <div style="font-size:10px;font-weight:800;letter-spacing:0.06em;text-transform:uppercase;color:#a8a29e;margin-bottom:8px">${escHtml(section)}</div>
      <div style="display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:8px">
        ${items.map((item) => `
          <button onclick="canvasAddCreativeLibraryItem('${escHtml(section)}','${escHtml(item.kind)}')" style="text-align:left;border:1px solid rgba(255,255,255,0.09);background:rgba(255,255,255,0.04);color:#f5f5f4;border-radius:10px;padding:10px 10px 9px;cursor:pointer">
            <div style="font-size:12px;font-weight:700">${escHtml(item.label)}</div>
            <div style="font-size:10px;color:#a8a29e;margin-top:4px">${escHtml(item.type)}</div>
          </button>
        `).join('')}
      </div>
    </div>
  `).join('');

  stage.style.width = `${creativeSceneDoc.width}px`;
  stage.style.height = `${creativeSceneDoc.height}px`;
  stage.style.background = creativeSceneDoc.background || '#ffffff';
  stage.innerHTML = creativeSceneDoc.elements
    .slice()
    .sort((a, b) => (a.zIndex || 0) - (b.zIndex || 0))
    .map((element) => {
      const selectedClass = element.id === creativeSelectedId ? '2px solid #38bdf8' : '1px solid transparent';
      const baseStyle = [
        'position:absolute',
        `left:${Number(element.x) || 0}px`,
        `top:${Number(element.y) || 0}px`,
        `width:${Math.max(8, Number(element.width) || 0)}px`,
        `height:${Math.max(8, Number(element.height) || 0)}px`,
        `opacity:${Number.isFinite(Number(element.opacity)) ? Number(element.opacity) : 1}`,
        `transform:rotate(${Number(element.rotation) || 0}deg)`,
        `z-index:${Number(element.zIndex) || 0}`,
        `outline:${selectedClass}`,
        'outline-offset:0',
        'cursor:pointer',
      ].join(';');
      if (element.type === 'text') {
        return `<div onclick="canvasSelectCreativeElement('${element.id}')" style="${baseStyle};padding:4px 6px;color:${escHtml(element.meta?.color || '#111827')};font-size:${Number(element.meta?.fontSize) || 24}px;font-weight:${Number(element.meta?.fontWeight) || 700};line-height:${Number(element.meta?.lineHeight) || 1.2};letter-spacing:${Number(element.meta?.letterSpacing) || 0}px;white-space:pre-wrap;overflow:hidden">${escHtml(element.meta?.content || 'Text')}</div>`;
      }
      if (element.type === 'icon') {
        return `<div onclick="canvasSelectCreativeElement('${element.id}')" style="${baseStyle};display:flex;align-items:center;justify-content:center;color:${escHtml(element.meta?.color || '#111827')}"><iconify-icon icon="${escHtml(element.meta?.iconName || 'solar:stars-bold-duotone')}" width="${Math.max(24, Math.min(Number(element.width) || 64, Number(element.height) || 64))}" height="${Math.max(24, Math.min(Number(element.width) || 64, Number(element.height) || 64))}"></iconify-icon></div>`;
      }
      if (element.type === 'image') {
        const bg = element.meta?.source ? `background-image:url('${escHtml(creativeMediaSourceUrl(element.meta.source)).replace(/'/g, '&#39;')}');background-size:cover;background-position:center center;` : 'background:linear-gradient(135deg,#d6d3d1,#f5f5f4);';
        return `<div onclick="canvasSelectCreativeElement('${element.id}')" style="${baseStyle};border-radius:${Number(element.meta?.radius) || 18}px;border:1px dashed rgba(15,23,42,0.18);${bg}"></div>`;
      }
      if (element.type === 'hyperframes') {
        // Mount placeholder — the HyperFrames iframe controller is attached
        // post-render in syncHyperframesControllers(), which keeps a registry
        // keyed by element.id so the iframe survives stage re-renders.
        return `<div onclick="canvasSelectCreativeElement('${element.id}')" data-hyperframes-mount="${escHtml(element.id)}" style="${baseStyle};background:rgba(0,0,0,0.04);overflow:hidden;border-radius:8px"></div>`;
      }
      const fill = element.meta?.fill || '#111827';
      const stroke = element.meta?.stroke || 'transparent';
      const radius = Number(element.meta?.radius) || 0;
      return `<div onclick="canvasSelectCreativeElement('${element.id}')" style="${baseStyle};background:${escHtml(fill)};border:${Math.max(0, Number(element.meta?.strokeWidth) || 0)}px solid ${escHtml(stroke)};border-radius:${radius}px"></div>`;
    }).join('');
  syncHyperframesControllers(stage);
  stage.onclick = (event) => {
    if (event.target === stage) setCreativeSelection(null);
  };

  const selectedContext = selected ? buildSceneSelectionContext(creativeSceneDoc, selected.id) : null;
  props.innerHTML = selected ? `
    <div style="padding:16px 16px 12px;border-bottom:1px solid rgba(255,255,255,0.08)">
      <div style="font-size:10px;font-weight:800;letter-spacing:0.06em;text-transform:uppercase;color:#a8a29e">Selection</div>
      <div style="font-size:15px;font-weight:800;color:#fafaf9;margin-top:6px">${escHtml(selected.type)} · ${escHtml(selected.id)}</div>
      <div style="font-size:11px;color:#a8a29e;line-height:1.6;margin-top:6px">${escHtml(`x ${selected.x} · y ${selected.y} · ${selected.width}×${selected.height}`)}</div>
      <div style="font-size:10px;color:#a8a29e;line-height:1.5;margin-top:6px">${escHtml(mode === 'video' ? 'Drag on stage to create or update a keyframe at the current playhead.' : 'Drag on stage to move elements. Use the corner handle to resize.')}</div>
    </div>
    <div style="padding:14px 16px;display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:10px">
      ${renderCreativePropertyField('X', 'x', selected.x)}
      ${renderCreativePropertyField('Y', 'y', selected.y)}
      ${renderCreativePropertyField('Width', 'width', selected.width)}
      ${renderCreativePropertyField('Height', 'height', selected.height)}
      ${renderCreativePropertyField('Rotate', 'rotation', selected.rotation)}
      ${renderCreativePropertyField('Opacity', 'opacity', selected.opacity, 'number', { step: '0.1', min: '0', max: '1' })}
    </div>
    ${selected.type === 'text' ? `
      <div style="padding:0 16px 14px">
        ${renderCreativePropertyTextarea('Content', 'meta.content', selected.meta?.content || '')}
        <div style="display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:10px;margin-top:10px">
          ${renderCreativePropertyField('Font Size', 'meta.fontSize', selected.meta?.fontSize || 24)}
          ${renderCreativePropertyField('Weight', 'meta.fontWeight', selected.meta?.fontWeight || 700)}
          ${renderCreativePropertyField('Line Height', 'meta.lineHeight', selected.meta?.lineHeight || 1.2, 'number', { step: '0.1' })}
          ${renderCreativePropertyField('Color', 'meta.color', selected.meta?.color || '#111827', 'color')}
        </div>
      </div>` : ''}
    ${selected.type === 'shape' ? `
      <div style="padding:0 16px 14px">
        <div style="display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:10px">
          ${renderCreativePropertyField('Fill', 'meta.fill', selected.meta?.fill || '#111827', 'color')}
          ${renderCreativePropertyField('Stroke', 'meta.stroke', selected.meta?.stroke || '#111827', 'color')}
          ${renderCreativePropertyField('Radius', 'meta.radius', selected.meta?.radius || 0)}
          ${renderCreativePropertyField('Stroke Width', 'meta.strokeWidth', selected.meta?.strokeWidth || 0)}
        </div>
      </div>` : ''}
    ${selected.type === 'hyperframes' ? renderHyperframesInspector(selected) : ''}
    ${selected.type === 'icon' ? `
      <div style="padding:0 16px 14px">
        ${renderCreativePropertyField('Icon', 'meta.iconName', selected.meta?.iconName || 'solar:stars-bold-duotone', 'text')}
        <div style="display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:10px;margin-top:10px">
          ${renderCreativePropertyField('Color', 'meta.color', selected.meta?.color || '#111827', 'color')}
        </div>
      </div>` : ''}
    <div style="padding:4px 16px 16px;display:flex;flex-wrap:wrap;gap:8px">
      <button onclick="canvasDeleteCreativeSelection()" style="display:inline-flex;align-items:center;gap:5px;border:1px solid rgba(239,68,68,0.28);background:rgba(239,68,68,0.12);color:#fca5a5;border-radius:8px;padding:6px 10px;font-size:11px;font-weight:700;cursor:pointer"><iconify-icon icon="solar:trash-bin-trash-bold-duotone" width="14" height="14"></iconify-icon>Delete</button>
      <button onclick="canvasNudgeCreativeZ(1)" style="display:inline-flex;align-items:center;gap:5px;border:1px solid rgba(255,255,255,0.12);background:rgba(255,255,255,0.05);color:#f5f5f4;border-radius:8px;padding:6px 10px;font-size:11px;font-weight:700;cursor:pointer"><iconify-icon icon="solar:arrow-up-bold-duotone" width="14" height="14"></iconify-icon>Forward</button>
      <button onclick="canvasNudgeCreativeZ(-1)" style="display:inline-flex;align-items:center;gap:5px;border:1px solid rgba(255,255,255,0.12);background:rgba(255,255,255,0.05);color:#f5f5f4;border-radius:8px;padding:6px 10px;font-size:11px;font-weight:700;cursor:pointer"><iconify-icon icon="solar:arrow-down-bold-duotone" width="14" height="14"></iconify-icon>Back</button>
    </div>
    <div style="padding:0 16px 16px">
      <div style="font-size:10px;font-weight:800;letter-spacing:0.06em;text-transform:uppercase;color:#a8a29e;margin-bottom:8px">AI Focus</div>
      <pre style="margin:0;padding:12px;border-radius:12px;border:1px solid rgba(255,255,255,0.08);background:rgba(255,255,255,0.03);color:#d6d3d1;font-size:10px;line-height:1.65;white-space:pre-wrap">${escHtml(JSON.stringify(selectedContext, null, 2).slice(0, 2200))}</pre>
    </div>
  ` : `
    <div style="padding:18px 16px">
      <div style="font-size:10px;font-weight:800;letter-spacing:0.06em;text-transform:uppercase;color:#a8a29e">Properties</div>
      <div style="font-size:13px;font-weight:700;color:#fafaf9;margin-top:10px">Nothing selected</div>
      <div style="font-size:11px;color:#a8a29e;line-height:1.7;margin-top:8px">Select an element on the stage and this panel will expose focused controls and AI context.</div>
    </div>
  `;

  if (timeline && timelineTracks && timelineMeta) {
    const isVideo = mode === 'video';
    timeline.style.display = isVideo ? 'block' : 'none';
    if (isVideo) {
      timelineMeta.textContent = `${creativeSceneDoc.elements.length} tracks · 12s draft`;
      timelineTracks.innerHTML = creativeSceneDoc.elements.map((element, idx) => `
        <div style="display:grid;grid-template-columns:160px minmax(0,1fr);gap:10px;align-items:center">
          <div style="font-size:11px;color:${element.id === creativeSelectedId ? '#f8fafc' : '#a8a29e'};font-weight:${element.id === creativeSelectedId ? '700' : '600'}">${escHtml(element.meta?.content || element.meta?.iconName || `${element.type} ${idx + 1}`)}</div>
          <div style="height:16px;border-radius:999px;background:rgba(255,255,255,0.06);position:relative;overflow:hidden">
            <div style="position:absolute;left:${8 + idx * 6}%;top:2px;bottom:2px;width:${Math.max(18, 28 - idx)}%;border-radius:999px;background:${element.id === creativeSelectedId ? 'linear-gradient(90deg,#38bdf8,#60a5fa)' : 'linear-gradient(90deg,#f97316,#fb923c)'}"></div>
          </div>
        </div>
      `).join('');
    }
  }
}

function renderCreativePropertyField(label, key, value, type = 'number', extra = {}) {
  const step = extra.step ? `step="${escHtml(extra.step)}"` : '';
  const min = extra.min ? `min="${escHtml(extra.min)}"` : '';
  const max = extra.max ? `max="${escHtml(extra.max)}"` : '';
  const inputValue = type === 'color' || type === 'text'
    ? String(value ?? '')
    : Number.isFinite(Number(value)) ? String(value) : '0';
  return `
    <label style="display:flex;flex-direction:column;gap:5px">
      <span style="font-size:10px;font-weight:800;letter-spacing:0.05em;text-transform:uppercase;color:#a8a29e">${escHtml(label)}</span>
      <input type="${type}" value="${escHtml(inputValue)}" ${step} ${min} ${max} oninput="canvasUpdateCreativeProperty('${escHtml(key)}', this.value, '${type}')" style="width:100%;box-sizing:border-box;border:1px solid rgba(255,255,255,0.12);background:rgba(255,255,255,0.04);color:#fafaf9;border-radius:9px;padding:8px 10px;font-size:12px;font-family:inherit">
    </label>
  `;
}

function renderCreativePropertyTextarea(label, key, value) {
  return `
    <label style="display:flex;flex-direction:column;gap:5px">
      <span style="font-size:10px;font-weight:800;letter-spacing:0.05em;text-transform:uppercase;color:#a8a29e">${escHtml(label)}</span>
      <textarea oninput="canvasUpdateCreativeProperty('${escHtml(key)}', this.value, 'text')" style="width:100%;min-height:88px;box-sizing:border-box;border:1px solid rgba(255,255,255,0.12);background:rgba(255,255,255,0.04);color:#fafaf9;border-radius:10px;padding:10px 12px;font-size:12px;font-family:inherit;resize:vertical">${escHtml(String(value || ''))}</textarea>
    </label>
  `;
}

function renderCreativePropertyFieldV2(label, key, value, type = 'number', extra = {}) {
  const step = extra.step ? `step="${escHtml(extra.step)}"` : '';
  const min = extra.min ? `min="${escHtml(extra.min)}"` : '';
  const max = extra.max ? `max="${escHtml(extra.max)}"` : '';
  const handler = extra.handler || 'canvasUpdateCreativeProperty';
  const inputValue = type === 'color'
    ? (/^#(?:[0-9a-f]{3}|[0-9a-f]{6})$/i.test(String(value ?? '').trim()) ? String(value).trim() : '#111827')
    : type === 'text'
    ? String(value ?? '')
    : Number.isFinite(Number(value)) ? String(value) : '0';
  return `
    <label style="display:flex;flex-direction:column;gap:5px">
      <span style="font-size:10px;font-weight:800;letter-spacing:0.05em;text-transform:uppercase;color:#a8a29e">${escHtml(label)}</span>
      <input type="${type}" value="${escHtml(inputValue)}" ${step} ${min} ${max} oninput="${handler}('${escHtml(key)}', this.value, '${type}')" style="width:100%;box-sizing:border-box;border:1px solid rgba(255,255,255,0.12);background:rgba(255,255,255,0.04);color:#fafaf9;border-radius:9px;padding:8px 10px;font-size:12px;font-family:inherit">
    </label>
  `;
}

function renderCreativePropertyToggleV2(label, key, value, extra = {}) {
  const handler = extra.handler || 'canvasUpdateCreativeProperty';
  return `
    <label style="display:flex;flex-direction:column;gap:5px;justify-content:flex-end">
      <span style="font-size:10px;font-weight:800;letter-spacing:0.05em;text-transform:uppercase;color:#a8a29e">${escHtml(label)}</span>
      <label style="display:flex;align-items:center;gap:8px;border:1px solid rgba(255,255,255,0.12);background:rgba(255,255,255,0.04);color:#fafaf9;border-radius:9px;padding:9px 10px;font-size:12px">
        <input type="checkbox" ${value ? 'checked' : ''} onchange="${handler}('${escHtml(key)}', this.checked, 'boolean')">
        <span>${value ? 'On' : 'Off'}</span>
      </label>
    </label>
  `;
}

function renderCreativePropertyTextareaV2(label, key, value, extra = {}) {
  const handler = extra.handler || 'canvasUpdateCreativeProperty';
  return `
    <label style="display:flex;flex-direction:column;gap:5px">
      <span style="font-size:10px;font-weight:800;letter-spacing:0.05em;text-transform:uppercase;color:#a8a29e">${escHtml(label)}</span>
      <textarea oninput="${handler}('${escHtml(key)}', this.value, 'text')" style="width:100%;min-height:88px;box-sizing:border-box;border:1px solid rgba(255,255,255,0.12);background:rgba(255,255,255,0.04);color:#fafaf9;border-radius:10px;padding:10px 12px;font-size:12px;font-family:inherit;resize:vertical">${escHtml(String(value || ''))}</textarea>
    </label>
  `;
}

function renderCreativeKeyframeSectionV2(selected) {
  const keyframes = Array.isArray(selected?.meta?.keyframes) ? selected.meta.keyframes.slice().sort((a, b) => (a.atMs || 0) - (b.atMs || 0)) : [];
  const currentEase = keyframes.find((keyframe) => Number(keyframe.atMs) === Number(creativeTimelineMs))?.ease || '';
  return `
    <div style="padding:0 16px 14px">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:10px">
        <div style="font-size:10px;font-weight:800;letter-spacing:0.06em;text-transform:uppercase;color:#a8a29e">Keyframes</div>
        <button onclick="canvasAddCreativeKeyframe()" style="display:inline-flex;align-items:center;gap:5px;border:1px solid rgba(56,189,248,0.35);background:rgba(56,189,248,0.14);color:#7dd3fc;border-radius:8px;padding:6px 9px;font-size:11px;font-weight:700;cursor:pointer"><iconify-icon icon="solar:add-circle-bold-duotone" width="14" height="14"></iconify-icon>Add @ ${escHtml(formatCreativeTimelineTime(creativeTimelineMs))}</button>
      </div>
      <div style="display:flex;flex-wrap:wrap;gap:8px;margin-bottom:10px">
        <button onclick="canvasApplyCreativeAnimationPreset('fade_in')" style="display:inline-flex;align-items:center;gap:5px;border:1px solid rgba(249,115,22,0.32);background:rgba(249,115,22,0.14);color:#fdba74;border-radius:8px;padding:6px 9px;font-size:11px;font-weight:700;cursor:pointer">Fade In</button>
        <button onclick="canvasApplyCreativeAnimationPreset('slide_up')" style="display:inline-flex;align-items:center;gap:5px;border:1px solid rgba(56,189,248,0.32);background:rgba(56,189,248,0.14);color:#7dd3fc;border-radius:8px;padding:6px 9px;font-size:11px;font-weight:700;cursor:pointer">Slide Up</button>
        <button onclick="canvasApplyCreativeAnimationPreset('fade_slide_up')" style="display:inline-flex;align-items:center;gap:5px;border:1px solid rgba(168,85,247,0.32);background:rgba(168,85,247,0.14);color:#d8b4fe;border-radius:8px;padding:6px 9px;font-size:11px;font-weight:700;cursor:pointer">Fade + Up</button>
      </div>
      <label style="display:flex;flex-direction:column;gap:5px;margin-bottom:10px">
        <span style="font-size:10px;font-weight:800;letter-spacing:0.05em;text-transform:uppercase;color:#a8a29e">Ease At Playhead</span>
        <select onchange="canvasSetCreativeKeyframeEase(this.value)" style="width:100%;box-sizing:border-box;border:1px solid rgba(255,255,255,0.12);background:rgba(255,255,255,0.04);color:#fafaf9;border-radius:10px;padding:9px 10px;font-size:12px;font-family:inherit">
          <option value="">Choose ease...</option>
          ${['power2.out', 'power2.inOut', 'power3.out', 'power3.inOut', 'back.out(1.7)'].map((ease) => `
            <option value="${escHtml(ease)}" ${currentEase === ease ? 'selected' : ''}>${escHtml(ease)}</option>
          `).join('')}
        </select>
      </label>
      <div style="display:flex;flex-wrap:wrap;gap:8px;margin-bottom:10px">
        <button onclick="canvasApplyCreativeAnimationPreset('fade_in')" style="display:inline-flex;align-items:center;gap:5px;border:1px solid rgba(249,115,22,0.32);background:rgba(249,115,22,0.14);color:#fdba74;border-radius:8px;padding:6px 9px;font-size:11px;font-weight:700;cursor:pointer">Fade In</button>
        <button onclick="canvasApplyCreativeAnimationPreset('slide_up')" style="display:inline-flex;align-items:center;gap:5px;border:1px solid rgba(56,189,248,0.32);background:rgba(56,189,248,0.14);color:#7dd3fc;border-radius:8px;padding:6px 9px;font-size:11px;font-weight:700;cursor:pointer">Slide Up</button>
        <button onclick="canvasApplyCreativeAnimationPreset('fade_slide_up')" style="display:inline-flex;align-items:center;gap:5px;border:1px solid rgba(168,85,247,0.32);background:rgba(168,85,247,0.14);color:#d8b4fe;border-radius:8px;padding:6px 9px;font-size:11px;font-weight:700;cursor:pointer">Fade + Up</button>
      </div>
      <label style="display:flex;flex-direction:column;gap:5px;margin-bottom:10px">
        <span style="font-size:10px;font-weight:800;letter-spacing:0.05em;text-transform:uppercase;color:#a8a29e">Ease At Playhead</span>
        <select onchange="canvasSetCreativeKeyframeEase(this.value)" style="width:100%;box-sizing:border-box;border:1px solid rgba(255,255,255,0.12);background:rgba(255,255,255,0.04);color:#fafaf9;border-radius:10px;padding:9px 10px;font-size:12px;font-family:inherit">
          <option value="">Choose ease...</option>
          ${['power2.out', 'power2.inOut', 'power3.out', 'power3.inOut', 'back.out(1.7)'].map((ease) => `
            <option value="${escHtml(ease)}" ${currentEase === ease ? 'selected' : ''}>${escHtml(ease)}</option>
          `).join('')}
        </select>
      </label>
      ${keyframes.length ? keyframes.map((keyframe) => `
        <div style="display:grid;grid-template-columns:minmax(0,1fr) auto;gap:10px;align-items:center;padding:8px 10px;border:1px solid rgba(255,255,255,0.08);background:rgba(255,255,255,0.03);border-radius:10px;margin-bottom:8px">
          <div>
            <div style="font-size:11px;font-weight:700;color:#fafaf9">${escHtml(formatCreativeTimelineTime(keyframe.atMs))}</div>
            <div style="font-size:10px;color:#a8a29e;margin-top:3px">${escHtml(`x ${Math.round(Number(keyframe.x ?? selected.x) || 0)} | y ${Math.round(Number(keyframe.y ?? selected.y) || 0)} | opacity ${Number(keyframe.opacity ?? selected.opacity ?? 1).toFixed(2)}${keyframe.ease ? ` | ${keyframe.ease}` : ''}`)}</div>
          </div>
          <button onclick="canvasDeleteCreativeKeyframe('${escHtml(keyframe.id)}')" style="display:inline-flex;align-items:center;gap:5px;border:1px solid rgba(239,68,68,0.24);background:rgba(239,68,68,0.12);color:#fca5a5;border-radius:8px;padding:6px 8px;font-size:11px;font-weight:700;cursor:pointer"><iconify-icon icon="solar:trash-bin-trash-bold-duotone" width="13" height="13"></iconify-icon></button>
        </div>
      `).join('') : `<div style="font-size:11px;color:#a8a29e;line-height:1.6">No keyframes yet. Scrub the playhead, then add one from the current element state.</div>`}
    </div>
  `;
}

function renderCreativeStageElementV2(baseElement, mode) {
  const element = getRenderedCreativeElement(baseElement, mode);
  const selectedClass = baseElement.id === creativeSelectedId ? '2px solid #38bdf8' : '1px solid transparent';
  const canResize = baseElement.id === creativeSelectedId && baseElement.locked !== true && baseElement.visible !== false;
  const resizeHandle = canResize
    ? `<div data-creative-resize-handle="true" title="Drag to resize" style="position:absolute;right:6px;bottom:6px;width:12px;height:12px;border-radius:4px;background:#f8fafc;border:2px solid #0f172a;box-shadow:0 0 0 1px rgba(56,189,248,0.65);cursor:nwse-resize;z-index:3"></div>`
    : '';
  const sharedStyle = [
    'position:absolute',
    `left:${Number(element.x) || 0}px`,
    `top:${Number(element.y) || 0}px`,
    `width:${Math.max(8, Number(element.width) || 0)}px`,
    `height:${Math.max(8, Number(element.height) || 0)}px`,
    `opacity:${Number.isFinite(Number(element.opacity)) ? Number(element.opacity) : 1}`,
    `transform:rotate(${Number(element.rotation) || 0}deg)`,
    `z-index:${Number(baseElement.zIndex) || 0}`,
    `outline:${selectedClass}`,
    `box-shadow:${baseElement.locked ? 'inset 0 0 0 1px rgba(250,204,21,0.85)' : 'none'}`,
    `visibility:${baseElement.visible === false ? 'hidden' : 'visible'}`,
    `pointer-events:${baseElement.visible === false ? 'none' : 'auto'}`,
    'outline-offset:0',
    `cursor:${baseElement.locked ? 'not-allowed' : (baseElement.id === creativeSelectedId ? 'grab' : 'pointer')}`,
    'touch-action:none',
  ].join(';');
  const clickAttr = `onclick="canvasSelectCreativeElement('${baseElement.id}')"`;
  const baseAttrs = `${clickAttr} data-creative-element-id="${escHtml(baseElement.id)}"`;
  if (baseElement.type === 'text') {
    return `<div ${baseAttrs} style="${sharedStyle}"><div style="width:100%;height:100%;padding:4px 6px;box-sizing:border-box;color:${escHtml(baseElement.meta?.color || '#111827')};font-size:${Number(baseElement.meta?.fontSize) || 24}px;font-weight:${Number(baseElement.meta?.fontWeight) || 700};font-family:${escHtml(baseElement.meta?.fontFamily || 'Manrope')};font-style:${escHtml(baseElement.meta?.fontStyle || 'normal')};line-height:${Number(baseElement.meta?.lineHeight) || 1.2};letter-spacing:${Number(baseElement.meta?.letterSpacing) || 0}px;text-align:${escHtml(baseElement.meta?.textAlign || 'left')};white-space:pre-wrap;overflow:hidden">${escHtml(baseElement.meta?.content || 'Text')}</div>${resizeHandle}</div>`;
  }
  if (baseElement.type === 'icon') {
    const size = Math.max(24, Math.min(Number(element.width) || 64, Number(element.height) || 64));
    return `<div ${baseAttrs} style="${sharedStyle}"><div style="width:100%;height:100%;display:flex;align-items:center;justify-content:center;color:${escHtml(baseElement.meta?.color || '#111827')}"><iconify-icon icon="${escHtml(baseElement.meta?.iconName || 'solar:stars-bold-duotone')}" width="${size}" height="${size}"></iconify-icon></div>${resizeHandle}</div>`;
  }
  if (baseElement.type === 'image') {
    const bg = baseElement.meta?.source
      ? `background-image:url('${escHtml(creativeMediaSourceUrl(baseElement.meta.source)).replace(/'/g, '&#39;')}');background-size:${escHtml(baseElement.meta?.fit || 'cover')};background-position:center center;`
      : 'background:linear-gradient(135deg,#d6d3d1,#f5f5f4);';
    return `<div ${baseAttrs} style="${sharedStyle}"><div style="width:100%;height:100%;border-radius:${Number(baseElement.meta?.radius) || 18}px;border:1px dashed rgba(15,23,42,0.18);${bg}"></div>${resizeHandle}</div>`;
  }
  if (baseElement.type === 'video') {
    const source = escHtml(creativeMediaSourceUrl(baseElement.meta?.source || ''));
    const fit = escHtml(String(baseElement.meta?.fit || 'cover'));
    const radius = Number(baseElement.meta?.radius) || 18;
    const poster = baseElement.meta?.poster ? ` poster="${escHtml(creativeMediaSourceUrl(baseElement.meta.poster))}"` : '';
    const body = source
      ? `<video data-creative-video-element="${escHtml(baseElement.id)}" src="${source}"${poster} muted playsinline preload="auto" style="width:100%;height:100%;object-fit:${fit};border-radius:${radius}px;display:block;background:#111827"></video>`
      : `<div style="width:100%;height:100%;display:flex;align-items:center;justify-content:center;border-radius:${radius}px;border:1px dashed rgba(15,23,42,0.18);background:linear-gradient(135deg,#1f2937,#374151);color:#f9fafb;font-size:12px;font-weight:800">Video</div>`;
    return `<div ${baseAttrs} style="${sharedStyle}">${body}${resizeHandle}</div>`;
  }
  if (baseElement.type === 'group') {
    const component = String(baseElement.meta?.component || 'component');
    return `<div ${baseAttrs} style="${sharedStyle}"><div style="width:100%;height:100%;display:flex;align-items:center;justify-content:center;border-radius:${component === 'badge' ? 999 : 18}px;border:1px solid rgba(255,255,255,0.16);background:linear-gradient(135deg,#1f2937,#334155);color:#f8fafc;font-size:12px;font-weight:800;letter-spacing:0.04em;text-transform:${component === 'badge' ? 'uppercase' : 'none'}">${escHtml(component)}</div>${resizeHandle}</div>`;
  }
  const shape = String(baseElement.meta?.shape || 'rect');
  const fill = baseElement.meta?.fill || '#111827';
  const stroke = baseElement.meta?.stroke || 'transparent';
  const strokeWidth = Math.max(0, Number(baseElement.meta?.strokeWidth) || 0);
  const radius = shape === 'circle' ? 999 : Math.max(0, Number(baseElement.meta?.radius) || 0);
  if (shape === 'line' || shape === 'arrow') {
    const arrowHead = shape === 'arrow'
      ? `<div style="position:absolute;right:-1px;top:50%;transform:translateY(-50%);width:0;height:0;border-top:${Math.max(6, strokeWidth * 2)}px solid transparent;border-bottom:${Math.max(6, strokeWidth * 2)}px solid transparent;border-left:${Math.max(10, strokeWidth * 3)}px solid ${escHtml(stroke || fill)}"></div>`
      : '';
    return `<div ${baseAttrs} style="${sharedStyle};background:${escHtml(stroke || fill)};border-radius:999px">${arrowHead}${resizeHandle}</div>`;
  }
  return `<div ${baseAttrs} style="${sharedStyle};background:${escHtml(fill)};border:${strokeWidth}px solid ${escHtml(stroke)};border-radius:${radius}px">${resizeHandle}</div>`;
}

function renderCreativeWorkspaceV2({ shell, library, stage, props, timeline, timelineTracks, timelineMeta, title, subtitle, mode }) {
  shell.style.display = 'flex';
  shell.style.position = 'relative';
  shell.style.zIndex = '2';
  if (title) title.textContent = getStructuredCreativeModeLabel(mode);
  if (subtitle) subtitle.textContent = mode === 'video'
    ? 'Shared scene graph with timeline, playhead, and keyframes'
    : 'Shared scene graph with direct composition controls';
  const selected = getSelectedCreativeElement();
  const selectedContext = selected ? buildSceneSelectionContext(creativeSceneDoc, selected.id) : null;
  const selectedRendered = selected ? getRenderedCreativeElement(selected, mode) : null;

  library.innerHTML = `<div style="padding:10px 14px;border-bottom:1px solid rgba(255,255,255,0.06)"><button onclick="canvasOpenHyperframesCatalog()" style="width:100%;text-align:left;padding:8px 10px;border:1px solid rgba(255,255,255,0.12);background:linear-gradient(135deg,#0ea5e9,#6366f1);color:#fff;border-radius:8px;font-size:12px;font-weight:700;cursor:pointer">＋ HyperFrames Catalog</button></div>` + (mode === 'video' ? renderCompositionAssetSection() : '') + Object.entries(getActiveCreativeElementLibrary()).map(([section, items]) => `
    <div style="padding:14px 14px 6px">
      <div style="font-size:10px;font-weight:800;letter-spacing:0.06em;text-transform:uppercase;color:#a8a29e;margin-bottom:8px">${escHtml(section)}</div>
      <div style="display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:8px">
        ${items.map((item) => `
          <button onclick="canvasAddCreativeLibraryItem('${escHtml(section)}','${escHtml(item.kind)}')" style="text-align:left;border:1px solid rgba(255,255,255,0.09);background:rgba(255,255,255,0.04);color:#f5f5f4;border-radius:10px;padding:10px 10px 9px;cursor:pointer">
            <div style="font-size:12px;font-weight:700">${escHtml(item.label)}</div>
            <div style="font-size:10px;color:#a8a29e;margin-top:4px">${escHtml(item.type)}</div>
          </button>
        `).join('')}
      </div>
    </div>
  `).join('');
  library.style.minWidth = '0';
  library.style.overflowY = 'auto';

  stage.style.width = `${creativeSceneDoc.width}px`;
  stage.style.height = `${creativeSceneDoc.height}px`;
  stage.style.background = creativeSceneDoc.background || '#ffffff';
  stage.style.maxWidth = '100%';
  stage.innerHTML = creativeSceneDoc.elements
    .slice()
    .sort((a, b) => (a.zIndex || 0) - (b.zIndex || 0))
    .map((element) => renderCreativeStageElementV2(element, mode))
    .join('');
  bindCreativeStageInteractions(stage, mode);
  stage.onclick = (event) => {
    if (event.target === stage) setCreativeSelection(null);
  };

  const stageWrap = document.getElementById('canvas-creative-stage-wrap');
  if (stageWrap) {
    stageWrap.style.minWidth = '0';
    stageWrap.style.position = 'relative';
    stageWrap.style.isolation = 'isolate';
  }

  props.style.minWidth = '0';
  props.style.overflowX = 'hidden';
  props.style.overflowY = 'auto';
  const propertyElement = mode === 'video' && selectedRendered ? { ...selected, ...selectedRendered } : selected;

  props.innerHTML = selected ? `
    <div style="padding:16px 16px 12px;border-bottom:1px solid rgba(255,255,255,0.08)">
      <div style="font-size:10px;font-weight:800;letter-spacing:0.06em;text-transform:uppercase;color:#a8a29e">Selection</div>
      <div style="font-size:15px;font-weight:800;color:#fafaf9;margin-top:6px">${escHtml(selected.type)} · ${escHtml(selected.id)}</div>
      <div style="font-size:11px;color:#a8a29e;line-height:1.6;margin-top:6px">${escHtml(`x ${Math.round(selectedRendered?.x || selected.x)} · y ${Math.round(selectedRendered?.y || selected.y)} · ${Math.round(selectedRendered?.width || selected.width)}×${Math.round(selectedRendered?.height || selected.height)}`)}</div>
      ${mode === 'video' ? `<div style="font-size:10px;color:#7dd3fc;margin-top:6px">Playhead ${formatCreativeTimelineTime(creativeTimelineMs)} · ${Array.isArray(selected.meta?.keyframes) ? selected.meta.keyframes.length : 0} keyframes</div>` : ''}
    </div>
    <div style="padding:14px 16px;display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:10px">
      ${renderCreativePropertyFieldV2('X', 'x', propertyElement?.x ?? selected.x)}
      ${renderCreativePropertyFieldV2('Y', 'y', propertyElement?.y ?? selected.y)}
      ${renderCreativePropertyFieldV2('Width', 'width', propertyElement?.width ?? selected.width)}
      ${renderCreativePropertyFieldV2('Height', 'height', propertyElement?.height ?? selected.height)}
      ${renderCreativePropertyFieldV2('Rotate', 'rotation', propertyElement?.rotation ?? selected.rotation)}
      ${renderCreativePropertyFieldV2('Opacity', 'opacity', propertyElement?.opacity ?? selected.opacity, 'number', { step: '0.1', min: '0', max: '1' })}
      ${renderCreativePropertyFieldV2('Z Index', 'zIndex', selected.zIndex)}
      ${renderCreativePropertyToggleV2('Visible', 'visible', selected.visible !== false)}
      ${renderCreativePropertyToggleV2('Locked', 'locked', selected.locked === true)}
    </div>
    ${selected.type === 'text' ? `
      <div style="padding:0 16px 14px">
        ${renderCreativePropertyTextareaV2('Content', 'meta.content', selected.meta?.content || '')}
        <div style="display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:10px;margin-top:10px">
          ${renderCreativePropertyFieldV2('Font Size', 'meta.fontSize', selected.meta?.fontSize || 24)}
          ${renderCreativePropertyFieldV2('Weight', 'meta.fontWeight', selected.meta?.fontWeight || 700)}
          ${renderCreativePropertyFieldV2('Font Family', 'meta.fontFamily', selected.meta?.fontFamily || 'Manrope', 'text')}
          ${renderCreativePropertyFieldV2('Align', 'meta.textAlign', selected.meta?.textAlign || 'left', 'text')}
          ${renderCreativePropertyFieldV2('Line Height', 'meta.lineHeight', selected.meta?.lineHeight || 1.2, 'number', { step: '0.1' })}
          ${renderCreativePropertyFieldV2('Letter Spacing', 'meta.letterSpacing', selected.meta?.letterSpacing || 0, 'number', { step: '0.5' })}
          ${renderCreativePropertyFieldV2('Color', 'meta.color', selected.meta?.color || '#111827', 'color')}
        </div>
        <div style="margin-top:10px;padding:10px 12px;border-radius:10px;border:1px solid rgba(255,255,255,0.08);background:rgba(255,255,255,0.03);font-size:11px;color:#d6d3d1;line-height:1.7">
          <div><strong>Measurement:</strong> ${escHtml(selected.meta?.pretextMeasured ? 'Pretext' : (selected.meta?.measurement?.kind || 'fallback'))}</div>
          <div><strong>Lines:</strong> ${escHtml(String(selected.meta?.measurement?.lineCount || 1))} · <strong>Height:</strong> ${escHtml(String(Math.round(Number(selected.meta?.measurement?.height || selected.height || 0))))} px</div>
        </div>
      </div>` : ''}
    ${selected.type === 'shape' ? `
      <div style="padding:0 16px 14px">
        <div style="display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:10px">
          ${renderCreativePropertyFieldV2('Shape', 'meta.shape', selected.meta?.shape || 'rect', 'text')}
          ${renderCreativePropertyFieldV2('Fill', 'meta.fill', selected.meta?.fill || '#111827', 'color')}
          ${renderCreativePropertyFieldV2('Stroke', 'meta.stroke', selected.meta?.stroke || '#111827', 'color')}
          ${renderCreativePropertyFieldV2('Radius', 'meta.radius', selected.meta?.radius || 0)}
          ${renderCreativePropertyFieldV2('Stroke Width', 'meta.strokeWidth', selected.meta?.strokeWidth || 0)}
        </div>
      </div>` : ''}
    ${selected.type === 'icon' ? `
      <div style="padding:0 16px 14px">
        ${renderCreativePropertyFieldV2('Icon', 'meta.iconName', selected.meta?.iconName || 'solar:stars-bold-duotone', 'text')}
        <div style="display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:10px;margin-top:10px">
          ${renderCreativePropertyFieldV2('Color', 'meta.color', selected.meta?.color || '#111827', 'color')}
        </div>
      </div>` : ''}
    ${selected.type === 'image' || selected.type === 'video' ? `
        <div style="padding:0 16px 14px">
          ${renderCreativePropertyFieldV2('Source', 'meta.source', selected.meta?.source || '', 'text')}
          <div style="display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:10px;margin-top:10px">
            ${renderCreativePropertyFieldV2('Fit', 'meta.fit', selected.meta?.fit || 'cover', 'text')}
            ${renderCreativePropertyFieldV2('Radius', 'meta.radius', selected.meta?.radius || 18)}
          </div>
          ${selected.type === 'video' ? `<div style="display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:10px;margin-top:10px">
            ${renderCreativePropertyFieldV2('Start Ms', 'meta.timelineStartMs', selected.meta?.timelineStartMs || 0)}
            ${renderCreativePropertyFieldV2('Trim Start', 'meta.trimStartMs', selected.meta?.trimStartMs || 0)}
          </div>` : ''}
        </div>` : ''}
    ${selected.type === 'group' ? `
      <div style="padding:0 16px 14px">
        ${renderCreativePropertyFieldV2('Component', 'meta.component', selected.meta?.component || 'card', 'text')}
      </div>` : ''}
    ${mode === 'video' ? renderCreativeKeyframeSectionV2(selected) : ''}
    <div style="padding:4px 16px 16px;display:flex;flex-wrap:wrap;gap:8px">
      <button onclick="canvasDeleteCreativeSelection()" style="display:inline-flex;align-items:center;gap:5px;border:1px solid rgba(239,68,68,0.28);background:rgba(239,68,68,0.12);color:#fca5a5;border-radius:8px;padding:6px 10px;font-size:11px;font-weight:700;cursor:pointer"><iconify-icon icon="solar:trash-bin-trash-bold-duotone" width="14" height="14"></iconify-icon>Delete</button>
      <button onclick="canvasNudgeCreativeZ(1)" style="display:inline-flex;align-items:center;gap:5px;border:1px solid rgba(255,255,255,0.12);background:rgba(255,255,255,0.05);color:#f5f5f4;border-radius:8px;padding:6px 10px;font-size:11px;font-weight:700;cursor:pointer"><iconify-icon icon="solar:arrow-up-bold-duotone" width="14" height="14"></iconify-icon>Forward</button>
      <button onclick="canvasNudgeCreativeZ(-1)" style="display:inline-flex;align-items:center;gap:5px;border:1px solid rgba(255,255,255,0.12);background:rgba(255,255,255,0.05);color:#f5f5f4;border-radius:8px;padding:6px 10px;font-size:11px;font-weight:700;cursor:pointer"><iconify-icon icon="solar:arrow-down-bold-duotone" width="14" height="14"></iconify-icon>Back</button>
    </div>
    <div style="padding:0 16px 16px">
      <div style="font-size:10px;font-weight:800;letter-spacing:0.06em;text-transform:uppercase;color:#a8a29e;margin-bottom:8px">AI Focus</div>
      <pre style="margin:0;padding:12px;border-radius:12px;border:1px solid rgba(255,255,255,0.08);background:rgba(255,255,255,0.03);color:#d6d3d1;font-size:10px;line-height:1.65;white-space:pre-wrap">${escHtml(JSON.stringify(selectedContext, null, 2).slice(0, 2200))}</pre>
    </div>
  ` : `
    <div style="padding:18px 16px">
      <div style="font-size:10px;font-weight:800;letter-spacing:0.06em;text-transform:uppercase;color:#a8a29e">Scene</div>
      <div style="font-size:13px;font-weight:700;color:#fafaf9;margin-top:10px">${escHtml(getStructuredCreativeModeLabel(mode))}</div>
      <div style="font-size:11px;color:#a8a29e;line-height:1.7;margin-top:8px">No element selected. Adjust the scene shell directly or select an element on the stage for shared property controls.</div>
    </div>
    <div style="padding:0 16px 14px">
      <label style="display:flex;flex-direction:column;gap:5px;margin-bottom:10px">
        <span style="font-size:10px;font-weight:800;letter-spacing:0.05em;text-transform:uppercase;color:#a8a29e">Canvas Preset</span>
        <select onchange="canvasApplyCreativeSizePreset(this.value)" style="width:100%;box-sizing:border-box;border:1px solid rgba(255,255,255,0.12);background:rgba(255,255,255,0.04);color:#fafaf9;border-radius:10px;padding:9px 10px;font-size:12px;font-family:inherit">
          <option value="">Choose a preset…</option>
          ${Object.entries(CREATIVE_SIZE_PRESETS).map(([presetKey, preset]) => `
            <option value="${escHtml(presetKey)}">${escHtml(`${preset.label} · ${preset.width}×${preset.height}`)}</option>
          `).join('')}
        </select>
      </label>
      <div style="display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:10px">
      ${renderCreativePropertyFieldV2('Canvas Width', 'width', creativeSceneDoc.width, 'number', { handler: 'canvasUpdateCreativeDocumentProperty' })}
      ${renderCreativePropertyFieldV2('Canvas Height', 'height', creativeSceneDoc.height, 'number', { handler: 'canvasUpdateCreativeDocumentProperty' })}
      ${renderCreativePropertyFieldV2('Background', 'background', creativeSceneDoc.background || '#ffffff', 'color', { handler: 'canvasUpdateCreativeDocumentProperty' })}
      ${mode === 'video' ? renderCreativePropertyFieldV2('Duration (ms)', 'durationMs', creativeSceneDoc.durationMs || 12000, 'number', { min: '1000', step: '250', handler: 'canvasUpdateCreativeDocumentProperty' }) : ''}
            ${mode === 'video' ? renderCreativePropertyFieldV2('Frame Rate', 'frameRate', creativeSceneDoc.frameRate || 60, 'number', { min: '60', step: '1', handler: 'canvasUpdateCreativeDocumentProperty' }) : ''}
      </div>
    </div>
    ${mode === 'video' ? `
      <div style="padding:0 16px 16px">
        <div style="font-size:10px;font-weight:800;letter-spacing:0.06em;text-transform:uppercase;color:#a8a29e;margin-bottom:8px">Timeline</div>
        <div style="font-size:11px;color:#d6d3d1;margin-bottom:8px">Playhead ${escHtml(formatCreativeTimelineTime(creativeTimelineMs))}</div>
          <input type="range" data-creative-timeline-range="true" min="0" max="${Math.max(1000, Number(creativeSceneDoc.durationMs) || 12000)}" step="50" value="${creativeTimelineMs}" oninput="canvasSetCreativeTimeline(this.value)" style="width:100%">
        <div style="display:flex;gap:8px;margin-top:10px">
          <button onclick="toggleCreativePlayback()" style="display:inline-flex;align-items:center;gap:5px;border:1px solid rgba(56,189,248,0.35);background:rgba(56,189,248,0.14);color:#7dd3fc;border-radius:8px;padding:6px 10px;font-size:11px;font-weight:700;cursor:pointer">${isCreativePlaybackActive() ? 'Pause' : 'Play'}</button>
          <button onclick="stopCreativePlayback({ reset: true, persist: true })" style="display:inline-flex;align-items:center;gap:5px;border:1px solid rgba(255,255,255,0.12);background:rgba(255,255,255,0.05);color:#f5f5f4;border-radius:8px;padding:6px 10px;font-size:11px;font-weight:700;cursor:pointer">Reset</button>
        </div>
      </div>` : ''}
  `;

  if (timeline && timelineTracks && timelineMeta) {
    const isVideo = mode === 'video';
    timeline.style.display = isVideo ? 'block' : 'none';
    if (isVideo) {
      const durationMs = Math.max(1000, Number(creativeSceneDoc.durationMs) || 12000);
      timelineMeta.textContent = `${creativeSceneDoc.elements.length} tracks · ${formatCreativeTimelineTime(durationMs)} · ${Number(creativeSceneDoc.frameRate) || 60}fps · playhead ${formatCreativeTimelineTime(creativeTimelineMs)}`;
      timelineTracks.innerHTML = `
        <div style="display:grid;grid-template-columns:160px minmax(0,1fr);gap:10px;align-items:center;margin-bottom:10px">
          <div style="display:flex;align-items:center;gap:8px;font-size:11px;color:#7dd3fc;font-weight:700">
            <button onclick="toggleCreativePlayback()" style="display:inline-flex;align-items:center;justify-content:center;border:1px solid rgba(56,189,248,0.35);background:rgba(56,189,248,0.14);color:#7dd3fc;border-radius:8px;padding:5px 8px;font-size:11px;font-weight:700;cursor:pointer">${isCreativePlaybackActive() ? 'Pause' : 'Play'}</button>
            <button onclick="stopCreativePlayback({ reset: true, persist: true })" style="display:inline-flex;align-items:center;justify-content:center;border:1px solid rgba(255,255,255,0.12);background:rgba(255,255,255,0.05);color:#f5f5f4;border-radius:8px;padding:5px 8px;font-size:11px;font-weight:700;cursor:pointer">Reset</button>
          </div>
        <div><input type="range" data-creative-timeline-range="true" min="0" max="${durationMs}" step="50" value="${creativeTimelineMs}" oninput="canvasSetCreativeTimeline(this.value)" style="width:100%"></div>
        </div>
      ` + renderCompositionTimelineStrip() + creativeSceneDoc.elements.map((element, idx) => {
        const label = element.meta?.content || element.meta?.iconName || element.meta?.component || `${element.type} ${idx + 1}`;
        const keyframes = Array.isArray(element.meta?.keyframes) ? element.meta.keyframes.slice().sort((a, b) => (a.atMs || 0) - (b.atMs || 0)) : [];
        const firstAt = keyframes.length ? Math.max(0, Number(keyframes[0].atMs) || 0) : 0;
        const lastAt = keyframes.length ? Math.max(firstAt, Number(keyframes[keyframes.length - 1].atMs) || 0) : durationMs;
        const left = Math.max(0, Math.min(100, (firstAt / durationMs) * 100));
        const width = Math.max(8, Math.min(100 - left, ((Math.max(firstAt + 300, lastAt) - firstAt) / durationMs) * 100));
        const playheadLeft = Math.max(0, Math.min(100, (creativeTimelineMs / durationMs) * 100));
        return `
          <div style="display:grid;grid-template-columns:160px minmax(0,1fr);gap:10px;align-items:center;margin-bottom:8px">
            <div style="font-size:11px;color:${element.id === creativeSelectedId ? '#f8fafc' : '#a8a29e'};font-weight:${element.id === creativeSelectedId ? '700' : '600'};cursor:pointer" onclick="canvasSelectCreativeElement('${element.id}')">${escHtml(String(label).slice(0, 34))}</div>
            <div style="height:20px;border-radius:999px;background:rgba(255,255,255,0.06);position:relative;overflow:hidden">
              <div style="position:absolute;left:${left}%;top:3px;bottom:3px;width:${width}%;border-radius:999px;background:${element.id === creativeSelectedId ? 'linear-gradient(90deg,#38bdf8,#60a5fa)' : 'linear-gradient(90deg,#f97316,#fb923c)'}"></div>
              ${keyframes.map((keyframe) => {
                const dotLeft = Math.max(0, Math.min(100, ((Number(keyframe.atMs) || 0) / durationMs) * 100));
                return `<div title="${escHtml(formatCreativeTimelineTime(keyframe.atMs))}" style="position:absolute;left:calc(${dotLeft}% - 4px);top:5px;width:8px;height:8px;border-radius:999px;background:${element.id === creativeSelectedId ? '#e0f2fe' : '#fde68a'};box-shadow:0 0 0 2px rgba(15,23,42,0.75)"></div>`;
              }).join('')}
              <div style="position:absolute;left:calc(${playheadLeft}% - 1px);top:0;bottom:0;width:2px;background:#f8fafc;opacity:0.9"></div>
            </div>
          </div>
        `;
      }).join('');
    }
  }
}

// ── Composition asset section (drag source for the timeline) ─────────────────
function renderCompositionAssetSection() {
  const assets = Array.isArray(creativeAssetsState?.indexedAssets) ? creativeAssetsState.indexedAssets : [];
  const exports = Array.isArray(creativeAssetsState?.exports) ? creativeAssetsState.exports : [];
  const items = [
    ...assets.map((a) => ({ kind: 'asset', label: a.label || a.filename || a.path, path: a.path || a.absPath, mime: a.mimeType || '', durationMs: a.durationMs || 0, source: a })),
    ...exports.filter((e) => /\.(mp4|webm|mov|m4v)$/i.test(e.path || e.filename || '')).map((e) => ({ kind: 'export', label: e.filename || e.path, path: e.path, mime: 'video/mp4', durationMs: 0, source: e })),
  ];
  if (items.length === 0) {
    return `<div style="padding:14px 14px 6px"><div style="font-size:10px;font-weight:800;letter-spacing:0.06em;text-transform:uppercase;color:#a8a29e;margin-bottom:8px">Drop on Timeline</div><div style="font-size:11px;color:#78716c;line-height:1.55">No indexed assets yet. Run creative_search_assets or attach media to populate this list.</div></div>`;
  }
  return `
    <div style="padding:14px 14px 6px">
      <div style="font-size:10px;font-weight:800;letter-spacing:0.06em;text-transform:uppercase;color:#a8a29e;margin-bottom:8px">Drop on Timeline</div>
      <div style="display:flex;flex-direction:column;gap:6px">
        ${items.slice(0, 30).map((item) => {
          const isVideo = /^video\//i.test(item.mime) || /\.(mp4|webm|mov|m4v)$/i.test(String(item.path || ''));
          const isAudio = /^audio\//i.test(item.mime) || /\.(mp3|wav|m4a|aac|ogg)$/i.test(String(item.path || ''));
          const lane = isAudio ? 'audio' : 'video';
          const accent = isVideo ? '#7dd3fc' : isAudio ? '#34d399' : '#fbbf24';
          return `
            <div
              draggable="true"
              ondragstart="canvasCompositionAssetDragStart(event, ${escHtml(JSON.stringify({ label: item.label, path: item.path, mime: item.mime, durationMs: item.durationMs, lane }))})"
              style="display:flex;align-items:center;gap:8px;padding:6px 8px;border-radius:8px;border:1px solid rgba(255,255,255,0.08);background:rgba(255,255,255,0.03);cursor:grab">
              <span style="display:inline-block;width:6px;height:6px;border-radius:999px;background:${accent}"></span>
              <span style="font-size:11px;color:#f5f5f4;font-weight:700;flex:1;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${escHtml(String(item.label || '').slice(0, 36))}</span>
              <span style="font-size:9px;color:#a8a29e">${escHtml(isVideo ? 'video' : isAudio ? 'audio' : 'asset')}</span>
            </div>
          `;
        }).join('')}
      </div>
    </div>
  `;
}

window.canvasCompositionAssetDragStart = function(event, payload) {
  try {
    const data = typeof payload === 'string' ? JSON.parse(payload) : payload;
    const isAudio = /^audio\//i.test(data.mime || '') || /\.(mp3|wav|m4a|aac|ogg)$/i.test(String(data.path || ''));
    const isVideo = /^video\//i.test(data.mime || '') || /\.(mp4|webm|mov|m4v)$/i.test(String(data.path || ''));
    const dropPayload = {
      label: data.label,
      path: data.path,
      mime: data.mime,
      durationMs: Math.max(1000, Number(data.durationMs) || 4000),
      lane: isAudio ? 'audio' : '',
    };
    event.dataTransfer?.setData('application/x-prom-asset', JSON.stringify(dropPayload));
    event.dataTransfer?.setData('text/plain', data.label || data.path || '');
    if (event.dataTransfer) event.dataTransfer.effectAllowed = 'copy';
  } catch (err) {
    console.error('asset drag failed', err);
  }
};

// ── Composition timeline strip (Premiere-style multi-track) ──────────────────
function renderCompositionTimelineStrip() {
  const comp = ensureCreativeComposition();
  if (!comp) return '';
  const durationMs = Math.max(1000, Number(comp.durationMs) || 12000);
  const playheadLeft = Math.max(0, Math.min(100, (creativeTimelineMs / durationMs) * 100));
  const tracks = (comp.tracks || []).slice().sort((a, b) => (a.index || 0) - (b.index || 0));

  const tracksHtml = tracks.map((track) => {
    const clips = (comp.clips || []).filter((c) => c.trackId === track.id);
    const clipsHtml = clips.map((clip) => {
      const left = Math.max(0, (clip.inMs / durationMs) * 100);
      const width = Math.max(1.2, ((clip.outMs - clip.inMs) / durationMs) * 100);
      const isSelected = comp.selectedClipId === clip.id;
      const palette = track.kind === 'video'
        ? (isSelected ? 'linear-gradient(90deg,#38bdf8,#60a5fa)' : 'linear-gradient(90deg,#0ea5e9,#3b82f6)')
        : track.kind === 'audio'
          ? (isSelected ? 'linear-gradient(90deg,#34d399,#10b981)' : 'linear-gradient(90deg,#059669,#047857)')
          : (isSelected ? 'linear-gradient(90deg,#facc15,#f59e0b)' : 'linear-gradient(90deg,#d97706,#92400e)');
      return `
        <div
          data-comp-clip="${escHtml(clip.id)}"
          data-comp-track="${escHtml(track.id)}"
          onmousedown="canvasCompositionClipMouseDown(event,'${escHtml(clip.id)}')"
          style="position:absolute;left:${left}%;width:${width}%;top:4px;bottom:4px;border-radius:6px;background:${palette};cursor:grab;display:flex;align-items:center;padding:0 8px;color:#0b1220;font-size:10px;font-weight:800;box-shadow:${isSelected ? '0 0 0 2px #fff' : '0 1px 2px rgba(0,0,0,0.4)'};overflow:hidden">
          <div onmousedown="event.stopPropagation();canvasCompositionEdgeMouseDown(event,'${escHtml(clip.id)}','head')" style="position:absolute;left:0;top:0;bottom:0;width:6px;cursor:ew-resize;background:rgba(0,0,0,0.25)"></div>
          <span style="white-space:nowrap;overflow:hidden;text-overflow:ellipsis;flex:1">${escHtml(String(clip.label || clip.lane).slice(0, 24))}</span>
          <div onmousedown="event.stopPropagation();canvasCompositionEdgeMouseDown(event,'${escHtml(clip.id)}','tail')" style="position:absolute;right:0;top:0;bottom:0;width:6px;cursor:ew-resize;background:rgba(0,0,0,0.25)"></div>
        </div>
      `;
    }).join('');
    const trackBg = track.kind === 'video' ? 'rgba(56,189,248,0.05)' : track.kind === 'audio' ? 'rgba(16,185,129,0.05)' : 'rgba(245,158,11,0.05)';
    return `
      <div style="display:grid;grid-template-columns:120px minmax(0,1fr);gap:10px;align-items:center;margin-bottom:6px">
        <div style="display:flex;align-items:center;gap:6px;font-size:10px;color:#a8a29e;font-weight:700">
          <span style="display:inline-block;width:24px;text-align:center;color:#7dd3fc">${escHtml(track.label)}</span>
          <button title="Mute lane" onclick="canvasCompositionToggleTrackFlag('${escHtml(track.id)}','muted')" style="border:1px solid rgba(255,255,255,0.12);background:${track.muted ? 'rgba(244,63,94,0.25)' : 'rgba(255,255,255,0.04)'};color:#fff;border-radius:5px;padding:2px 5px;font-size:9px;cursor:pointer">M</button>
          <button title="Lock lane" onclick="canvasCompositionToggleTrackFlag('${escHtml(track.id)}','locked')" style="border:1px solid rgba(255,255,255,0.12);background:${track.locked ? 'rgba(245,158,11,0.25)' : 'rgba(255,255,255,0.04)'};color:#fff;border-radius:5px;padding:2px 5px;font-size:9px;cursor:pointer">L</button>
        </div>
        <div
          data-comp-lane="${escHtml(track.id)}"
          ondragover="canvasCompositionLaneDragOver(event,'${escHtml(track.id)}')"
          ondragleave="canvasCompositionLaneDragLeave(event)"
          ondrop="canvasCompositionLaneDrop(event,'${escHtml(track.id)}')"
          style="position:relative;height:32px;border-radius:8px;background:${trackBg};border:1px solid rgba(255,255,255,0.06);overflow:hidden">
          ${clipsHtml}
          <div style="position:absolute;left:calc(${playheadLeft}% - 1px);top:0;bottom:0;width:2px;background:#f8fafc;opacity:0.85;pointer-events:none"></div>
        </div>
      </div>
    `;
  }).join('');

  const summary = summarizeComposition(comp);
  return `
    <div data-composition-strip="true" tabindex="0" onkeydown="canvasCompositionKeyDown(event)" style="margin-bottom:14px;padding:10px;border-radius:10px;border:1px solid rgba(56,189,248,0.18);background:rgba(8,12,24,0.6);outline:none">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:8px">
        <div style="font-size:10px;font-weight:800;letter-spacing:0.06em;text-transform:uppercase;color:#7dd3fc">Composition · ${summary.clipCount} clips · ${summary.trackCount} tracks</div>
        <div style="display:flex;gap:4px">
          <button onclick="canvasCompositionAddTrack('video')" style="border:1px solid rgba(56,189,248,0.35);background:rgba(56,189,248,0.1);color:#7dd3fc;border-radius:6px;padding:3px 7px;font-size:10px;font-weight:700;cursor:pointer">+V</button>
          <button onclick="canvasCompositionAddTrack('audio')" style="border:1px solid rgba(16,185,129,0.35);background:rgba(16,185,129,0.1);color:#34d399;border-radius:6px;padding:3px 7px;font-size:10px;font-weight:700;cursor:pointer">+A</button>
          <button onclick="canvasCompositionAddTrack('caption')" style="border:1px solid rgba(245,158,11,0.35);background:rgba(245,158,11,0.1);color:#fbbf24;border-radius:6px;padding:3px 7px;font-size:10px;font-weight:700;cursor:pointer">+C</button>
          <button onclick="canvasCompositionSplitAtPlayhead()" title="Split selected clip at playhead (S)" style="border:1px solid rgba(255,255,255,0.14);background:rgba(255,255,255,0.05);color:#f5f5f4;border-radius:6px;padding:3px 7px;font-size:10px;font-weight:700;cursor:pointer">✂ Split</button>
          <button onclick="canvasCompositionDeleteSelected()" title="Delete selected clip (Del)" style="border:1px solid rgba(244,63,94,0.35);background:rgba(244,63,94,0.1);color:#fca5a5;border-radius:6px;padding:3px 7px;font-size:10px;font-weight:700;cursor:pointer">Del</button>
          <button onclick="canvasCompositionRender()" title="Render composition to MP4" style="border:1px solid rgba(168,85,247,0.35);background:rgba(168,85,247,0.1);color:#c4b5fd;border-radius:6px;padding:3px 7px;font-size:10px;font-weight:700;cursor:pointer">▶ Render</button>
        </div>
      </div>
      <div style="position:relative">
        ${tracksHtml}
      </div>
    </div>
  `;
}

let _compClipDrag = null;

window.canvasCompositionClipMouseDown = function(event, clipId) {
  event.preventDefault();
  const comp = ensureCreativeComposition();
  if (!comp) return;
  const clip = comp.clips.find((c) => c.id === clipId);
  if (!clip) return;
  const lane = event.target instanceof Element ? event.target.closest('[data-comp-lane]') : null;
  const laneRect = lane?.getBoundingClientRect();
  if (!laneRect) return;
  comp.selectedClipId = clipId;
  enterClipForEditing(clip);
  persistCompositionState();
  _compClipDrag = {
    mode: 'move',
    clipId,
    startX: event.clientX,
    startInMs: clip.inMs,
    startOutMs: clip.outMs,
    durationMs: comp.durationMs,
    laneWidth: laneRect.width,
  };
  document.addEventListener('mousemove', _onCompMouseMove);
  document.addEventListener('mouseup', _onCompMouseUp);
  renderCreativeWorkspace?.();
};

window.canvasCompositionEdgeMouseDown = function(event, clipId, edge) {
  event.preventDefault();
  event.stopPropagation();
  const comp = ensureCreativeComposition();
  if (!comp) return;
  const clip = comp.clips.find((c) => c.id === clipId);
  if (!clip) return;
  const lane = event.target instanceof Element ? event.target.closest('[data-comp-lane]') : null;
  const laneRect = lane?.getBoundingClientRect();
  if (!laneRect) return;
  comp.selectedClipId = clipId;
  _compClipDrag = {
    mode: 'trim',
    edge,
    clipId,
    startX: event.clientX,
    startInMs: clip.inMs,
    startOutMs: clip.outMs,
    durationMs: comp.durationMs,
    laneWidth: laneRect.width,
  };
  document.addEventListener('mousemove', _onCompMouseMove);
  document.addEventListener('mouseup', _onCompMouseUp);
};

function _onCompMouseMove(event) {
  if (!_compClipDrag) return;
  const comp = creativeComposition;
  if (!comp) return;
  const clip = comp.clips.find((c) => c.id === _compClipDrag.clipId);
  if (!clip) return;
  const dx = event.clientX - _compClipDrag.startX;
  const msPerPx = _compClipDrag.durationMs / Math.max(1, _compClipDrag.laneWidth);
  const deltaMs = Math.round(dx * msPerPx);
  if (_compClipDrag.mode === 'move') {
    const dur = _compClipDrag.startOutMs - _compClipDrag.startInMs;
    clip.inMs = Math.max(0, _compClipDrag.startInMs + deltaMs);
    clip.outMs = clip.inMs + dur;
  } else if (_compClipDrag.mode === 'trim') {
    if (_compClipDrag.edge === 'head') {
      const target = Math.max(0, Math.min(_compClipDrag.startOutMs - 100, _compClipDrag.startInMs + deltaMs));
      const trimDelta = target - _compClipDrag.startInMs;
      clip.inMs = target;
      clip.trimStartMs = Math.max(0, (clip.trimStartMs || 0) + (trimDelta - (clip.inMs - _compClipDrag.startInMs)) * 0); // re-derive below
      // simpler: recompute trimStart from absolute change vs original startInMs
      clip.trimStartMs = Math.max(0, (clip.trimStartMs || 0));
    } else {
      const target = Math.max(_compClipDrag.startInMs + 100, _compClipDrag.startOutMs + deltaMs);
      clip.outMs = target;
    }
  }
  recomputeCompositionDuration(comp);
  renderCreativeWorkspace?.();
}

function _onCompMouseUp() {
  if (_compClipDrag) {
    persistCompositionState();
    _compClipDrag = null;
  }
  document.removeEventListener('mousemove', _onCompMouseMove);
  document.removeEventListener('mouseup', _onCompMouseUp);
}

window.canvasCompositionAddTrack = function(kind) {
  const comp = ensureCreativeComposition();
  if (!comp) return;
  compositionAddTrack(comp, kind);
  persistCompositionState();
  renderCreativeWorkspace?.();
};

window.canvasCompositionToggleTrackFlag = function(trackId, flag) {
  const comp = ensureCreativeComposition();
  const track = comp?.tracks.find((t) => t.id === trackId);
  if (!track) return;
  track[flag] = !track[flag];
  persistCompositionState();
  renderCreativeWorkspace?.();
};

window.canvasCompositionSplitAtPlayhead = function() {
  const comp = ensureCreativeComposition();
  if (!comp || !comp.selectedClipId) return;
  try {
    compositionSplitClip(comp, comp.selectedClipId, creativeTimelineMs);
    persistCompositionState();
    renderCreativeWorkspace?.();
  } catch (err) {
    showToast?.('Split failed', String(err?.message || err), 'error');
  }
};

window.canvasCompositionDeleteSelected = function() {
  const comp = ensureCreativeComposition();
  if (!comp || !comp.selectedClipId) return;
  compositionDeleteClip(comp, comp.selectedClipId, { ripple: false });
  persistCompositionState();
  renderCreativeWorkspace?.();
};

window.canvasCompositionRender = async function() {
  const comp = ensureCreativeComposition();
  if (!comp) return;
  const sid = window.currentChatSessionId || 'default';
  const root = (window.canvasProjectRoot || '').toString();
  showToast?.('Rendering composition…', 'Encoding frames + muxing audio. Watch progress in the toast log.', 'info');
  try {
    const response = await fetch('/api/canvas/composition/render', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ sessionId: sid, root, composition: comp, format: 'mp4' }),
    });
    const json = await response.json().catch(() => ({}));
    if (!response.ok || json?.success === false) throw new Error(json?.error || `HTTP ${response.status}`);
    showToast?.('Render complete', `Saved to ${json.path}`, 'success');
  } catch (err) {
    showToast?.('Render failed', String(err?.message || err), 'error');
  }
};

window.canvasCompositionKeyDown = function(event) {
  const key = String(event.key || '').toLowerCase();
  if (key === 's') { event.preventDefault(); canvasCompositionSplitAtPlayhead(); }
  else if (key === 'delete' || key === 'backspace') { event.preventDefault(); canvasCompositionDeleteSelected(); }
  else if (key === 'escape') { event.preventDefault(); exitClipEditing(); }
};

function enterClipForEditing(clip) {
  if (!clip || !clip.source) return;
  showToast?.('Edit source clip', `${clip.lane} clips are edited through HTML Motion, HyperFrames, or Remotion source tools.`, 'info');
}

function exitClipEditing() {
  const comp = creativeComposition;
  if (!comp) return;
  comp.selectedClipId = null;
  persistCompositionState();
  renderCreativeWorkspace?.();
}

window.canvasCompositionLaneDragOver = function(event, trackId) {
  event.preventDefault();
  if (event.currentTarget instanceof Element) {
    event.currentTarget.style.outline = '2px dashed #38bdf8';
  }
};
window.canvasCompositionLaneDragLeave = function(event) {
  if (event.currentTarget instanceof Element) {
    event.currentTarget.style.outline = '';
  }
};
window.canvasCompositionLaneDrop = function(event, trackId) {
  event.preventDefault();
  if (event.currentTarget instanceof Element) {
    event.currentTarget.style.outline = '';
  }
  const comp = ensureCreativeComposition();
  if (!comp) return;
  const lane = event.currentTarget;
  const rect = lane.getBoundingClientRect();
  const ratio = Math.max(0, Math.min(1, (event.clientX - rect.left) / Math.max(1, rect.width)));
  const atMs = Math.round(ratio * comp.durationMs);
  // application/x-prom-asset payload (Phase 2.2 format)
  let payload = null;
  try {
    const json = event.dataTransfer?.getData('application/x-prom-asset');
    if (json) payload = JSON.parse(json);
  } catch {}
  if (!payload) {
    showToast?.('Unsupported drop', 'Only assets from the Prometheus library are accepted today.', 'warning');
    return;
  }
  const track = comp.tracks.find((t) => t.id === trackId);
  if (!track) return;
  if (!payload.lane || !['hyperframes', 'html-motion', 'remotion'].includes(payload.lane)) {
    showToast?.('Use HyperFrames', 'Assets now go into HyperFrames, HTML Motion, or Remotion clips instead of raw timeline layers.', 'warning');
    return;
  }
  try {
    compositionAddClip(comp, {
      trackId,
      atMs,
      durationMs: payload.durationMs || 4000,
      lane: payload.lane,
      label: payload.label || 'Asset',
      source: payload.source,
    });
    persistCompositionState();
    renderCreativeWorkspace?.();
  } catch (err) {
    showToast?.('Drop failed', String(err?.message || err), 'error');
  }
};

