function appendVoiceAgentToolProcessEvent(msg = {}) {
  const sid = String(msg.sessionId || '').trim();
  if (!sid) return;
  const evt = { type: String(msg.event || ''), ...(msg.data || {}) };
  const action = String(evt.action || evt.name || '').trim();
  if (!action) return;
  if (evt.type === 'tool_call') {
    const args = evt.args && typeof evt.args === 'object' ? evt.args : {};
    const entry = {
      type: (action.startsWith('skill_') || action.startsWith('voice_skill')) ? 'skill' : 'tool',
      content: formatToolCallForLog(action, args, null),
      actor: 'Voice Agent',
      extra: { actor: 'Voice Agent', ...args },
      ts: new Date().toLocaleTimeString(),
    };
    addSessionProcessEntry(sid, entry.type, entry.content, entry.extra);
    attachVoiceAgentProcessEntriesToRecentAssistantTurn(sid, [entry]);
    return;
  }
  if (evt.type === 'tool_result') {
    const resultText = String(evt.result || evt.output || '').trim();
    const ok = evt.error === true ? false : !/^ERROR:/i.test(resultText);
    const entry = {
      type: ok ? 'result' : 'error',
      content: formatToolResultForLog(action, resultText, ok, null),
      actor: 'Voice Agent',
      extra: { actor: 'Voice Agent' },
      ts: new Date().toLocaleTimeString(),
    };
    addSessionProcessEntry(sid, entry.type, entry.content, entry.extra);
    attachVoiceAgentProcessEntriesToRecentAssistantTurn(sid, [entry]);
  }
}

wsEventBus.on('voice_agent_tool_event', appendVoiceAgentToolProcessEvent);

function appendTimerMessageToSession(sessionId, message) {
  const sid = String(sessionId || '').trim();
  if (!sid || !message || !message.role) return;
  let sess = (window.chatSessions || []).find((s) => s.id === sid);
  if (!sess) {
    sess = {
      id: sid,
      title: 'Timer chat',
      history: [],
      processLog: [],
      createdAt: Date.now(),
      updatedAt: Date.now(),
      unread: sid !== window.activeChatSessionId,
    };
    window.chatSessions.push(sess);
  }
  sess.history = Array.isArray(sess.history) ? sess.history : [];
  const next = {
    role: message.role === 'ai' ? 'assistant' : (message.role === 'assistant' ? 'assistant' : 'user'),
    content: String(message.content || ''),
    timestamp: Number(message.timestamp) || Date.now(),
    channel: 'system',
    channelLabel: 'timer',
  };
  const last = sess.history.length > 0 ? sess.history[sess.history.length - 1] : null;
  if (
    last
    && String(last.role || '') === String(next.role || '')
    && String(last.content || '') === String(next.content || '')
    && String(last.channelLabel || '').toLowerCase() === 'timer'
  ) {
    return;
  }
  sess.history.push(next);
  sess.updatedAt = Date.now();
  applyAutoSessionTitleOnce(sess, sess.history);
  if (sid !== window.activeChatSessionId) sess.unread = true;
  saveChatSessions();
  if (typeof window.renderSessionsList === 'function') window.renderSessionsList();
  if (sid === window.activeChatSessionId) {
    syncActiveChat();
    renderChatMessages();
  }
}

function appendTimerProcessEntry(sessionId, type, content) {
  const sid = String(sessionId || '').trim();
  const text = String(content || '').trim();
  if (!sid || !text) return;
  const sess = (window.chatSessions || []).find((s) => s.id === sid);
  if (!sess) return;
  sess.processLog = Array.isArray(sess.processLog) ? sess.processLog : [];
  sess.processLog.push({
    type,
    content: text,
    timestamp: Date.now(),
    actor: 'Timer',
  });
  sess.updatedAt = Date.now();
  saveChatSessions();
  if (sid === window.activeChatSessionId) {
    syncActiveChat();
    renderProcessLog();
  }
}

