wsEventBus.on('browser:teach:verification_started', (msg) => {
  if (!isBrowserEventForActiveSession(msg, { scope: 'primary' })) return;
  const state = getBrowserCanvasState();
  const teach = getBrowserTeachSession(state);
  if (!teach.active) return;
  teach.phase = 'verifying';
  teach.verification = null;
  state.active = true;
  state.url = String(msg?.url || state.url || '').trim();
  state.title = String(msg?.title || state.title || '').trim();
  state.statusLabel = String(msg?.statusLabel || 'Watching the detached Teach verifier tab.').trim();
  followBrowserCanvasSession(String(msg?.verifierSessionId || '').trim(), {
    statusLabel: state.statusLabel,
    render: false,
    requestData: false,
  });
  setBrowserCanvasSurface('browser');
  renderBrowserCanvasSurface();
  persistActiveChat();
  requestBrowserKnowledge(true);
  syncBrowserCanvasStream({ force: true });
  addProcessEntry('info', 'Teach: switched the browser canvas to the detached verifier tab.');
});

wsEventBus.on('browser:teach:verification', (msg) => {
  if (!isBrowserEventForActiveSession(msg, { scope: 'primary' })) return;
  const state = getBrowserCanvasState();
  const teach = getBrowserTeachSession(state);
  if (!teach.active) return;
  teach.phase = normalizeBrowserTeachPhase(msg?.phase || 'verified');
  teach.verification = msg?.verification && typeof msg.verification === 'object'
    ? {
        status: String(msg.verification.status || '').trim(),
        mode: String(msg.verification.mode || '').trim(),
        boundaryLabel: String(msg.verification.boundaryLabel || '').trim(),
        stopBeforeStep: Number(msg.verification.stopBeforeStep || 0) || 0,
        verifierSessionId: String(msg.verification.verifierSessionId || '').trim(),
        executedCount: Number(msg.verification.executedCount || 0) || 0,
        totalRecordedSteps: Number(msg.verification.totalRecordedSteps || 0) || 0,
        riskyStepIndexes: Array.isArray(msg.verification.riskyStepIndexes)
          ? msg.verification.riskyStepIndexes.map((value) => Number(value || 0) || 0).filter(Boolean)
          : [],
        failedStep: Number(msg.verification.failedStep || 0) || 0,
        failureSummary: String(msg.verification.failureSummary || '').trim(),
        finalUrl: String(msg.verification.finalUrl || '').trim(),
        finalTitle: String(msg.verification.finalTitle || '').trim(),
        startedAt: Number(msg.verification.startedAt || 0) || 0,
        completedAt: Number(msg.verification.completedAt || 0) || 0,
      }
    : null;
  state.statusLabel = teach.verification
    ? `Teach verification ${String(teach.verification.status || 'completed').trim().toLowerCase()}.`
    : 'Teach verification completed.';
  state.updatedAt = Number(msg?.timestamp || Date.now()) || Date.now();
  renderBrowserCanvasSurface();
  persistActiveChat();
  syncBrowserTeachSessionToBackend();
});

