// ─── Background agent late-completion injection ───────────────
// When a background agent finishes AFTER the main turn's finalization gate
// already ran (or during the turn but after the done event), the server
// sends bg_agent_done via WebSocket with the full result. We inject it into
// the last AI message as a proper inner panel so it's visible to the user.
wsEventBus.on('bg_agent_done', (msg) => {
  completeBackgroundSpawnLane(msg || {});
  if (msg.state !== 'completed' || !msg.result) return;
  if (window.isThinking) {
    addProcessEntry('info', `Background Agent ${msg.bgId}: result ready; merging into final reply.`, { actor: 'Background Agent' });
    renderProcessLog();
    return;
  }
  // Only inject into the currently active session's history
  const activeSession = window.chatSessions?.find(s => s.id === window.activeChatSessionId);
  if (!activeSession) return;
  const history = activeSession.history || [];
  // Find the last AI message
  let lastAiIdx = -1;
  for (let i = history.length - 1; i >= 0; i--) {
    if (history[i].role === 'ai' || history[i].role === 'assistant') { lastAiIdx = i; break; }
  }
  if (lastAiIdx === -1) return;
  const lastMsg = history[lastAiIdx];
  const existingContent = String(lastMsg.content || '');
  const nextFileChanges = mergeFileChangesWithBackground(lastMsg.fileChanges || null, window.activeChatSessionId) || lastMsg.fileChanges;
  // Don't double-inject text, but still allow late file-change metadata to attach.
  if (/background agent response:/i.test(existingContent)) {
    if (nextFileChanges && nextFileChanges !== lastMsg.fileChanges) {
      history[lastAiIdx] = { ...lastMsg, fileChanges: nextFileChanges };
      persistActiveChat();
      renderChatMessages();
    }
    return;
  }
  // Append the background agent inner panel marker
  history[lastAiIdx] = {
    ...lastMsg,
    content: existingContent.trim() + '\n\nBackground agent response:\n' + String(msg.result || ''),
    fileChanges: nextFileChanges,
  };
  persistActiveChat();
  renderChatMessages();
  addProcessEntry('info', `Background Agent ${msg.bgId}: result injected into reply.`, { actor: 'Background Agent' });
});

// ─── Coordinator progress: show team coordinator activity in process log ───
// When ask_team_coordinator runs (or the team coordinator is working), the backend
// broadcasts coordinator_progress WS events so the process log shows activity
// instead of appearing to hang silently.
wsEventBus.on('voice_interruption', (msg) => {
  if (msg?.isInterruption === false) return;
  const sessionId = String(msg?.sessionId || '').trim();
  const activeSessionId = String(window.activeChatSessionId || '').trim();
  if (!sessionId || sessionId !== activeSessionId) return;
  const intent = String(msg?.intent || 'unknown').trim();
  const transcript = String(msg?.transcript || msg?.currentUserPrompt || msg?.userInterruptionTranscript || '').trim();
  addSessionProcessEntry(sessionId, 'warn', `Voice interruption: ${intent}${msg?.shouldAbortOriginalRun ? ' (worker abort requested)' : ''}`, {
    actor: 'Voice Interruption',
    eventId: msg?.eventId,
    runtimeId: msg?.runtimeId,
    transcript,
    action: msg?.action,
    steerApplied: msg?.steerApplied === true,
  });
  appendVoiceInterruptionWorkflowSplit(sessionId, transcript, {
    ...msg,
    classification: {
      ...(msg?.classification || {}),
      intent,
      shouldAbortOriginalRun: msg?.shouldAbortOriginalRun === true,
    },
  });
});

wsEventBus.on('coordinator_progress', (msg) => {
  const eventSessionId = String(msg.sessionId || '').trim();
  const activeSessionId = String(window.activeChatSessionId || '').trim();
  if (!eventSessionId || eventSessionId !== activeSessionId) return;
  const teamTag = msg.teamId ? ` [team:${msg.teamId}]` : '';
  addProcessEntry('info', `[coordinator${teamTag}] ${formatForwardedToolMessageForLog(msg.message).slice(0, 200)}`, { actor: 'Coordinator' });
  renderProcessLog();
});

// ─── State sync: ensure window.* stays in sync ────────────────
// Wrap key functions to sync state before/after execution



['approval_created', 'approval_approved', 'approval_denied', 'approval_executing', 'approval_executed', 'approval_failed', 'approval_expired'].forEach((eventName) => {
  wsEventBus.on(eventName, (msg) => {
    const matchesSession = String(msg.sessionId || '').trim() === String(window.activeChatSessionId || '').trim();
    if (typeof window.loadApprovals === 'function') window.loadApprovals();
    if (matchesSession && typeof window.loadSessionApprovals === 'function') {
      window.loadSessionApprovals();
    } else if (eventName === 'approval_created') {
      const badge = document.getElementById('approvals-badge');
      if (badge) {
        badge.style.display = 'inline-block';
        badge.textContent = '+';
      }
    }
    if (eventName === 'approval_created' && matchesSession) {
      showInlineApprovalFromEvent(msg);
    } else if (matchesSession) {
      const statusByEvent = {
        approval_approved: 'approved',
        approval_denied: 'rejected',
        approval_executing: 'approved',
        approval_executed: 'approved',
        approval_failed: 'failed',
        approval_expired: 'expired',
      };
      updateInlineApprovalStatusFromEvent(msg, statusByEvent[eventName] || '');
    }
  });
});

['question_created', 'question_answered', 'question_cancelled', 'question_expired'].forEach((eventName) => {
  wsEventBus.on(eventName, async (msg) => {
    if (typeof window.loadSessionApprovals === 'function') window.loadSessionApprovals();
    if (eventName === 'question_created') {
      // Insert into the question's OWN session (upsert handles non-active sessions
      // by marking unread) — do not gate on the currently-focused session, or
      // questions from background tasks / subagents never render.
      const question = msg.question ? questionFromEventPayload(msg, 'pending') : normalizePrometheusQuestionRecord(await fetchPrometheusQuestionDetailsById(msg.questionId), { ...msg, status: 'pending' });
      upsertInlinePrometheusQuestion(question);
      return;
    }
    const statusByEvent = {
      question_answered: 'answered',
      question_cancelled: 'cancelled',
      question_expired: 'expired',
    };
    updateInlinePrometheusQuestionStatus(msg, statusByEvent[eventName] || '');
  });
});

if (isCreativeRenderWorkerMode()) {
  setTimeout(() => {
    bootCreativeRenderWorkerMode().catch((err) => {
      console.error('[creative render worker]', err);
    });
  }, 250);
}
